window.TG_SEED_CORPUS = [{"id":"english1-2010-t1-p1-s1","examKey":"english1","examLabel":"英语一","year":"2010","text":1,"paragraph":1,"sentenceNo":1,"sentence":"Of all the changes that have taken place in English-language newspapers during the past quarter-century, perhaps the most far-reaching has been the inexorable decline in the scope and seriousness of their arts coverage.","path":"english1/2010.html"},{"id":"english1-2010-t1-p2-s1","examKey":"english1","examLabel":"英语一","year":"2010","text":1,"paragraph":2,"sentenceNo":1,"sentence":"It is difficult to the point of impossibility for the average reader under the age of forty to imagine a time when high-quality arts criticism could be found in most big-city newspapers.","path":"english1/2010.html"},{"id":"english1-2010-t1-p2-s2","examKey":"english1","examLabel":"英语一","year":"2010","text":1,"paragraph":2,"sentenceNo":2,"sentence":"Yet a considerable number of the most significant collections of criticism published in the 20th century consisted in large part of newspaper reviews.","path":"english1/2010.html"},{"id":"english1-2010-t1-p2-s3","examKey":"english1","examLabel":"英语一","year":"2010","text":1,"paragraph":2,"sentenceNo":3,"sentence":"To read such books today is to marvel at the fact that their learned contents were once deemed suitable for publication in general-circulation dailies.","path":"english1/2010.html"},{"id":"english1-2010-t1-p3-s1","examKey":"english1","examLabel":"英语一","year":"2010","text":1,"paragraph":3,"sentenceNo":1,"sentence":"We are even farther removed from the unfocused newspaper reviews published in England between the turn of the 20th century and the eve of World War II, at a time when newsprint was dirt-cheap and stylish arts criticism was considered an ornament to the publications in which it appeared.","path":"english1/2010.html"},{"id":"english1-2010-t1-p3-s2","examKey":"english1","examLabel":"英语一","year":"2010","text":1,"paragraph":3,"sentenceNo":2,"sentence":"In those far-off days, it was taken for granted that the critics of major papers would write in detail and at length about the events they covered.","path":"english1/2010.html"},{"id":"english1-2010-t1-p3-s3","examKey":"english1","examLabel":"英语一","year":"2010","text":1,"paragraph":3,"sentenceNo":3,"sentence":"Theirs was a serious business, and even those reviewers who wore their learning lightly, like George Bernard Shaw and Ernest Newman, could be trusted to know what they were about.","path":"english1/2010.html"},{"id":"english1-2010-t1-p3-s4","examKey":"english1","examLabel":"英语一","year":"2010","text":1,"paragraph":3,"sentenceNo":4,"sentence":"These men believed in journalism as a calling, and were proud to be published in the daily press.","path":"english1/2010.html"},{"id":"english1-2010-t1-p3-s5","examKey":"english1","examLabel":"英语一","year":"2010","text":1,"paragraph":3,"sentenceNo":5,"sentence":"“So few authors have brains enough or literary gift enough to keep their own end up in journalism,” Newman wrote, “that I am tempted to define ‘journalism’ as ‘a term of contempt applied by writers who are not read to writers who are’.”","path":"english1/2010.html"},{"id":"english1-2010-t1-p4-s1","examKey":"english1","examLabel":"英语一","year":"2010","text":1,"paragraph":4,"sentenceNo":1,"sentence":"Unfortunately, these critics are virtually forgotten.","path":"english1/2010.html"},{"id":"english1-2010-t1-p4-s2","examKey":"english1","examLabel":"英语一","year":"2010","text":1,"paragraph":4,"sentenceNo":2,"sentence":"Neville Cardus, who wrote for the Manchester Guardian from 1917 until shortly before his death in 1975, is now known solely as a writer of essays on the game of cricket.","path":"english1/2010.html"},{"id":"english1-2010-t1-p4-s3","examKey":"english1","examLabel":"英语一","year":"2010","text":1,"paragraph":4,"sentenceNo":3,"sentence":"During his lifetime, though, he was also one of England ’s foremost classical-music critics, and a stylist so widely admired that his Autobiography (1947) became a best-seller.","path":"english1/2010.html"},{"id":"english1-2010-t1-p4-s4","examKey":"english1","examLabel":"英语一","year":"2010","text":1,"paragraph":4,"sentenceNo":4,"sentence":"He was knighted in 1967, the first music critic to be so honored.","path":"english1/2010.html"},{"id":"english1-2010-t1-p4-s5","examKey":"english1","examLabel":"英语一","year":"2010","text":1,"paragraph":4,"sentenceNo":5,"sentence":"Yet only one of his books is now in print, and his vast body of writings on music is unknown save to specialists.","path":"english1/2010.html"},{"id":"english1-2010-t1-p5-s1","examKey":"english1","examLabel":"英语一","year":"2010","text":1,"paragraph":5,"sentenceNo":1,"sentence":"Is there any chance that Cardus’s criticism will enjoy a revival?","path":"english1/2010.html"},{"id":"english1-2010-t1-p5-s2","examKey":"english1","examLabel":"英语一","year":"2010","text":1,"paragraph":5,"sentenceNo":2,"sentence":"The prospect seems remote.","path":"english1/2010.html"},{"id":"english1-2010-t1-p5-s3","examKey":"english1","examLabel":"英语一","year":"2010","text":1,"paragraph":5,"sentenceNo":3,"sentence":"Journalistic tastes had changed long before his death, and postmodern readers have little use for the richly upholstered Victorian prose in which he specialized.","path":"english1/2010.html"},{"id":"english1-2010-t1-p5-s4","examKey":"english1","examLabel":"英语一","year":"2010","text":1,"paragraph":5,"sentenceNo":4,"sentence":"Moreover, the amateur tradition in music criticism has been in headlong retreat.","path":"english1/2010.html"},{"id":"english1-2010-t2-p1-s1","examKey":"english1","examLabel":"英语一","year":"2010","text":2,"paragraph":1,"sentenceNo":1,"sentence":"Over the past decade, thousands of patents have been granted for what are called business methods.","path":"english1/2010.html"},{"id":"english1-2010-t2-p1-s2","examKey":"english1","examLabel":"英语一","year":"2010","text":2,"paragraph":1,"sentenceNo":2,"sentence":"Amazon.com received one for its “one-click” on line payment system.","path":"english1/2010.html"},{"id":"english1-2010-t2-p1-s3","examKey":"english1","examLabel":"英语一","year":"2010","text":2,"paragraph":1,"sentenceNo":3,"sentence":"Merrill Lynch got legal protection for an asset allocation strategy.","path":"english1/2010.html"},{"id":"english1-2010-t2-p1-s4","examKey":"english1","examLabel":"英语一","year":"2010","text":2,"paragraph":1,"sentenceNo":4,"sentence":"One inventor patented a technique for lifting a box.","path":"english1/2010.html"},{"id":"english1-2010-t2-p2-s1","examKey":"english1","examLabel":"英语一","year":"2010","text":2,"paragraph":2,"sentenceNo":1,"sentence":"Now the nation’s top patent court appears completely ready to scale back on business-method patents, which have been completely ready to scale back on business-method patents.","path":"english1/2010.html"},{"id":"english1-2010-t2-p2-s2","examKey":"english1","examLabel":"英语一","year":"2010","text":2,"paragraph":2,"sentenceNo":2,"sentence":"In a move that has intellectual-property lawyers abuzz, the U.S.","path":"english1/2010.html"},{"id":"english1-2010-t2-p2-s3","examKey":"english1","examLabel":"英语一","year":"2010","text":2,"paragraph":2,"sentenceNo":3,"sentence":"Court of Appeals for the Federal Circuit said it would use a particular case to conduct a broad review of business-method patents.","path":"english1/2010.html"},{"id":"english1-2010-t2-p2-s4","examKey":"english1","examLabel":"英语一","year":"2010","text":2,"paragraph":2,"sentenceNo":4,"sentence":"In re Bilski, as the case is known, is “a very big deal,” says Dennis D.","path":"english1/2010.html"},{"id":"english1-2010-t2-p2-s5","examKey":"english1","examLabel":"英语一","year":"2010","text":2,"paragraph":2,"sentenceNo":5,"sentence":"Crouch of the University of Missouri School of Law.","path":"english1/2010.html"},{"id":"english1-2010-t2-p2-s6","examKey":"english1","examLabel":"英语一","year":"2010","text":2,"paragraph":2,"sentenceNo":6,"sentence":"It “has the potential to eliminate an entire class of patents.”","path":"english1/2010.html"},{"id":"english1-2010-t2-p3-s1","examKey":"english1","examLabel":"英语一","year":"2010","text":2,"paragraph":3,"sentenceNo":1,"sentence":"Curbs on business-method claims would be a dramatic about-face, because it was the Federal Circuit itself that introduced such patents with its 1998 decision in the so-called State Street Bank case, approving a patent on a way of pooling mutual-fund assets.","path":"english1/2010.html"},{"id":"english1-2010-t2-p3-s2","examKey":"english1","examLabel":"英语一","year":"2010","text":2,"paragraph":3,"sentenceNo":2,"sentence":"That ruling produced an explosion in business-method patent filings, initially by emerging Internet companies trying to stake out exclusive rights to specific types of online transactions.","path":"english1/2010.html"},{"id":"english1-2010-t2-p3-s3","examKey":"english1","examLabel":"英语一","year":"2010","text":2,"paragraph":3,"sentenceNo":3,"sentence":"Later, more established companies raced to add such patents to their files, if only as a defensive move against rivals that might beat them to the punch.","path":"english1/2010.html"},{"id":"english1-2010-t2-p3-s4","examKey":"english1","examLabel":"英语一","year":"2010","text":2,"paragraph":3,"sentenceNo":4,"sentence":"In 2005, IBM noted in a court filing that it had been issued more than 300 business-method patents, despite the fact that it questioned the legal basis for granting them.","path":"english1/2010.html"},{"id":"english1-2010-t2-p3-s5","examKey":"english1","examLabel":"英语一","year":"2010","text":2,"paragraph":3,"sentenceNo":5,"sentence":"Similarly, some Wall Street investment firms armed themselves with patents for financial products, even as they took positions in court cases opposing the practice.","path":"english1/2010.html"},{"id":"english1-2010-t2-p4-s1","examKey":"english1","examLabel":"英语一","year":"2010","text":2,"paragraph":4,"sentenceNo":1,"sentence":"The Bilski case involves a claimed patent on a method for hedging risk in the energy market.","path":"english1/2010.html"},{"id":"english1-2010-t2-p4-s2","examKey":"english1","examLabel":"英语一","year":"2010","text":2,"paragraph":4,"sentenceNo":2,"sentence":"The Federal Circuit issued an unusual order stating that the case would be heard by all 12 of the court’s judges, rather than a typical panel of three, and that one issue it wants to evaluate is whether it should “reconsider” its State Street Bank ruling.","path":"english1/2010.html"},{"id":"english1-2010-t2-p5-s1","examKey":"english1","examLabel":"英语一","year":"2010","text":2,"paragraph":5,"sentenceNo":1,"sentence":"The Federal Circuit’s action comes in the wake of a series of recent decisions by the Supreme Court that has narrowed the scope of protections for patent holders.","path":"english1/2010.html"},{"id":"english1-2010-t2-p5-s2","examKey":"english1","examLabel":"英语一","year":"2010","text":2,"paragraph":5,"sentenceNo":2,"sentence":"Last April, for example, the justices signaled that too many patents were being upheld for “inventions” that are obvious.","path":"english1/2010.html"},{"id":"english1-2010-t2-p5-s3","examKey":"english1","examLabel":"英语一","year":"2010","text":2,"paragraph":5,"sentenceNo":3,"sentence":"The judges on the Federal Circuit are “reacting to the anti-patent trend at the Supreme Court,” says Harold C.","path":"english1/2010.html"},{"id":"english1-2010-t2-p5-s4","examKey":"english1","examLabel":"英语一","year":"2010","text":2,"paragraph":5,"sentenceNo":4,"sentence":"Wegner, a patent attorney and professor at George Washington University Law School.","path":"english1/2010.html"},{"id":"english1-2010-t3-p1-s1","examKey":"english1","examLabel":"英语一","year":"2010","text":3,"paragraph":1,"sentenceNo":1,"sentence":"In his book The Tipping Point, Malcolm Gladwell argues that “ social epidemics” are driven in large part by the actions of a tiny minority of special individuals, often called influentials, who are unusually informed, persuasive, or well connected.","path":"english1/2010.html"},{"id":"english1-2010-t3-p1-s2","examKey":"english1","examLabel":"英语一","year":"2010","text":3,"paragraph":1,"sentenceNo":2,"sentence":"The idea is intuitively compelling, but it doesn’t explain how ideas actually spread.","path":"english1/2010.html"},{"id":"english1-2010-t3-p2-s1","examKey":"english1","examLabel":"英语一","year":"2010","text":3,"paragraph":2,"sentenceNo":1,"sentence":"The supposed importance of influentials derives from a plausible-sounding but largely untested theory called the “ two-step flow of communication ”: Information flows from the media to the influentials and from them to everyone else.","path":"english1/2010.html"},{"id":"english1-2010-t3-p2-s2","examKey":"english1","examLabel":"英语一","year":"2010","text":3,"paragraph":2,"sentenceNo":2,"sentence":"Marketers have embraced the two-step flow because it suggests that if they can just find and influence the influentials, those select people will do most of the work for them.","path":"english1/2010.html"},{"id":"english1-2010-t3-p2-s3","examKey":"english1","examLabel":"英语一","year":"2010","text":3,"paragraph":2,"sentenceNo":3,"sentence":"The theory also seems to explain the sudden and unexpected popularity of certain looks, brands, or neighborhoods.","path":"english1/2010.html"},{"id":"english1-2010-t3-p2-s4","examKey":"english1","examLabel":"英语一","year":"2010","text":3,"paragraph":2,"sentenceNo":4,"sentence":"In many such cases, a cursory search for causes finds that some small group of people was wearing, promoting, or developing whatever it is before anyone else paid attention.","path":"english1/2010.html"},{"id":"english1-2010-t3-p2-s5","examKey":"english1","examLabel":"英语一","year":"2010","text":3,"paragraph":2,"sentenceNo":5,"sentence":"Anecdotal evidence of this kind fits nicely with the idea that only certain special people can drive trends.","path":"english1/2010.html"},{"id":"english1-2010-t3-p3-s1","examKey":"english1","examLabel":"英语一","year":"2010","text":3,"paragraph":3,"sentenceNo":1,"sentence":"In their recent work, however, some researchers have come up with the finding that influentials have far less impact on social epidemics than is generally supposed.","path":"english1/2010.html"},{"id":"english1-2010-t3-p3-s2","examKey":"english1","examLabel":"英语一","year":"2010","text":3,"paragraph":3,"sentenceNo":2,"sentence":"In fact, they don’t seem to be required at all.","path":"english1/2010.html"},{"id":"english1-2010-t3-p4-s1","examKey":"english1","examLabel":"英语一","year":"2010","text":3,"paragraph":4,"sentenceNo":1,"sentence":"The researchers ’ argument stems from a simple observation about social influence: With the exception of a few celebrities like Oprah Winfrey — whose outsize presence is primarily a function of media, not interpersonal, influence — even the most influential members of a population simply don’t interact with that many others.","path":"english1/2010.html"},{"id":"english1-2010-t3-p4-s2","examKey":"english1","examLabel":"英语一","year":"2010","text":3,"paragraph":4,"sentenceNo":2,"sentence":"Yet it is precisely these non-celebrity influentials who, according to the two-step-flow theory, are supposed to drive social epidemics by influencing their friends and colleagues directly.","path":"english1/2010.html"},{"id":"english1-2010-t3-p4-s3","examKey":"english1","examLabel":"英语一","year":"2010","text":3,"paragraph":4,"sentenceNo":3,"sentence":"For a social epidemic to occur, however, each person so affected must then influence his or her own acquaintances, who must in turn influence theirs, and so on; and just how many others pay attention to each of these people has little to do with the initial influential.","path":"english1/2010.html"},{"id":"english1-2010-t3-p4-s4","examKey":"english1","examLabel":"英语一","year":"2010","text":3,"paragraph":4,"sentenceNo":4,"sentence":"If people in the network just two degrees removed from the initial influential prove resistant, for example, the cascade of change won’t propagate very far or affect many people.","path":"english1/2010.html"},{"id":"english1-2010-t3-p5-s1","examKey":"english1","examLabel":"英语一","year":"2010","text":3,"paragraph":5,"sentenceNo":1,"sentence":"Building on the basic truth about interpersonal influence, the researchers studied the dynamics of social influence by conducting thousands of computer simulations of populations, manipulating a number of variables relating to people’s ability to influence others and their tendency to be influenced.","path":"english1/2010.html"},{"id":"english1-2010-t3-p5-s2","examKey":"english1","examLabel":"英语一","year":"2010","text":3,"paragraph":5,"sentenceNo":2,"sentence":"They found that the principal requirement for what is called “global cascades” — the widespread propagation of influence through networks — is the presence not of a few influentials, but, rather, of a critical mass of easily influenced people.","path":"english1/2010.html"},{"id":"english1-2010-t4-p1-s1","examKey":"english1","examLabel":"英语一","year":"2010","text":4,"paragraph":1,"sentenceNo":1,"sentence":"Bankers have been blaming themselves for their troubles in public.","path":"english1/2010.html"},{"id":"english1-2010-t4-p1-s2","examKey":"english1","examLabel":"英语一","year":"2010","text":4,"paragraph":1,"sentenceNo":2,"sentence":"Behind the scenes, they have been taking aim at someone else: the accounting standard-setters.","path":"english1/2010.html"},{"id":"english1-2010-t4-p1-s3","examKey":"english1","examLabel":"英语一","year":"2010","text":4,"paragraph":1,"sentenceNo":3,"sentence":"Their rules, moan the banks, have forced them to report enormous losses, and it’s just not fair.","path":"english1/2010.html"},{"id":"english1-2010-t4-p1-s4","examKey":"english1","examLabel":"英语一","year":"2010","text":4,"paragraph":1,"sentenceNo":4,"sentence":"These rules say they must value some assets at the price a third party would pay, not the price managers and regulators would like them to fetch.","path":"english1/2010.html"},{"id":"english1-2010-t4-p2-s1","examKey":"english1","examLabel":"英语一","year":"2010","text":4,"paragraph":2,"sentenceNo":1,"sentence":"Unfortunately, banks’ lobbying now seems to be working.","path":"english1/2010.html"},{"id":"english1-2010-t4-p2-s2","examKey":"english1","examLabel":"英语一","year":"2010","text":4,"paragraph":2,"sentenceNo":2,"sentence":"The details may be unknowable, but the independence of standard-setters, essential to the proper functioning of capital markets, is being compromised.","path":"english1/2010.html"},{"id":"english1-2010-t4-p2-s3","examKey":"english1","examLabel":"英语一","year":"2010","text":4,"paragraph":2,"sentenceNo":3,"sentence":"And, unless banks carry toxic assets at prices that attract buyers, reviving the banking system will be difficult.","path":"english1/2010.html"},{"id":"english1-2010-t4-p3-s1","examKey":"english1","examLabel":"英语一","year":"2010","text":4,"paragraph":3,"sentenceNo":1,"sentence":"After a bruising encounter with Congress, America’s Financial Accounting Standards Board ( FASB ) rushed through rule changes.","path":"english1/2010.html"},{"id":"english1-2010-t4-p3-s2","examKey":"english1","examLabel":"英语一","year":"2010","text":4,"paragraph":3,"sentenceNo":2,"sentence":"These gave banks more freedom to use models to value illiquid assets and more flexibility in recognizing losses on long-term assets in their income statements.","path":"english1/2010.html"},{"id":"english1-2010-t4-p3-s3","examKey":"english1","examLabel":"英语一","year":"2010","text":4,"paragraph":3,"sentenceNo":3,"sentence":"Bob Herz, the FASB’s chairman, cried out against those who “question our motives.” Yet bank shares rose and the changes enhance what one lobbying group politely calls “the use of judgment by management.”","path":"english1/2010.html"},{"id":"english1-2010-t4-p4-s1","examKey":"english1","examLabel":"英语一","year":"2010","text":4,"paragraph":4,"sentenceNo":1,"sentence":"European ministers instantly demanded that the International Accounting Standards Board (IASB) do likewise.","path":"english1/2010.html"},{"id":"english1-2010-t4-p4-s2","examKey":"english1","examLabel":"英语一","year":"2010","text":4,"paragraph":4,"sentenceNo":2,"sentence":"The IASB says it does not want to act without overall planning, but the pressure to fold when it completes its reconstruction of rules later this year is strong.","path":"english1/2010.html"},{"id":"english1-2010-t4-p4-s3","examKey":"english1","examLabel":"英语一","year":"2010","text":4,"paragraph":4,"sentenceNo":3,"sentence":"Charlie McCreevy, a European commissioner, warned the IASB that if it did not “live in a political vacuum” but “in the real world” and that Europe could yet develop different rules and that Europe could yet develop different rules.","path":"english1/2010.html"},{"id":"english1-2010-t4-p5-s1","examKey":"english1","examLabel":"英语一","year":"2010","text":4,"paragraph":5,"sentenceNo":1,"sentence":"It was banks that were on the wrong planet, with accounts that vastly overvalued assets.","path":"english1/2010.html"},{"id":"english1-2010-t4-p5-s2","examKey":"english1","examLabel":"英语一","year":"2010","text":4,"paragraph":5,"sentenceNo":2,"sentence":"Today they argue that market prices overstate losses, because they largely reflect the temporary illiquidity of markets, not the likely extent of bad debts.","path":"english1/2010.html"},{"id":"english1-2010-t4-p5-s3","examKey":"english1","examLabel":"英语一","year":"2010","text":4,"paragraph":5,"sentenceNo":3,"sentence":"The truth will not be known for years.","path":"english1/2010.html"},{"id":"english1-2010-t4-p5-s4","examKey":"english1","examLabel":"英语一","year":"2010","text":4,"paragraph":5,"sentenceNo":4,"sentence":"But banks’ shares trade below their book value, suggesting that investors are skeptical.","path":"english1/2010.html"},{"id":"english1-2010-t4-p5-s5","examKey":"english1","examLabel":"英语一","year":"2010","text":4,"paragraph":5,"sentenceNo":5,"sentence":"And dead markets partly reflect the paralysis of banks which will not sell assets for fear of booking losses, yet are reluctant to buy all those supposed bargains.","path":"english1/2010.html"},{"id":"english1-2010-t4-p6-s1","examKey":"english1","examLabel":"英语一","year":"2010","text":4,"paragraph":6,"sentenceNo":1,"sentence":"To get the system working again, losses must be recognized and dealt with.","path":"english1/2010.html"},{"id":"english1-2010-t4-p6-s2","examKey":"english1","examLabel":"英语一","year":"2010","text":4,"paragraph":6,"sentenceNo":2,"sentence":"America’s new plan to buy up toxic assets will not work unless banks mark assets to levels which buyers find attractive.","path":"english1/2010.html"},{"id":"english1-2010-t4-p6-s3","examKey":"english1","examLabel":"英语一","year":"2010","text":4,"paragraph":6,"sentenceNo":3,"sentence":"Successful markets require independent and even combative standard-setters.","path":"english1/2010.html"},{"id":"english1-2010-t4-p6-s4","examKey":"english1","examLabel":"英语一","year":"2010","text":4,"paragraph":6,"sentenceNo":4,"sentence":"The FASB and IASB have been exactly that, cleaning up rules on stock options and pensions, for example, against hostility from special interests.","path":"english1/2010.html"},{"id":"english1-2010-t4-p6-s5","examKey":"english1","examLabel":"英语一","year":"2010","text":4,"paragraph":6,"sentenceNo":5,"sentence":"But by giving in to critics now they are inviting pressure to make more concessions.","path":"english1/2010.html"},{"id":"english2-2010-t1-p1-s1","examKey":"english2","examLabel":"英语二","year":"2010","text":1,"paragraph":1,"sentenceNo":1,"sentence":"Q21 段落定位 The longest bull run in a century of art-market history ended on a dramatic note with a sale of 56 works by Damien Hirst, Beautiful Inside My Head Forever, at Sotheby’s in London on September 15th 2008.","path":"english2/2010.html"},{"id":"english2-2010-t1-p1-s2","examKey":"english2","examLabel":"英语二","year":"2010","text":1,"paragraph":1,"sentenceNo":2,"sentence":"All but two pieces sold, fetching more than £70m, a record for a sale by a single artist.","path":"english2/2010.html"},{"id":"english2-2010-t1-p1-s3","examKey":"english2","examLabel":"英语二","year":"2010","text":1,"paragraph":1,"sentenceNo":3,"sentence":"It was a last victory.","path":"english2/2010.html"},{"id":"english2-2010-t1-p1-s4","examKey":"english2","examLabel":"英语二","year":"2010","text":1,"paragraph":1,"sentenceNo":4,"sentence":"As the auctioneer called out bids, in New York one of the oldest banks on Wall Street, Lehman Brothers, filed for bankruptcy.","path":"english2/2010.html"},{"id":"english2-2010-t1-p2-s1","examKey":"english2","examLabel":"英语二","year":"2010","text":1,"paragraph":2,"sentenceNo":1,"sentence":"Q25 段落定位 Q23 段落定位 The world art market had already been losing momentum for a while after rising bewilderingly since 2003.","path":"english2/2010.html"},{"id":"english2-2010-t1-p2-s2","examKey":"english2","examLabel":"英语二","year":"2010","text":1,"paragraph":2,"sentenceNo":2,"sentence":"At its peak in 2007 it was worth some $65 billion, reckons Clare McAndrew, founder of Arts Economics, a research firm — double the figure five years earlier.","path":"english2/2010.html"},{"id":"english2-2010-t1-p2-s3","examKey":"english2","examLabel":"英语二","year":"2010","text":1,"paragraph":2,"sentenceNo":3,"sentence":"Since then it may have come down to $50 billion.","path":"english2/2010.html"},{"id":"english2-2010-t1-p2-s4","examKey":"english2","examLabel":"英语二","year":"2010","text":1,"paragraph":2,"sentenceNo":4,"sentence":"But the market generates interest far beyond its size because it brings together great wealth, enormous egos, greed, passion and controversy in a way matched by few other industries.","path":"english2/2010.html"},{"id":"english2-2010-t1-p3-s1","examKey":"english2","examLabel":"英语二","year":"2010","text":1,"paragraph":3,"sentenceNo":1,"sentence":"Q22 段落定位 In the weeks and months that followed Mr.","path":"english2/2010.html"},{"id":"english2-2010-t1-p3-s2","examKey":"english2","examLabel":"英语二","year":"2010","text":1,"paragraph":3,"sentenceNo":2,"sentence":"Hirst’s sale, spending of any sort became deeply unfashionable.","path":"english2/2010.html"},{"id":"english2-2010-t1-p3-s3","examKey":"english2","examLabel":"英语二","year":"2010","text":1,"paragraph":3,"sentenceNo":3,"sentence":"In the art world that meant collectors stayed away from galleries and salerooms.","path":"english2/2010.html"},{"id":"english2-2010-t1-p3-s4","examKey":"english2","examLabel":"英语二","year":"2010","text":1,"paragraph":3,"sentenceNo":4,"sentence":"Sales of contemporary art fell by two-thirds, and in the most overheated sector, they were down by nearly 90% in the year to November 2008.","path":"english2/2010.html"},{"id":"english2-2010-t1-p3-s5","examKey":"english2","examLabel":"英语二","year":"2010","text":1,"paragraph":3,"sentenceNo":5,"sentence":"Within weeks the world’s two biggest auction houses, Sotheby’s and Christie’s, had to pay out nearly $200m in guarantees to clients who had placed works for sale with them.","path":"english2/2010.html"},{"id":"english2-2010-t1-p4-s1","examKey":"english2","examLabel":"英语二","year":"2010","text":1,"paragraph":4,"sentenceNo":1,"sentence":"The current downturn in the art market is the worst since the Japanese stopped buying Impressionists at the end of 1989.","path":"english2/2010.html"},{"id":"english2-2010-t1-p4-s2","examKey":"english2","examLabel":"英语二","year":"2010","text":1,"paragraph":4,"sentenceNo":2,"sentence":"This time experts reckon that prices are about 40% down on their peak on average, though some have been far more fluctuant.","path":"english2/2010.html"},{"id":"english2-2010-t1-p4-s3","examKey":"english2","examLabel":"英语二","year":"2010","text":1,"paragraph":4,"sentenceNo":3,"sentence":"But Edward Dolman, Christie’s chief executive, says: “I’m pretty confident we’re at the bottom.”","path":"english2/2010.html"},{"id":"english2-2010-t1-p5-s1","examKey":"english2","examLabel":"英语二","year":"2010","text":1,"paragraph":5,"sentenceNo":1,"sentence":"Q24 段落定位 What makes this slump different from the last, he says, is that there are still buyers in the market.","path":"english2/2010.html"},{"id":"english2-2010-t1-p5-s2","examKey":"english2","examLabel":"英语二","year":"2010","text":1,"paragraph":5,"sentenceNo":2,"sentence":"Almost everyone who was interviewed for this special report said that the biggest problem at the moment is not a lack of demand but a lack of good work to sell.","path":"english2/2010.html"},{"id":"english2-2010-t1-p5-s3","examKey":"english2","examLabel":"英语二","year":"2010","text":1,"paragraph":5,"sentenceNo":3,"sentence":"The three Ds — death, debt and divorce — still deliver works of art to the market.","path":"english2/2010.html"},{"id":"english2-2010-t1-p5-s4","examKey":"english2","examLabel":"英语二","year":"2010","text":1,"paragraph":5,"sentenceNo":4,"sentence":"But anyone who does not have to sell is keeping away, waiting for confidence to return.","path":"english2/2010.html"},{"id":"english2-2010-t2-p1-s1","examKey":"english2","examLabel":"英语二","year":"2010","text":2,"paragraph":1,"sentenceNo":1,"sentence":"I was addressing a small gathering in a suburban Virginia living room — a women’s group that had invited men to join them.","path":"english2/2010.html"},{"id":"english2-2010-t2-p1-s2","examKey":"english2","examLabel":"英语二","year":"2010","text":2,"paragraph":1,"sentenceNo":2,"sentence":"Throughout the evening, one man had been particularly talkative, frequently offering ideas and anecdotes, while his wife sat silently beside him on the couch.","path":"english2/2010.html"},{"id":"english2-2010-t2-p1-s3","examKey":"english2","examLabel":"英语二","year":"2010","text":2,"paragraph":1,"sentenceNo":3,"sentence":"Toward the end of the evening, I commented that women frequently complain that their husbands don’t talk to them.","path":"english2/2010.html"},{"id":"english2-2010-t2-p1-s4","examKey":"english2","examLabel":"英语二","year":"2010","text":2,"paragraph":1,"sentenceNo":4,"sentence":"This man quickly nodded in agreement.","path":"english2/2010.html"},{"id":"english2-2010-t2-p1-s5","examKey":"english2","examLabel":"英语二","year":"2010","text":2,"paragraph":1,"sentenceNo":5,"sentence":"He gestured toward his wife and said, “She’s the talker in our family.” The room burst into laughter; the man looked puzzled and hurt.","path":"english2/2010.html"},{"id":"english2-2010-t2-p1-s6","examKey":"english2","examLabel":"英语二","year":"2010","text":2,"paragraph":1,"sentenceNo":6,"sentence":"“It’s true,” he explained.","path":"english2/2010.html"},{"id":"english2-2010-t2-p1-s7","examKey":"english2","examLabel":"英语二","year":"2010","text":2,"paragraph":1,"sentenceNo":7,"sentence":"“When I come home from work I have nothing to say.","path":"english2/2010.html"},{"id":"english2-2010-t2-p1-s8","examKey":"english2","examLabel":"英语二","year":"2010","text":2,"paragraph":1,"sentenceNo":8,"sentence":"If she didn’t keep the conversation going, we’d spend the whole evening in silence.”","path":"english2/2010.html"},{"id":"english2-2010-t2-p2-s1","examKey":"english2","examLabel":"英语二","year":"2010","text":2,"paragraph":2,"sentenceNo":1,"sentence":"Q29 段落定位 Q27 段落定位 This episode crystallizes the irony that although American men tend to talk more than women in public situations, they often talk less at home.","path":"english2/2010.html"},{"id":"english2-2010-t2-p2-s2","examKey":"english2","examLabel":"英语二","year":"2010","text":2,"paragraph":2,"sentenceNo":2,"sentence":"And this pattern is wreaking havoc with marriage.","path":"english2/2010.html"},{"id":"english2-2010-t2-p3-s1","examKey":"english2","examLabel":"英语二","year":"2010","text":2,"paragraph":3,"sentenceNo":1,"sentence":"Q28 段落定位 The pattern was observed by political scientist Andrew Hacker in the late 1970s.","path":"english2/2010.html"},{"id":"english2-2010-t2-p3-s2","examKey":"english2","examLabel":"英语二","year":"2010","text":2,"paragraph":3,"sentenceNo":2,"sentence":"Sociologist Catherine Kohler Riessman reports in her new book Divorce Talk that most of the women she interviewed — but only a few of the men — gave lack of communication as the reason for their divorces.","path":"english2/2010.html"},{"id":"english2-2010-t2-p3-s3","examKey":"english2","examLabel":"英语二","year":"2010","text":2,"paragraph":3,"sentenceNo":3,"sentence":"Given the current divorce rate of nearly 50 percent, that amounts to millions of cases in the United States every year — a virtual epidemic of failed conversation.","path":"english2/2010.html"},{"id":"english2-2010-t2-p4-s1","examKey":"english2","examLabel":"英语二","year":"2010","text":2,"paragraph":4,"sentenceNo":1,"sentence":"Q26 段落定位 In my own research, complaints from women about their husbands most often focused not on tangible inequities such as having given up the chance for a career to accompany a husband to his, or doing far more than their share of daily life-support work like cleaning, cooking and social arrangements.","path":"english2/2010.html"},{"id":"english2-2010-t2-p4-s2","examKey":"english2","examLabel":"英语二","year":"2010","text":2,"paragraph":4,"sentenceNo":2,"sentence":"Instead, they focused on communication: “He doesn’t listen to me.” “He doesn’t talk to me.” I found, as Hacker observed years before, that most wives want their husbands to be, first and foremost, conversational partners, but few husbands share this expectation of their wives.","path":"english2/2010.html"},{"id":"english2-2010-t2-p5-s1","examKey":"english2","examLabel":"英语二","year":"2010","text":2,"paragraph":5,"sentenceNo":1,"sentence":"Q30 段落定位 In short, the image that best represents the current crisis is the stereotypical cartoon scene of a man sitting at the breakfast table with a newspaper held up in front of his face, while a woman glares at the back of it, wanting to talk.","path":"english2/2010.html"},{"id":"english2-2010-t3-p1-s1","examKey":"english2","examLabel":"英语二","year":"2010","text":3,"paragraph":1,"sentenceNo":1,"sentence":"Over the past decade, many companies had perfected the art of creating automatic behaviors — habits — among consumers.","path":"english2/2010.html"},{"id":"english2-2010-t3-p1-s2","examKey":"english2","examLabel":"英语二","year":"2010","text":3,"paragraph":1,"sentenceNo":2,"sentence":"These habits have helped companies earn billions of dollars when customers eat snacks or wipe counters almost without thinking, often in response to a carefully designed set of daily cues.","path":"english2/2010.html"},{"id":"english2-2010-t3-p2-s1","examKey":"english2","examLabel":"英语二","year":"2010","text":3,"paragraph":2,"sentenceNo":1,"sentence":"Q31 段落定位 “There are fundamental public health problems, like dirty hands instead of a soap habit, that remain killers only because we can’t figure out how to change people’s habits,” said Dr.","path":"english2/2010.html"},{"id":"english2-2010-t3-p2-s2","examKey":"english2","examLabel":"英语二","year":"2010","text":3,"paragraph":2,"sentenceNo":2,"sentence":"Curtis.","path":"english2/2010.html"},{"id":"english2-2010-t3-p2-s3","examKey":"english2","examLabel":"英语二","year":"2010","text":3,"paragraph":2,"sentenceNo":3,"sentence":"“We wanted to learn from private industry how to create new behaviors that happen automatically.”","path":"english2/2010.html"},{"id":"english2-2010-t3-p3-s1","examKey":"english2","examLabel":"英语二","year":"2010","text":3,"paragraph":3,"sentenceNo":1,"sentence":"Q33 段落定位 The companies that Dr.","path":"english2/2010.html"},{"id":"english2-2010-t3-p3-s2","examKey":"english2","examLabel":"英语二","year":"2010","text":3,"paragraph":3,"sentenceNo":2,"sentence":"Curtis turned to — Procter & Gamble, Colgate-Palmolive and Unilever — had invested hundreds of millions of dollars finding the subtle cues in consumers’ lives that corporations could use to introduce new routines.","path":"english2/2010.html"},{"id":"english2-2010-t3-p4-s1","examKey":"english2","examLabel":"英语二","year":"2010","text":3,"paragraph":4,"sentenceNo":1,"sentence":"Q34 段落定位 Many of the products we use every day — chewing gums, skin moisturizers, disinfecting wipes, air fresheners, water purifiers, health snacks, teeth whiteners, fabric softeners, vitamins — are results of manufactured habits.","path":"english2/2010.html"},{"id":"english2-2010-t3-p4-s2","examKey":"english2","examLabel":"英语二","year":"2010","text":3,"paragraph":4,"sentenceNo":2,"sentence":"Today, because of shrewd advertising and public health campaigns, many Americans brush teeth twice a day, often with Colgate, Crest or another brand.","path":"english2/2010.html"},{"id":"english2-2010-t3-p5-s1","examKey":"english2","examLabel":"英语二","year":"2010","text":3,"paragraph":5,"sentenceNo":1,"sentence":"Q32 段落定位 A few decades ago, many people didn’t drink water outside of a meal.","path":"english2/2010.html"},{"id":"english2-2010-t3-p5-s2","examKey":"english2","examLabel":"英语二","year":"2010","text":3,"paragraph":5,"sentenceNo":2,"sentence":"Then beverage companies started bottling spring water, and now office workers sip bottled water all day long.","path":"english2/2010.html"},{"id":"english2-2010-t3-p5-s3","examKey":"english2","examLabel":"英语二","year":"2010","text":3,"paragraph":5,"sentenceNo":3,"sentence":"Chewing gum and skin moisturizers also became daily routines.","path":"english2/2010.html"},{"id":"english2-2010-t3-p6-s1","examKey":"english2","examLabel":"英语二","year":"2010","text":3,"paragraph":6,"sentenceNo":1,"sentence":"Q35 段落定位 “Our products succeed when they become part of daily or weekly patterns,” said Carol Berning.","path":"english2/2010.html"},{"id":"english2-2010-t3-p6-s2","examKey":"english2","examLabel":"英语二","year":"2010","text":3,"paragraph":6,"sentenceNo":2,"sentence":"Through experiments and observation, social scientists have learned there is power in tying behaviors to habitual cues through ruthless advertising.","path":"english2/2010.html"},{"id":"english2-2010-t3-p6-s3","examKey":"english2","examLabel":"英语二","year":"2010","text":3,"paragraph":6,"sentenceNo":3,"sentence":"Controversies have erupted when tactics have been used to sell questionable beauty creams or unhealthy foods.","path":"english2/2010.html"},{"id":"english2-2010-t4-p1-s1","examKey":"english2","examLabel":"英语二","year":"2010","text":4,"paragraph":1,"sentenceNo":1,"sentence":"Q40 段落定位 Q36 段落定位 Many Americans regard the jury system as a concrete expression of crucial democratic values, including the principle that all citizens who meet minimal qualifications of age and literacy are equally competent to serve on juries; that jurors should be selected randomly from a representative cross section of the community; that no citizen should be denied the right to serve on a jury on account of race, religion, sex, or national origin; that defendants are entitled to trial by their peers; and that verdicts should represent the conscience of the community and not just the letter of the law.","path":"english2/2010.html"},{"id":"english2-2010-t4-p1-s2","examKey":"english2","examLabel":"英语二","year":"2010","text":4,"paragraph":1,"sentenceNo":2,"sentence":"The jury is also said to be the best surviving example of direct rather than representative democracy.","path":"english2/2010.html"},{"id":"english2-2010-t4-p2-s1","examKey":"english2","examLabel":"英语二","year":"2010","text":4,"paragraph":2,"sentenceNo":1,"sentence":"Q37 段落定位 But as recently as in 1968, jury selection procedures conflicted with these democratic ideals.","path":"english2/2010.html"},{"id":"english2-2010-t4-p2-s2","examKey":"english2","examLabel":"英语二","year":"2010","text":4,"paragraph":2,"sentenceNo":2,"sentence":"In some states, jury duty was limited to persons of supposedly superior intelligence, education, and moral character.","path":"english2/2010.html"},{"id":"english2-2010-t4-p2-s3","examKey":"english2","examLabel":"英语二","year":"2010","text":4,"paragraph":2,"sentenceNo":3,"sentence":"Although the Supreme Court had prohibited intentional racial discrimination, the practice of selecting so-called elite or blue-ribbon juries provided a convenient way around this and other antidiscrimination laws.","path":"english2/2010.html"},{"id":"english2-2010-t4-p3-s1","examKey":"english2","examLabel":"英语二","year":"2010","text":4,"paragraph":3,"sentenceNo":1,"sentence":"Q38 段落定位 The system also failed to regularly include women on juries until the mid-20th century.","path":"english2/2010.html"},{"id":"english2-2010-t4-p3-s2","examKey":"english2","examLabel":"英语二","year":"2010","text":4,"paragraph":3,"sentenceNo":2,"sentence":"Even then several states automatically exempted women from jury duty unless they personally asked to have their names included on the jury list.","path":"english2/2010.html"},{"id":"english2-2010-t4-p3-s3","examKey":"english2","examLabel":"英语二","year":"2010","text":4,"paragraph":3,"sentenceNo":3,"sentence":"This practice was justified by the claim that women were needed at home, and it kept juries unrepresentative of women through the 1960s.","path":"english2/2010.html"},{"id":"english2-2010-t4-p4-s1","examKey":"english2","examLabel":"英语二","year":"2010","text":4,"paragraph":4,"sentenceNo":1,"sentence":"Q39 段落定位 In 1968, the Congress of the United States passed the Jury Selection and Service Act, ushering in a new era of democratic reforms for the jury.","path":"english2/2010.html"},{"id":"english2-2010-t4-p4-s2","examKey":"english2","examLabel":"英语二","year":"2010","text":4,"paragraph":4,"sentenceNo":2,"sentence":"This law abolished special educational requirements for federal jurors and required them to be selected at random from a cross section of the entire community.","path":"english2/2010.html"},{"id":"english2-2010-t4-p4-s3","examKey":"english2","examLabel":"英语二","year":"2010","text":4,"paragraph":4,"sentenceNo":3,"sentence":"In the landmark 1975 decision Taylor v.","path":"english2/2010.html"},{"id":"english2-2010-t4-p4-s4","examKey":"english2","examLabel":"英语二","year":"2010","text":4,"paragraph":4,"sentenceNo":4,"sentence":"Louisiana, the Supreme Court extended the requirement that juries be representative of all parts of the community to the state level.","path":"english2/2010.html"},{"id":"english2-2010-t4-p4-s5","examKey":"english2","examLabel":"英语二","year":"2010","text":4,"paragraph":4,"sentenceNo":5,"sentence":"The Taylor decision also declared sex discrimination in jury selection to be unconstitutional and ordered states to use the same procedures for selecting male and female jurors.","path":"english2/2010.html"},{"id":"english1-2011-t1-p1-s1","examKey":"english1","examLabel":"英语一","year":"2011","text":1,"paragraph":1,"sentenceNo":1,"sentence":"The decision of the New York Philharmonic to hire Alan Gilbert as its next music director has been the talk of the classical-music world ever since the sudden announcement of his appointment in 2009.","path":"english1/2011.html"},{"id":"english1-2011-t1-p1-s2","examKey":"english1","examLabel":"英语一","year":"2011","text":1,"paragraph":1,"sentenceNo":2,"sentence":"For the most part, the response has been favorable, to say the least.","path":"english1/2011.html"},{"id":"english1-2011-t1-p1-s3","examKey":"english1","examLabel":"英语一","year":"2011","text":1,"paragraph":1,"sentenceNo":3,"sentence":"“Hooray!","path":"english1/2011.html"},{"id":"english1-2011-t1-p1-s4","examKey":"english1","examLabel":"英语一","year":"2011","text":1,"paragraph":1,"sentenceNo":4,"sentence":"At last!” wrote Anthony Tommasini, a sober-sided classical-music critic.","path":"english1/2011.html"},{"id":"english1-2011-t1-p2-s1","examKey":"english1","examLabel":"英语一","year":"2011","text":1,"paragraph":2,"sentenceNo":1,"sentence":"One of the reasons why the appointment came as such a surprise, however, is that Gilbert is comparatively little known.","path":"english1/2011.html"},{"id":"english1-2011-t1-p2-s2","examKey":"english1","examLabel":"英语一","year":"2011","text":1,"paragraph":2,"sentenceNo":2,"sentence":"Even Tommasini, who had advocated Gilbert ’s appointment in the Times, calls him “an unpretentious musician with no air of the formidable conductor about him.” As a description of the next music director of an orchestra that has hitherto been led by musicians like Gustav Mahler and Pierre Boulez, that seems likely to have struck at least some Times readers as faint praise.","path":"english1/2011.html"},{"id":"english1-2011-t1-p3-s1","examKey":"english1","examLabel":"英语一","year":"2011","text":1,"paragraph":3,"sentenceNo":1,"sentence":"For my part, I have no idea whether Gilbert is a great conductor or even a good one.","path":"english1/2011.html"},{"id":"english1-2011-t1-p3-s2","examKey":"english1","examLabel":"英语一","year":"2011","text":1,"paragraph":3,"sentenceNo":2,"sentence":"To be sure, he performs an impressive variety of interesting compositions, but it is not necessary for me to visit Avery Fisher Hall, or anywhere else, to hear interesting orchestral music.","path":"english1/2011.html"},{"id":"english1-2011-t1-p3-s3","examKey":"english1","examLabel":"英语一","year":"2011","text":1,"paragraph":3,"sentenceNo":3,"sentence":"All I have to do is to go to my CD shelf, or boot up my computer and download still more recorded music from iTunes.","path":"english1/2011.html"},{"id":"english1-2011-t1-p4-s1","examKey":"english1","examLabel":"英语一","year":"2011","text":1,"paragraph":4,"sentenceNo":1,"sentence":"Devoted concertgoers who reply that recordings are no substitute for live performance are missing the point.","path":"english1/2011.html"},{"id":"english1-2011-t1-p4-s2","examKey":"english1","examLabel":"英语一","year":"2011","text":1,"paragraph":4,"sentenceNo":2,"sentence":"For the time, attention, and money of the art-loving public, classical instrumentalists must compete not only with opera houses, dance troupes, theater companies, and museums, but also with the recorded performances of the great classical musicians of the 20th century.","path":"english1/2011.html"},{"id":"english1-2011-t1-p4-s3","examKey":"english1","examLabel":"英语一","year":"2011","text":1,"paragraph":4,"sentenceNo":3,"sentence":"These recordings are cheap, available everywhere, and very often much higher in artistic quality than today’s live performances; moreover, they can be “consumed” at a time and place of the listener’s choosing.","path":"english1/2011.html"},{"id":"english1-2011-t1-p4-s4","examKey":"english1","examLabel":"英语一","year":"2011","text":1,"paragraph":4,"sentenceNo":4,"sentence":"The widespread availability of such recordings has thus brought about a crisis in the institution of the traditional classical concert.","path":"english1/2011.html"},{"id":"english1-2011-t1-p5-s1","examKey":"english1","examLabel":"英语一","year":"2011","text":1,"paragraph":5,"sentenceNo":1,"sentence":"One possible response is for classical performers to program attractive new music that is not yet available on record.","path":"english1/2011.html"},{"id":"english1-2011-t1-p5-s2","examKey":"english1","examLabel":"英语一","year":"2011","text":1,"paragraph":5,"sentenceNo":2,"sentence":"Gilbert’s own interest in new music has been widely noted: Alex Ross, a classical-music critic, has described him as a man who is capable of turning the Philharmonic into “a markedly different, more vibrant organization.” But what will be the nature of that difference?","path":"english1/2011.html"},{"id":"english1-2011-t1-p5-s3","examKey":"english1","examLabel":"英语一","year":"2011","text":1,"paragraph":5,"sentenceNo":3,"sentence":"Merely expanding the orchestra’s repertoire will not be enough.","path":"english1/2011.html"},{"id":"english1-2011-t1-p5-s4","examKey":"english1","examLabel":"英语一","year":"2011","text":1,"paragraph":5,"sentenceNo":4,"sentence":"If Gilbert and the Philharmonic are to succeed, they must first change the relationship between America’s oldest orchestra and the new audience it hopes to attract.","path":"english1/2011.html"},{"id":"english1-2011-t2-p1-s1","examKey":"english1","examLabel":"英语一","year":"2011","text":2,"paragraph":1,"sentenceNo":1,"sentence":"When Liam McGee departed as president of Bank of America in August, his explanation was surprisingly straight up.","path":"english1/2011.html"},{"id":"english1-2011-t2-p1-s2","examKey":"english1","examLabel":"英语一","year":"2011","text":2,"paragraph":1,"sentenceNo":2,"sentence":"Rather than cloaking his exit in the usual vague excuses, he came right out and said he was leaving “to pursue my goal of running a company.” Broadcasting his ambition was “very much my decision,” McGee says.","path":"english1/2011.html"},{"id":"english1-2011-t2-p1-s3","examKey":"english1","examLabel":"英语一","year":"2011","text":2,"paragraph":1,"sentenceNo":3,"sentence":"Within two weeks, he was talking for the first time with the board of Hartford Financial Services Group, which named him CEO and chairman on September 29.","path":"english1/2011.html"},{"id":"english1-2011-t2-p2-s1","examKey":"english1","examLabel":"英语一","year":"2011","text":2,"paragraph":2,"sentenceNo":1,"sentence":"McGee says leaving without a position line d up gave him time to reflect on what kind of company he wanted to run.","path":"english1/2011.html"},{"id":"english1-2011-t2-p2-s2","examKey":"english1","examLabel":"英语一","year":"2011","text":2,"paragraph":2,"sentenceNo":2,"sentence":"It also sent a clear message to the outside world about his aspirations.","path":"english1/2011.html"},{"id":"english1-2011-t2-p2-s3","examKey":"english1","examLabel":"英语一","year":"2011","text":2,"paragraph":2,"sentenceNo":3,"sentence":"And McGee isn’t alone.","path":"english1/2011.html"},{"id":"english1-2011-t2-p2-s4","examKey":"english1","examLabel":"英语一","year":"2011","text":2,"paragraph":2,"sentenceNo":4,"sentence":"In recent weeks the No.2 executives at Avon and American Express quit with the explanation that they were looking for a CEO post.","path":"english1/2011.html"},{"id":"english1-2011-t2-p2-s5","examKey":"english1","examLabel":"英语一","year":"2011","text":2,"paragraph":2,"sentenceNo":5,"sentence":"As boards scrutinize succession plans in response to shareholder pressure, executives who don’t get the nod also may wish to move on.","path":"english1/2011.html"},{"id":"english1-2011-t2-p2-s6","examKey":"english1","examLabel":"英语一","year":"2011","text":2,"paragraph":2,"sentenceNo":6,"sentence":"A turbulent business environment also has senior managers cautious of letting vague pronouncements cloud their reputations.","path":"english1/2011.html"},{"id":"english1-2011-t2-p3-s1","examKey":"english1","examLabel":"英语一","year":"2011","text":2,"paragraph":3,"sentenceNo":1,"sentence":"As the first signs of recovery begin to take hold, deputy chiefs may be more willing to make the jump without a net.","path":"english1/2011.html"},{"id":"english1-2011-t2-p3-s2","examKey":"english1","examLabel":"英语一","year":"2011","text":2,"paragraph":3,"sentenceNo":2,"sentence":"In the third quarter, CEO turnover was down 23% from a year ago as nervous boards stuck with the leaders they had, according to Liberum Research.","path":"english1/2011.html"},{"id":"english1-2011-t2-p3-s3","examKey":"english1","examLabel":"英语一","year":"2011","text":2,"paragraph":3,"sentenceNo":3,"sentence":"As the economy picks up, opportunities will abound for aspiring leaders.","path":"english1/2011.html"},{"id":"english1-2011-t2-p4-s1","examKey":"english1","examLabel":"英语一","year":"2011","text":2,"paragraph":4,"sentenceNo":1,"sentence":"The decision to quit a senior position to look for a better one is unconventional.","path":"english1/2011.html"},{"id":"english1-2011-t2-p4-s2","examKey":"english1","examLabel":"英语一","year":"2011","text":2,"paragraph":4,"sentenceNo":2,"sentence":"For years executives and headhunters have adhered to the rule that the most attractive CEO candidates are the ones who must be poached.","path":"english1/2011.html"},{"id":"english1-2011-t2-p4-s3","examKey":"english1","examLabel":"英语一","year":"2011","text":2,"paragraph":4,"sentenceNo":3,"sentence":"Says Korn/Ferry senior partner Dennis Carey: “I can’t think of a single search I’ve done where a board has not instructed me to look at sitting CEOs first.”","path":"english1/2011.html"},{"id":"english1-2011-t2-p5-s1","examKey":"english1","examLabel":"英语一","year":"2011","text":2,"paragraph":5,"sentenceNo":1,"sentence":"Those who jumped without a job haven’t always landed in top positions quickly.","path":"english1/2011.html"},{"id":"english1-2011-t2-p5-s2","examKey":"english1","examLabel":"英语一","year":"2011","text":2,"paragraph":5,"sentenceNo":2,"sentence":"Ellen Marram quit as chief of Tropicana a decade ago, saying she wanted to be a CEO.","path":"english1/2011.html"},{"id":"english1-2011-t2-p5-s3","examKey":"english1","examLabel":"英语一","year":"2011","text":2,"paragraph":5,"sentenceNo":3,"sentence":"It was a year before she became head of a tiny Internet-based commodities exchange.","path":"english1/2011.html"},{"id":"english1-2011-t2-p5-s4","examKey":"english1","examLabel":"英语一","year":"2011","text":2,"paragraph":5,"sentenceNo":4,"sentence":"Robert Willumstad left Citigroup in 2005 with ambitions to be a CEO.","path":"english1/2011.html"},{"id":"english1-2011-t2-p5-s5","examKey":"english1","examLabel":"英语一","year":"2011","text":2,"paragraph":5,"sentenceNo":5,"sentence":"He finally took that post at a major financial institution three years later.","path":"english1/2011.html"},{"id":"english1-2011-t2-p6-s1","examKey":"english1","examLabel":"英语一","year":"2011","text":2,"paragraph":6,"sentenceNo":1,"sentence":"Many recruiters say the old disgrace is fading for top performers.","path":"english1/2011.html"},{"id":"english1-2011-t2-p6-s2","examKey":"english1","examLabel":"英语一","year":"2011","text":2,"paragraph":6,"sentenceNo":2,"sentence":"The financial crisis has made it more acceptable to be between jobs or to leave a bad one.","path":"english1/2011.html"},{"id":"english1-2011-t2-p6-s3","examKey":"english1","examLabel":"英语一","year":"2011","text":2,"paragraph":6,"sentenceNo":3,"sentence":"“The traditional rule was it’s safer to stay where you are, but that’s been fundamentally inverted,” says one headhunter.","path":"english1/2011.html"},{"id":"english1-2011-t2-p6-s4","examKey":"english1","examLabel":"英语一","year":"2011","text":2,"paragraph":6,"sentenceNo":4,"sentence":"“The people who’ve been hurt the worst are those who’ve stayed too long.”","path":"english1/2011.html"},{"id":"english1-2011-t3-p1-s1","examKey":"english1","examLabel":"英语一","year":"2011","text":3,"paragraph":1,"sentenceNo":1,"sentence":"The rough guide to marketing success used to be that you got what you paid for.","path":"english1/2011.html"},{"id":"english1-2011-t3-p1-s2","examKey":"english1","examLabel":"英语一","year":"2011","text":3,"paragraph":1,"sentenceNo":2,"sentence":"No longer.","path":"english1/2011.html"},{"id":"english1-2011-t3-p1-s3","examKey":"english1","examLabel":"英语一","year":"2011","text":3,"paragraph":1,"sentenceNo":3,"sentence":"While traditional “paid” media — such as television commercials and print advertisements — still play a major role, companies today can exploit many alternative forms of media.","path":"english1/2011.html"},{"id":"english1-2011-t3-p1-s4","examKey":"english1","examLabel":"英语一","year":"2011","text":3,"paragraph":1,"sentenceNo":4,"sentence":"Consumers passionate about a product may create “earned” media by willingly promoting it to friends, and a company may leverage “owned” media by sending e-mail alerts about products and sales to customers registered with its Web site.","path":"english1/2011.html"},{"id":"english1-2011-t3-p1-s5","examKey":"english1","examLabel":"英语一","year":"2011","text":3,"paragraph":1,"sentenceNo":5,"sentence":"The way consumers now approach the process of making purchase decisions means that marketing’s impact stems from a broad range of factors beyond conventional paid media.","path":"english1/2011.html"},{"id":"english1-2011-t3-p2-s1","examKey":"english1","examLabel":"英语一","year":"2011","text":3,"paragraph":2,"sentenceNo":1,"sentence":"Paid and owned media are controlled by marketers promoting their own products.","path":"english1/2011.html"},{"id":"english1-2011-t3-p2-s2","examKey":"english1","examLabel":"英语一","year":"2011","text":3,"paragraph":2,"sentenceNo":2,"sentence":"For earned media, such marketers act as the initiator for users’ responses.","path":"english1/2011.html"},{"id":"english1-2011-t3-p2-s3","examKey":"english1","examLabel":"英语一","year":"2011","text":3,"paragraph":2,"sentenceNo":3,"sentence":"But in some cases, one marketer’s owned media become another marketer’s paid media — for instance, when an e-commerce retailer sells ad space on its Web site.","path":"english1/2011.html"},{"id":"english1-2011-t3-p2-s4","examKey":"english1","examLabel":"英语一","year":"2011","text":3,"paragraph":2,"sentenceNo":4,"sentence":"We define such sold media as owned media whose traffic is so strong that other organizations place their content or e-commerce engines within that environment.","path":"english1/2011.html"},{"id":"english1-2011-t3-p2-s5","examKey":"english1","examLabel":"英语一","year":"2011","text":3,"paragraph":2,"sentenceNo":5,"sentence":"This trend, which we believe is still in its infancy, effectively began with retailers and travel providers such as airlines and hotels and will no doubt go further.","path":"english1/2011.html"},{"id":"english1-2011-t3-p2-s6","examKey":"english1","examLabel":"英语一","year":"2011","text":3,"paragraph":2,"sentenceNo":6,"sentence":"Johnson & Johnson, for example, has created BabyCenter, a stand-alone media property that promotes complementary and even competitive products.","path":"english1/2011.html"},{"id":"english1-2011-t3-p2-s7","examKey":"english1","examLabel":"英语一","year":"2011","text":3,"paragraph":2,"sentenceNo":7,"sentence":"Besides generating income, the presence of other marketers makes the site seem objective, gives companies opportunities to learn valuable information about the appeal of other companies’ marketing, and may help expand user traffic for all companies concerned.","path":"english1/2011.html"},{"id":"english1-2011-t3-p3-s1","examKey":"english1","examLabel":"英语一","year":"2011","text":3,"paragraph":3,"sentenceNo":1,"sentence":"The same dramatic technological changes that have provided marketers with more (and more diverse) communications choices have also increased the risk that passionate consumers will voice their opinions in quicker, more visible, and much more damaging ways.","path":"english1/2011.html"},{"id":"english1-2011-t3-p3-s2","examKey":"english1","examLabel":"英语一","year":"2011","text":3,"paragraph":3,"sentenceNo":2,"sentence":"Such hijacked media are the opposite of earned media: an asset or campaign becomes hostage to consumers, other stakeholders, or activists who make negative allegations about a brand or product.","path":"english1/2011.html"},{"id":"english1-2011-t3-p3-s3","examKey":"english1","examLabel":"英语一","year":"2011","text":3,"paragraph":3,"sentenceNo":3,"sentence":"Members of social networks, for instance, are learning that they can hijack media to apply pressure on the businesses that originally created them.","path":"english1/2011.html"},{"id":"english1-2011-t3-p4-s1","examKey":"english1","examLabel":"英语一","year":"2011","text":3,"paragraph":4,"sentenceNo":1,"sentence":"If that happens, passionate consumers would try to persuade others to boycott products, putting the reputation of the target company at risk.","path":"english1/2011.html"},{"id":"english1-2011-t3-p4-s2","examKey":"english1","examLabel":"英语一","year":"2011","text":3,"paragraph":4,"sentenceNo":2,"sentence":"In such a case, the company’s response may not be sufficiently quick or thoughtful, and the learning curve has been steep.","path":"english1/2011.html"},{"id":"english1-2011-t3-p4-s3","examKey":"english1","examLabel":"英语一","year":"2011","text":3,"paragraph":4,"sentenceNo":3,"sentence":"Toyota Motor, for example, alleviated some of the damage from its recall crisis earlier this year with a relatively quick and well-orchestrated social-media response campaign, which included efforts to engage with consumers directly on sites such as Twitter and the social-news site Digg.","path":"english1/2011.html"},{"id":"english1-2011-t4-p1-s1","examKey":"english1","examLabel":"英语一","year":"2011","text":4,"paragraph":1,"sentenceNo":1,"sentence":"It’s no surprise that Jennifer Senior ’s insightful, provocative magazine cover story, “I Love My Child ren, I Hate My Life,” is arousing much chatter — nothing gets people talking like the suggestion that child rearing is anything less than a completely fulfilling, life-enriching experience.","path":"english1/2011.html"},{"id":"english1-2011-t4-p1-s2","examKey":"english1","examLabel":"英语一","year":"2011","text":4,"paragraph":1,"sentenceNo":2,"sentence":"Rat her than concluding that children make parents either happy or miserable, Senior suggests we need to redefine happiness: instead of thinking of it as something that can be measured by moment-to-moment joy, we should consider being happy as a past-tense condition.","path":"english1/2011.html"},{"id":"english1-2011-t4-p1-s3","examKey":"english1","examLabel":"英语一","year":"2011","text":4,"paragraph":1,"sentenceNo":3,"sentence":"Even though the day-to-day experience of raising kids can be soul-crushingly hard, Senior writes that “the very things that in the moment dampen our moods can later be sources of intense gratification and delight.”","path":"english1/2011.html"},{"id":"english1-2011-t4-p2-s1","examKey":"english1","examLabel":"英语一","year":"2011","text":4,"paragraph":2,"sentenceNo":1,"sentence":"The magazine cover showing an attractive mother holding a cute baby is hardly the only Madonna-and-child image on newsstands this week.","path":"english1/2011.html"},{"id":"english1-2011-t4-p2-s2","examKey":"english1","examLabel":"英语一","year":"2011","text":4,"paragraph":2,"sentenceNo":2,"sentence":"There are also stories about newly adoptive — and newly single — mom Sandra Bullock, as well as the usual “Jennifer Aniston is pregnant” news.","path":"english1/2011.html"},{"id":"english1-2011-t4-p2-s3","examKey":"english1","examLabel":"英语一","year":"2011","text":4,"paragraph":2,"sentenceNo":3,"sentence":"Practically every week features at least one celebrity mom, or mom-to-be, smiling on the newsstands.","path":"english1/2011.html"},{"id":"english1-2011-t4-p3-s1","examKey":"english1","examLabel":"英语一","year":"2011","text":4,"paragraph":3,"sentenceNo":1,"sentence":"In a society that so persistently celebrates procreation, is it any wonder that admitting you regret having children is equivalent to admitting you support kitten-killing?","path":"english1/2011.html"},{"id":"english1-2011-t4-p3-s2","examKey":"english1","examLabel":"英语一","year":"2011","text":4,"paragraph":3,"sentenceNo":2,"sentence":"It doesn’t seem quite fair, then, to compare the regrets of parents to the regrets of the childless.","path":"english1/2011.html"},{"id":"english1-2011-t4-p3-s3","examKey":"english1","examLabel":"英语一","year":"2011","text":4,"paragraph":3,"sentenceNo":3,"sentence":"Unhappy parents rarely are provoked to wonder if they shouldn’t have had kids, but unhappy childless folks are bothered with the message that children are the single most important thing in the world: obviously their misery must be a direct result of the gaping baby-size holes in their lives.","path":"english1/2011.html"},{"id":"english1-2011-t4-p4-s1","examKey":"english1","examLabel":"英语一","year":"2011","text":4,"paragraph":4,"sentenceNo":1,"sentence":"Of course, the image of parenthood that celebrity magazines like Us Weekly and People present is hugely unrealistic, especially when the parents are single mothers like Bullock.","path":"english1/2011.html"},{"id":"english1-2011-t4-p4-s2","examKey":"english1","examLabel":"英语一","year":"2011","text":4,"paragraph":4,"sentenceNo":2,"sentence":"According to several studies concluding that parents are less happy than childless couples, single parents are the least happy of all.","path":"english1/2011.html"},{"id":"english1-2011-t4-p4-s3","examKey":"english1","examLabel":"英语一","year":"2011","text":4,"paragraph":4,"sentenceNo":3,"sentence":"No shock there, considering how much work it is to raise a kid without a partner to lean on; yet to hear Sandra and Britney tell it, raising a kid on their “own” (read: with round-the-clock help) is a piece of cake.","path":"english1/2011.html"},{"id":"english1-2011-t4-p5-s1","examKey":"english1","examLabel":"英语一","year":"2011","text":4,"paragraph":5,"sentenceNo":1,"sentence":"It’s hard to imagine that many people are dumb enough to want children just because Reese and Angelina make it look so glamorous: most adults understand that a baby is not a haircut.","path":"english1/2011.html"},{"id":"english1-2011-t4-p5-s2","examKey":"english1","examLabel":"英语一","year":"2011","text":4,"paragraph":5,"sentenceNo":2,"sentence":"But it’s interesting to wonder if the images we see every week of stress-free, happiness-enhancing parenthood aren’t in some small, subconscious way contributing to our own dissatisfactions with the actual experience, in the same way that a small part of us hoped getting “the Rachel” might make us look just a little bit like Jennifer Aniston.","path":"english1/2011.html"},{"id":"english2-2011-t1-p1-s1","examKey":"english2","examLabel":"英语二","year":"2011","text":1,"paragraph":1,"sentenceNo":1,"sentence":"Q21 段落定位 Ruth Simmons joined Goldman Sachs’s board as an outside director in January 2000; a year later she became president of Brown University.","path":"english2/2011.html"},{"id":"english2-2011-t1-p1-s2","examKey":"english2","examLabel":"英语二","year":"2011","text":1,"paragraph":1,"sentenceNo":2,"sentence":"For the rest of the decade she apparently managed both roles without attracting much criticism.","path":"english2/2011.html"},{"id":"english2-2011-t1-p1-s3","examKey":"english2","examLabel":"英语二","year":"2011","text":1,"paragraph":1,"sentenceNo":3,"sentence":"But by the end of 2009 Ms.","path":"english2/2011.html"},{"id":"english2-2011-t1-p1-s4","examKey":"english2","examLabel":"英语二","year":"2011","text":1,"paragraph":1,"sentenceNo":4,"sentence":"Simmons was under fire for having sat on Goldman’s compensation committee; how could she have let those enormous bonus payouts pass unremarked?","path":"english2/2011.html"},{"id":"english2-2011-t1-p1-s5","examKey":"english2","examLabel":"英语二","year":"2011","text":1,"paragraph":1,"sentenceNo":5,"sentence":"By February the next year Ms.","path":"english2/2011.html"},{"id":"english2-2011-t1-p1-s6","examKey":"english2","examLabel":"英语二","year":"2011","text":1,"paragraph":1,"sentenceNo":6,"sentence":"Simmons had left the board.","path":"english2/2011.html"},{"id":"english2-2011-t1-p1-s7","examKey":"english2","examLabel":"英语二","year":"2011","text":1,"paragraph":1,"sentenceNo":7,"sentence":"The position was just taking up too much time, she said.","path":"english2/2011.html"},{"id":"english2-2011-t1-p2-s1","examKey":"english2","examLabel":"英语二","year":"2011","text":1,"paragraph":2,"sentenceNo":1,"sentence":"Q22 段落定位 Q25 角色态度定位 Outside directors are supposed to serve as helpful, yet less biased, advisers on a firm’s board.","path":"english2/2011.html"},{"id":"english2-2011-t1-p2-s2","examKey":"english2","examLabel":"英语二","year":"2011","text":1,"paragraph":2,"sentenceNo":2,"sentence":"Having made their wealth and their reputations elsewhere, they presumably have enough independence to disagree with the chief executive’s proposals.","path":"english2/2011.html"},{"id":"english2-2011-t1-p2-s3","examKey":"english2","examLabel":"英语二","year":"2011","text":1,"paragraph":2,"sentenceNo":3,"sentence":"If the sky, and the share price is falling, outside directors should be able to give advice based on having weathered their own crises.","path":"english2/2011.html"},{"id":"english2-2011-t1-p3-s1","examKey":"english2","examLabel":"英语二","year":"2011","text":1,"paragraph":3,"sentenceNo":1,"sentence":"Q23 研究定位 The researchers from Ohio University used a database that covered more than 10,000 firms and more than 64,000 different directors between 1989 and 2004.","path":"english2/2011.html"},{"id":"english2-2011-t1-p3-s2","examKey":"english2","examLabel":"英语二","year":"2011","text":1,"paragraph":3,"sentenceNo":2,"sentence":"Then they simply checked which directors stayed from one proxy statement to the next.","path":"english2/2011.html"},{"id":"english2-2011-t1-p3-s3","examKey":"english2","examLabel":"英语二","year":"2011","text":1,"paragraph":3,"sentenceNo":3,"sentence":"The most likely reason for departing a board was age, so the researchers concentrated on those “surprise” disappearances by directors under the age of 70.","path":"english2/2011.html"},{"id":"english2-2011-t1-p3-s4","examKey":"english2","examLabel":"英语二","year":"2011","text":1,"paragraph":3,"sentenceNo":4,"sentence":"They found that after a surprise departure, the probability that the company will subsequently have to restate earnings increases by nearly 20%.","path":"english2/2011.html"},{"id":"english2-2011-t1-p3-s5","examKey":"english2","examLabel":"英语二","year":"2011","text":1,"paragraph":3,"sentenceNo":5,"sentence":"The likelihood of being named in a federal class-action lawsuit also increases, and the stock is likely to perform worse.","path":"english2/2011.html"},{"id":"english2-2011-t1-p3-s6","examKey":"english2","examLabel":"英语二","year":"2011","text":1,"paragraph":3,"sentenceNo":6,"sentence":"The effect tended to be larger for larger firms.","path":"english2/2011.html"},{"id":"english2-2011-t1-p3-s7","examKey":"english2","examLabel":"英语二","year":"2011","text":1,"paragraph":3,"sentenceNo":7,"sentence":"Although a correlation between them leaving and subsequent bad performance at the firm is suggestive, it does not mean that such directors are always jumping off a sinking ship.","path":"english2/2011.html"},{"id":"english2-2011-t1-p3-s8","examKey":"english2","examLabel":"英语二","year":"2011","text":1,"paragraph":3,"sentenceNo":8,"sentence":"Often they “trade up,” leaving riskier, smaller firms for larger and more stable firms.","path":"english2/2011.html"},{"id":"english2-2011-t1-p4-s1","examKey":"english2","examLabel":"英语二","year":"2011","text":1,"paragraph":4,"sentenceNo":1,"sentence":"Q24 末段推断 But the researchers believe that outside directors have an easier time of avoiding a blow to their reputations if they leave a firm before bad news breaks, even if a review of history shows they were on the board at the time any wrongdoing occurred.","path":"english2/2011.html"},{"id":"english2-2011-t1-p4-s2","examKey":"english2","examLabel":"英语二","year":"2011","text":1,"paragraph":4,"sentenceNo":2,"sentence":"Firms who want to keep their outside directors through tough times may have to create incentives.","path":"english2/2011.html"},{"id":"english2-2011-t1-p4-s3","examKey":"english2","examLabel":"英语二","year":"2011","text":1,"paragraph":4,"sentenceNo":3,"sentence":"Otherwise outside directors will follow the example of Ms.","path":"english2/2011.html"},{"id":"english2-2011-t1-p4-s4","examKey":"english2","examLabel":"英语二","year":"2011","text":1,"paragraph":4,"sentenceNo":4,"sentence":"Simmons, once again very popular on campus.","path":"english2/2011.html"},{"id":"english2-2011-t2-p1-s1","examKey":"english2","examLabel":"英语二","year":"2011","text":2,"paragraph":1,"sentenceNo":1,"sentence":"Q26 定位 Whatever happened to the death of newspapers?","path":"english2/2011.html"},{"id":"english2-2011-t2-p1-s2","examKey":"english2","examLabel":"英语二","year":"2011","text":2,"paragraph":1,"sentenceNo":2,"sentence":"A year ago the end seemed near.","path":"english2/2011.html"},{"id":"english2-2011-t2-p1-s3","examKey":"english2","examLabel":"英语二","year":"2011","text":2,"paragraph":1,"sentenceNo":3,"sentence":"The recession threatened to remove the advertising and readers that had not already fled to the internet.","path":"english2/2011.html"},{"id":"english2-2011-t2-p1-s4","examKey":"english2","examLabel":"英语二","year":"2011","text":2,"paragraph":1,"sentenceNo":4,"sentence":"Newspapers like the San Francisco Chronicle were chronicling their own doom.","path":"english2/2011.html"},{"id":"english2-2011-t2-p1-s5","examKey":"english2","examLabel":"英语二","year":"2011","text":2,"paragraph":1,"sentenceNo":5,"sentence":"America’s Federal Trade Commission launched a round of talks about how to save newspapers.","path":"english2/2011.html"},{"id":"english2-2011-t2-p1-s6","examKey":"english2","examLabel":"英语二","year":"2011","text":2,"paragraph":1,"sentenceNo":6,"sentence":"Should they become charitable corporations?","path":"english2/2011.html"},{"id":"english2-2011-t2-p1-s7","examKey":"english2","examLabel":"英语二","year":"2011","text":2,"paragraph":1,"sentenceNo":7,"sentence":"Should the state subsidize them?","path":"english2/2011.html"},{"id":"english2-2011-t2-p1-s8","examKey":"english2","examLabel":"英语二","year":"2011","text":2,"paragraph":1,"sentenceNo":8,"sentence":"It will hold another meeting soon.","path":"english2/2011.html"},{"id":"english2-2011-t2-p1-s9","examKey":"english2","examLabel":"英语二","year":"2011","text":2,"paragraph":1,"sentenceNo":9,"sentence":"But the discussions now seem out of date.","path":"english2/2011.html"},{"id":"english2-2011-t2-p2-s1","examKey":"english2","examLabel":"英语二","year":"2011","text":2,"paragraph":2,"sentenceNo":1,"sentence":"In much of the world there is little sign of crisis.","path":"english2/2011.html"},{"id":"english2-2011-t2-p2-s2","examKey":"english2","examLabel":"英语二","year":"2011","text":2,"paragraph":2,"sentenceNo":2,"sentence":"German and Brazilian papers have shrugged off the recession.","path":"english2/2011.html"},{"id":"english2-2011-t2-p2-s3","examKey":"english2","examLabel":"英语二","year":"2011","text":2,"paragraph":2,"sentenceNo":3,"sentence":"Even American newspapers, which inhabit the most troubled corner of the global industry, have not only survived but often returned to profit.","path":"english2/2011.html"},{"id":"english2-2011-t2-p2-s4","examKey":"english2","examLabel":"英语二","year":"2011","text":2,"paragraph":2,"sentenceNo":4,"sentence":"Not the 20% profit margins that were routine a few years ago, but profit all the same.","path":"english2/2011.html"},{"id":"english2-2011-t2-p3-s1","examKey":"english2","examLabel":"英语二","year":"2011","text":2,"paragraph":3,"sentenceNo":1,"sentence":"Q27 定位 It has not been much fun.","path":"english2/2011.html"},{"id":"english2-2011-t2-p3-s2","examKey":"english2","examLabel":"英语二","year":"2011","text":2,"paragraph":3,"sentenceNo":2,"sentence":"Many papers stayed afloat by pushing journalists overboard.","path":"english2/2011.html"},{"id":"english2-2011-t2-p3-s3","examKey":"english2","examLabel":"英语二","year":"2011","text":2,"paragraph":3,"sentenceNo":3,"sentence":"The American Society of News Editors reckons that 13,500 newsroom jobs have gone since 2007.","path":"english2/2011.html"},{"id":"english2-2011-t2-p3-s4","examKey":"english2","examLabel":"英语二","year":"2011","text":2,"paragraph":3,"sentenceNo":4,"sentence":"Readers are paying more for slimmer products.","path":"english2/2011.html"},{"id":"english2-2011-t2-p3-s5","examKey":"english2","examLabel":"英语二","year":"2011","text":2,"paragraph":3,"sentenceNo":5,"sentence":"Some papers even had the nerve to refuse delivery to distant suburbs.","path":"english2/2011.html"},{"id":"english2-2011-t2-p3-s6","examKey":"english2","examLabel":"英语二","year":"2011","text":2,"paragraph":3,"sentenceNo":6,"sentence":"Yet these desperate measures have proved the right ones and, sadly for many journalists, they can be pushed further.","path":"english2/2011.html"},{"id":"english2-2011-t2-p4-s1","examKey":"english2","examLabel":"英语二","year":"2011","text":2,"paragraph":4,"sentenceNo":1,"sentence":"Q28 定位 Newspapers are becoming more balanced businesses, with a healthier mix of revenues from readers and advertisers.","path":"english2/2011.html"},{"id":"english2-2011-t2-p4-s2","examKey":"english2","examLabel":"英语二","year":"2011","text":2,"paragraph":4,"sentenceNo":2,"sentence":"American papers have long been highly unusual in their reliance on ads.","path":"english2/2011.html"},{"id":"english2-2011-t2-p4-s3","examKey":"english2","examLabel":"英语二","year":"2011","text":2,"paragraph":4,"sentenceNo":3,"sentence":"Fully 87% of their revenues came from advertising in 2008, according to the Organization for Economic Co-operation & Development (OECD).","path":"english2/2011.html"},{"id":"english2-2011-t2-p4-s4","examKey":"english2","examLabel":"英语二","year":"2011","text":2,"paragraph":4,"sentenceNo":4,"sentence":"In Japan the proportion is 35%.","path":"english2/2011.html"},{"id":"english2-2011-t2-p4-s5","examKey":"english2","examLabel":"英语二","year":"2011","text":2,"paragraph":4,"sentenceNo":5,"sentence":"Not surprisingly, Japanese newspapers are much more stable.","path":"english2/2011.html"},{"id":"english2-2011-t2-p5-s1","examKey":"english2","examLabel":"英语二","year":"2011","text":2,"paragraph":5,"sentenceNo":1,"sentence":"Q29 末段定位 Q30 主旨定位 The whirlwind that swept through newsrooms harmed everybody, but much of the damage has been concentrated in areas where newspapers are least distinctive.","path":"english2/2011.html"},{"id":"english2-2011-t2-p5-s2","examKey":"english2","examLabel":"英语二","year":"2011","text":2,"paragraph":5,"sentenceNo":2,"sentence":"Car and film reviewers have gone.","path":"english2/2011.html"},{"id":"english2-2011-t2-p5-s3","examKey":"english2","examLabel":"英语二","year":"2011","text":2,"paragraph":5,"sentenceNo":3,"sentence":"So have science and general business reporters.","path":"english2/2011.html"},{"id":"english2-2011-t2-p5-s4","examKey":"english2","examLabel":"英语二","year":"2011","text":2,"paragraph":5,"sentenceNo":4,"sentence":"Foreign bureaus have been savagely cut off.","path":"english2/2011.html"},{"id":"english2-2011-t2-p5-s5","examKey":"english2","examLabel":"英语二","year":"2011","text":2,"paragraph":5,"sentenceNo":5,"sentence":"Newspapers are less complete as a result.","path":"english2/2011.html"},{"id":"english2-2011-t2-p5-s6","examKey":"english2","examLabel":"英语二","year":"2011","text":2,"paragraph":5,"sentenceNo":6,"sentence":"But completeness is no longer a virtue in the newspaper business.","path":"english2/2011.html"},{"id":"english2-2011-t3-p1-s1","examKey":"english2","examLabel":"英语二","year":"2011","text":3,"paragraph":1,"sentenceNo":1,"sentence":"Q31 全文起点 We tend to think of the decades immediately following World War II as a time of prosperity and growth, with soldiers returning home by the millions, going off to college on the G.","path":"english2/2011.html"},{"id":"english2-2011-t3-p1-s2","examKey":"english2","examLabel":"英语二","year":"2011","text":3,"paragraph":1,"sentenceNo":2,"sentence":"I.","path":"english2/2011.html"},{"id":"english2-2011-t3-p1-s3","examKey":"english2","examLabel":"英语二","year":"2011","text":3,"paragraph":1,"sentenceNo":3,"sentence":"Bill and lining up at the marriage bureaus.","path":"english2/2011.html"},{"id":"english2-2011-t3-p2-s1","examKey":"english2","examLabel":"英语二","year":"2011","text":3,"paragraph":2,"sentenceNo":1,"sentence":"But when it came to their houses, it was a time of common sense and a belief that less could truly be more.","path":"english2/2011.html"},{"id":"english2-2011-t3-p2-s2","examKey":"english2","examLabel":"英语二","year":"2011","text":3,"paragraph":2,"sentenceNo":2,"sentence":"During the Depression and the war, Americans had learned to live with less, and that restraint, in combination with the postwar confidence in the future, made small, efficient housing positively stylish.","path":"english2/2011.html"},{"id":"english2-2011-t3-p3-s1","examKey":"english2","examLabel":"英语二","year":"2011","text":3,"paragraph":3,"sentenceNo":1,"sentence":"Q32 Bauhaus 定位 Economic condition was only a stimulus for the trend toward efficient living.","path":"english2/2011.html"},{"id":"english2-2011-t3-p3-s2","examKey":"english2","examLabel":"英语二","year":"2011","text":3,"paragraph":3,"sentenceNo":2,"sentence":"The phrase “less is more” was actually first popularized by a German, the architect Ludwig Mies van der Rohe, who like other people associated with the Bauhaus, a school of design, emigrated to the United States before World War II and took up posts at American architecture schools.","path":"english2/2011.html"},{"id":"english2-2011-t3-p3-s3","examKey":"english2","examLabel":"英语二","year":"2011","text":3,"paragraph":3,"sentenceNo":3,"sentence":"These designers came to exert enormous influence on the course of American architecture, but none more so than Mies.","path":"english2/2011.html"},{"id":"english2-2011-t3-p4-s1","examKey":"english2","examLabel":"英语二","year":"2011","text":3,"paragraph":4,"sentenceNo":1,"sentence":"Q33 Mies 理念 Mies’s signature phrase means that less decoration, properly organized, has more impact than a lot.","path":"english2/2011.html"},{"id":"english2-2011-t3-p4-s2","examKey":"english2","examLabel":"英语二","year":"2011","text":3,"paragraph":4,"sentenceNo":2,"sentence":"Elegance, he believed, did not derive from abundance.","path":"english2/2011.html"},{"id":"english2-2011-t3-p4-s3","examKey":"english2","examLabel":"英语二","year":"2011","text":3,"paragraph":4,"sentenceNo":3,"sentence":"Like other modern architects, he employed metal, glass and laminated wood — materials that we take for granted today but that in the 1940s symbolized the future.","path":"english2/2011.html"},{"id":"english2-2011-t3-p4-s4","examKey":"english2","examLabel":"英语二","year":"2011","text":3,"paragraph":4,"sentenceNo":4,"sentence":"Mies’s sophisticated presentation masked the fact that the spaces he designed were small and efficient, rather than big and often empty.","path":"english2/2011.html"},{"id":"english2-2011-t3-p5-s1","examKey":"english2","examLabel":"英语二","year":"2011","text":3,"paragraph":5,"sentenceNo":1,"sentence":"Q34 公寓定位 The apartments in the elegant towers Mies built on Chicago’s Lake Shore Drive, for example, were smaller — two-bedroom units under 1,000 square feet — than those in their older neighbors along the city’s Gold Coast.","path":"english2/2011.html"},{"id":"english2-2011-t3-p5-s2","examKey":"english2","examLabel":"英语二","year":"2011","text":3,"paragraph":5,"sentenceNo":2,"sentence":"But they were popular because of their airy glass walls, the views they afforded and the elegance of the buildings’ details and proportions, the architectural equivalent of the abstract art so popular at the time.","path":"english2/2011.html"},{"id":"english2-2011-t3-p6-s1","examKey":"english2","examLabel":"英语二","year":"2011","text":3,"paragraph":6,"sentenceNo":1,"sentence":"The trend toward “less” was not entirely foreign.","path":"english2/2011.html"},{"id":"english2-2011-t3-p6-s2","examKey":"english2","examLabel":"英语二","year":"2011","text":3,"paragraph":6,"sentenceNo":2,"sentence":"In the 1930s Frank Lloyd Wright started building more modest and efficient houses — usually around 1,200 square feet — than the spreading two-story ones he had designed in the 1890s and the early 20th century.","path":"english2/2011.html"},{"id":"english2-2011-t3-p7-s1","examKey":"english2","examLabel":"英语二","year":"2011","text":3,"paragraph":7,"sentenceNo":1,"sentence":"Q35 Case Study Houses 定位 The “ Case Study Houses ” commissioned from talented modern architects by California Arts & Architecture magazine between 1945 and 1962 were yet another homegrown influence on the “less is more” trend.","path":"english2/2011.html"},{"id":"english2-2011-t3-p7-s2","examKey":"english2","examLabel":"英语二","year":"2011","text":3,"paragraph":7,"sentenceNo":2,"sentence":"Aesthetic effect came from the landscape, new materials and forthright detailing.","path":"english2/2011.html"},{"id":"english2-2011-t3-p7-s3","examKey":"english2","examLabel":"英语二","year":"2011","text":3,"paragraph":7,"sentenceNo":3,"sentence":"In his Case Study House, Ralph Rapson may have mispredicted just how the mechanical revolution would impact everyday life — few American families acquired helicopters, though most eventually got clothes dryers — but his belief that self-sufficiency was both desirable and inevitable was widely shared.","path":"english2/2011.html"},{"id":"english2-2011-t4-p1-s1","examKey":"english2","examLabel":"英语二","year":"2011","text":4,"paragraph":1,"sentenceNo":1,"sentence":"Q36 起点定位 Will the European Union make it?","path":"english2/2011.html"},{"id":"english2-2011-t4-p1-s2","examKey":"english2","examLabel":"英语二","year":"2011","text":4,"paragraph":1,"sentenceNo":2,"sentence":"The question would have sounded strange not long ago.","path":"english2/2011.html"},{"id":"english2-2011-t4-p1-s3","examKey":"english2","examLabel":"英语二","year":"2011","text":4,"paragraph":1,"sentenceNo":3,"sentence":"Now even the project’s greatest cheerleaders talk of a continent facing a “Bermuda triangle” of debt, population decline and lower growth.","path":"english2/2011.html"},{"id":"english2-2011-t4-p2-s1","examKey":"english2","examLabel":"英语二","year":"2011","text":4,"paragraph":2,"sentenceNo":1,"sentence":"As well as those chronic problems, the EU faces an acute crisis in its economic core, the 16 countries that use the single currency.","path":"english2/2011.html"},{"id":"english2-2011-t4-p2-s2","examKey":"english2","examLabel":"英语二","year":"2011","text":4,"paragraph":2,"sentenceNo":2,"sentence":"Markets have lost faith that the euro zone’s economies, weaker or stronger, will one day converge thanks to the discipline of sharing a single currency, which denies uncompetitive members the quick fix of devaluation.","path":"english2/2011.html"},{"id":"english2-2011-t4-p3-s1","examKey":"english2","examLabel":"英语二","year":"2011","text":4,"paragraph":3,"sentenceNo":1,"sentence":"Q37 争论定位 Yet the debate about how to save Europe’s single currency from disintegration is stuck.","path":"english2/2011.html"},{"id":"english2-2011-t4-p3-s2","examKey":"english2","examLabel":"英语二","year":"2011","text":4,"paragraph":3,"sentenceNo":2,"sentence":"It is stuck because the euro zone’s dominant powers, France and Germany, agree on the need for greater harmonisation within the euro zone, but disagree about what to harmonise.","path":"english2/2011.html"},{"id":"english2-2011-t4-p4-s1","examKey":"english2","examLabel":"英语二","year":"2011","text":4,"paragraph":4,"sentenceNo":1,"sentence":"Q38 德国方案 Germany thinks the euro must be saved by stricter rules on borrowing, spending and competitiveness, backed by quasi-automatic sanctions for governments that do not obey.","path":"english2/2011.html"},{"id":"english2-2011-t4-p4-s2","examKey":"english2","examLabel":"英语二","year":"2011","text":4,"paragraph":4,"sentenceNo":2,"sentence":"These might include threats to freeze EU funds for poorer regions and EU mega-projects, and even the suspension of a country’s voting rights in EU ministerial councils.","path":"english2/2011.html"},{"id":"english2-2011-t4-p4-s3","examKey":"english2","examLabel":"英语二","year":"2011","text":4,"paragraph":4,"sentenceNo":3,"sentence":"It insists that economic co-ordination should involve all 27 members of the EU club, among whom there is a small majority for free-market liberalism and economic rigour; in the inner core alone, Germany fears, a small majority favour French interference.","path":"english2/2011.html"},{"id":"english2-2011-t4-p5-s1","examKey":"english2","examLabel":"英语二","year":"2011","text":4,"paragraph":5,"sentenceNo":1,"sentence":"Q39 法国方案 A “southern” camp headed by France wants something different: “European economic government” within an inner core of euro-zone members.","path":"english2/2011.html"},{"id":"english2-2011-t4-p5-s2","examKey":"english2","examLabel":"英语二","year":"2011","text":4,"paragraph":5,"sentenceNo":2,"sentence":"Translated, that means politicians intervening in monetary policy and a system of redistribution from richer to poorer members, via cheaper borrowing for governments through common Eurobonds or complete fiscal transfers.","path":"english2/2011.html"},{"id":"english2-2011-t4-p5-s3","examKey":"english2","examLabel":"英语二","year":"2011","text":4,"paragraph":5,"sentenceNo":3,"sentence":"Finally, figures close to the French government have murmured, euro-zone members should agree to some fiscal and social harmonisation: e.g., curbing competition in corporate-tax rates or labour costs.","path":"english2/2011.html"},{"id":"english2-2011-t4-p6-s1","examKey":"english2","examLabel":"英语二","year":"2011","text":4,"paragraph":6,"sentenceNo":1,"sentence":"Q40 结论定位 It is too soon to write off the EU.","path":"english2/2011.html"},{"id":"english2-2011-t4-p6-s2","examKey":"english2","examLabel":"英语二","year":"2011","text":4,"paragraph":6,"sentenceNo":2,"sentence":"It remains the world’s largest trading block.","path":"english2/2011.html"},{"id":"english2-2011-t4-p6-s3","examKey":"english2","examLabel":"英语二","year":"2011","text":4,"paragraph":6,"sentenceNo":3,"sentence":"At its best, the European project is remarkably liberal: built around a single market of 27 rich and poor countries, its internal borders are far more open to goods, capital and labour than any comparable trading area.","path":"english2/2011.html"},{"id":"english2-2011-t4-p6-s4","examKey":"english2","examLabel":"英语二","year":"2011","text":4,"paragraph":6,"sentenceNo":4,"sentence":"It is an ambitious attempt to blunt the sharpest edges of globalisation, and make capitalism benign.","path":"english2/2011.html"},{"id":"english1-2012-t1-p1-s1","examKey":"english1","examLabel":"英语一","year":"2012","text":1,"paragraph":1,"sentenceNo":1,"sentence":"Come on—Everybody’s doing it.","path":"english1/2012.html"},{"id":"english1-2012-t1-p1-s2","examKey":"english1","examLabel":"英语一","year":"2012","text":1,"paragraph":1,"sentenceNo":2,"sentence":"That whispered message, half invitation and half forcing, is what most of us think of when we hear the words peer pressure.","path":"english1/2012.html"},{"id":"english1-2012-t1-p1-s3","examKey":"english1","examLabel":"英语一","year":"2012","text":1,"paragraph":1,"sentenceNo":3,"sentence":"It usually leads to no good—drinking, drugs and casual sex.","path":"english1/2012.html"},{"id":"english1-2012-t1-p1-s4","examKey":"english1","examLabel":"英语一","year":"2012","text":1,"paragraph":1,"sentenceNo":4,"sentence":"But in her new book Join the Club, Tina Rosenberg contends that peer pressure can also be a positive force through what she calls the social cure, in which organizations and officials use the power of group dynamics to help individuals improve their lives and possibly the world.","path":"english1/2012.html"},{"id":"english1-2012-t1-p2-s1","examKey":"english1","examLabel":"英语一","year":"2012","text":1,"paragraph":2,"sentenceNo":1,"sentence":"Rosenberg, the recipient of a Pulitzer Prize, offers a host of examples of the social cure in action: In South Carolina, a state-sponsored antismoking program called Rage Against the Haze sets out to make cigarettes uncool.","path":"english1/2012.html"},{"id":"english1-2012-t1-p2-s2","examKey":"english1","examLabel":"英语一","year":"2012","text":1,"paragraph":2,"sentenceNo":2,"sentence":"In South Africa, an HIV-prevention initiative known as loveLife recruits young people to promote safe sex among their peers.","path":"english1/2012.html"},{"id":"english1-2012-t1-p3-s1","examKey":"english1","examLabel":"英语一","year":"2012","text":1,"paragraph":3,"sentenceNo":1,"sentence":"The idea seems promising, and Rosenberg is a perceptive observer.","path":"english1/2012.html"},{"id":"english1-2012-t1-p3-s2","examKey":"english1","examLabel":"英语一","year":"2012","text":1,"paragraph":3,"sentenceNo":2,"sentence":"Her critique of the lameness of many public-health campaigns is spot-on: they fail to mobilize peer pressure for healthy habits, and they demonstrate a seriously flawed understanding of psychology.","path":"english1/2012.html"},{"id":"english1-2012-t1-p3-s3","examKey":"english1","examLabel":"英语一","year":"2012","text":1,"paragraph":3,"sentenceNo":3,"sentence":"“Dare to be different, please don’t smoke!” pleads one billboard campaign aimed at reducing smoking among teenagers — teenagers, who desire nothing more than fitting in.","path":"english1/2012.html"},{"id":"english1-2012-t1-p3-s4","examKey":"english1","examLabel":"英语一","year":"2012","text":1,"paragraph":3,"sentenceNo":4,"sentence":"Rosenberg argues convincingly that public-health advocates ought to take a page from advertisers, so skilled at applying peer pressure.","path":"english1/2012.html"},{"id":"english1-2012-t1-p4-s1","examKey":"english1","examLabel":"英语一","year":"2012","text":1,"paragraph":4,"sentenceNo":1,"sentence":"But on the general effect iveness of the social cure, Rosenberg is less persuasive.","path":"english1/2012.html"},{"id":"english1-2012-t1-p4-s2","examKey":"english1","examLabel":"英语一","year":"2012","text":1,"paragraph":4,"sentenceNo":2,"sentence":"Join the Club is filled with too much irrelevant detail and not enough exploration of the social and biological factors that make peer pressure so powerful.","path":"english1/2012.html"},{"id":"english1-2012-t1-p4-s3","examKey":"english1","examLabel":"英语一","year":"2012","text":1,"paragraph":4,"sentenceNo":3,"sentence":"The most glaring flaw of the social cure as it’s presented here is that it doesn’t work very well for very long.","path":"english1/2012.html"},{"id":"english1-2012-t1-p4-s4","examKey":"english1","examLabel":"英语一","year":"2012","text":1,"paragraph":4,"sentenceNo":4,"sentence":"Rage Against the Haze failed once state funding was cut.","path":"english1/2012.html"},{"id":"english1-2012-t1-p4-s5","examKey":"english1","examLabel":"英语一","year":"2012","text":1,"paragraph":4,"sentenceNo":5,"sentence":"Evidence that the loveLife program produces lasting changes is limited and mixed.","path":"english1/2012.html"},{"id":"english1-2012-t1-p5-s1","examKey":"english1","examLabel":"英语一","year":"2012","text":1,"paragraph":5,"sentenceNo":1,"sentence":"There’s no doubt that our peer groups exert enormous influence on our behavior.","path":"english1/2012.html"},{"id":"english1-2012-t1-p5-s2","examKey":"english1","examLabel":"英语一","year":"2012","text":1,"paragraph":5,"sentenceNo":2,"sentence":"An emerging body of research shows that positive health habits — as well as negative ones — spread through networks of friends via social communication.","path":"english1/2012.html"},{"id":"english1-2012-t1-p5-s3","examKey":"english1","examLabel":"英语一","year":"2012","text":1,"paragraph":5,"sentenceNo":3,"sentence":"This is a subtle form of peer pressure: we unconsciously imitate the behavior we see every day.","path":"english1/2012.html"},{"id":"english1-2012-t1-p6-s1","examKey":"english1","examLabel":"英语一","year":"2012","text":1,"paragraph":6,"sentenceNo":1,"sentence":"Far less certain, however, is how successfully experts and bureaucrats can select our peer groups and steer their activities in virtuous directions.","path":"english1/2012.html"},{"id":"english1-2012-t1-p6-s2","examKey":"english1","examLabel":"英语一","year":"2012","text":1,"paragraph":6,"sentenceNo":2,"sentence":"It’s like the teacher who breaks up the troublemakers in the back row by pairing them with better-behaved classmates.","path":"english1/2012.html"},{"id":"english1-2012-t1-p6-s3","examKey":"english1","examLabel":"英语一","year":"2012","text":1,"paragraph":6,"sentenceNo":3,"sentence":"The tactic never really works.","path":"english1/2012.html"},{"id":"english1-2012-t1-p6-s4","examKey":"english1","examLabel":"英语一","year":"2012","text":1,"paragraph":6,"sentenceNo":4,"sentence":"And that’s the problem with a social cure engineered from the outside: in the real world, as in school, we insist on choosing our own friends.","path":"english1/2012.html"},{"id":"english1-2012-t2-p1-s1","examKey":"english1","examLabel":"英语一","year":"2012","text":2,"paragraph":1,"sentenceNo":1,"sentence":"A deal is a deal — except, apparently, when Entergy is involved.","path":"english1/2012.html"},{"id":"english1-2012-t2-p1-s2","examKey":"english1","examLabel":"英语一","year":"2012","text":2,"paragraph":1,"sentenceNo":2,"sentence":"The company, a major energy supplier in New England, provoked justified outrage in Vermont last week when it announced it was reneging on a longstanding commitment to abide by the state’s strict nuclear regulations.","path":"english1/2012.html"},{"id":"english1-2012-t2-p2-s1","examKey":"english1","examLabel":"英语一","year":"2012","text":2,"paragraph":2,"sentenceNo":1,"sentence":"Instead, the company has done precisely what it had long promised it would not: challenge the constitutionality of Vermont’s rules in the federal court, as part of a desperate effort to keep its Vermont Yankee nuclear power plant running.","path":"english1/2012.html"},{"id":"english1-2012-t2-p2-s2","examKey":"english1","examLabel":"英语一","year":"2012","text":2,"paragraph":2,"sentenceNo":2,"sentence":"It’s a stunning move.","path":"english1/2012.html"},{"id":"english1-2012-t2-p3-s1","examKey":"english1","examLabel":"英语一","year":"2012","text":2,"paragraph":3,"sentenceNo":1,"sentence":"The conflict has been surfacing since 2002, when the corporation bought Vermont’s only nuclear power plant, an aging reactor in Vernon.","path":"english1/2012.html"},{"id":"english1-2012-t2-p3-s2","examKey":"english1","examLabel":"英语一","year":"2012","text":2,"paragraph":3,"sentenceNo":2,"sentence":"As a condition of receiving state approval for the sale, the company agreed to seek permission from state regulators to operate past 2012.","path":"english1/2012.html"},{"id":"english1-2012-t2-p3-s3","examKey":"english1","examLabel":"英语一","year":"2012","text":2,"paragraph":3,"sentenceNo":3,"sentence":"In 2006, the state went a step further, requiring that any extension of the plant’s license be subject to the Vermont legislature’s approval.","path":"english1/2012.html"},{"id":"english1-2012-t2-p3-s4","examKey":"english1","examLabel":"英语一","year":"2012","text":2,"paragraph":3,"sentenceNo":4,"sentence":"Then, too, the company went along.","path":"english1/2012.html"},{"id":"english1-2012-t2-p4-s1","examKey":"english1","examLabel":"英语一","year":"2012","text":2,"paragraph":4,"sentenceNo":1,"sentence":"Either Entergy never really intended to live by those commitments, or it simply didn’t foresee what would happen next.","path":"english1/2012.html"},{"id":"english1-2012-t2-p4-s2","examKey":"english1","examLabel":"英语一","year":"2012","text":2,"paragraph":4,"sentenceNo":2,"sentence":"A string of accidents, including the partial collapse of a cooling tower in 2007 and the discovery of an underground pipe system leakage, raised serious questions about both Vermont Yankee’s safety and Entergy’s management — especially after the company made misleading statements about the pipe.","path":"english1/2012.html"},{"id":"english1-2012-t2-p4-s3","examKey":"english1","examLabel":"英语一","year":"2012","text":2,"paragraph":4,"sentenceNo":3,"sentence":"Enraged by Entergy’s behavior, the Vermont Senate voted 26 to 4 last year against allowing an extension.","path":"english1/2012.html"},{"id":"english1-2012-t2-p5-s1","examKey":"english1","examLabel":"英语一","year":"2012","text":2,"paragraph":5,"sentenceNo":1,"sentence":"Now the company is suddenly claiming that the 2002 agreement is invalid because of the 2006 legislation, and that only the federal government has regulatory power over nuclear issues.","path":"english1/2012.html"},{"id":"english1-2012-t2-p5-s2","examKey":"english1","examLabel":"英语一","year":"2012","text":2,"paragraph":5,"sentenceNo":2,"sentence":"The legal issues in the case are obscure; whereas the Supreme Court has ruled that states do have some regulatory authority over nuclear power, legal scholars say the Vermont case will offer a precedent-setting test of how far those powers extend.","path":"english1/2012.html"},{"id":"english1-2012-t2-p5-s3","examKey":"english1","examLabel":"英语一","year":"2012","text":2,"paragraph":5,"sentenceNo":3,"sentence":"Certainly, there are valid concerns about the patchwork regulations that could result if every state sets its own rules.","path":"english1/2012.html"},{"id":"english1-2012-t2-p5-s4","examKey":"english1","examLabel":"英语一","year":"2012","text":2,"paragraph":5,"sentenceNo":4,"sentence":"But had Entergy kept its word, that debate would be beside the point.","path":"english1/2012.html"},{"id":"english1-2012-t2-p6-s1","examKey":"english1","examLabel":"英语一","year":"2012","text":2,"paragraph":6,"sentenceNo":1,"sentence":"The company seems to have concluded that its reputation in Vermont is already so damaged that it has nothing left to lose by going to war with the state.","path":"english1/2012.html"},{"id":"english1-2012-t2-p6-s2","examKey":"english1","examLabel":"英语一","year":"2012","text":2,"paragraph":6,"sentenceNo":2,"sentence":"But there should be consequences.","path":"english1/2012.html"},{"id":"english1-2012-t2-p6-s3","examKey":"english1","examLabel":"英语一","year":"2012","text":2,"paragraph":6,"sentenceNo":3,"sentence":"Permission to run a nuclear plant is a public trust.","path":"english1/2012.html"},{"id":"english1-2012-t2-p6-s4","examKey":"english1","examLabel":"英语一","year":"2012","text":2,"paragraph":6,"sentenceNo":4,"sentence":"Entergy runs 11 other reactors in the United States, including Pilgrim Nuclear station in Plymouth.","path":"english1/2012.html"},{"id":"english1-2012-t2-p6-s5","examKey":"english1","examLabel":"英语一","year":"2012","text":2,"paragraph":6,"sentenceNo":5,"sentence":"Pledging to run Pilgrim safely, the company has applied for federal permission to keep it open for another 20 years.","path":"english1/2012.html"},{"id":"english1-2012-t2-p6-s6","examKey":"english1","examLabel":"英语一","year":"2012","text":2,"paragraph":6,"sentenceNo":6,"sentence":"But as the Nuclear Regulatory Commission (NRC) reviews the company’s application, it should keep in mind what promises from Entergy are worth.","path":"english1/2012.html"},{"id":"english1-2012-t3-p1-s1","examKey":"english1","examLabel":"英语一","year":"2012","text":3,"paragraph":1,"sentenceNo":1,"sentence":"In the idealized version of how science is done, facts about the world are waiting to be observed and collected by objective researchers who use the scientific method to carry out their work.","path":"english1/2012.html"},{"id":"english1-2012-t3-p1-s2","examKey":"english1","examLabel":"英语一","year":"2012","text":3,"paragraph":1,"sentenceNo":2,"sentence":"But in the everyday practice of science, discovery frequently follows an ambiguous and complicated route.","path":"english1/2012.html"},{"id":"english1-2012-t3-p1-s3","examKey":"english1","examLabel":"英语一","year":"2012","text":3,"paragraph":1,"sentenceNo":3,"sentence":"We aim to be objective, but we cannot escape the context of our unique life experiences.","path":"english1/2012.html"},{"id":"english1-2012-t3-p1-s4","examKey":"english1","examLabel":"英语一","year":"2012","text":3,"paragraph":1,"sentenceNo":4,"sentence":"Prior knowledge and interests influence what we experience, what we think our experiences mean, and the subsequent actions we take.","path":"english1/2012.html"},{"id":"english1-2012-t3-p1-s5","examKey":"english1","examLabel":"英语一","year":"2012","text":3,"paragraph":1,"sentenceNo":5,"sentence":"Opportunities for misinterpretation, error, and self-deception abound.","path":"english1/2012.html"},{"id":"english1-2012-t3-p2-s1","examKey":"english1","examLabel":"英语一","year":"2012","text":3,"paragraph":2,"sentenceNo":1,"sentence":"Consequently, discovery claim s should be thought of as protoscience.","path":"english1/2012.html"},{"id":"english1-2012-t3-p2-s2","examKey":"english1","examLabel":"英语一","year":"2012","text":3,"paragraph":2,"sentenceNo":2,"sentence":"Similar to newly staked mining claims, they are full of potential.","path":"english1/2012.html"},{"id":"english1-2012-t3-p2-s3","examKey":"english1","examLabel":"英语一","year":"2012","text":3,"paragraph":2,"sentenceNo":3,"sentence":"But it takes collective scrutiny and acceptance to transform a discovery claim into a mature discovery.","path":"english1/2012.html"},{"id":"english1-2012-t3-p2-s4","examKey":"english1","examLabel":"英语一","year":"2012","text":3,"paragraph":2,"sentenceNo":4,"sentence":"This is the credibility process, through which the individual researcher’s me, here, now becomes the community’s anyone, anywhere, anytime.","path":"english1/2012.html"},{"id":"english1-2012-t3-p2-s5","examKey":"english1","examLabel":"英语一","year":"2012","text":3,"paragraph":2,"sentenceNo":5,"sentence":"Objective knowledge is the goal, not the starting point.","path":"english1/2012.html"},{"id":"english1-2012-t3-p3-s1","examKey":"english1","examLabel":"英语一","year":"2012","text":3,"paragraph":3,"sentenceNo":1,"sentence":"Once a discovery claim becomes public, the discoverer receives intellectual credit.","path":"english1/2012.html"},{"id":"english1-2012-t3-p3-s2","examKey":"english1","examLabel":"英语一","year":"2012","text":3,"paragraph":3,"sentenceNo":2,"sentence":"But, unlike with mining claims, the community takes control of what happens next.","path":"english1/2012.html"},{"id":"english1-2012-t3-p3-s3","examKey":"english1","examLabel":"英语一","year":"2012","text":3,"paragraph":3,"sentenceNo":3,"sentence":"Within the complex social structure of the scientific community, researchers make discoveries; editors and reviewers act as gatekeepers by controlling the publication process; other scientists use the new finding to suit their own purposes; and finally, the public (including other scientists) receives the new discovery and possibly accompanying technology.","path":"english1/2012.html"},{"id":"english1-2012-t3-p3-s4","examKey":"english1","examLabel":"英语一","year":"2012","text":3,"paragraph":3,"sentenceNo":4,"sentence":"As a discovery claim works its way through the community, the interaction and confrontation between shared and competing beliefs about the science and the technology involved transforms an individual’s discovery claim into the community’s credible discovery.","path":"english1/2012.html"},{"id":"english1-2012-t3-p4-s1","examKey":"english1","examLabel":"英语一","year":"2012","text":3,"paragraph":4,"sentenceNo":1,"sentence":"Two paradoxes exist throughout this credibility process.","path":"english1/2012.html"},{"id":"english1-2012-t3-p4-s2","examKey":"english1","examLabel":"英语一","year":"2012","text":3,"paragraph":4,"sentenceNo":2,"sentence":"First, scientific work tends to focus on some aspect of prevailing knowledge that is viewed as incomplete or incorrect.","path":"english1/2012.html"},{"id":"english1-2012-t3-p4-s3","examKey":"english1","examLabel":"英语一","year":"2012","text":3,"paragraph":4,"sentenceNo":3,"sentence":"Little reward accompanies duplication and confirmation of what is already known and believed.","path":"english1/2012.html"},{"id":"english1-2012-t3-p4-s4","examKey":"english1","examLabel":"英语一","year":"2012","text":3,"paragraph":4,"sentenceNo":4,"sentence":"The goal is new-search, not re-search.","path":"english1/2012.html"},{"id":"english1-2012-t3-p4-s5","examKey":"english1","examLabel":"英语一","year":"2012","text":3,"paragraph":4,"sentenceNo":5,"sentence":"Not surprisingly, newly published discovery claims and credible discoveries that appear to be important and convincing will always be open to challenge and potential modification or refutation by future researchers.","path":"english1/2012.html"},{"id":"english1-2012-t3-p4-s6","examKey":"english1","examLabel":"英语一","year":"2012","text":3,"paragraph":4,"sentenceNo":6,"sentence":"Second, novelty itself frequently provokes disbelief.","path":"english1/2012.html"},{"id":"english1-2012-t3-p4-s7","examKey":"english1","examLabel":"英语一","year":"2012","text":3,"paragraph":4,"sentenceNo":7,"sentence":"Nobel Laureate and physiologist Albert Szent-Györgyi once described discovery as “ seeing what everybody has seen and thinking what nobody has thought.” But thinking what nobody else has thought and telling others what they have missed may not change their views.","path":"english1/2012.html"},{"id":"english1-2012-t3-p4-s8","examKey":"english1","examLabel":"英语一","year":"2012","text":3,"paragraph":4,"sentenceNo":8,"sentence":"Sometimes years are required for truly novel discovery claims to be accepted and appreciated.","path":"english1/2012.html"},{"id":"english1-2012-t3-p5-s1","examKey":"english1","examLabel":"英语一","year":"2012","text":3,"paragraph":5,"sentenceNo":1,"sentence":"In the end, credibility “happens” to a discovery claim — a process that corresponds to what philosopher Annette Baier has described as the commons of the mind.","path":"english1/2012.html"},{"id":"english1-2012-t3-p5-s2","examKey":"english1","examLabel":"英语一","year":"2012","text":3,"paragraph":5,"sentenceNo":2,"sentence":"“We reason together, challenge, revise, and complete each other’s reasoning and each other’s conceptions of reason.”","path":"english1/2012.html"},{"id":"english1-2012-t4-p1-s1","examKey":"english1","examLabel":"英语一","year":"2012","text":4,"paragraph":1,"sentenceNo":1,"sentence":"If the trade unionist Jimmy Hoffa were alive today, he would probably represent civil servants.","path":"english1/2012.html"},{"id":"english1-2012-t4-p1-s2","examKey":"english1","examLabel":"英语一","year":"2012","text":4,"paragraph":1,"sentenceNo":2,"sentence":"When Hoffa’s Teamsters were in their prime in 1960, only one in ten American government workers belonged to a union; now 36% do.","path":"english1/2012.html"},{"id":"english1-2012-t4-p1-s3","examKey":"english1","examLabel":"英语一","year":"2012","text":4,"paragraph":1,"sentenceNo":3,"sentence":"In 2009 the number of unionists in America’s public sector passed that of their fellow members in the private sector.","path":"english1/2012.html"},{"id":"english1-2012-t4-p1-s4","examKey":"english1","examLabel":"英语一","year":"2012","text":4,"paragraph":1,"sentenceNo":4,"sentence":"In Britain, more than half of public- sector workers but only about 15% of private-sector ones are unionized.","path":"english1/2012.html"},{"id":"english1-2012-t4-p2-s1","examKey":"english1","examLabel":"英语一","year":"2012","text":4,"paragraph":2,"sentenceNo":1,"sentence":"There are three reasons for the public-sector unions ’ thriving.","path":"english1/2012.html"},{"id":"english1-2012-t4-p2-s2","examKey":"english1","examLabel":"英语一","year":"2012","text":4,"paragraph":2,"sentenceNo":2,"sentence":"First, they can shut things down without suffering much in the way of consequences.","path":"english1/2012.html"},{"id":"english1-2012-t4-p2-s3","examKey":"english1","examLabel":"英语一","year":"2012","text":4,"paragraph":2,"sentenceNo":3,"sentence":"Second, they are mostly bright and well-educated.","path":"english1/2012.html"},{"id":"english1-2012-t4-p2-s4","examKey":"english1","examLabel":"英语一","year":"2012","text":4,"paragraph":2,"sentenceNo":4,"sentence":"A quarter of America’s public-sector workers have a university degree.","path":"english1/2012.html"},{"id":"english1-2012-t4-p2-s5","examKey":"english1","examLabel":"英语一","year":"2012","text":4,"paragraph":2,"sentenceNo":5,"sentence":"Third, they now dominate left-of-centre politics.","path":"english1/2012.html"},{"id":"english1-2012-t4-p2-s6","examKey":"english1","examLabel":"英语一","year":"2012","text":4,"paragraph":2,"sentenceNo":6,"sentence":"Some of their ties go back a long way.","path":"english1/2012.html"},{"id":"english1-2012-t4-p2-s7","examKey":"english1","examLabel":"英语一","year":"2012","text":4,"paragraph":2,"sentenceNo":7,"sentence":"Britain’s Labor Party, as its name implies, has long been associated with trade unionism.","path":"english1/2012.html"},{"id":"english1-2012-t4-p2-s8","examKey":"english1","examLabel":"英语一","year":"2012","text":4,"paragraph":2,"sentenceNo":8,"sentence":"Its current leader, Ed Miliband, owes his position to votes from public-sector unions.","path":"english1/2012.html"},{"id":"english1-2012-t4-p3-s1","examKey":"english1","examLabel":"英语一","year":"2012","text":4,"paragraph":3,"sentenceNo":1,"sentence":"At the state level their influence can be even more fearsome.","path":"english1/2012.html"},{"id":"english1-2012-t4-p3-s2","examKey":"english1","examLabel":"英语一","year":"2012","text":4,"paragraph":3,"sentenceNo":2,"sentence":"Mark Baldassare of the Public Policy Institute of California points out that much of the state’s budget is patrolled by unions.","path":"english1/2012.html"},{"id":"english1-2012-t4-p3-s3","examKey":"english1","examLabel":"英语一","year":"2012","text":4,"paragraph":3,"sentenceNo":3,"sentence":"The teachers’ unions keep an eye on schools, the CCPOA on prisons and a variety of labor groups on health care.","path":"english1/2012.html"},{"id":"english1-2012-t4-p4-s1","examKey":"english1","examLabel":"英语一","year":"2012","text":4,"paragraph":4,"sentenceNo":1,"sentence":"In many rich countries average wages in the state sector are higher than in the private one.","path":"english1/2012.html"},{"id":"english1-2012-t4-p4-s2","examKey":"english1","examLabel":"英语一","year":"2012","text":4,"paragraph":4,"sentenceNo":2,"sentence":"But the real gains come in benefits and work practices.","path":"english1/2012.html"},{"id":"english1-2012-t4-p4-s3","examKey":"english1","examLabel":"英语一","year":"2012","text":4,"paragraph":4,"sentenceNo":3,"sentence":"Politicians have repeatedly backloaded public-sector pay deals, keeping the pay increases modest but adding to holidays and especially pensions that are already generous.","path":"english1/2012.html"},{"id":"english1-2012-t4-p5-s1","examKey":"english1","examLabel":"英语一","year":"2012","text":4,"paragraph":5,"sentenceNo":1,"sentence":"Reform has been vigorously opposed, perhaps most notoriously in education, where charter schools, academies and merit pay all faced drawn-out battles.","path":"english1/2012.html"},{"id":"english1-2012-t4-p5-s2","examKey":"english1","examLabel":"英语一","year":"2012","text":4,"paragraph":5,"sentenceNo":2,"sentence":"Even though there is plenty of evidence that the quality of the teachers is the most important variable, teachers’ unions have fought against getting rid of bad ones and promoting good ones.","path":"english1/2012.html"},{"id":"english1-2012-t4-p6-s1","examKey":"english1","examLabel":"英语一","year":"2012","text":4,"paragraph":6,"sentenceNo":1,"sentence":"As the cost to everyone else has become clearer, politicians have begun to clamp down.","path":"english1/2012.html"},{"id":"english1-2012-t4-p6-s2","examKey":"english1","examLabel":"英语一","year":"2012","text":4,"paragraph":6,"sentenceNo":2,"sentence":"In Wisconsin the unions have rallied thousands of supporters against Scott Walker, the hardline Republican governor.","path":"english1/2012.html"},{"id":"english1-2012-t4-p6-s3","examKey":"english1","examLabel":"英语一","year":"2012","text":4,"paragraph":6,"sentenceNo":3,"sentence":"But many within the public sector suffer under the current system, too.","path":"english1/2012.html"},{"id":"english1-2012-t4-p7-s1","examKey":"english1","examLabel":"英语一","year":"2012","text":4,"paragraph":7,"sentenceNo":1,"sentence":"John Donahue at Harvard’s Kennedy School points out that the norms of culture in Western civil services suit those who want to stay put but is bad for high achievers.","path":"english1/2012.html"},{"id":"english1-2012-t4-p7-s2","examKey":"english1","examLabel":"英语一","year":"2012","text":4,"paragraph":7,"sentenceNo":2,"sentence":"The only American public-sector workers who earn well above $250,000 a year are university sports coaches and the president of the United States.","path":"english1/2012.html"},{"id":"english1-2012-t4-p7-s3","examKey":"english1","examLabel":"英语一","year":"2012","text":4,"paragraph":7,"sentenceNo":3,"sentence":"Bankers’ fat pay packets have attracted much criticism, but a public-sector system that does not reward high achievers may be a much bigger problem for America.","path":"english1/2012.html"},{"id":"english2-2012-t1-p1-s1","examKey":"english2","examLabel":"英语二","year":"2012","text":1,"paragraph":1,"sentenceNo":1,"sentence":"Q21 段落定位 1 Homework has never been terribly popular with students and even many parents, but in recent years it has been particularly scorned.","path":"english2/2012.html"},{"id":"english2-2012-t1-p1-s2","examKey":"english2","examLabel":"英语二","year":"2012","text":1,"paragraph":1,"sentenceNo":2,"sentence":"2 School districts across the country, most recently Los Angeles Unified, are revising their thinking on this educational ritual.","path":"english2/2012.html"},{"id":"english2-2012-t1-p1-s3","examKey":"english2","examLabel":"英语二","year":"2012","text":1,"paragraph":1,"sentenceNo":3,"sentence":"3 Unfortunately, L.A.","path":"english2/2012.html"},{"id":"english2-2012-t1-p1-s4","examKey":"english2","examLabel":"英语二","year":"2012","text":1,"paragraph":1,"sentenceNo":4,"sentence":"Unified has produced an inflexible policy which mandates that with the exception of some advanced courses, homework may no longer count for more than 10% of a student’s academic grade.","path":"english2/2012.html"},{"id":"english2-2012-t1-p2-s1","examKey":"english2","examLabel":"英语二","year":"2012","text":1,"paragraph":2,"sentenceNo":1,"sentence":"4 This rule is meant to address the difficulty that students from impoverished or chaotic homes might have in completing their homework.","path":"english2/2012.html"},{"id":"english2-2012-t1-p2-s2","examKey":"english2","examLabel":"英语二","year":"2012","text":1,"paragraph":2,"sentenceNo":2,"sentence":"5 But the policy is unclear and contradictory.","path":"english2/2012.html"},{"id":"english2-2012-t1-p2-s3","examKey":"english2","examLabel":"英语二","year":"2012","text":1,"paragraph":2,"sentenceNo":3,"sentence":"6 Certainly, no homework should be assigned that students cannot complete on their own or that they cannot do without expensive equipment.","path":"english2/2012.html"},{"id":"english2-2012-t1-p2-s4","examKey":"english2","examLabel":"英语二","year":"2012","text":1,"paragraph":2,"sentenceNo":4,"sentence":"7 But if the district is essentially giving a pass to students who do not do their homework because of complicated family lives, it is going riskily close to the implication that standards need to be lowered for poor children.","path":"english2/2012.html"},{"id":"english2-2012-t1-p3-s1","examKey":"english2","examLabel":"英语二","year":"2012","text":1,"paragraph":3,"sentenceNo":1,"sentence":"Q23 段落定位 8 District administrators say that homework will still be a part of schooling; teachers are allowed to assign as much of it as they want.","path":"english2/2012.html"},{"id":"english2-2012-t1-p3-s2","examKey":"english2","examLabel":"英语二","year":"2012","text":1,"paragraph":3,"sentenceNo":2,"sentence":"9 But with homework counting for no more than 10% of their grades, students can easily skip half their homework and see very little difference on their report cards.","path":"english2/2012.html"},{"id":"english2-2012-t1-p3-s3","examKey":"english2","examLabel":"英语二","year":"2012","text":1,"paragraph":3,"sentenceNo":3,"sentence":"10 Some students might do well on state tests without completing their homework, but what about the students who performed well on the tests and did their homework?","path":"english2/2012.html"},{"id":"english2-2012-t1-p3-s4","examKey":"english2","examLabel":"英语二","year":"2012","text":1,"paragraph":3,"sentenceNo":4,"sentence":"11 It is quite possible that the homework helped.","path":"english2/2012.html"},{"id":"english2-2012-t1-p3-s5","examKey":"english2","examLabel":"英语二","year":"2012","text":1,"paragraph":3,"sentenceNo":5,"sentence":"12 Yet rather than empowering teachers to find what works best for their students, the policy imposes a flat, across-the-board rule.","path":"english2/2012.html"},{"id":"english2-2012-t1-p4-s1","examKey":"english2","examLabel":"英语二","year":"2012","text":1,"paragraph":4,"sentenceNo":1,"sentence":"Q24 段落定位 13 At the same time, the policy addresses none of the truly thorny questions about homework.","path":"english2/2012.html"},{"id":"english2-2012-t1-p4-s2","examKey":"english2","examLabel":"英语二","year":"2012","text":1,"paragraph":4,"sentenceNo":2,"sentence":"14 If the district finds homework to be unimportant to its students’ academic achievement, it should move to reduce or eliminate the assignments, not make them count for almost nothing.","path":"english2/2012.html"},{"id":"english2-2012-t1-p4-s3","examKey":"english2","examLabel":"英语二","year":"2012","text":1,"paragraph":4,"sentenceNo":3,"sentence":"Conversely, if homework matters, it should account for a significant portion of the grade.","path":"english2/2012.html"},{"id":"english2-2012-t1-p4-s4","examKey":"english2","examLabel":"英语二","year":"2012","text":1,"paragraph":4,"sentenceNo":4,"sentence":"15 Meanwhile, this policy does nothing to ensure that the homework students receive is meaningful or appropriate to their age and the subject, or that teachers are not assigning more than they are willing to review and correct.","path":"english2/2012.html"},{"id":"english2-2012-t1-p5-s1","examKey":"english2","examLabel":"英语二","year":"2012","text":1,"paragraph":5,"sentenceNo":1,"sentence":"Q25 主旨定位 16 The homework rules should be put on hold while the school board, which is responsible for setting educational policy, looks into the matter and conducts public hearings.","path":"english2/2012.html"},{"id":"english2-2012-t1-p5-s2","examKey":"english2","examLabel":"英语二","year":"2012","text":1,"paragraph":5,"sentenceNo":2,"sentence":"17 It is not too late for L.A.","path":"english2/2012.html"},{"id":"english2-2012-t1-p5-s3","examKey":"english2","examLabel":"英语二","year":"2012","text":1,"paragraph":5,"sentenceNo":3,"sentence":"Unified to do homework right.","path":"english2/2012.html"},{"id":"english2-2012-t2-p1-s1","examKey":"english2","examLabel":"英语二","year":"2012","text":2,"paragraph":1,"sentenceNo":1,"sentence":"1 Pretty in pink: adult women do not remember being so obsessed with the colour, yet it is pervasive in our young girls’ lives.","path":"english2/2012.html"},{"id":"english2-2012-t2-p1-s2","examKey":"english2","examLabel":"英语二","year":"2012","text":2,"paragraph":1,"sentenceNo":2,"sentence":"2 It is not that pink is intrinsically bad, but it is such a tiny slice of the rainbow and, though it may celebrate girlhood in one way, it also repeatedly and firmly fuses girls’ identity to appearance.","path":"english2/2012.html"},{"id":"english2-2012-t2-p1-s3","examKey":"english2","examLabel":"英语二","year":"2012","text":2,"paragraph":1,"sentenceNo":3,"sentence":"3 Then it presents that connection, even among two-year-olds, between girls as not only innocent but as evidence of innocence.","path":"english2/2012.html"},{"id":"english2-2012-t2-p1-s4","examKey":"english2","examLabel":"英语二","year":"2012","text":2,"paragraph":1,"sentenceNo":4,"sentence":"4 Looking around, I despaired at the singular lack of imagination about girls’ lives and interests.","path":"english2/2012.html"},{"id":"english2-2012-t2-p2-s1","examKey":"english2","examLabel":"英语二","year":"2012","text":2,"paragraph":2,"sentenceNo":1,"sentence":"Q27 段落定位 5 Girls’ attraction to pink may seem unavoidable, somehow encoded in their DNA, but according to Jo Paoletti, an associate professor of American Studies, it is not.","path":"english2/2012.html"},{"id":"english2-2012-t2-p2-s2","examKey":"english2","examLabel":"英语二","year":"2012","text":2,"paragraph":2,"sentenceNo":2,"sentence":"6 Children were not colour-coded at all until the early 20th century: in the era before domestic washing machines all babies wore white as a practical matter, since the only way of getting clothes clean was to boil them.","path":"english2/2012.html"},{"id":"english2-2012-t2-p2-s3","examKey":"english2","examLabel":"英语二","year":"2012","text":2,"paragraph":2,"sentenceNo":3,"sentence":"7 What’s more, both boys and girls wore what were thought of as gender-neutral dresses.","path":"english2/2012.html"},{"id":"english2-2012-t2-p2-s4","examKey":"english2","examLabel":"英语二","year":"2012","text":2,"paragraph":2,"sentenceNo":4,"sentence":"8 When nursery colours were introduced, pink was actually considered the more masculine colour, a pastel version of red, which was associated with strength.","path":"english2/2012.html"},{"id":"english2-2012-t2-p2-s5","examKey":"english2","examLabel":"英语二","year":"2012","text":2,"paragraph":2,"sentenceNo":5,"sentence":"Blue, with its intimations of the Virgin Mary, constancy and faithfulness, symbolised femininity.","path":"english2/2012.html"},{"id":"english2-2012-t2-p2-s6","examKey":"english2","examLabel":"英语二","year":"2012","text":2,"paragraph":2,"sentenceNo":6,"sentence":"9 It was not until the mid-1980s, when amplifying age and sex differences became a dominant children’s marketing strategy, that pink fully came into its own, when it began to seem inherently attractive to girls, part of what defined them as female, at least for the first few critical years.","path":"english2/2012.html"},{"id":"english2-2012-t2-p3-s1","examKey":"english2","examLabel":"英语二","year":"2012","text":2,"paragraph":3,"sentenceNo":1,"sentence":"10 I had not realised how profoundly marketing trends dictated our perception of what is natural to kids, including our core beliefs about their psychological development.","path":"english2/2012.html"},{"id":"english2-2012-t2-p3-s2","examKey":"english2","examLabel":"英语二","year":"2012","text":2,"paragraph":3,"sentenceNo":2,"sentence":"11 Take the toddler.","path":"english2/2012.html"},{"id":"english2-2012-t2-p3-s3","examKey":"english2","examLabel":"英语二","year":"2012","text":2,"paragraph":3,"sentenceNo":3,"sentence":"12 I assumed that phase was something experts developed after years of research into children’s behaviour: wrong.","path":"english2/2012.html"},{"id":"english2-2012-t2-p3-s4","examKey":"english2","examLabel":"英语二","year":"2012","text":2,"paragraph":3,"sentenceNo":4,"sentence":"13 Turns out, according to Daniel Cook, a historian of childhood consumerism, it was popularised as a marketing trick by clothing manufacturers in the 1930s.","path":"english2/2012.html"},{"id":"english2-2012-t2-p4-s1","examKey":"english2","examLabel":"英语二","year":"2012","text":2,"paragraph":4,"sentenceNo":1,"sentence":"Q29 段落定位 14 Trade publications counselled department stores that, in order to increase sales, they should create a “third stepping stone” between infant wear and older kids’ clothes.","path":"english2/2012.html"},{"id":"english2-2012-t2-p4-s2","examKey":"english2","examLabel":"英语二","year":"2012","text":2,"paragraph":4,"sentenceNo":2,"sentence":"15 It was only after “toddler” became a common shoppers’ term that it evolved into a broadly accepted developmental stage.","path":"english2/2012.html"},{"id":"english2-2012-t2-p4-s3","examKey":"english2","examLabel":"英语二","year":"2012","text":2,"paragraph":4,"sentenceNo":3,"sentence":"16 Splitting kids, or adults, into ever-tinier categories has proved a sure-fire way to boost profits.","path":"english2/2012.html"},{"id":"english2-2012-t2-p4-s4","examKey":"english2","examLabel":"英语二","year":"2012","text":2,"paragraph":4,"sentenceNo":4,"sentence":"17 And one of the easiest ways to segment a market is to magnify gender differences — or invent them where they did not previously exist.","path":"english2/2012.html"},{"id":"english2-2012-t3-p1-s1","examKey":"english2","examLabel":"英语二","year":"2012","text":3,"paragraph":1,"sentenceNo":1,"sentence":"Q31 段落定位 1 In 2010, a federal judge shook America’s biotech industry to its core.","path":"english2/2012.html"},{"id":"english2-2012-t3-p1-s2","examKey":"english2","examLabel":"英语二","year":"2012","text":3,"paragraph":1,"sentenceNo":2,"sentence":"2 Companies had won patents for isolated DNA for decades — by 2005 some 20% of human genes were patented.","path":"english2/2012.html"},{"id":"english2-2012-t3-p1-s3","examKey":"english2","examLabel":"英语二","year":"2012","text":3,"paragraph":1,"sentenceNo":3,"sentence":"3 But in March 2010 a judge ruled that genes were unpatentable.","path":"english2/2012.html"},{"id":"english2-2012-t3-p1-s4","examKey":"english2","examLabel":"英语二","year":"2012","text":3,"paragraph":1,"sentenceNo":4,"sentence":"4 Executives were violently agitated.","path":"english2/2012.html"},{"id":"english2-2012-t3-p1-s5","examKey":"english2","examLabel":"英语二","year":"2012","text":3,"paragraph":1,"sentenceNo":5,"sentence":"5 The Biotechnology Industry Organisation (BIO), a trade group, assured members that this was just a “preliminary step” in a longer battle.","path":"english2/2012.html"},{"id":"english2-2012-t3-p2-s1","examKey":"english2","examLabel":"英语二","year":"2012","text":3,"paragraph":2,"sentenceNo":1,"sentence":"6 On July 29th they were relieved, at least temporarily.","path":"english2/2012.html"},{"id":"english2-2012-t3-p2-s2","examKey":"english2","examLabel":"英语二","year":"2012","text":3,"paragraph":2,"sentenceNo":2,"sentence":"7 A federal appeals court overturned the prior decision, ruling that Myriad Genetics could indeed hold patents to two genes that help forecast a woman’s risk of breast cancer.","path":"english2/2012.html"},{"id":"english2-2012-t3-p2-s3","examKey":"english2","examLabel":"英语二","year":"2012","text":3,"paragraph":2,"sentenceNo":3,"sentence":"8 The chief executive of Myriad, a company in Utah, said the ruling was a blessing to firms and patients alike.","path":"english2/2012.html"},{"id":"english2-2012-t3-p3-s1","examKey":"english2","examLabel":"英语二","year":"2012","text":3,"paragraph":3,"sentenceNo":1,"sentence":"9 But as companies continue their attempts at personalised medicine, the courts will remain rather busy.","path":"english2/2012.html"},{"id":"english2-2012-t3-p3-s2","examKey":"english2","examLabel":"英语二","year":"2012","text":3,"paragraph":3,"sentenceNo":2,"sentence":"10 The Myriad case itself is probably not over.","path":"english2/2012.html"},{"id":"english2-2012-t3-p3-s3","examKey":"english2","examLabel":"英语二","year":"2012","text":3,"paragraph":3,"sentenceNo":3,"sentence":"11 Critics make three main arguments against gene patents: a gene is a product of nature, so it may not be patented; gene patents suppress innovation rather than reward it; and patents’ monopolies restrict access to genetic tests such as Myriad’s.","path":"english2/2012.html"},{"id":"english2-2012-t3-p3-s4","examKey":"english2","examLabel":"英语二","year":"2012","text":3,"paragraph":3,"sentenceNo":4,"sentence":"12 A growing number seem to agree.","path":"english2/2012.html"},{"id":"english2-2012-t3-p3-s5","examKey":"english2","examLabel":"英语二","year":"2012","text":3,"paragraph":3,"sentenceNo":5,"sentence":"13 Last year a federal task-force urged reform for patents related to genetic tests.","path":"english2/2012.html"},{"id":"english2-2012-t3-p3-s6","examKey":"english2","examLabel":"英语二","year":"2012","text":3,"paragraph":3,"sentenceNo":6,"sentence":"14 In October the Department of Justice filed a brief in the Myriad case, arguing that an isolated DNA molecule “is no less a product of nature...than are cotton fibres that have been separated from cotton seeds.”","path":"english2/2012.html"},{"id":"english2-2012-t3-p4-s1","examKey":"english2","examLabel":"英语二","year":"2012","text":3,"paragraph":4,"sentenceNo":1,"sentence":"15 Despite the appeals court’s decision, big questions remain unanswered.","path":"english2/2012.html"},{"id":"english2-2012-t3-p4-s2","examKey":"english2","examLabel":"英语二","year":"2012","text":3,"paragraph":4,"sentenceNo":2,"sentence":"16 For example, it is unclear whether the sequencing of a whole genome violates the patents of individual genes within it, or whether diagnostic uses of genes can be kept away from patients and researchers by a single patent holder.","path":"english2/2012.html"},{"id":"english2-2012-t3-p5-s1","examKey":"english2","examLabel":"英语二","year":"2012","text":3,"paragraph":5,"sentenceNo":1,"sentence":"17 Industry lawyers insist that patents are not being sought for life itself.","path":"english2/2012.html"},{"id":"english2-2012-t3-p5-s2","examKey":"english2","examLabel":"英语二","year":"2012","text":3,"paragraph":5,"sentenceNo":2,"sentence":"18 Hans Sauer, a lawyer for BIO, says firms are eager to protect discoveries that connect genes with illnesses.","path":"english2/2012.html"},{"id":"english2-2012-t3-p5-s3","examKey":"english2","examLabel":"英语二","year":"2012","text":3,"paragraph":5,"sentenceNo":3,"sentence":"19 What companies want, he argues, are patents for establishing useful correlations between genes and diseases, not simple ownership of human DNA.","path":"english2/2012.html"},{"id":"english2-2012-t3-p6-s1","examKey":"english2","examLabel":"英语二","year":"2012","text":3,"paragraph":6,"sentenceNo":1,"sentence":"20 The debate has become a central issue for researchers, doctors, lawyers and business groups.","path":"english2/2012.html"},{"id":"english2-2012-t3-p6-s2","examKey":"english2","examLabel":"英语二","year":"2012","text":3,"paragraph":6,"sentenceNo":2,"sentence":"21 At recent meetings on the future of genetic testing, each meeting was packed, reflecting how widely gene patenting worried those involved.","path":"english2/2012.html"},{"id":"english2-2012-t3-p6-s3","examKey":"english2","examLabel":"英语二","year":"2012","text":3,"paragraph":6,"sentenceNo":3,"sentence":"22 For now, the courts have supplied temporary answers, but the larger controversy over gene patenting remains unsettled.","path":"english2/2012.html"},{"id":"english2-2012-t4-p1-s1","examKey":"english2","examLabel":"英语二","year":"2012","text":4,"paragraph":1,"sentenceNo":1,"sentence":"1 The great recession may be over, but this era of high joblessness is probably beginning.","path":"english2/2012.html"},{"id":"english2-2012-t4-p1-s2","examKey":"english2","examLabel":"英语二","year":"2012","text":4,"paragraph":1,"sentenceNo":2,"sentence":"2 Before it ends, it will likely change the life course and character of a generation of young adults.","path":"english2/2012.html"},{"id":"english2-2012-t4-p1-s3","examKey":"english2","examLabel":"英语二","year":"2012","text":4,"paragraph":1,"sentenceNo":3,"sentence":"3 And ultimately, it is likely to reshape our politics, our culture, and the character of our society for years.","path":"english2/2012.html"},{"id":"english2-2012-t4-p2-s1","examKey":"english2","examLabel":"英语二","year":"2012","text":4,"paragraph":2,"sentenceNo":1,"sentence":"Q36/Q37 段落定位 4 No one tries harder than the jobless to find silver linings in this national economic disaster.","path":"english2/2012.html"},{"id":"english2-2012-t4-p2-s2","examKey":"english2","examLabel":"英语二","year":"2012","text":4,"paragraph":2,"sentenceNo":2,"sentence":"5 Many said that unemployment, while extremely painful, had improved them in some ways: they had become less materialistic and more financially prudent; they were more aware of the struggles of others.","path":"english2/2012.html"},{"id":"english2-2012-t4-p2-s3","examKey":"english2","examLabel":"英语二","year":"2012","text":4,"paragraph":2,"sentenceNo":3,"sentence":"6 In limited respects, perhaps the recession will leave society better off.","path":"english2/2012.html"},{"id":"english2-2012-t4-p2-s4","examKey":"english2","examLabel":"英语二","year":"2012","text":4,"paragraph":2,"sentenceNo":4,"sentence":"7 At the very least, it has awoken us from our national fever dream of easy riches and bigger houses, and put a necessary end to an era of reckless personal spending.","path":"english2/2012.html"},{"id":"english2-2012-t4-p3-s1","examKey":"english2","examLabel":"英语二","year":"2012","text":4,"paragraph":3,"sentenceNo":1,"sentence":"8 But for the most part, these benefits seem thin, uncertain, and far off.","path":"english2/2012.html"},{"id":"english2-2012-t4-p3-s2","examKey":"english2","examLabel":"英语二","year":"2012","text":4,"paragraph":3,"sentenceNo":2,"sentence":"9 In The Moral Consequences of Economic Growth, the economic historian Benjamin Friedman argues that both inside and outside the U.S., lengthy periods of economic stagnation or decline have almost always left society more mean-spirited and less inclusive, and have usually stopped or reversed the advance of rights and freedoms.","path":"english2/2012.html"},{"id":"english2-2012-t4-p3-s3","examKey":"english2","examLabel":"英语二","year":"2012","text":4,"paragraph":3,"sentenceNo":3,"sentence":"10 Anti-immigrant sentiment typically increases, as does conflict between races and classes.","path":"english2/2012.html"},{"id":"english2-2012-t4-p4-s1","examKey":"english2","examLabel":"英语二","year":"2012","text":4,"paragraph":4,"sentenceNo":1,"sentence":"11 Income inequality usually falls during a recession, but it has not shrunk in this one.","path":"english2/2012.html"},{"id":"english2-2012-t4-p4-s2","examKey":"english2","examLabel":"英语二","year":"2012","text":4,"paragraph":4,"sentenceNo":2,"sentence":"12 Indeed, this period of economic weakness may reinforce class divides, and decrease opportunities to cross them — especially for young people.","path":"english2/2012.html"},{"id":"english2-2012-t4-p4-s3","examKey":"english2","examLabel":"英语二","year":"2012","text":4,"paragraph":4,"sentenceNo":3,"sentence":"13 The research of Till Von Wachter, the economist at Columbia University, suggests that not all people graduating into a recession see their life chances dimmed: those with degrees from elite universities catch up fairly quickly to where they otherwise would have been if they had graduated in better times; it is the masses beneath them that are left behind.","path":"english2/2012.html"},{"id":"english2-2012-t4-p5-s1","examKey":"english2","examLabel":"英语二","year":"2012","text":4,"paragraph":5,"sentenceNo":1,"sentence":"14 In the Internet age, it is particularly easy to see the resentment that has always been hidden within American society.","path":"english2/2012.html"},{"id":"english2-2012-t4-p5-s2","examKey":"english2","examLabel":"英语二","year":"2012","text":4,"paragraph":5,"sentenceNo":2,"sentence":"15 More difficult, in the moment, is discerning precisely how these lean times are affecting society’s character.","path":"english2/2012.html"},{"id":"english2-2012-t4-p5-s3","examKey":"english2","examLabel":"英语二","year":"2012","text":4,"paragraph":5,"sentenceNo":3,"sentence":"16 In many respects, the U.S. was more socially tolerant entering this recession than at any time in its history, and a variety of national polls on social conflict since then have shown mixed results.","path":"english2/2012.html"},{"id":"english2-2012-t4-p5-s4","examKey":"english2","examLabel":"英语二","year":"2012","text":4,"paragraph":5,"sentenceNo":4,"sentence":"17 We will have to wait and see exactly how these hard times will reshape our social fabric.","path":"english2/2012.html"},{"id":"english2-2012-t4-p5-s5","examKey":"english2","examLabel":"英语二","year":"2012","text":4,"paragraph":5,"sentenceNo":5,"sentence":"18 But they certainly will reshape it, and all the more so the longer they extend.","path":"english2/2012.html"},{"id":"english1-2013-t1-p1-s1","examKey":"english1","examLabel":"英语一","year":"2013","text":1,"paragraph":1,"sentenceNo":1,"sentence":"In the 2006 film version of The Devil Wears Prada, Miranda Priestly, played by Meryl Streep, scolds her unattractive assistant for imagining that high fashion doesn’t affect her.","path":"english1/2013.html"},{"id":"english1-2013-t1-p1-s2","examKey":"english1","examLabel":"英语一","year":"2013","text":1,"paragraph":1,"sentenceNo":2,"sentence":"Priestly explains how the deep blue color of the assistant’s sweater descended over the years from fashion shows to department stores and to the bargain bin in which the poor girl doubtless found her garment.","path":"english1/2013.html"},{"id":"english1-2013-t1-p2-s1","examKey":"english1","examLabel":"英语一","year":"2013","text":1,"paragraph":2,"sentenceNo":1,"sentence":"This top-down conception of the fashion business couldn’t be more out of date or at odds with the feverish world described in Overdressed, Elizabeth C line ’s three-year indictment of “fast fashion”.","path":"english1/2013.html"},{"id":"english1-2013-t1-p2-s2","examKey":"english1","examLabel":"英语一","year":"2013","text":1,"paragraph":2,"sentenceNo":2,"sentence":"In the last decade or so, advances in technology have allowed mass-market labels such as Zara, H&M, and Uniqlo to react to trends more quickly and anticipate demand more precisely.","path":"english1/2013.html"},{"id":"english1-2013-t1-p2-s3","examKey":"english1","examLabel":"英语一","year":"2013","text":1,"paragraph":2,"sentenceNo":3,"sentence":"Quicker turnarounds mean less wasted inventory, more frequent releases, and more profit.","path":"english1/2013.html"},{"id":"english1-2013-t1-p3-s1","examKey":"english1","examLabel":"英语一","year":"2013","text":1,"paragraph":3,"sentenceNo":1,"sentence":"These labels encourage style-conscious consumers to see clothes as disposable – meant to last only a wash or two, although they don’t advertise that – and to renew their wardrobe every few weeks.","path":"english1/2013.html"},{"id":"english1-2013-t1-p3-s2","examKey":"english1","examLabel":"英语一","year":"2013","text":1,"paragraph":3,"sentenceNo":2,"sentence":"By offering on-trend items at dirt-cheap prices, Cline argues, these brands have hijacked fashion cycles, shaking an industry long accustomed to a seasonal pace.","path":"english1/2013.html"},{"id":"english1-2013-t1-p4-s1","examKey":"english1","examLabel":"英语一","year":"2013","text":1,"paragraph":4,"sentenceNo":1,"sentence":"The victims of this revolution, of course, are not limited to designers.","path":"english1/2013.html"},{"id":"english1-2013-t1-p4-s2","examKey":"english1","examLabel":"英语一","year":"2013","text":1,"paragraph":4,"sentenceNo":2,"sentence":"For H&M to offer a $5.95 knit miniskirt in all its 2,300-plus stores around the world, it must rely on low-wage overseas labor, order in volumes that strain natural resources, and use massive amounts of harmful chemicals.","path":"english1/2013.html"},{"id":"english1-2013-t1-p5-s1","examKey":"english1","examLabel":"英语一","year":"2013","text":1,"paragraph":5,"sentenceNo":1,"sentence":"Overdressed is the fashion world’s answer to consumer-activist bestsellers like Michael Pollan’s The Omnivore’s Dilemma.","path":"english1/2013.html"},{"id":"english1-2013-t1-p5-s2","examKey":"english1","examLabel":"英语一","year":"2013","text":1,"paragraph":5,"sentenceNo":2,"sentence":"“ Mass-produced clothing, like fast food, fills a hunger and need, yet is non-durable and wasteful,” Cline argues.","path":"english1/2013.html"},{"id":"english1-2013-t1-p5-s3","examKey":"english1","examLabel":"英语一","year":"2013","text":1,"paragraph":5,"sentenceNo":3,"sentence":"Americans, she finds, buy roughly 20 billion garments a year – about 64 items per person – and no matter how much they give away, this excess leads to waste.","path":"english1/2013.html"},{"id":"english1-2013-t1-p6-s1","examKey":"english1","examLabel":"英语一","year":"2013","text":1,"paragraph":6,"sentenceNo":1,"sentence":"Towards the end of Overdressed, Cline introduced her ideal, a Brooklyn woman named Sarah Kate Beaumont, who since 2008 has made all of her own clothes – and beautifully.","path":"english1/2013.html"},{"id":"english1-2013-t1-p6-s2","examKey":"english1","examLabel":"英语一","year":"2013","text":1,"paragraph":6,"sentenceNo":2,"sentence":"But as Cline is the first to note, it took Beaumont decades to perfect her craft; her example can’t be knocked off.","path":"english1/2013.html"},{"id":"english1-2013-t1-p7-s1","examKey":"english1","examLabel":"英语一","year":"2013","text":1,"paragraph":7,"sentenceNo":1,"sentence":"Though several fast-fashion companies have made efforts to curb their impact on labor and the environment – including H&M, with its green Conscious Collection line – Cline believes lasting change can only be effected by the customer.","path":"english1/2013.html"},{"id":"english1-2013-t1-p7-s2","examKey":"english1","examLabel":"英语一","year":"2013","text":1,"paragraph":7,"sentenceNo":2,"sentence":"She exhibits the idealism common to many advocates of sustainability, be it in food or in energy.","path":"english1/2013.html"},{"id":"english1-2013-t1-p7-s3","examKey":"english1","examLabel":"英语一","year":"2013","text":1,"paragraph":7,"sentenceNo":3,"sentence":"Vanity is a constant; people will only start shopping more sustainably when they can’t afford not to.","path":"english1/2013.html"},{"id":"english1-2013-t2-p1-s1","examKey":"english1","examLabel":"英语一","year":"2013","text":2,"paragraph":1,"sentenceNo":1,"sentence":"An old saying has it that half of all advertising budgets are wasted – the trouble is, no one knows which half.","path":"english1/2013.html"},{"id":"english1-2013-t2-p1-s2","examKey":"english1","examLabel":"英语一","year":"2013","text":2,"paragraph":1,"sentenceNo":2,"sentence":"In the internet age, at least in theory, t his fraction can be much reduced.","path":"english1/2013.html"},{"id":"english1-2013-t2-p1-s3","examKey":"english1","examLabel":"英语一","year":"2013","text":2,"paragraph":1,"sentenceNo":3,"sentence":"By watching what people search for, click on and say on line, companies can aim “behavioural” ads at those most likely to buy.","path":"english1/2013.html"},{"id":"english1-2013-t2-p2-s1","examKey":"english1","examLabel":"英语一","year":"2013","text":2,"paragraph":2,"sentenceNo":1,"sentence":"In the past couple of weeks a quarrel has illustrated the value to advertisers of such fine-grained information: Should advertisers assume that people are happy to be tracked and sent behavioural ads?","path":"english1/2013.html"},{"id":"english1-2013-t2-p2-s2","examKey":"english1","examLabel":"英语一","year":"2013","text":2,"paragraph":2,"sentenceNo":2,"sentence":"Or should they have explicit permission?","path":"english1/2013.html"},{"id":"english1-2013-t2-p3-s1","examKey":"english1","examLabel":"英语一","year":"2013","text":2,"paragraph":3,"sentenceNo":1,"sentence":"In December 2010 America’s Federal Trade Commission (FTC) proposed adding a “do not track” (DNT) option to internet browsers, so that users could tell advertisers that they did not want to be followed.","path":"english1/2013.html"},{"id":"english1-2013-t2-p3-s2","examKey":"english1","examLabel":"英语一","year":"2013","text":2,"paragraph":3,"sentenceNo":2,"sentence":"Microsoft’s Internet Explorer and Apple’s Safari both offer DNT; Google’s Chrome is due to do so this year.","path":"english1/2013.html"},{"id":"english1-2013-t2-p3-s3","examKey":"english1","examLabel":"英语一","year":"2013","text":2,"paragraph":3,"sentenceNo":3,"sentence":"In February the FTC and the Digital Advertising Alliance (DAA) agreed that the industry would get cracking on responding to DNT requests.","path":"english1/2013.html"},{"id":"english1-2013-t2-p4-s1","examKey":"english1","examLabel":"英语一","year":"2013","text":2,"paragraph":4,"sentenceNo":1,"sentence":"On May 31st Microsoft set off the row.","path":"english1/2013.html"},{"id":"english1-2013-t2-p4-s2","examKey":"english1","examLabel":"英语一","year":"2013","text":2,"paragraph":4,"sentenceNo":2,"sentence":"It said that Internet Explorer 10, the version due to appear with Windows 8, would have DNT as a default.","path":"english1/2013.html"},{"id":"english1-2013-t2-p5-s1","examKey":"english1","examLabel":"英语一","year":"2013","text":2,"paragraph":5,"sentenceNo":1,"sentence":"Advertisers are horrified.","path":"english1/2013.html"},{"id":"english1-2013-t2-p5-s2","examKey":"english1","examLabel":"英语一","year":"2013","text":2,"paragraph":5,"sentenceNo":2,"sentence":"Human nature being what it is, most people stick with default setting s.","path":"english1/2013.html"},{"id":"english1-2013-t2-p5-s3","examKey":"english1","examLabel":"英语一","year":"2013","text":2,"paragraph":5,"sentenceNo":3,"sentence":"Few switch DNT on now, but if tracking is off it will stay off.","path":"english1/2013.html"},{"id":"english1-2013-t2-p5-s4","examKey":"english1","examLabel":"英语一","year":"2013","text":2,"paragraph":5,"sentenceNo":4,"sentence":"Bob Liodice, the chief executive of the Association of National Advertisers, says consumers will be worse off if the industry cannot collect information about their preferences.","path":"english1/2013.html"},{"id":"english1-2013-t2-p5-s5","examKey":"english1","examLabel":"英语一","year":"2013","text":2,"paragraph":5,"sentenceNo":5,"sentence":"People will not get fewer ads, he says. “ They’ll get less meaningful, less targeted ads.\"","path":"english1/2013.html"},{"id":"english1-2013-t2-p6-s1","examKey":"english1","examLabel":"英语一","year":"2013","text":2,"paragraph":6,"sentenceNo":1,"sentence":"It is not yet clear how advertisers will respond.","path":"english1/2013.html"},{"id":"english1-2013-t2-p6-s2","examKey":"english1","examLabel":"英语一","year":"2013","text":2,"paragraph":6,"sentenceNo":2,"sentence":"Getting a DNT signal does not oblige anyone to stop tracking, although some companies have promised to do so.","path":"english1/2013.html"},{"id":"english1-2013-t2-p6-s3","examKey":"english1","examLabel":"英语一","year":"2013","text":2,"paragraph":6,"sentenceNo":3,"sentence":"Unable to tell whether someone really objects to behavioural ads or whether they are sticking with Microsoft’s default, some may ignore a DNT signal and press on anyway.","path":"english1/2013.html"},{"id":"english1-2013-t2-p7-s1","examKey":"english1","examLabel":"英语一","year":"2013","text":2,"paragraph":7,"sentenceNo":1,"sentence":"Also unclear is why Microsoft has gone it alone.","path":"english1/2013.html"},{"id":"english1-2013-t2-p7-s2","examKey":"english1","examLabel":"英语一","year":"2013","text":2,"paragraph":7,"sentenceNo":2,"sentence":"After all, it has an ad business too, which it says will comply with DNT requests, though it is still working out how.","path":"english1/2013.html"},{"id":"english1-2013-t2-p7-s3","examKey":"english1","examLabel":"英语一","year":"2013","text":2,"paragraph":7,"sentenceNo":3,"sentence":"If it is trying to upset Google, which relies almost wholly on advertising, it has chosen an indirect method: there is no guarantee that DNT by default will become the norm.","path":"english1/2013.html"},{"id":"english1-2013-t2-p7-s4","examKey":"english1","examLabel":"英语一","year":"2013","text":2,"paragraph":7,"sentenceNo":4,"sentence":"DNT does not seem an obviously huge selling point for Windows 8 – though the firm has compared some of its other products favourably with Google’s on that count before.","path":"english1/2013.html"},{"id":"english1-2013-t2-p7-s5","examKey":"english1","examLabel":"英语一","year":"2013","text":2,"paragraph":7,"sentenceNo":5,"sentence":"Brendon Lynch, Microsoft’s chief privacy officer, blog ged: “We believe consumers should have more control.” Could it really be that simple?","path":"english1/2013.html"},{"id":"english1-2013-t3-p1-s1","examKey":"english1","examLabel":"英语一","year":"2013","text":3,"paragraph":1,"sentenceNo":1,"sentence":"Up until a few decades ago, our vision s of the future were largely – though by no means uniformly – glowingly positive.","path":"english1/2013.html"},{"id":"english1-2013-t3-p1-s2","examKey":"english1","examLabel":"英语一","year":"2013","text":3,"paragraph":1,"sentenceNo":2,"sentence":"Science and technology would cure all the ills of humanity, leading to lives of fulfilment and opportunity for all.","path":"english1/2013.html"},{"id":"english1-2013-t3-p2-s1","examKey":"english1","examLabel":"英语一","year":"2013","text":3,"paragraph":2,"sentenceNo":1,"sentence":"Now utopia has grown unfashionable, as we have gained a deeper appreciation of the range of threats facing us, from asteroid strike to epidemic flu and to climate change.","path":"english1/2013.html"},{"id":"english1-2013-t3-p2-s2","examKey":"english1","examLabel":"英语一","year":"2013","text":3,"paragraph":2,"sentenceNo":2,"sentence":"You might even be tempted to assume that human ity has little future to look forward to.","path":"english1/2013.html"},{"id":"english1-2013-t3-p3-s1","examKey":"english1","examLabel":"英语一","year":"2013","text":3,"paragraph":3,"sentenceNo":1,"sentence":"But such gloominess is misplaced.","path":"english1/2013.html"},{"id":"english1-2013-t3-p3-s2","examKey":"english1","examLabel":"英语一","year":"2013","text":3,"paragraph":3,"sentenceNo":2,"sentence":"The fossil record shows that many species have endured for millions of years – so why shouldn’t we?","path":"english1/2013.html"},{"id":"english1-2013-t3-p3-s3","examKey":"english1","examLabel":"英语一","year":"2013","text":3,"paragraph":3,"sentenceNo":3,"sentence":"Take a broader look at our species’ place in the universe, and it becomes clear that we have an excellent chance of surviving for tens, if not hundreds, of thousands of years.","path":"english1/2013.html"},{"id":"english1-2013-t3-p4-s1","examKey":"english1","examLabel":"英语一","year":"2013","text":3,"paragraph":4,"sentenceNo":1,"sentence":"Look up Homo sapiens in the “ Red List ” of threatened species of the International Union for the Conservation of Nature (IUCN) and you will read: “ Listed as Least Concern as the species is very widely distributed, adaptable, currently increasing, and there are no major threats resulting in an overall population decline.\"","path":"english1/2013.html"},{"id":"english1-2013-t3-p5-s1","examKey":"english1","examLabel":"英语一","year":"2013","text":3,"paragraph":5,"sentenceNo":1,"sentence":"So what does our deep future hold?","path":"english1/2013.html"},{"id":"english1-2013-t3-p5-s2","examKey":"english1","examLabel":"英语一","year":"2013","text":3,"paragraph":5,"sentenceNo":2,"sentence":"A growing number of researchers and organisations are now thinking seriously about that question.","path":"english1/2013.html"},{"id":"english1-2013-t3-p5-s3","examKey":"english1","examLabel":"英语一","year":"2013","text":3,"paragraph":5,"sentenceNo":3,"sentence":"For example, the Long Now Foundation has as its flagship project a mechanical clock that is designed to still be marking time thousands of years hence.","path":"english1/2013.html"},{"id":"english1-2013-t3-p6-s1","examKey":"english1","examLabel":"英语一","year":"2013","text":3,"paragraph":6,"sentenceNo":1,"sentence":"Perhaps willfully, it may be easier to think about such lengthy timescales than about the more immediate future.","path":"english1/2013.html"},{"id":"english1-2013-t3-p6-s2","examKey":"english1","examLabel":"英语一","year":"2013","text":3,"paragraph":6,"sentenceNo":2,"sentence":"The potential evolution of today’s technology, and its social consequences, is dazzlingly complicated, and it’s perhaps best left to science fiction writers and futurologists to explore the many possibilities we can envisage.","path":"english1/2013.html"},{"id":"english1-2013-t3-p6-s3","examKey":"english1","examLabel":"英语一","year":"2013","text":3,"paragraph":6,"sentenceNo":3,"sentence":"That’s one reason why we have launched Arc, a new publication dedicated to the near future.","path":"english1/2013.html"},{"id":"english1-2013-t3-p7-s1","examKey":"english1","examLabel":"英语一","year":"2013","text":3,"paragraph":7,"sentenceNo":1,"sentence":"But take a longer view and there is a surprising amount that we can say with considerable assurance.","path":"english1/2013.html"},{"id":"english1-2013-t3-p7-s2","examKey":"english1","examLabel":"英语一","year":"2013","text":3,"paragraph":7,"sentenceNo":2,"sentence":"As so often, the past holds the key to the future: we have now identified enough of the long-term patterns shaping the history of the planet, and our species, to make evidence-based forecasts about the situations in which our descendants will find themselves.","path":"english1/2013.html"},{"id":"english1-2013-t3-p8-s1","examKey":"english1","examLabel":"英语一","year":"2013","text":3,"paragraph":8,"sentenceNo":1,"sentence":"This long perspective makes the pessimistic view of our prospects seem more likely to be a passing fad.","path":"english1/2013.html"},{"id":"english1-2013-t3-p8-s2","examKey":"english1","examLabel":"英语一","year":"2013","text":3,"paragraph":8,"sentenceNo":2,"sentence":"To be sure, the future is not all rosy.","path":"english1/2013.html"},{"id":"english1-2013-t3-p8-s3","examKey":"english1","examLabel":"英语一","year":"2013","text":3,"paragraph":8,"sentenceNo":3,"sentence":"But we are now knowledgeable enough to reduce many of the risks that threatened the existence of earlier humans, and to improve the lot of those to come.","path":"english1/2013.html"},{"id":"english1-2013-t4-p1-s1","examKey":"english1","examLabel":"英语一","year":"2013","text":4,"paragraph":1,"sentenceNo":1,"sentence":"On a five to three vote, the Supreme Court knocked out much of Arizona’s immigration law Monday – a modest policy victory for the Obama Administration.","path":"english1/2013.html"},{"id":"english1-2013-t4-p1-s2","examKey":"english1","examLabel":"英语一","year":"2013","text":4,"paragraph":1,"sentenceNo":2,"sentence":"But on the more important matter of the Constitution, the decision was an 8-0 defeat for the Administration’s effort to upset the balance of power between the federal government and the states.","path":"english1/2013.html"},{"id":"english1-2013-t4-p2-s1","examKey":"english1","examLabel":"英语一","year":"2013","text":4,"paragraph":2,"sentenceNo":1,"sentence":"In Arizona v.","path":"english1/2013.html"},{"id":"english1-2013-t4-p2-s2","examKey":"english1","examLabel":"英语一","year":"2013","text":4,"paragraph":2,"sentenceNo":2,"sentence":"United States, the majority overturned three of the four contested provisions of Arizona’s controversial plan to have state and local police enforce federal immigration law.","path":"english1/2013.html"},{"id":"english1-2013-t4-p2-s3","examKey":"english1","examLabel":"英语一","year":"2013","text":4,"paragraph":2,"sentenceNo":3,"sentence":"The Constitutional principles that Washington alone has the power to “establish a uniform Rule of Naturalization” and that federal laws precede state laws are noncontroversial.","path":"english1/2013.html"},{"id":"english1-2013-t4-p2-s4","examKey":"english1","examLabel":"英语一","year":"2013","text":4,"paragraph":2,"sentenceNo":4,"sentence":"Arizona had attempted to fashion state policies that ran parallel to the existing federal ones.","path":"english1/2013.html"},{"id":"english1-2013-t4-p3-s1","examKey":"english1","examLabel":"英语一","year":"2013","text":4,"paragraph":3,"sentenceNo":1,"sentence":"Justice Anthony Kennedy, joined by Chief Justice John Roberts and the Court’s liberals, ruled that the state flew too close to the federal sun.","path":"english1/2013.html"},{"id":"english1-2013-t4-p3-s2","examKey":"english1","examLabel":"英语一","year":"2013","text":4,"paragraph":3,"sentenceNo":2,"sentence":"On the overturned provisions the majority held that Congress had deliberately “ occupied the field ” and Arizona had thus intruded on the federal’s privileged powers.","path":"english1/2013.html"},{"id":"english1-2013-t4-p4-s1","examKey":"english1","examLabel":"英语一","year":"2013","text":4,"paragraph":4,"sentenceNo":1,"sentence":"However, the Justices said that Arizona police would be allowed to verify the legal status of people who come in contact with law enforcement.","path":"english1/2013.html"},{"id":"english1-2013-t4-p4-s2","examKey":"english1","examLabel":"英语一","year":"2013","text":4,"paragraph":4,"sentenceNo":2,"sentence":"That’s because Congress has always envisioned joint federal-state immigration enforcement and explicitly encourages state officers to share information and cooperate with federal colleagues.","path":"english1/2013.html"},{"id":"english1-2013-t4-p5-s1","examKey":"english1","examLabel":"英语一","year":"2013","text":4,"paragraph":5,"sentenceNo":1,"sentence":"Two of the three objecting Justices – Samuel Alito and Clarence Thomas – agreed with this Constitutional logic but disagreed about which Arizona rules conflicted with the federal statute.","path":"english1/2013.html"},{"id":"english1-2013-t4-p5-s2","examKey":"english1","examLabel":"英语一","year":"2013","text":4,"paragraph":5,"sentenceNo":2,"sentence":"The only major objection came from Justice Antonin Scalia, who offered an even more robust defense of state privileges going back to the Alien and Sedition Acts.","path":"english1/2013.html"},{"id":"english1-2013-t4-p6-s1","examKey":"english1","examLabel":"英语一","year":"2013","text":4,"paragraph":6,"sentenceNo":1,"sentence":"The 8-0 objection to President Obama turns on what Justice Samuel Alito describes in his objection as “ a shocking assertion of federal executive power.” The White House argued that Arizona’s laws conflicted with its enforcement priorities, even if state laws complied with federal statutes to the letter.","path":"english1/2013.html"},{"id":"english1-2013-t4-p6-s2","examKey":"english1","examLabel":"英语一","year":"2013","text":4,"paragraph":6,"sentenceNo":2,"sentence":"In effect, the White House claimed that it could invalidate any otherwise legitimate state law that it disagrees with.","path":"english1/2013.html"},{"id":"english1-2013-t4-p7-s1","examKey":"english1","examLabel":"英语一","year":"2013","text":4,"paragraph":7,"sentenceNo":1,"sentence":"Some powers do belong exclusively to the federal government, and control of citizenship and the borders is among them.","path":"english1/2013.html"},{"id":"english1-2013-t4-p7-s2","examKey":"english1","examLabel":"英语一","year":"2013","text":4,"paragraph":7,"sentenceNo":2,"sentence":"But if Congress wanted to prevent states from using their own resources to check immigration status, it could.","path":"english1/2013.html"},{"id":"english1-2013-t4-p7-s3","examKey":"english1","examLabel":"英语一","year":"2013","text":4,"paragraph":7,"sentenceNo":3,"sentence":"It never did so.","path":"english1/2013.html"},{"id":"english1-2013-t4-p7-s4","examKey":"english1","examLabel":"英语一","year":"2013","text":4,"paragraph":7,"sentenceNo":4,"sentence":"The Administration was in essence asserting that because it didn’t want to carry out Congress’s immigration wishes, no state should be allowed to do so either.","path":"english1/2013.html"},{"id":"english1-2013-t4-p7-s5","examKey":"english1","examLabel":"英语一","year":"2013","text":4,"paragraph":7,"sentenceNo":5,"sentence":"Every Justice rightly rejected this remarkable claim.","path":"english1/2013.html"},{"id":"english2-2013-t1-p1-s1","examKey":"english2","examLabel":"英语二","year":"2013","text":1,"paragraph":1,"sentenceNo":1,"sentence":"Q21 段落定位 In an essay entitled “Making It in America,” the author Adam Davidson relates a joke from cotton country about just how much a modern textile mill has been automated: The average mill has only two employees today, “a man and a dog.","path":"english2/2013.html"},{"id":"english2-2013-t1-p1-s2","examKey":"english2","examLabel":"英语二","year":"2013","text":1,"paragraph":1,"sentenceNo":2,"sentence":"The man is there to feed the dog, and the dog is there to keep the man away from the machines.”","path":"english2/2013.html"},{"id":"english2-2013-t1-p2-s1","examKey":"english2","examLabel":"英语二","year":"2013","text":1,"paragraph":2,"sentenceNo":1,"sentence":"Davidson's article is one of a number of pieces that have recently appeared making the point that the reason we have such stubbornly high unemployment and declining middle-class incomes today is largely because of the big drop in demand because of the Great Recession, but it is also because of the advances in both globalization and the information technology revolution, which are more rapidly than ever replacing labor with machines or foreign workers.","path":"english2/2013.html"},{"id":"english2-2013-t1-p3-s1","examKey":"english2","examLabel":"英语二","year":"2013","text":1,"paragraph":3,"sentenceNo":1,"sentence":"Q25 段落定位 Q22 段落定位 In the past, workers with average skills, doing an average job, could earn an average lifestyle.","path":"english2/2013.html"},{"id":"english2-2013-t1-p3-s2","examKey":"english2","examLabel":"英语二","year":"2013","text":1,"paragraph":3,"sentenceNo":2,"sentence":"But, today, average is officially over.","path":"english2/2013.html"},{"id":"english2-2013-t1-p3-s3","examKey":"english2","examLabel":"英语二","year":"2013","text":1,"paragraph":3,"sentenceNo":3,"sentence":"Being average just won’t earn you what it used to.","path":"english2/2013.html"},{"id":"english2-2013-t1-p3-s4","examKey":"english2","examLabel":"英语二","year":"2013","text":1,"paragraph":3,"sentenceNo":4,"sentence":"It can’t when so many more employers have so much more access to so much more above average cheap foreign labor, cheap robotics, cheap software, cheap automation and cheap genius.","path":"english2/2013.html"},{"id":"english2-2013-t1-p3-s5","examKey":"english2","examLabel":"英语二","year":"2013","text":1,"paragraph":3,"sentenceNo":5,"sentence":"Therefore, everyone needs to find their extra — their unique value contribution that makes them stand out in whatever is their field of employment.","path":"english2/2013.html"},{"id":"english2-2013-t1-p4-s1","examKey":"english2","examLabel":"英语二","year":"2013","text":1,"paragraph":4,"sentenceNo":1,"sentence":"Q23 段落定位 Yes, new technology has been eating jobs forever, and always will.","path":"english2/2013.html"},{"id":"english2-2013-t1-p4-s2","examKey":"english2","examLabel":"英语二","year":"2013","text":1,"paragraph":4,"sentenceNo":2,"sentence":"But there’s been an acceleration.","path":"english2/2013.html"},{"id":"english2-2013-t1-p4-s3","examKey":"english2","examLabel":"英语二","year":"2013","text":1,"paragraph":4,"sentenceNo":3,"sentence":"As Davidson notes, “In the 10 years ending in 2009, [U.S.] factories shed workers so fast that they erased almost all the gains of the previous 70 years; roughly one out of every three manufacturing jobs — about 6 million in total — disappeared.”","path":"english2/2013.html"},{"id":"english2-2013-t1-p5-s1","examKey":"english2","examLabel":"英语二","year":"2013","text":1,"paragraph":5,"sentenceNo":1,"sentence":"There will always be change — new jobs, new products, new services.","path":"english2/2013.html"},{"id":"english2-2013-t1-p5-s2","examKey":"english2","examLabel":"英语二","year":"2013","text":1,"paragraph":5,"sentenceNo":2,"sentence":"But the one thing we know for sure is that with each advance in globalization and the I.T. revolution, the best jobs will require workers to have more and better education to make themselves above average.","path":"english2/2013.html"},{"id":"english2-2013-t1-p6-s1","examKey":"english2","examLabel":"英语二","year":"2013","text":1,"paragraph":6,"sentenceNo":1,"sentence":"Q24 段落定位 In a world where average is officially over, there are many things we need to do to support employment, but nothing would be more important than passing some kind of G.I.","path":"english2/2013.html"},{"id":"english2-2013-t1-p6-s2","examKey":"english2","examLabel":"英语二","year":"2013","text":1,"paragraph":6,"sentenceNo":2,"sentence":"Bill for the 21st century that ensures that every American has access to post-high school education.","path":"english2/2013.html"},{"id":"english2-2013-t2-p1-s1","examKey":"english2","examLabel":"英语二","year":"2013","text":2,"paragraph":1,"sentenceNo":1,"sentence":"Q26 段落定位 A century ago, the immigrants from across the Atlantic included settlers and sojourners.","path":"english2/2013.html"},{"id":"english2-2013-t2-p1-s2","examKey":"english2","examLabel":"英语二","year":"2013","text":2,"paragraph":1,"sentenceNo":2,"sentence":"Along with the many folks looking to make a permanent home in the United States came those who had no intention to stay, and who would make some money and then go home.","path":"english2/2013.html"},{"id":"english2-2013-t2-p1-s3","examKey":"english2","examLabel":"英语二","year":"2013","text":2,"paragraph":1,"sentenceNo":3,"sentence":"Between 1908 and 1915, about 7 million people arrived while about 2 million departed.","path":"english2/2013.html"},{"id":"english2-2013-t2-p1-s4","examKey":"english2","examLabel":"英语二","year":"2013","text":2,"paragraph":1,"sentenceNo":4,"sentence":"About a quarter of all Italian immigrants, for example, eventually returned to Italy for good.","path":"english2/2013.html"},{"id":"english2-2013-t2-p1-s5","examKey":"english2","examLabel":"英语二","year":"2013","text":2,"paragraph":1,"sentenceNo":5,"sentence":"They even had an affectionate nickname, “uccelli di passaggio,” birds of passage.","path":"english2/2013.html"},{"id":"english2-2013-t2-p2-s1","examKey":"english2","examLabel":"英语二","year":"2013","text":2,"paragraph":2,"sentenceNo":1,"sentence":"Q27 段落定位 Today, we are much more rigid about immigrants.","path":"english2/2013.html"},{"id":"english2-2013-t2-p2-s2","examKey":"english2","examLabel":"英语二","year":"2013","text":2,"paragraph":2,"sentenceNo":2,"sentence":"We divide newcomers into two categories: legal or illegal, good or bad.","path":"english2/2013.html"},{"id":"english2-2013-t2-p2-s3","examKey":"english2","examLabel":"英语二","year":"2013","text":2,"paragraph":2,"sentenceNo":3,"sentence":"We hail them as Americans in the making, or brand them as aliens to be kicked out.","path":"english2/2013.html"},{"id":"english2-2013-t2-p2-s4","examKey":"english2","examLabel":"英语二","year":"2013","text":2,"paragraph":2,"sentenceNo":4,"sentence":"That framework has contributed mightily to our broken immigration system and the long political paralysis over how to fix it.","path":"english2/2013.html"},{"id":"english2-2013-t2-p2-s5","examKey":"english2","examLabel":"英语二","year":"2013","text":2,"paragraph":2,"sentenceNo":5,"sentence":"We don’t need more categories, but we need to change the way we think about categories.","path":"english2/2013.html"},{"id":"english2-2013-t2-p2-s6","examKey":"english2","examLabel":"英语二","year":"2013","text":2,"paragraph":2,"sentenceNo":6,"sentence":"We need to look beyond strict definitions of legal and illegal.","path":"english2/2013.html"},{"id":"english2-2013-t2-p2-s7","examKey":"english2","examLabel":"英语二","year":"2013","text":2,"paragraph":2,"sentenceNo":7,"sentence":"To start, we can recognize the new birds of passage, those living and thriving in the gray areas.","path":"english2/2013.html"},{"id":"english2-2013-t2-p2-s8","examKey":"english2","examLabel":"英语二","year":"2013","text":2,"paragraph":2,"sentenceNo":8,"sentence":"We might then begin to solve our immigration challenges.","path":"english2/2013.html"},{"id":"english2-2013-t2-p3-s1","examKey":"english2","examLabel":"英语二","year":"2013","text":2,"paragraph":3,"sentenceNo":1,"sentence":"Q30 段落定位 Q28 段落定位 Crop pickers, violinists, construction workers, entrepreneurs, engineers, home health-care aides and physicists are among today’s birds of passage.","path":"english2/2013.html"},{"id":"english2-2013-t2-p3-s2","examKey":"english2","examLabel":"英语二","year":"2013","text":2,"paragraph":3,"sentenceNo":2,"sentence":"They are energetic participants in a global economy driven by the flow of work, money and ideas.","path":"english2/2013.html"},{"id":"english2-2013-t2-p3-s3","examKey":"english2","examLabel":"英语二","year":"2013","text":2,"paragraph":3,"sentenceNo":3,"sentence":"They prefer to come and go as opportunity calls them.","path":"english2/2013.html"},{"id":"english2-2013-t2-p3-s4","examKey":"english2","examLabel":"英语二","year":"2013","text":2,"paragraph":3,"sentenceNo":4,"sentence":"They can manage to have a job in one place and a family in another.","path":"english2/2013.html"},{"id":"english2-2013-t2-p4-s1","examKey":"english2","examLabel":"英语二","year":"2013","text":2,"paragraph":4,"sentenceNo":1,"sentence":"With or without permission, they straddle laws, jurisdictions and identities with ease.","path":"english2/2013.html"},{"id":"english2-2013-t2-p4-s2","examKey":"english2","examLabel":"英语二","year":"2013","text":2,"paragraph":4,"sentenceNo":2,"sentence":"We need them to imagine the United States as a place where they can be productive for a while without committing themselves to staying forever.","path":"english2/2013.html"},{"id":"english2-2013-t2-p4-s3","examKey":"english2","examLabel":"英语二","year":"2013","text":2,"paragraph":4,"sentenceNo":3,"sentence":"We need them to feel that home can be both here and there and that they can belong to two nations honorably.","path":"english2/2013.html"},{"id":"english2-2013-t2-p5-s1","examKey":"english2","examLabel":"英语二","year":"2013","text":2,"paragraph":5,"sentenceNo":1,"sentence":"Q29 段落定位 Accommodating this new world of people in motion will require new attitudes on both sides of the immigration battle.","path":"english2/2013.html"},{"id":"english2-2013-t2-p5-s2","examKey":"english2","examLabel":"英语二","year":"2013","text":2,"paragraph":5,"sentenceNo":2,"sentence":"Looking beyond the culture war logic of right or wrong means opening up the middle ground and understanding that managing immigration today requires multiple paths and multiple outcomes, including some that are not easy to accomplish legally in the existing system.","path":"english2/2013.html"},{"id":"english2-2013-t3-p1-s1","examKey":"english2","examLabel":"英语二","year":"2013","text":3,"paragraph":1,"sentenceNo":1,"sentence":"Q33 段落定位 Scientists have found that although we are prone to snap overreactions, if we take a moment and think about how we are likely to react, we can reduce or even eliminate the negative effects of our quick, hard-wired responses.","path":"english2/2013.html"},{"id":"english2-2013-t3-p2-s1","examKey":"english2","examLabel":"英语二","year":"2013","text":3,"paragraph":2,"sentenceNo":1,"sentence":"Q31 段落定位 Snap decisions can be important defense mechanisms; if we are judging whether someone is dangerous, our brains and bodies are hard-wired to react very quickly, within milliseconds.","path":"english2/2013.html"},{"id":"english2-2013-t3-p2-s2","examKey":"english2","examLabel":"英语二","year":"2013","text":3,"paragraph":2,"sentenceNo":2,"sentence":"But we need more time to assess other factors.","path":"english2/2013.html"},{"id":"english2-2013-t3-p2-s3","examKey":"english2","examLabel":"英语二","year":"2013","text":3,"paragraph":2,"sentenceNo":3,"sentence":"To accurately tell whether someone is sociable, studies show, we need at least a minute, preferably five.","path":"english2/2013.html"},{"id":"english2-2013-t3-p2-s4","examKey":"english2","examLabel":"英语二","year":"2013","text":3,"paragraph":2,"sentenceNo":4,"sentence":"It takes a while to judge complex aspects of personality, like neuroticism or open -mindedness.","path":"english2/2013.html"},{"id":"english2-2013-t3-p3-s1","examKey":"english2","examLabel":"英语二","year":"2013","text":3,"paragraph":3,"sentenceNo":1,"sentence":"Q32 段落定位 But snap decisions in reaction to rapid stimuli aren’t exclusive to the interpersonal realm.","path":"english2/2013.html"},{"id":"english2-2013-t3-p3-s2","examKey":"english2","examLabel":"英语二","year":"2013","text":3,"paragraph":3,"sentenceNo":2,"sentence":"Psychologists at the University of Toronto found that viewing a fast-food logo for just a few milliseconds primes us to read 20 percent faster, even though reading has little to do with eating.","path":"english2/2013.html"},{"id":"english2-2013-t3-p3-s3","examKey":"english2","examLabel":"英语二","year":"2013","text":3,"paragraph":3,"sentenceNo":3,"sentence":"We unconsciously associate fast food with speed and impatience and carry those impulses into whatever else we're doing, Subjects exposed to fast-food flashes also tend to think a musical piece lasts too long.","path":"english2/2013.html"},{"id":"english2-2013-t3-p4-s1","examKey":"english2","examLabel":"英语二","year":"2013","text":3,"paragraph":4,"sentenceNo":1,"sentence":"Yet we can reverse such influences.","path":"english2/2013.html"},{"id":"english2-2013-t3-p4-s2","examKey":"english2","examLabel":"英语二","year":"2013","text":3,"paragraph":4,"sentenceNo":2,"sentence":"If we know we will overreact to consumer products or housing options when we see a happy face (one reason good sales representatives and real estate agents are always smiling), we can take a moment before buying.","path":"english2/2013.html"},{"id":"english2-2013-t3-p4-s3","examKey":"english2","examLabel":"英语二","year":"2013","text":3,"paragraph":4,"sentenceNo":3,"sentence":"If we know female job screeners are more likely to reject attractive female applicants, we can help screeners understand their biases — or hire outside screeners.","path":"english2/2013.html"},{"id":"english2-2013-t3-p5-s1","examKey":"english2","examLabel":"英语二","year":"2013","text":3,"paragraph":5,"sentenceNo":1,"sentence":"Q34 段落定位 John Gottman, the marriage expert, explains that we quickly “thin slice” information reliably only after we ground such snap reactions in “thick sliced” long-term study.","path":"english2/2013.html"},{"id":"english2-2013-t3-p5-s2","examKey":"english2","examLabel":"英语二","year":"2013","text":3,"paragraph":5,"sentenceNo":2,"sentence":"When Dr.","path":"english2/2013.html"},{"id":"english2-2013-t3-p5-s3","examKey":"english2","examLabel":"英语二","year":"2013","text":3,"paragraph":5,"sentenceNo":3,"sentence":"Gottman really wants to assess whether a couple will stay together, he invites them to his island retreat for a much longer evaluation: two days, not two seconds.","path":"english2/2013.html"},{"id":"english2-2013-t3-p6-s1","examKey":"english2","examLabel":"英语二","year":"2013","text":3,"paragraph":6,"sentenceNo":1,"sentence":"Q35 段落定位 Our ability to mute our hard-wired reactions by pausing is what differentiates us from animals: dogs can think about the future only intermittently or for a few minutes.","path":"english2/2013.html"},{"id":"english2-2013-t3-p6-s2","examKey":"english2","examLabel":"英语二","year":"2013","text":3,"paragraph":6,"sentenceNo":2,"sentence":"But historically we have spent about 12 percent of our days contemplating the longer term.","path":"english2/2013.html"},{"id":"english2-2013-t3-p6-s3","examKey":"english2","examLabel":"英语二","year":"2013","text":3,"paragraph":6,"sentenceNo":3,"sentence":"Although technology might change the way we react, it hasn’t changed our nature.","path":"english2/2013.html"},{"id":"english2-2013-t3-p6-s4","examKey":"english2","examLabel":"英语二","year":"2013","text":3,"paragraph":6,"sentenceNo":4,"sentence":"We still have the imaginative capacity to rise above temptation and reverse the high-speed trend.","path":"english2/2013.html"},{"id":"english2-2013-t4-p1-s1","examKey":"english2","examLabel":"英语二","year":"2013","text":4,"paragraph":1,"sentenceNo":1,"sentence":"Q36 段落定位 Europe is not a gender-equality heaven.","path":"english2/2013.html"},{"id":"english2-2013-t4-p1-s2","examKey":"english2","examLabel":"英语二","year":"2013","text":4,"paragraph":1,"sentenceNo":2,"sentence":"In particular, the corporate workplace will never be completely family-friendly until women are part of senior management decisions, and Europe’s top corporate-governance positions remain overwhelmingly male.","path":"english2/2013.html"},{"id":"english2-2013-t4-p1-s3","examKey":"english2","examLabel":"英语二","year":"2013","text":4,"paragraph":1,"sentenceNo":3,"sentence":"Indeed, women hold only 14 per cent of positions on European corporate boards.","path":"english2/2013.html"},{"id":"english2-2013-t4-p2-s1","examKey":"english2","examLabel":"英语二","year":"2013","text":4,"paragraph":2,"sentenceNo":1,"sentence":"Q37 段落定位 The European Union is now considering legislation to compel corporate boards to maintain a certain proportion of women — up to 60 per cent.","path":"english2/2013.html"},{"id":"english2-2013-t4-p2-s2","examKey":"english2","examLabel":"英语二","year":"2013","text":4,"paragraph":2,"sentenceNo":2,"sentence":"This proposed mandate was born of frustration.","path":"english2/2013.html"},{"id":"english2-2013-t4-p2-s3","examKey":"english2","examLabel":"英语二","year":"2013","text":4,"paragraph":2,"sentenceNo":3,"sentence":"Last year, European Commission Vice President Viviane Reding issued a call to voluntary action.","path":"english2/2013.html"},{"id":"english2-2013-t4-p2-s4","examKey":"english2","examLabel":"英语二","year":"2013","text":4,"paragraph":2,"sentenceNo":4,"sentence":"Reding invited corporations to sign up for gender balance goals of 40 per cent female board membership.","path":"english2/2013.html"},{"id":"english2-2013-t4-p2-s5","examKey":"english2","examLabel":"英语二","year":"2013","text":4,"paragraph":2,"sentenceNo":5,"sentence":"But her appeal was considered a failure: only 24 companies took it up.","path":"english2/2013.html"},{"id":"english2-2013-t4-p3-s1","examKey":"english2","examLabel":"英语二","year":"2013","text":4,"paragraph":3,"sentenceNo":1,"sentence":"Do we need quotas to ensure that women can continue to climb the corporate ladder fairly as they balance work and family?","path":"english2/2013.html"},{"id":"english2-2013-t4-p4-s1","examKey":"english2","examLabel":"英语二","year":"2013","text":4,"paragraph":4,"sentenceNo":1,"sentence":"Q38 段落定位 “Personally, I don’t like quotas,” Reding said recently.","path":"english2/2013.html"},{"id":"english2-2013-t4-p4-s2","examKey":"english2","examLabel":"英语二","year":"2013","text":4,"paragraph":4,"sentenceNo":2,"sentence":"“But I like what the quotas do.” Quotas get action: they “open the way to equality and they break through the glass ceiling,” according to Reding, a result seen in France and other countries with legally binding provisions on placing women in top business positions.","path":"english2/2013.html"},{"id":"english2-2013-t4-p5-s1","examKey":"english2","examLabel":"英语二","year":"2013","text":4,"paragraph":5,"sentenceNo":1,"sentence":"Q39 段落定位 I understand Reding’s reluctance — and her frustration.","path":"english2/2013.html"},{"id":"english2-2013-t4-p5-s2","examKey":"english2","examLabel":"英语二","year":"2013","text":4,"paragraph":5,"sentenceNo":2,"sentence":"I don’t like quotas either; they run counter to my belief in meritocracy, governance by the capable.","path":"english2/2013.html"},{"id":"english2-2013-t4-p5-s3","examKey":"english2","examLabel":"英语二","year":"2013","text":4,"paragraph":5,"sentenceNo":3,"sentence":"But, when one considers the obstacles to achieving the meritocratic ideal, it does look as if a fairer world must be temporarily ordered.","path":"english2/2013.html"},{"id":"english2-2013-t4-p6-s1","examKey":"english2","examLabel":"英语二","year":"2013","text":4,"paragraph":6,"sentenceNo":1,"sentence":"After all, four decades of evidence has now shown that corporations in Europe as well as the US are evading the meritocratic hiring and promotion of women to top positions — no matter how much “soft pressure” is put upon them.","path":"english2/2013.html"},{"id":"english2-2013-t4-p6-s2","examKey":"english2","examLabel":"英语二","year":"2013","text":4,"paragraph":6,"sentenceNo":2,"sentence":"When women do break through to the summit of corporate power — as, for example, Sheryl Sandberg recently did at Facebook — they attract massive attention precisely because they remain the exception to the rule.","path":"english2/2013.html"},{"id":"english2-2013-t4-p7-s1","examKey":"english2","examLabel":"英语二","year":"2013","text":4,"paragraph":7,"sentenceNo":1,"sentence":"Q40 段落定位 If appropriate public policies were in place to help all women — whether CEOs or their children’s caregivers — and all families, Sandberg would be no more newsworthy than any other highly capable person living in a more just society.","path":"english2/2013.html"},{"id":"english1-2014-t1-p1-s1","examKey":"english1","examLabel":"英语一","year":"2014","text":1,"paragraph":1,"sentenceNo":1,"sentence":"In order to “change lives for the better” and reduce “dependency”, George Osborne, Chancellor of the Exchequer, introduced the “upfront work search” scheme.","path":"english1/2014.html"},{"id":"english1-2014-t1-p1-s2","examKey":"english1","examLabel":"英语一","year":"2014","text":1,"paragraph":1,"sentenceNo":2,"sentence":"Only if the jobless arrive at the jobcentre with a CV, register for online job search, and start looking for work will they be eligible for benefit — and then they should report weekly rather than fortnightly.","path":"english1/2014.html"},{"id":"english1-2014-t1-p1-s3","examKey":"english1","examLabel":"英语一","year":"2014","text":1,"paragraph":1,"sentenceNo":3,"sentence":"What could be more reasonable?","path":"english1/2014.html"},{"id":"english1-2014-t1-p2-s1","examKey":"english1","examLabel":"英语一","year":"2014","text":1,"paragraph":2,"sentenceNo":1,"sentence":"More apparent reasonableness followed.","path":"english1/2014.html"},{"id":"english1-2014-t1-p2-s2","examKey":"english1","examLabel":"英语一","year":"2014","text":1,"paragraph":2,"sentenceNo":2,"sentence":"There will now be a seven-day wait for the jobseeker’s allowance.","path":"english1/2014.html"},{"id":"english1-2014-t1-p2-s3","examKey":"english1","examLabel":"英语一","year":"2014","text":1,"paragraph":2,"sentenceNo":3,"sentence":"“Those first few days should be spent looking for work, not looking to sign on,” he claimed.","path":"english1/2014.html"},{"id":"english1-2014-t1-p2-s4","examKey":"english1","examLabel":"英语一","year":"2014","text":1,"paragraph":2,"sentenceNo":4,"sentence":"“We’re doing these things because we know they help people stay off benefits and help those on benefits get into work faster.” Help?","path":"english1/2014.html"},{"id":"english1-2014-t1-p2-s5","examKey":"english1","examLabel":"英语一","year":"2014","text":1,"paragraph":2,"sentenceNo":5,"sentence":"Really?","path":"english1/2014.html"},{"id":"english1-2014-t1-p2-s6","examKey":"english1","examLabel":"英语一","year":"2014","text":1,"paragraph":2,"sentenceNo":6,"sentence":"On first hearing, this was the socially concerned chancellor, trying to change lives for the better, complete with “reforms” to an obviously indulgent system that demands too little effort from the newly unemployed to find work, and subsidises laziness.","path":"english1/2014.html"},{"id":"english1-2014-t1-p2-s7","examKey":"english1","examLabel":"英语一","year":"2014","text":1,"paragraph":2,"sentenceNo":7,"sentence":"What motivated him, we were to understand, was his zeal for “ fundamental fairness ” — protecting the taxpayer, controlling spending and ensuring that only the most deserving claimants received their benefits.","path":"english1/2014.html"},{"id":"english1-2014-t1-p3-s1","examKey":"english1","examLabel":"英语一","year":"2014","text":1,"paragraph":3,"sentenceNo":1,"sentence":"Losing a job is hurting: you don’t skip down to the jobcentre with a song in your heart, delighted at the prospect of doubling your income from the generous state.","path":"english1/2014.html"},{"id":"english1-2014-t1-p3-s2","examKey":"english1","examLabel":"英语一","year":"2014","text":1,"paragraph":3,"sentenceNo":2,"sentence":"It is financially terrifying, psychologically embarrassing and you know that support is minimal and extraordinarily hard to get.","path":"english1/2014.html"},{"id":"english1-2014-t1-p3-s3","examKey":"english1","examLabel":"英语一","year":"2014","text":1,"paragraph":3,"sentenceNo":3,"sentence":"You are now not wanted; you are now excluded from the work environment that offers purpose and structure in your life.","path":"english1/2014.html"},{"id":"english1-2014-t1-p3-s4","examKey":"english1","examLabel":"英语一","year":"2014","text":1,"paragraph":3,"sentenceNo":4,"sentence":"Worse, the crucial income to feed yourself and your family and pay the bills has disappeared.","path":"english1/2014.html"},{"id":"english1-2014-t1-p3-s5","examKey":"english1","examLabel":"英语一","year":"2014","text":1,"paragraph":3,"sentenceNo":5,"sentence":"Ask anyone newly unemployed what they want and the answer is always: a job.","path":"english1/2014.html"},{"id":"english1-2014-t1-p4-s1","examKey":"english1","examLabel":"英语一","year":"2014","text":1,"paragraph":4,"sentenceNo":1,"sentence":"But in Osborneland, your first instinct is to fall into dependency — permanent dependency if you can get it — supported by a state only too ready to indulge your falsehood.","path":"english1/2014.html"},{"id":"english1-2014-t1-p4-s2","examKey":"english1","examLabel":"英语一","year":"2014","text":1,"paragraph":4,"sentenceNo":2,"sentence":"It is as though 20 years of ever-tougher reforms of the job search and benefit administration system never happened.","path":"english1/2014.html"},{"id":"english1-2014-t1-p4-s3","examKey":"english1","examLabel":"英语一","year":"2014","text":1,"paragraph":4,"sentenceNo":3,"sentence":"The principle of British welfare is no longer that you can insure yourself against the risk of unemployment and receive unconditional payments if the disaster happens.","path":"english1/2014.html"},{"id":"english1-2014-t1-p4-s4","examKey":"english1","examLabel":"英语一","year":"2014","text":1,"paragraph":4,"sentenceNo":4,"sentence":"Even the very phrase “jobseeker’s allowance” is about redefining the unemployed as a “jobseeker” who had no mandatory right to a benefit he or she has earned through making national insurance contributions.","path":"english1/2014.html"},{"id":"english1-2014-t1-p4-s5","examKey":"english1","examLabel":"英语一","year":"2014","text":1,"paragraph":4,"sentenceNo":5,"sentence":"Instead, the claimant receives a time-limited “allowance,” conditional on actively seeking a job; no entitlement and no insurance, at £71.70 a week, one of the least generous in the EU.","path":"english1/2014.html"},{"id":"english1-2014-t2-p1-s1","examKey":"english1","examLabel":"英语一","year":"2014","text":2,"paragraph":1,"sentenceNo":1,"sentence":"All around the world, lawyers generate more hostility than the members of any other profession — with the possible exception of journalism.","path":"english1/2014.html"},{"id":"english1-2014-t2-p1-s2","examKey":"english1","examLabel":"英语一","year":"2014","text":2,"paragraph":1,"sentenceNo":2,"sentence":"But there are few places where clients have more grounds for complaint than America.","path":"english1/2014.html"},{"id":"english1-2014-t2-p2-s1","examKey":"english1","examLabel":"英语一","year":"2014","text":2,"paragraph":2,"sentenceNo":1,"sentence":"During the decade before the economic crisis, spending on legal services in America grew twice as fast as inflation.","path":"english1/2014.html"},{"id":"english1-2014-t2-p2-s2","examKey":"english1","examLabel":"英语一","year":"2014","text":2,"paragraph":2,"sentenceNo":2,"sentence":"The best lawyers made skyscrapers-full of money, tempting ever more students to pile into law schools.","path":"english1/2014.html"},{"id":"english1-2014-t2-p2-s3","examKey":"english1","examLabel":"英语一","year":"2014","text":2,"paragraph":2,"sentenceNo":3,"sentence":"But most law graduates never get a big-firm job.","path":"english1/2014.html"},{"id":"english1-2014-t2-p2-s4","examKey":"english1","examLabel":"英语一","year":"2014","text":2,"paragraph":2,"sentenceNo":4,"sentence":"Many of them instead become the kind of nuisance-lawsuit filer that makes the tort system a costly nightmare.","path":"english1/2014.html"},{"id":"english1-2014-t2-p3-s1","examKey":"english1","examLabel":"英语一","year":"2014","text":2,"paragraph":3,"sentenceNo":1,"sentence":"There are many reasons for this.","path":"english1/2014.html"},{"id":"english1-2014-t2-p3-s2","examKey":"english1","examLabel":"英语一","year":"2014","text":2,"paragraph":3,"sentenceNo":2,"sentence":"One is the excessive costs of a legal education.","path":"english1/2014.html"},{"id":"english1-2014-t2-p3-s3","examKey":"english1","examLabel":"英语一","year":"2014","text":2,"paragraph":3,"sentenceNo":3,"sentence":"There is just one path for a lawyer in most American states: a four-year undergraduate degree in some unrelated subject, then a three-year law degree at one of 200 law schools authorized by the American Bar Association and an expensive preparation for the bar exam.","path":"english1/2014.html"},{"id":"english1-2014-t2-p3-s4","examKey":"english1","examLabel":"英语一","year":"2014","text":2,"paragraph":3,"sentenceNo":4,"sentence":"This leaves today’s average law-school graduate with $100,000 of debt on top of undergraduate debts.","path":"english1/2014.html"},{"id":"english1-2014-t2-p3-s5","examKey":"english1","examLabel":"英语一","year":"2014","text":2,"paragraph":3,"sentenceNo":5,"sentence":"Law-school debt means that they have to work fearsomely hard.","path":"english1/2014.html"},{"id":"english1-2014-t2-p4-s1","examKey":"english1","examLabel":"英语一","year":"2014","text":2,"paragraph":4,"sentenceNo":1,"sentence":"Reforming the system would help both lawyers and their customers.","path":"english1/2014.html"},{"id":"english1-2014-t2-p4-s2","examKey":"english1","examLabel":"英语一","year":"2014","text":2,"paragraph":4,"sentenceNo":2,"sentence":"Sensible ideas have been around for a long time, but the state-level bodies that govern the profession have been too conservative to implement them.","path":"english1/2014.html"},{"id":"english1-2014-t2-p4-s3","examKey":"english1","examLabel":"英语一","year":"2014","text":2,"paragraph":4,"sentenceNo":3,"sentence":"One idea is to allow people to study law as an undergraduate degree.","path":"english1/2014.html"},{"id":"english1-2014-t2-p4-s4","examKey":"english1","examLabel":"英语一","year":"2014","text":2,"paragraph":4,"sentenceNo":4,"sentence":"Another is to let students sit for the bar after only two years of law school.","path":"english1/2014.html"},{"id":"english1-2014-t2-p4-s5","examKey":"english1","examLabel":"英语一","year":"2014","text":2,"paragraph":4,"sentenceNo":5,"sentence":"If the bar exam is truly a stern enough test for a would-be lawyer, those who can sit it earlier should be allowed to do so.","path":"english1/2014.html"},{"id":"english1-2014-t2-p4-s6","examKey":"english1","examLabel":"英语一","year":"2014","text":2,"paragraph":4,"sentenceNo":6,"sentence":"Students who do not need the extra training could cut their debt mountain by a third.","path":"english1/2014.html"},{"id":"english1-2014-t2-p5-s1","examKey":"english1","examLabel":"英语一","year":"2014","text":2,"paragraph":5,"sentenceNo":1,"sentence":"The other reason why costs are so high is the restrictive guild-like ownership structure of the business.","path":"english1/2014.html"},{"id":"english1-2014-t2-p5-s2","examKey":"english1","examLabel":"英语一","year":"2014","text":2,"paragraph":5,"sentenceNo":2,"sentence":"Except in the District of Columbia, non-lawyers may not own any share of a law firm.","path":"english1/2014.html"},{"id":"english1-2014-t2-p5-s3","examKey":"english1","examLabel":"英语一","year":"2014","text":2,"paragraph":5,"sentenceNo":3,"sentence":"This keeps fees high and innovation slow.","path":"english1/2014.html"},{"id":"english1-2014-t2-p5-s4","examKey":"english1","examLabel":"英语一","year":"2014","text":2,"paragraph":5,"sentenceNo":4,"sentence":"There is pressure for change from within the profession, but opponents of change among the regulators insist that keeping outsiders out of a law firm isolates lawyers from the pressure to make money rather than serve clients ethically.","path":"english1/2014.html"},{"id":"english1-2014-t2-p6-s1","examKey":"english1","examLabel":"英语一","year":"2014","text":2,"paragraph":6,"sentenceNo":1,"sentence":"In fact, allowing non-lawyers to own shares in law firms would reduce costs and improve services to customers, by encouraging law firms to use technology and to employ professional managers to focus on improving firms’ efficiency.","path":"english1/2014.html"},{"id":"english1-2014-t2-p6-s2","examKey":"english1","examLabel":"英语一","year":"2014","text":2,"paragraph":6,"sentenceNo":2,"sentence":"After all, other countries, such as Australia and Britain, have started liberalizing their legal professions.","path":"english1/2014.html"},{"id":"english1-2014-t2-p6-s3","examKey":"english1","examLabel":"英语一","year":"2014","text":2,"paragraph":6,"sentenceNo":3,"sentence":"America should follow.","path":"english1/2014.html"},{"id":"english1-2014-t3-p1-s1","examKey":"english1","examLabel":"英语一","year":"2014","text":3,"paragraph":1,"sentenceNo":1,"sentence":"The US$3-million Fundamental Physics Prize is indeed an interesting experiment, as Alexander Polyakov said when he accepted this year’s award in March.","path":"english1/2014.html"},{"id":"english1-2014-t3-p1-s2","examKey":"english1","examLabel":"英语一","year":"2014","text":3,"paragraph":1,"sentenceNo":2,"sentence":"And it is far from the only one of its type.","path":"english1/2014.html"},{"id":"english1-2014-t3-p1-s3","examKey":"english1","examLabel":"英语一","year":"2014","text":3,"paragraph":1,"sentenceNo":3,"sentence":"As a New s Feature article in Nature discusses, a string of lucrative awards for researchers have joined the Nobel Prizes in recent years.","path":"english1/2014.html"},{"id":"english1-2014-t3-p1-s4","examKey":"english1","examLabel":"英语一","year":"2014","text":3,"paragraph":1,"sentenceNo":4,"sentence":"Many, like the Fundamental Physics Prize, are funded from the telephone-number-sized bank accounts of Internet entrepreneurs.","path":"english1/2014.html"},{"id":"english1-2014-t3-p1-s5","examKey":"english1","examLabel":"英语一","year":"2014","text":3,"paragraph":1,"sentenceNo":5,"sentence":"These benefactors have succeeded in their chosen fields, they say, and they want to use their wealth to draw attention to those who have succeeded in science.","path":"english1/2014.html"},{"id":"english1-2014-t3-p2-s1","examKey":"english1","examLabel":"英语一","year":"2014","text":3,"paragraph":2,"sentenceNo":1,"sentence":"What’s not to like?","path":"english1/2014.html"},{"id":"english1-2014-t3-p2-s2","examKey":"english1","examLabel":"英语一","year":"2014","text":3,"paragraph":2,"sentenceNo":2,"sentence":"Quite a lot, according to a handful of scientists quoted in the News Feature.","path":"english1/2014.html"},{"id":"english1-2014-t3-p2-s3","examKey":"english1","examLabel":"英语一","year":"2014","text":3,"paragraph":2,"sentenceNo":3,"sentence":"You cannot buy class, as the old saying goes, and these upstart entrepreneurs cannot buy their prizes the prestige of the Nobels.","path":"english1/2014.html"},{"id":"english1-2014-t3-p2-s4","examKey":"english1","examLabel":"英语一","year":"2014","text":3,"paragraph":2,"sentenceNo":4,"sentence":"The new awards are an exercise in self-promotion for those behind them, say scientists.","path":"english1/2014.html"},{"id":"english1-2014-t3-p2-s5","examKey":"english1","examLabel":"英语一","year":"2014","text":3,"paragraph":2,"sentenceNo":5,"sentence":"They could distort the achievement-based system of peer-review-led research.","path":"english1/2014.html"},{"id":"english1-2014-t3-p2-s6","examKey":"english1","examLabel":"英语一","year":"2014","text":3,"paragraph":2,"sentenceNo":6,"sentence":"They could cement the status quo of peer-reviewed research.","path":"english1/2014.html"},{"id":"english1-2014-t3-p2-s7","examKey":"english1","examLabel":"英语一","year":"2014","text":3,"paragraph":2,"sentenceNo":7,"sentence":"They do not fund peer-reviewed research.","path":"english1/2014.html"},{"id":"english1-2014-t3-p2-s8","examKey":"english1","examLabel":"英语一","year":"2014","text":3,"paragraph":2,"sentenceNo":8,"sentence":"They perpetuate the myth of the lone genius.","path":"english1/2014.html"},{"id":"english1-2014-t3-p3-s1","examKey":"english1","examLabel":"英语一","year":"2014","text":3,"paragraph":3,"sentenceNo":1,"sentence":"The goals of the prize-givers seem as scattered as the criticism.","path":"english1/2014.html"},{"id":"english1-2014-t3-p3-s2","examKey":"english1","examLabel":"英语一","year":"2014","text":3,"paragraph":3,"sentenceNo":2,"sentence":"Some want to shock, others to draw people into science, or to better reward those who have made their careers in research.","path":"english1/2014.html"},{"id":"english1-2014-t3-p4-s1","examKey":"english1","examLabel":"英语一","year":"2014","text":3,"paragraph":4,"sentenceNo":1,"sentence":"As Nature has pointed out before, there are some legitimate concerns about how science prizes — both new and old — are distributed.","path":"english1/2014.html"},{"id":"english1-2014-t3-p4-s2","examKey":"english1","examLabel":"英语一","year":"2014","text":3,"paragraph":4,"sentenceNo":2,"sentence":"The Breakthrough Prize in Life Sciences, launched this year, takes an unrepresentative view of what the life sciences include.","path":"english1/2014.html"},{"id":"english1-2014-t3-p4-s3","examKey":"english1","examLabel":"英语一","year":"2014","text":3,"paragraph":4,"sentenceNo":3,"sentence":"But the Nobel Foundation’s limit of three recipients per prize, each of whom must still be living, has long been outgrown by the collaborative nature of modern research — as will be demonstrated by the inevitable row over who is ignored when it comes to acknowledging the discovery of the Higgs boson.","path":"english1/2014.html"},{"id":"english1-2014-t3-p4-s4","examKey":"english1","examLabel":"英语一","year":"2014","text":3,"paragraph":4,"sentenceNo":4,"sentence":"The Nobels were, of course, themselves set up by a very rich individual who had decided what he wanted to do with his own money.","path":"english1/2014.html"},{"id":"english1-2014-t3-p4-s5","examKey":"english1","examLabel":"英语一","year":"2014","text":3,"paragraph":4,"sentenceNo":5,"sentence":"Time, rather than intention, has given them legitimacy.","path":"english1/2014.html"},{"id":"english1-2014-t3-p5-s1","examKey":"english1","examLabel":"英语一","year":"2014","text":3,"paragraph":5,"sentenceNo":1,"sentence":"As much as some scientists may complain about the new awards, two things seem clear.","path":"english1/2014.html"},{"id":"english1-2014-t3-p5-s2","examKey":"english1","examLabel":"英语一","year":"2014","text":3,"paragraph":5,"sentenceNo":2,"sentence":"First, most researchers would accept such a prize if they were offered one.","path":"english1/2014.html"},{"id":"english1-2014-t3-p5-s3","examKey":"english1","examLabel":"英语一","year":"2014","text":3,"paragraph":5,"sentenceNo":3,"sentence":"Second, it is surely a good thing that the money and attention come to science rather than go elsewhere.","path":"english1/2014.html"},{"id":"english1-2014-t3-p5-s4","examKey":"english1","examLabel":"英语一","year":"2014","text":3,"paragraph":5,"sentenceNo":4,"sentence":"It is fair to criticize and question the mechanism — that is the culture of research, after all — but it is the prize-givers’ money to do with as they please.","path":"english1/2014.html"},{"id":"english1-2014-t3-p5-s5","examKey":"english1","examLabel":"英语一","year":"2014","text":3,"paragraph":5,"sentenceNo":5,"sentence":"It is wise to take such gifts with gratitude and grace.","path":"english1/2014.html"},{"id":"english1-2014-t4-p1-s1","examKey":"english1","examLabel":"英语一","year":"2014","text":4,"paragraph":1,"sentenceNo":1,"sentence":"“The Heart of the Matter,” the just-released report by the American Academy of Arts and Sciences ( AAAS ), deserves praise for affirming the importance of the humanities and social sciences to the prosperity and security of liberal democracy in America.","path":"english1/2014.html"},{"id":"english1-2014-t4-p1-s2","examKey":"english1","examLabel":"英语一","year":"2014","text":4,"paragraph":1,"sentenceNo":2,"sentence":"Regrettably, however, the report’s failure to address the true nature of the crisis facing liberal education may cause more harm than good.","path":"english1/2014.html"},{"id":"english1-2014-t4-p2-s1","examKey":"english1","examLabel":"英语一","year":"2014","text":4,"paragraph":2,"sentenceNo":1,"sentence":"In 2010, leading congressional Democrats and Republicans sent letters to the AAAS asking that it identify actions that could be taken by “federal, state and local governments, universities, foundations, educators, individual benefactors and others” to “ maintain national excellence in humanities and social scientific scholarship and education.” In response, the American Academy formed the Commission on the Humanities and Social Sciences.","path":"english1/2014.html"},{"id":"english1-2014-t4-p2-s2","examKey":"english1","examLabel":"英语一","year":"2014","text":4,"paragraph":2,"sentenceNo":2,"sentence":"Among the commission’s 51 members are top-tier-university presidents, scholars, lawyers, judges, and business executives, as well as prominent figures from diplomacy, filmmaking, music and journalism.","path":"english1/2014.html"},{"id":"english1-2014-t4-p3-s1","examKey":"english1","examLabel":"英语一","year":"2014","text":4,"paragraph":3,"sentenceNo":1,"sentence":"The goals identified in the report are generally admirable.","path":"english1/2014.html"},{"id":"english1-2014-t4-p3-s2","examKey":"english1","examLabel":"英语一","year":"2014","text":4,"paragraph":3,"sentenceNo":2,"sentence":"Because representative government presupposes an informed citizenry, the report supports full literacy; stresses the study of history and government, particularly American history and American government; and encourages the use of new digital technologies.","path":"english1/2014.html"},{"id":"english1-2014-t4-p3-s3","examKey":"english1","examLabel":"英语一","year":"2014","text":4,"paragraph":3,"sentenceNo":3,"sentence":"To encourage innovation and competition, the report calls for increased investment in research, the crafting of coherent curricula that improve students’ ability to solve problems and communicate effectively in the 21st century, increased funding for teachers and the encouragement of scholars to bring their learning to bear on the great challenges of the day.","path":"english1/2014.html"},{"id":"english1-2014-t4-p3-s4","examKey":"english1","examLabel":"英语一","year":"2014","text":4,"paragraph":3,"sentenceNo":4,"sentence":"The report also advocates greater study of foreign languages, international affairs and the expansion of study abroad programs.","path":"english1/2014.html"},{"id":"english1-2014-t4-p4-s1","examKey":"english1","examLabel":"英语一","year":"2014","text":4,"paragraph":4,"sentenceNo":1,"sentence":"Unfortunately, despite 2½ years in the making, “The Heart of the Matter” never gets to the heart of the matter: the illiberal nature of liberal education at our leading colleges and universities.","path":"english1/2014.html"},{"id":"english1-2014-t4-p4-s2","examKey":"english1","examLabel":"英语一","year":"2014","text":4,"paragraph":4,"sentenceNo":2,"sentence":"The commission ignores that for several decades America’s colleges and universities have produced graduates who don’t know the content and character of liberal education and are thus deprived of its benefits.","path":"english1/2014.html"},{"id":"english1-2014-t4-p4-s3","examKey":"english1","examLabel":"英语一","year":"2014","text":4,"paragraph":4,"sentenceNo":3,"sentence":"Sadly, the spirit of inquiry once at home on campus has been replaced by the use of the humanities and social sciences as vehicles for publicizing “progressive,” or left-liberal propaganda.","path":"english1/2014.html"},{"id":"english1-2014-t4-p5-s1","examKey":"english1","examLabel":"英语一","year":"2014","text":4,"paragraph":5,"sentenceNo":1,"sentence":"Today, professors routinely treat the progressive interpretation of history and progressive public policy as the proper subject of study while portraying conservative or classical liberal ideas — such as free markets and self-reliance — as falling outside the boundaries of routine, and sometimes legitimate, intellectual investigation.","path":"english1/2014.html"},{"id":"english1-2014-t4-p6-s1","examKey":"english1","examLabel":"英语一","year":"2014","text":4,"paragraph":6,"sentenceNo":1,"sentence":"The AAAS displays great enthusiasm for liberal education.","path":"english1/2014.html"},{"id":"english1-2014-t4-p6-s2","examKey":"english1","examLabel":"英语一","year":"2014","text":4,"paragraph":6,"sentenceNo":2,"sentence":"Yet its report may well set back reform by obscuring the depth and breadth of the challenge that Congress asked it to illuminate.","path":"english1/2014.html"},{"id":"english2-2014-t1-p1-s1","examKey":"english2","examLabel":"英语二","year":"2014","text":1,"paragraph":1,"sentenceNo":1,"sentence":"1 What would you do with $590m?","path":"english2/2014.html"},{"id":"english2-2014-t1-p1-s2","examKey":"english2","examLabel":"英语二","year":"2014","text":1,"paragraph":1,"sentenceNo":2,"sentence":"This is now a question for Gloria MacKenzie, an 84-year-old widow who recently emerged from her small, tin-roofed house in Florida to collect the biggest undivided lottery jackpot in history.","path":"english2/2014.html"},{"id":"english2-2014-t1-p1-s3","examKey":"english2","examLabel":"英语二","year":"2014","text":1,"paragraph":1,"sentenceNo":3,"sentence":"2 If she hopes her new-found fortune will yield lasting feelings of fulfilment, she could do worse than read Happy Money by Elizabeth Dunn and Michael Norton.","path":"english2/2014.html"},{"id":"english2-2014-t1-p2-s1","examKey":"english2","examLabel":"英语二","year":"2014","text":1,"paragraph":2,"sentenceNo":1,"sentence":"3 These two academics use an array of behavioral research to show that the most rewarding ways to spend money can be counterintuitive.","path":"english2/2014.html"},{"id":"english2-2014-t1-p2-s2","examKey":"english2","examLabel":"英语二","year":"2014","text":1,"paragraph":2,"sentenceNo":2,"sentence":"4 Fantasies of great wealth often involve visions of fancy cars and extravagant homes.","path":"english2/2014.html"},{"id":"english2-2014-t1-p2-s3","examKey":"english2","examLabel":"英语二","year":"2014","text":1,"paragraph":2,"sentenceNo":3,"sentence":"5 Yet satisfaction with these material purchases wears off fairly quickly.","path":"english2/2014.html"},{"id":"english2-2014-t1-p2-s4","examKey":"english2","examLabel":"英语二","year":"2014","text":1,"paragraph":2,"sentenceNo":4,"sentence":"6 What was once exciting and new becomes old-hat; regret creeps in.","path":"english2/2014.html"},{"id":"english2-2014-t1-p2-s5","examKey":"english2","examLabel":"英语二","year":"2014","text":1,"paragraph":2,"sentenceNo":5,"sentence":"7 It is far better to spend money on experiences, say Ms Dunn and Mr Norton, like interesting trips, unique meals or even going to the cinema.","path":"english2/2014.html"},{"id":"english2-2014-t1-p2-s6","examKey":"english2","examLabel":"英语二","year":"2014","text":1,"paragraph":2,"sentenceNo":6,"sentence":"8 These purchases often become more valuable with time — as stories or memories — particularly if they involve feeling more connected to others.","path":"english2/2014.html"},{"id":"english2-2014-t1-p3-s1","examKey":"english2","examLabel":"英语二","year":"2014","text":1,"paragraph":3,"sentenceNo":1,"sentence":"9 This slim volume is packed with tips to help wage slaves as well as lottery winners get the most “happiness bang for your buck.” 10 It seems most people would be better off if they could shorten their commutes to work, spend more time with friends and family and less of it watching television (something the average American spends a whopping two months a year doing, and is hardly jollier for it).","path":"english2/2014.html"},{"id":"english2-2014-t1-p3-s2","examKey":"english2","examLabel":"英语二","year":"2014","text":1,"paragraph":3,"sentenceNo":2,"sentence":"11 Buying gifts or giving to charity is often more pleasurable than purchasing things for oneself, and luxuries are most enjoyable when they are consumed sparingly.","path":"english2/2014.html"},{"id":"english2-2014-t1-p3-s3","examKey":"english2","examLabel":"英语二","year":"2014","text":1,"paragraph":3,"sentenceNo":3,"sentence":"12 This is apparently the reason McDonald’s restricts the availability of its popular McRib — a marketing trick that has turned the pork sandwich into an object of obsession.","path":"english2/2014.html"},{"id":"english2-2014-t1-p4-s1","examKey":"english2","examLabel":"英语二","year":"2014","text":1,"paragraph":4,"sentenceNo":1,"sentence":"Q24 段落定位 Q25 全文主旨 13 Readers of Happy Money are clearly a privileged lot, anxious about fulfilment, not hunger.","path":"english2/2014.html"},{"id":"english2-2014-t1-p4-s2","examKey":"english2","examLabel":"英语二","year":"2014","text":1,"paragraph":4,"sentenceNo":2,"sentence":"14 Money may not quite buy happiness, but people in wealthier countries are generally happier than those in poor ones.","path":"english2/2014.html"},{"id":"english2-2014-t1-p4-s3","examKey":"english2","examLabel":"英语二","year":"2014","text":1,"paragraph":4,"sentenceNo":3,"sentence":"15 Yet the link between feeling good and spending money on others can be seen among rich and poor people around the world, and scarcity enhances the pleasure of most things for most people.","path":"english2/2014.html"},{"id":"english2-2014-t1-p4-s4","examKey":"english2","examLabel":"英语二","year":"2014","text":1,"paragraph":4,"sentenceNo":4,"sentence":"16 Not everyone will agree with the authors’ policy ideas, which range from mandating more holiday time to reducing tax incentives for American homebuyers.","path":"english2/2014.html"},{"id":"english2-2014-t1-p4-s5","examKey":"english2","examLabel":"英语二","year":"2014","text":1,"paragraph":4,"sentenceNo":5,"sentence":"17 But most people will come away from this book believing it was money well spent.","path":"english2/2014.html"},{"id":"english2-2014-t2-p1-s1","examKey":"english2","examLabel":"英语二","year":"2014","text":2,"paragraph":1,"sentenceNo":1,"sentence":"Q26 段落定位 1 An article in Scientific American has pointed out that empirical research says that, actually, you think you’re more beautiful than you are.","path":"english2/2014.html"},{"id":"english2-2014-t2-p1-s2","examKey":"english2","examLabel":"英语二","year":"2014","text":2,"paragraph":1,"sentenceNo":2,"sentence":"2 We have a deep-seated need to feel good about ourselves and we naturally employ a number of self-enhancing strategies to achieve this.","path":"english2/2014.html"},{"id":"english2-2014-t2-p1-s3","examKey":"english2","examLabel":"英语二","year":"2014","text":2,"paragraph":1,"sentenceNo":3,"sentence":"3 Social psychologists have amassed oceans of research into what they call the “above average effect,” or “illusory superiority,” and shown that, for example, 70% of us rate ourselves as above average in leadership, 93% in driving and 85% at getting on well with others — all obviously statistical impossibilities.","path":"english2/2014.html"},{"id":"english2-2014-t2-p2-s1","examKey":"english2","examLabel":"英语二","year":"2014","text":2,"paragraph":2,"sentenceNo":1,"sentence":"4 We rose-tint our memories and put ourselves into self-affirming situations.","path":"english2/2014.html"},{"id":"english2-2014-t2-p2-s2","examKey":"english2","examLabel":"英语二","year":"2014","text":2,"paragraph":2,"sentenceNo":2,"sentence":"5 We become defensive when criticised, and apply negative stereotypes to others to boost our own esteem.","path":"english2/2014.html"},{"id":"english2-2014-t2-p2-s3","examKey":"english2","examLabel":"英语二","year":"2014","text":2,"paragraph":2,"sentenceNo":3,"sentence":"6 We stalk around thinking we’re hot stuff.","path":"english2/2014.html"},{"id":"english2-2014-t2-p3-s1","examKey":"english2","examLabel":"英语二","year":"2014","text":2,"paragraph":3,"sentenceNo":1,"sentence":"7 Psychologist and behavioural scientist Nicholas Epley oversaw a key study into self-enhancement and attractiveness.","path":"english2/2014.html"},{"id":"english2-2014-t2-p3-s2","examKey":"english2","examLabel":"英语二","year":"2014","text":2,"paragraph":3,"sentenceNo":2,"sentence":"8 Rather than have people simply rate their beauty compared with others, he asked them to identify an original photograph of themselves from a lineup including versions that had been altered to appear more and less attractive.","path":"english2/2014.html"},{"id":"english2-2014-t2-p3-s3","examKey":"english2","examLabel":"英语二","year":"2014","text":2,"paragraph":3,"sentenceNo":3,"sentence":"9 Visual recognition, reads the study, is “an automatic psychological process, occurring rapidly and intuitively with little or no apparent conscious deliberation.” 10 If the subjects quickly chose a falsely flattering image — which most did — they genuinely believed it was really how they looked.","path":"english2/2014.html"},{"id":"english2-2014-t2-p4-s1","examKey":"english2","examLabel":"英语二","year":"2014","text":2,"paragraph":4,"sentenceNo":1,"sentence":"11 Epley found no significant gender difference in responses.","path":"english2/2014.html"},{"id":"english2-2014-t2-p4-s2","examKey":"english2","examLabel":"英语二","year":"2014","text":2,"paragraph":4,"sentenceNo":2,"sentence":"12 Nor was there any evidence that those who self-enhanced the most were doing so to make up for profound insecurities.","path":"english2/2014.html"},{"id":"english2-2014-t2-p4-s3","examKey":"english2","examLabel":"英语二","year":"2014","text":2,"paragraph":4,"sentenceNo":3,"sentence":"13 In fact, those who thought that the images higher up the attractiveness scale were real directly corresponded with those who showed other markers for having higher self-esteem.","path":"english2/2014.html"},{"id":"english2-2014-t2-p4-s4","examKey":"english2","examLabel":"英语二","year":"2014","text":2,"paragraph":4,"sentenceNo":4,"sentence":"14 “I don’t think the findings that we have are any evidence of personal delusion,” says Epley.","path":"english2/2014.html"},{"id":"english2-2014-t2-p4-s5","examKey":"english2","examLabel":"英语二","year":"2014","text":2,"paragraph":4,"sentenceNo":5,"sentence":"15 “It’s a reflection simply of people generally thinking well of themselves.” 16 If you are depressed, you won’t be self-enhancing.","path":"english2/2014.html"},{"id":"english2-2014-t2-p5-s1","examKey":"english2","examLabel":"英语二","year":"2014","text":2,"paragraph":5,"sentenceNo":1,"sentence":"Q29 词义定位 17 Knowing the results of Epley’s study, it makes sense that many people hate photographs of themselves viscerally — on one level, they don’t even recognise the person in the picture as themselves.","path":"english2/2014.html"},{"id":"english2-2014-t2-p5-s2","examKey":"english2","examLabel":"英语二","year":"2014","text":2,"paragraph":5,"sentenceNo":2,"sentence":"18 Facebook, therefore, is a self-enhancer’s paradise, where people can share only the most flattering photos, the cream of their wit, style, beauty, intellect and lifestyles.","path":"english2/2014.html"},{"id":"english2-2014-t2-p5-s3","examKey":"english2","examLabel":"英语二","year":"2014","text":2,"paragraph":5,"sentenceNo":3,"sentence":"19 It’s not that people’s profiles are dishonest, says Catalina Toma of Wisconsin-Madison University, “but they portray an idealised version of themselves.”","path":"english2/2014.html"},{"id":"english2-2014-t3-p1-s1","examKey":"english2","examLabel":"英语二","year":"2014","text":3,"paragraph":1,"sentenceNo":1,"sentence":"Q31 段落定位 1 The concept of man versus machine is at least as old as the industrial revolution, but this phenomenon tends to be most acutely felt during economic downturns and fragile recoveries.","path":"english2/2014.html"},{"id":"english2-2014-t3-p1-s2","examKey":"english2","examLabel":"英语二","year":"2014","text":3,"paragraph":1,"sentenceNo":2,"sentence":"2 And yet, it would be a mistake to think we are right now simply experiencing the painful side of a boom and bust cycle.","path":"english2/2014.html"},{"id":"english2-2014-t3-p1-s3","examKey":"english2","examLabel":"英语二","year":"2014","text":3,"paragraph":1,"sentenceNo":3,"sentence":"3 Certain jobs have gone away for good, outmoded by machines.","path":"english2/2014.html"},{"id":"english2-2014-t3-p1-s4","examKey":"english2","examLabel":"英语二","year":"2014","text":3,"paragraph":1,"sentenceNo":4,"sentence":"4 Since technology has such an insatiable appetite for eating up human jobs, this phenomenon will continue to restructure our economy in ways we cannot immediately foresee.","path":"english2/2014.html"},{"id":"english2-2014-t3-p2-s1","examKey":"english2","examLabel":"英语二","year":"2014","text":3,"paragraph":2,"sentenceNo":1,"sentence":"5 When there is rapid improvement in the price and performance of technology, jobs that were once thought to be immune from automation suddenly become threatened.","path":"english2/2014.html"},{"id":"english2-2014-t3-p2-s2","examKey":"english2","examLabel":"英语二","year":"2014","text":3,"paragraph":2,"sentenceNo":2,"sentence":"6 This argument has attracted a lot of attention, via the success of the book Race Against the Machine, by Erik Brynjolfsson and Andrew McAfee, who both hail from MIT’s Center for Digital Business.","path":"english2/2014.html"},{"id":"english2-2014-t3-p3-s1","examKey":"english2","examLabel":"英语二","year":"2014","text":3,"paragraph":3,"sentenceNo":1,"sentence":"7 This is a powerful argument, and a scary one.","path":"english2/2014.html"},{"id":"english2-2014-t3-p3-s2","examKey":"english2","examLabel":"英语二","year":"2014","text":3,"paragraph":3,"sentenceNo":2,"sentence":"8 And yet, John Hagel, author of The Power of Pull and other books, says Brynjolfsson and McAfee miss the reason why these jobs are so vulnerable to technology in the first place.","path":"english2/2014.html"},{"id":"english2-2014-t3-p4-s1","examKey":"english2","examLabel":"英语二","year":"2014","text":3,"paragraph":4,"sentenceNo":1,"sentence":"9 Hagel says we have designed jobs in the U.S. that tend to be “ tightly scripted ” and “highly standardized” ones that leave no room for “individual initiative or creativity”.","path":"english2/2014.html"},{"id":"english2-2014-t3-p4-s2","examKey":"english2","examLabel":"英语二","year":"2014","text":3,"paragraph":4,"sentenceNo":2,"sentence":"10 In short, these are the types of jobs that machines can perform much better than human beings.","path":"english2/2014.html"},{"id":"english2-2014-t3-p4-s3","examKey":"english2","examLabel":"英语二","year":"2014","text":3,"paragraph":4,"sentenceNo":3,"sentence":"11 That is how we have put a giant target sign on the backs of American workers, Hagel says.","path":"english2/2014.html"},{"id":"english2-2014-t3-p5-s1","examKey":"english2","examLabel":"英语二","year":"2014","text":3,"paragraph":5,"sentenceNo":1,"sentence":"12 It’s time to reinvent the formula for how work is conducted, since we are still relying on a very 20th century notion of work, Hagel says.","path":"english2/2014.html"},{"id":"english2-2014-t3-p5-s2","examKey":"english2","examLabel":"英语二","year":"2014","text":3,"paragraph":5,"sentenceNo":2,"sentence":"13 In our rapidly changing economy, we more than ever need people in the workplace who can take initiative and exercise their imagination “to respond to unexpected events.” 14 That is not something machines are good at.","path":"english2/2014.html"},{"id":"english2-2014-t3-p5-s3","examKey":"english2","examLabel":"英语二","year":"2014","text":3,"paragraph":5,"sentenceNo":3,"sentence":"15 They are designed to perform very predictable activities.","path":"english2/2014.html"},{"id":"english2-2014-t3-p6-s1","examKey":"english2","examLabel":"英语二","year":"2014","text":3,"paragraph":6,"sentenceNo":1,"sentence":"Q34 段落定位 Q35 主旨定位 16 As Hagel notes, Brynjolfsson and McAfee indeed touched on this point in their book.","path":"english2/2014.html"},{"id":"english2-2014-t3-p6-s2","examKey":"english2","examLabel":"英语二","year":"2014","text":3,"paragraph":6,"sentenceNo":2,"sentence":"17 We need to reframe race against the machine as race with the machine.","path":"english2/2014.html"},{"id":"english2-2014-t3-p6-s3","examKey":"english2","examLabel":"英语二","year":"2014","text":3,"paragraph":6,"sentenceNo":3,"sentence":"18 In other words, we need to look at the ways in which machines can augment human labor rather than replace it.","path":"english2/2014.html"},{"id":"english2-2014-t3-p6-s4","examKey":"english2","examLabel":"英语二","year":"2014","text":3,"paragraph":6,"sentenceNo":4,"sentence":"19 So then the problem is not really about technology, but rather, “how do we innovate our institutions and our work practices?”","path":"english2/2014.html"},{"id":"english2-2014-t4-p1-s1","examKey":"english2","examLabel":"英语二","year":"2014","text":4,"paragraph":1,"sentenceNo":1,"sentence":"1 When the government talks about infrastructure contributing to the economy the focus is usually on roads, railways, broadband and energy.","path":"english2/2014.html"},{"id":"english2-2014-t4-p1-s2","examKey":"english2","examLabel":"英语二","year":"2014","text":4,"paragraph":1,"sentenceNo":2,"sentence":"2 Housing is seldom mentioned.","path":"english2/2014.html"},{"id":"english2-2014-t4-p2-s1","examKey":"english2","examLabel":"英语二","year":"2014","text":4,"paragraph":2,"sentenceNo":1,"sentence":"3 Why is that?","path":"english2/2014.html"},{"id":"english2-2014-t4-p2-s2","examKey":"english2","examLabel":"英语二","year":"2014","text":4,"paragraph":2,"sentenceNo":2,"sentence":"4 To some extent the housing sector must shoulder the blame.","path":"english2/2014.html"},{"id":"english2-2014-t4-p2-s3","examKey":"english2","examLabel":"英语二","year":"2014","text":4,"paragraph":2,"sentenceNo":3,"sentence":"5 We have not been good at communicating the real value that housing can contribute to economic growth.","path":"english2/2014.html"},{"id":"english2-2014-t4-p2-s4","examKey":"english2","examLabel":"英语二","year":"2014","text":4,"paragraph":2,"sentenceNo":4,"sentence":"6 Then there is the scale of the typical housing project.","path":"english2/2014.html"},{"id":"english2-2014-t4-p2-s5","examKey":"english2","examLabel":"英语二","year":"2014","text":4,"paragraph":2,"sentenceNo":5,"sentence":"7 It is hard to shove for attention among multibillion-pound infrastructure projects, so it is inevitable that the attention is focused elsewhere.","path":"english2/2014.html"},{"id":"english2-2014-t4-p2-s6","examKey":"english2","examLabel":"英语二","year":"2014","text":4,"paragraph":2,"sentenceNo":6,"sentence":"8 But perhaps the most significant reason is that the issue has always been so politically charged.","path":"english2/2014.html"},{"id":"english2-2014-t4-p3-s1","examKey":"english2","examLabel":"英语二","year":"2014","text":4,"paragraph":3,"sentenceNo":1,"sentence":"9 Nevertheless, the affordable housing situation is desperate.","path":"english2/2014.html"},{"id":"english2-2014-t4-p3-s2","examKey":"english2","examLabel":"英语二","year":"2014","text":4,"paragraph":3,"sentenceNo":2,"sentence":"10 Waiting lists increase all the time and we are simply not building enough new homes.","path":"english2/2014.html"},{"id":"english2-2014-t4-p4-s1","examKey":"english2","examLabel":"英语二","year":"2014","text":4,"paragraph":4,"sentenceNo":1,"sentence":"11 The comprehensive spending review offers an opportunity for the government to help rectify this.","path":"english2/2014.html"},{"id":"english2-2014-t4-p4-s2","examKey":"english2","examLabel":"英语二","year":"2014","text":4,"paragraph":4,"sentenceNo":2,"sentence":"12 It needs to put historical prejudices to one side and take some steps to address our urgent housing need.","path":"english2/2014.html"},{"id":"english2-2014-t4-p5-s1","examKey":"english2","examLabel":"英语二","year":"2014","text":4,"paragraph":5,"sentenceNo":1,"sentence":"Q38 段落定位 13 There are some indications that it is preparing to do just that.","path":"english2/2014.html"},{"id":"english2-2014-t4-p5-s2","examKey":"english2","examLabel":"英语二","year":"2014","text":4,"paragraph":5,"sentenceNo":2,"sentence":"14 The communities minister, Don Foster, has hinted that George Osborne, Chancellor of the Exchequer, may introduce more flexibility to the current cap on the amount that local authorities can borrow against their housing stock debt.","path":"english2/2014.html"},{"id":"english2-2014-t4-p5-s3","examKey":"english2","examLabel":"英语二","year":"2014","text":4,"paragraph":5,"sentenceNo":3,"sentence":"15 Evidence shows that 60,000 extra new homes could be built over the next five years if the cap were lifted, increasing GDP by 0.6%.","path":"english2/2014.html"},{"id":"english2-2014-t4-p6-s1","examKey":"english2","examLabel":"英语二","year":"2014","text":4,"paragraph":6,"sentenceNo":1,"sentence":"16 Ministers should also look at creating greater certainty in the rental environment, which would have a significant impact on the ability of registered providers to fund new developments from revenues.","path":"english2/2014.html"},{"id":"english2-2014-t4-p7-s1","examKey":"english2","examLabel":"英语二","year":"2014","text":4,"paragraph":7,"sentenceNo":1,"sentence":"17 But it is not just down to the government.","path":"english2/2014.html"},{"id":"english2-2014-t4-p7-s2","examKey":"english2","examLabel":"英语二","year":"2014","text":4,"paragraph":7,"sentenceNo":2,"sentence":"18 While these measures would be welcome in the short term, we must face up to the fact that the existing £4.5bn programme of grants to fund new affordable housing, set to expire in 2015, is unlikely to be extended beyond then.","path":"english2/2014.html"},{"id":"english2-2014-t4-p7-s3","examKey":"english2","examLabel":"英语二","year":"2014","text":4,"paragraph":7,"sentenceNo":3,"sentence":"19 The Labour party has recently announced that it will retain a large part of the coalition’s spending plans if it returns to power.","path":"english2/2014.html"},{"id":"english2-2014-t4-p7-s4","examKey":"english2","examLabel":"英语二","year":"2014","text":4,"paragraph":7,"sentenceNo":4,"sentence":"20 The housing sector needs to accept that we are very unlikely to ever return to the era of large-scale public grants.","path":"english2/2014.html"},{"id":"english2-2014-t4-p7-s5","examKey":"english2","examLabel":"英语二","year":"2014","text":4,"paragraph":7,"sentenceNo":5,"sentence":"21 We need to adjust to this changing climate.","path":"english2/2014.html"},{"id":"english2-2014-t4-p8-s1","examKey":"english2","examLabel":"英语二","year":"2014","text":4,"paragraph":8,"sentenceNo":1,"sentence":"22 While the government’s commitment to long-term funding may have changed, the very pressing need for more affordable housing is real and is not going away.","path":"english2/2014.html"},{"id":"english1-2015-t1-p1-s1","examKey":"english1","examLabel":"英语一","year":"2015","text":1,"paragraph":1,"sentenceNo":1,"sentence":"King Juan Carlos of Spain once insisted “kings don’t abdicate, they die in their sleep.” But embarrassing scandals and the popularity of the republican left in the recent Euro-elections have forced him to eat his words and stand down.","path":"english1/2015.html"},{"id":"english1-2015-t1-p1-s2","examKey":"english1","examLabel":"英语一","year":"2015","text":1,"paragraph":1,"sentenceNo":2,"sentence":"So, does the Spanish crisis suggest that monarchy is seeing its last days?","path":"english1/2015.html"},{"id":"english1-2015-t1-p1-s3","examKey":"english1","examLabel":"英语一","year":"2015","text":1,"paragraph":1,"sentenceNo":3,"sentence":"Does that mean the writing is on the wall for all European royals, with their magnificent uniforms and majestic lifestyles?","path":"english1/2015.html"},{"id":"english1-2015-t1-p2-s1","examKey":"english1","examLabel":"英语一","year":"2015","text":1,"paragraph":2,"sentenceNo":1,"sentence":"The Spanish case provides arguments both for and against monarchy.","path":"english1/2015.html"},{"id":"english1-2015-t1-p2-s2","examKey":"english1","examLabel":"英语一","year":"2015","text":1,"paragraph":2,"sentenceNo":2,"sentence":"When public opinion is particularly polarised, as it was following the end of the Franco regime, monarchs can rise above “mere” politics and “embody” a spirit of national unity.","path":"english1/2015.html"},{"id":"english1-2015-t1-p3-s1","examKey":"english1","examLabel":"英语一","year":"2015","text":1,"paragraph":3,"sentenceNo":1,"sentence":"It is this apparent transcendence of politics that explains monarchs’ continuing popularity as heads of state.","path":"english1/2015.html"},{"id":"english1-2015-t1-p3-s2","examKey":"english1","examLabel":"英语一","year":"2015","text":1,"paragraph":3,"sentenceNo":2,"sentence":"And so, the Middle East excepted, Europe is the most monarch-infested region in the world, with 10 kingdoms (not counting Vatican city and Andorra).","path":"english1/2015.html"},{"id":"english1-2015-t1-p3-s3","examKey":"english1","examLabel":"英语一","year":"2015","text":1,"paragraph":3,"sentenceNo":3,"sentence":"But unlike their absolutist counterparts in the Gulf and Asia, most royal families have survived because they allow voters to avoid the difficult search for a non-controversial but respected public figure.","path":"english1/2015.html"},{"id":"english1-2015-t1-p4-s1","examKey":"english1","examLabel":"英语一","year":"2015","text":1,"paragraph":4,"sentenceNo":1,"sentence":"Even so, kings and queens undoubtedly have a downside.","path":"english1/2015.html"},{"id":"english1-2015-t1-p4-s2","examKey":"english1","examLabel":"英语一","year":"2015","text":1,"paragraph":4,"sentenceNo":2,"sentence":"Symbolic of national unity as they claim to be, their very history—and sometimes the way they behave today—embodies outdated and indefensible privileges and inequalities.","path":"english1/2015.html"},{"id":"english1-2015-t1-p4-s3","examKey":"english1","examLabel":"英语一","year":"2015","text":1,"paragraph":4,"sentenceNo":3,"sentence":"At a time when Thomas Piketty and other economists are warning of rising inequality and the increasing power of inherited wealth, it is bizarre that wealthy aristocratic families should still be the symbolic heart of modern democratic states.","path":"english1/2015.html"},{"id":"english1-2015-t1-p5-s1","examKey":"english1","examLabel":"英语一","year":"2015","text":1,"paragraph":5,"sentenceNo":1,"sentence":"The most successful monarchies strive to abandon or hide their old aristocratic ways.","path":"english1/2015.html"},{"id":"english1-2015-t1-p5-s2","examKey":"english1","examLabel":"英语一","year":"2015","text":1,"paragraph":5,"sentenceNo":2,"sentence":"Princes and princesses have day-jobs and ride bicycles, not horses (or helicopters).","path":"english1/2015.html"},{"id":"english1-2015-t1-p5-s3","examKey":"english1","examLabel":"英语一","year":"2015","text":1,"paragraph":5,"sentenceNo":3,"sentence":"Even so, these are wealthy families who party with the international 1%, and media intrusiveness makes it increasingly difficult to maintain the right image.","path":"english1/2015.html"},{"id":"english1-2015-t1-p6-s1","examKey":"english1","examLabel":"英语一","year":"2015","text":1,"paragraph":6,"sentenceNo":1,"sentence":"While Europe’s monarchies will no doubt be smart enough to survive for some time to come, it is the British royals who have most to fear from the Spanish example.","path":"english1/2015.html"},{"id":"english1-2015-t1-p7-s1","examKey":"english1","examLabel":"英语一","year":"2015","text":1,"paragraph":7,"sentenceNo":1,"sentence":"It is only the Queen who has preserved the monarchy’s reputation with her rather ordinary (if well-heeled) granny style.","path":"english1/2015.html"},{"id":"english1-2015-t1-p7-s2","examKey":"english1","examLabel":"英语一","year":"2015","text":1,"paragraph":7,"sentenceNo":2,"sentence":"The danger will come with Charles, who has both an expensive taste of lifestyle and a pretty hierarchical view of the world.","path":"english1/2015.html"},{"id":"english1-2015-t1-p7-s3","examKey":"english1","examLabel":"英语一","year":"2015","text":1,"paragraph":7,"sentenceNo":3,"sentence":"He has failed to understand that monarchies have largely survived because they provide a service—as non-controversial and non-political heads of state.","path":"english1/2015.html"},{"id":"english1-2015-t1-p7-s4","examKey":"english1","examLabel":"英语一","year":"2015","text":1,"paragraph":7,"sentenceNo":4,"sentence":"Charles ought to know that, as English history shows, it is kings, not republicans, who are the monarchy’s worst enemies.","path":"english1/2015.html"},{"id":"english1-2015-t2-p1-s1","examKey":"english1","examLabel":"英语一","year":"2015","text":2,"paragraph":1,"sentenceNo":1,"sentence":"Just how much does the Constitution protect your digital data?","path":"english1/2015.html"},{"id":"english1-2015-t2-p1-s2","examKey":"english1","examLabel":"英语一","year":"2015","text":2,"paragraph":1,"sentenceNo":2,"sentence":"The Supreme Court will now consider whether police can search the contents of a mobile phone without a warrant if the phone is on or around a person during an arrest.","path":"english1/2015.html"},{"id":"english1-2015-t2-p2-s1","examKey":"english1","examLabel":"英语一","year":"2015","text":2,"paragraph":2,"sentenceNo":1,"sentence":"California has asked the justices to refrain from a sweeping ruling, particularly one that upsets the old assumption that authorities may search through the possessions of suspects at the time of their arrest.","path":"english1/2015.html"},{"id":"english1-2015-t2-p2-s2","examKey":"english1","examLabel":"英语一","year":"2015","text":2,"paragraph":2,"sentenceNo":2,"sentence":"It is hard, the state argues, for judges to assess the implications of new and rapidly changing technologies.","path":"english1/2015.html"},{"id":"english1-2015-t2-p3-s1","examKey":"english1","examLabel":"英语一","year":"2015","text":2,"paragraph":3,"sentenceNo":1,"sentence":"The court would be recklessly modest if it followed California’s advice.","path":"english1/2015.html"},{"id":"english1-2015-t2-p3-s2","examKey":"english1","examLabel":"英语一","year":"2015","text":2,"paragraph":3,"sentenceNo":2,"sentence":"Enough of the implications are discernable, even obvious, so that the justices can and should provide updated guidelines to police, lawyers and defendants.","path":"english1/2015.html"},{"id":"english1-2015-t2-p4-s1","examKey":"english1","examLabel":"英语一","year":"2015","text":2,"paragraph":4,"sentenceNo":1,"sentence":"They should start by discarding California’s lame argument that exploring the contents of a smart phone—a vast storehouse of digital information—is similar to, say, going through a suspect’s purse.","path":"english1/2015.html"},{"id":"english1-2015-t2-p4-s2","examKey":"english1","examLabel":"英语一","year":"2015","text":2,"paragraph":4,"sentenceNo":2,"sentence":"The court has ruled that police don’t violate the Fourth Amendment when they go through the wallet or pocketbook of an arrestee without a warrant.","path":"english1/2015.html"},{"id":"english1-2015-t2-p4-s3","examKey":"english1","examLabel":"英语一","year":"2015","text":2,"paragraph":4,"sentenceNo":3,"sentence":"But exploring one’s smartphone is more like entering his or her home.","path":"english1/2015.html"},{"id":"english1-2015-t2-p5-s1","examKey":"english1","examLabel":"英语一","year":"2015","text":2,"paragraph":5,"sentenceNo":1,"sentence":"A smart phone may contain an arrestee’s reading history, financial history, medical history and comprehensive records of recent correspondence.","path":"english1/2015.html"},{"id":"english1-2015-t2-p5-s2","examKey":"english1","examLabel":"英语一","year":"2015","text":2,"paragraph":5,"sentenceNo":2,"sentence":"The development of “cloud computing,” meanwhile, has made that exploration so much the easier.","path":"english1/2015.html"},{"id":"english1-2015-t2-p6-s1","examKey":"english1","examLabel":"英语一","year":"2015","text":2,"paragraph":6,"sentenceNo":1,"sentence":"Americans should take steps to protect their digital privacy.","path":"english1/2015.html"},{"id":"english1-2015-t2-p6-s2","examKey":"english1","examLabel":"英语一","year":"2015","text":2,"paragraph":6,"sentenceNo":2,"sentence":"But keeping sensitive information on these devices is increasingly a requirement of normal life.","path":"english1/2015.html"},{"id":"english1-2015-t2-p6-s3","examKey":"english1","examLabel":"英语一","year":"2015","text":2,"paragraph":6,"sentenceNo":3,"sentence":"Citizens still have a right to expect private documents to remain private and protected by the Constitution’s prohibition on unreasonable searches.","path":"english1/2015.html"},{"id":"english1-2015-t2-p7-s1","examKey":"english1","examLabel":"英语一","year":"2015","text":2,"paragraph":7,"sentenceNo":1,"sentence":"As so often is the case, stating that principle doesn’t ease the challenge of line-drawing.","path":"english1/2015.html"},{"id":"english1-2015-t2-p7-s2","examKey":"english1","examLabel":"英语一","year":"2015","text":2,"paragraph":7,"sentenceNo":2,"sentence":"In many cases, it would not be overly burdensome for authorities to obtain a warrant to search through phone contents.","path":"english1/2015.html"},{"id":"english1-2015-t2-p7-s3","examKey":"english1","examLabel":"英语一","year":"2015","text":2,"paragraph":7,"sentenceNo":3,"sentence":"They could still invalidate Fourth Amendment protections when facing severe, urgent circumstances, and they could take reasonable measures to ensure that phone data are not erased or altered while waiting for a warrant.","path":"english1/2015.html"},{"id":"english1-2015-t2-p7-s4","examKey":"english1","examLabel":"英语一","year":"2015","text":2,"paragraph":7,"sentenceNo":4,"sentence":"The court, though, may want to allow room for police to cite situations where they are entitled to more freedom.","path":"english1/2015.html"},{"id":"english1-2015-t2-p8-s1","examKey":"english1","examLabel":"英语一","year":"2015","text":2,"paragraph":8,"sentenceNo":1,"sentence":"But the justices should not swallow California’s argument whole.","path":"english1/2015.html"},{"id":"english1-2015-t2-p8-s2","examKey":"english1","examLabel":"英语一","year":"2015","text":2,"paragraph":8,"sentenceNo":2,"sentence":"New, disruptive technology sometimes demands novel applications of the Constitution’s protections.","path":"english1/2015.html"},{"id":"english1-2015-t2-p9-s1","examKey":"english1","examLabel":"英语一","year":"2015","text":2,"paragraph":9,"sentenceNo":1,"sentence":"Orin Kerr, a law professor, compares the explosion and accessibility of digital information in the 21st century with the establishment of automobile use as a virtual necessity of life in the 20th: The justices had to specify novel rules for the new personal domain of the passenger car then; they must sort out how the Fourth Amendment applies to digital information now.","path":"english1/2015.html"},{"id":"english1-2015-t3-p1-s1","examKey":"english1","examLabel":"英语一","year":"2015","text":3,"paragraph":1,"sentenceNo":1,"sentence":"The journal Science is adding an extra round of statistical checks to its peer-review process, editor-in-chief Marcia McNutt announced today.","path":"english1/2015.html"},{"id":"english1-2015-t3-p1-s2","examKey":"english1","examLabel":"英语一","year":"2015","text":3,"paragraph":1,"sentenceNo":2,"sentence":"The policy follows similar efforts from other journals, after widespread concern that basic mistakes in data analysis are contributing to the irreproducibility of many published research findings.","path":"english1/2015.html"},{"id":"english1-2015-t3-p2-s1","examKey":"english1","examLabel":"英语一","year":"2015","text":3,"paragraph":2,"sentenceNo":1,"sentence":"“Readers must have confidence in the conclusions published in our journal,” writes McNutt in an editorial.","path":"english1/2015.html"},{"id":"english1-2015-t3-p2-s2","examKey":"english1","examLabel":"英语一","year":"2015","text":3,"paragraph":2,"sentenceNo":2,"sentence":"Working with the American Statistical Association, the journal has appointed seven experts to a statistics board of reviewing editors ( SBoRE ).","path":"english1/2015.html"},{"id":"english1-2015-t3-p2-s3","examKey":"english1","examLabel":"英语一","year":"2015","text":3,"paragraph":2,"sentenceNo":3,"sentence":"Manuscripts will be flagged up for additional scrutiny by the journal’s internal editors, or by its existing Board of Reviewing Editors or by outside peer reviewers.","path":"english1/2015.html"},{"id":"english1-2015-t3-p2-s4","examKey":"english1","examLabel":"英语一","year":"2015","text":3,"paragraph":2,"sentenceNo":4,"sentence":"The SBoRE panel will then find external statisticians to review these manuscripts.","path":"english1/2015.html"},{"id":"english1-2015-t3-p3-s1","examKey":"english1","examLabel":"英语一","year":"2015","text":3,"paragraph":3,"sentenceNo":1,"sentence":"Asked whether any particular papers had impelled the change, McNutt said: “The creation of the ‘statistics board’ was motivated by concerns broadly with the application of statistics and data analysis in scientific research and is part of Science ’s overall drive to increase reproducibility in the research we publish.”","path":"english1/2015.html"},{"id":"english1-2015-t3-p4-s1","examKey":"english1","examLabel":"英语一","year":"2015","text":3,"paragraph":4,"sentenceNo":1,"sentence":"Giovanni Parmigiani, a biostatistician at the Harvard School of Public Health, a member of the SBoRE group, says he expects the board to “play primarily an advisory role.” He agreed to join because he “found the foresight behind the establishment of the SBoRE to be novel, unique and likely to have a lasting impact.","path":"english1/2015.html"},{"id":"english1-2015-t3-p4-s2","examKey":"english1","examLabel":"英语一","year":"2015","text":3,"paragraph":4,"sentenceNo":2,"sentence":"This impact will not only be through the publications in Science itself, but hopefully through a larger group of publishing places that may want to model their approach after Science.”","path":"english1/2015.html"},{"id":"english1-2015-t3-p5-s1","examKey":"english1","examLabel":"英语一","year":"2015","text":3,"paragraph":5,"sentenceNo":1,"sentence":"John Ioannidis, a physician who studies research methodology, says that the policy is “a most welcome step forward” and “long overdue.” “Most journals are weak in statistical review, and this damages the quality of what they publish.","path":"english1/2015.html"},{"id":"english1-2015-t3-p5-s2","examKey":"english1","examLabel":"英语一","year":"2015","text":3,"paragraph":5,"sentenceNo":2,"sentence":"I think that, for the majority of scientific papers now adays, statistical review is more essential than expert review,” he says, but he noted that biomedical journals such as Annals of Internal Medicine, the Journal of the American Medical Association and The Lancet pay strong attention to statistical review.","path":"english1/2015.html"},{"id":"english1-2015-t3-p6-s1","examKey":"english1","examLabel":"英语一","year":"2015","text":3,"paragraph":6,"sentenceNo":1,"sentence":"Professional scientists are expected to know how to analyse data, but statistical errors are alarmingly common in published research, according to David Vaux, a cell biologist.","path":"english1/2015.html"},{"id":"english1-2015-t3-p6-s2","examKey":"english1","examLabel":"英语一","year":"2015","text":3,"paragraph":6,"sentenceNo":2,"sentence":"Researchers should improve their standards, he wrote in 2012, but journals should also take a tougher line, “engaging reviewers who are statistically literate and editors who can verify the process.” Vaux says that Science ’s idea to pass some papers to statisticians “has some merit, but a weakness is that it relies on the board of reviewing editors to identify ‘the papers that need scrutiny’ in the first place”.","path":"english1/2015.html"},{"id":"english1-2015-t4-p1-s1","examKey":"english1","examLabel":"英语一","year":"2015","text":4,"paragraph":1,"sentenceNo":1,"sentence":"Two years ago, Rupert Murdoch’s daughter, Elisabeth, spoke of the “unsettling dearth of integrity across so many of our institutions.” Integrity had collapsed, she argued, because of a collective acceptance that the only “ sorting mechanism ” in society should be profit and the market.","path":"english1/2015.html"},{"id":"english1-2015-t4-p1-s2","examKey":"english1","examLabel":"英语一","year":"2015","text":4,"paragraph":1,"sentenceNo":2,"sentence":"But “it’s us, human beings, we the people who create the society we want, not profit.”","path":"english1/2015.html"},{"id":"english1-2015-t4-p2-s1","examKey":"english1","examLabel":"英语一","year":"2015","text":4,"paragraph":2,"sentenceNo":1,"sentence":"Driving her point home, she continued: “It’s increasingly apparent that the absence of purpose, of a moral language within government, media or business could become one of the most dangerous goals for capitalism and freedom.” This same absence of moral purpose was wounding companies such as News International, she thought, making it more likely that it would lose its way as it had with widespread illegal telephone hacking.","path":"english1/2015.html"},{"id":"english1-2015-t4-p3-s1","examKey":"english1","examLabel":"英语一","year":"2015","text":4,"paragraph":3,"sentenceNo":1,"sentence":"As the hacking trial concludes—finding guilty one ex-editor of the News of the World, Andy Coulson, for conspiring to hack phones, and finding his predecessor, Rebekah Brooks, innocent of the same charge—the wider issue of dearth of integrity still stands.","path":"english1/2015.html"},{"id":"english1-2015-t4-p3-s2","examKey":"english1","examLabel":"英语一","year":"2015","text":4,"paragraph":3,"sentenceNo":2,"sentence":"Journalists are known to have hacked the phones of up to 5,500 people.","path":"english1/2015.html"},{"id":"english1-2015-t4-p3-s3","examKey":"english1","examLabel":"英语一","year":"2015","text":4,"paragraph":3,"sentenceNo":3,"sentence":"This is hacking on an industrial scale, as was acknowledged by Glenn Mulcaire, the man hired by the News of the World in 2001 to be the point person for phone hacking.","path":"english1/2015.html"},{"id":"english1-2015-t4-p3-s4","examKey":"english1","examLabel":"英语一","year":"2015","text":4,"paragraph":3,"sentenceNo":4,"sentence":"Others await trial.","path":"english1/2015.html"},{"id":"english1-2015-t4-p3-s5","examKey":"english1","examLabel":"英语一","year":"2015","text":4,"paragraph":3,"sentenceNo":5,"sentence":"This long story still unfolds.","path":"english1/2015.html"},{"id":"english1-2015-t4-p4-s1","examKey":"english1","examLabel":"英语一","year":"2015","text":4,"paragraph":4,"sentenceNo":1,"sentence":"In many respects, the dearth of moral purpose frames not only the fact of such widespread phone hacking but the terms on which the trial took place.","path":"english1/2015.html"},{"id":"english1-2015-t4-p4-s2","examKey":"english1","examLabel":"英语一","year":"2015","text":4,"paragraph":4,"sentenceNo":2,"sentence":"One of the astonishing revelations was how little Rebekah Brooks knew of what went on in her newsroom, how little she thought to ask and the fact that she never inquired how the stories arrived.","path":"english1/2015.html"},{"id":"english1-2015-t4-p4-s3","examKey":"english1","examLabel":"英语一","year":"2015","text":4,"paragraph":4,"sentenceNo":3,"sentence":"The core of her successful defence was that she knew nothing.","path":"english1/2015.html"},{"id":"english1-2015-t4-p5-s1","examKey":"english1","examLabel":"英语一","year":"2015","text":4,"paragraph":5,"sentenceNo":1,"sentence":"In today’s world, it has become normal that well-paid executives should not be accountable for what happens in the organisations that they run.","path":"english1/2015.html"},{"id":"english1-2015-t4-p5-s2","examKey":"english1","examLabel":"英语一","year":"2015","text":4,"paragraph":5,"sentenceNo":2,"sentence":"Perhaps we should not be so surprised.","path":"english1/2015.html"},{"id":"english1-2015-t4-p5-s3","examKey":"english1","examLabel":"英语一","year":"2015","text":4,"paragraph":5,"sentenceNo":3,"sentence":"For a generation, the collective doctrine has been that the sorting mechanism of society should be profit.","path":"english1/2015.html"},{"id":"english1-2015-t4-p5-s4","examKey":"english1","examLabel":"英语一","year":"2015","text":4,"paragraph":5,"sentenceNo":4,"sentence":"The words that have mattered are efficiency, flexibility, shareholder value, business-friendly, wealth generation, sales, impact and, in newspapers, circulation.","path":"english1/2015.html"},{"id":"english1-2015-t4-p5-s5","examKey":"english1","examLabel":"英语一","year":"2015","text":4,"paragraph":5,"sentenceNo":5,"sentence":"Words degraded to the margin have been justice, fairness, tolerance, proportionality and accountability.","path":"english1/2015.html"},{"id":"english1-2015-t4-p6-s1","examKey":"english1","examLabel":"英语一","year":"2015","text":4,"paragraph":6,"sentenceNo":1,"sentence":"The purpose of editing the News of the World was not to promote reader understanding, to be fair in what was written or to betray any common humanity.","path":"english1/2015.html"},{"id":"english1-2015-t4-p6-s2","examKey":"english1","examLabel":"英语一","year":"2015","text":4,"paragraph":6,"sentenceNo":2,"sentence":"It was to ruin lives in the quest for circulation and impact.","path":"english1/2015.html"},{"id":"english1-2015-t4-p6-s3","examKey":"english1","examLabel":"英语一","year":"2015","text":4,"paragraph":6,"sentenceNo":3,"sentence":"Ms Brooks may or may not have had suspicions about how her journalists got their stories, but she asked no questions, gave no instructions—nor received traceable, recorded answers.","path":"english1/2015.html"},{"id":"english2-2015-t1-p1-s1","examKey":"english2","examLabel":"英语二","year":"2015","text":1,"paragraph":1,"sentenceNo":1,"sentence":"Q21 段落定位 A new study suggests that contrary to most surveys, people are actually more stressed at home than at work.","path":"english2/2015.html"},{"id":"english2-2015-t1-p1-s2","examKey":"english2","examLabel":"英语二","year":"2015","text":1,"paragraph":1,"sentenceNo":2,"sentence":"Researchers measured people’s cortisol, which is a stress marker, while they were at work and while they were at home and found it higher at what is supposed to be a place of refuge.","path":"english2/2015.html"},{"id":"english2-2015-t1-p2-s1","examKey":"english2","examLabel":"英语二","year":"2015","text":1,"paragraph":2,"sentenceNo":1,"sentence":"Q22 人物定位 “Further contradicting conventional wisdom, we found that women as well as men have lower levels of stress at work than at home,” writes one of the researchers, Sarah Damaske.","path":"english2/2015.html"},{"id":"english2-2015-t1-p2-s2","examKey":"english2","examLabel":"英语二","year":"2015","text":1,"paragraph":2,"sentenceNo":2,"sentence":"In fact women even say they feel better at work, she notes.","path":"english2/2015.html"},{"id":"english2-2015-t1-p2-s3","examKey":"english2","examLabel":"英语二","year":"2015","text":1,"paragraph":2,"sentenceNo":3,"sentence":"“It is men, not women, who report being happier at home than at work.” Another surprise is that the findings hold true for both those with children and without, but more so for nonparents.","path":"english2/2015.html"},{"id":"english2-2015-t1-p2-s4","examKey":"english2","examLabel":"英语二","year":"2015","text":1,"paragraph":2,"sentenceNo":4,"sentence":"This is why people who work outside the home have better health.","path":"english2/2015.html"},{"id":"english2-2015-t1-p3-s1","examKey":"english2","examLabel":"英语二","year":"2015","text":1,"paragraph":3,"sentenceNo":1,"sentence":"Q23 段落定位 What the study doesn’t measure is whether people are still doing work when they’re at home, whether it is household work or work brought home from the office.","path":"english2/2015.html"},{"id":"english2-2015-t1-p3-s2","examKey":"english2","examLabel":"英语二","year":"2015","text":1,"paragraph":3,"sentenceNo":2,"sentence":"For many men, the end of the workday is a time to kick back.","path":"english2/2015.html"},{"id":"english2-2015-t1-p3-s3","examKey":"english2","examLabel":"英语二","year":"2015","text":1,"paragraph":3,"sentenceNo":3,"sentence":"For women who stay home, they never get to leave the office.","path":"english2/2015.html"},{"id":"english2-2015-t1-p3-s4","examKey":"english2","examLabel":"英语二","year":"2015","text":1,"paragraph":3,"sentenceNo":4,"sentence":"And for women who work outside the home, they often are playing catch-up-with-household tasks.","path":"english2/2015.html"},{"id":"english2-2015-t1-p3-s5","examKey":"english2","examLabel":"英语二","year":"2015","text":1,"paragraph":3,"sentenceNo":5,"sentence":"With the blurring of roles, and the fact that the home front lags well behind the workplace in making adjustments for working women, it’s not surprising that women are more stressed at home.","path":"english2/2015.html"},{"id":"english2-2015-t1-p4-s1","examKey":"english2","examLabel":"英语二","year":"2015","text":1,"paragraph":4,"sentenceNo":1,"sentence":"Q24 词义定位 But it’s not just a gender thing.","path":"english2/2015.html"},{"id":"english2-2015-t1-p4-s2","examKey":"english2","examLabel":"英语二","year":"2015","text":1,"paragraph":4,"sentenceNo":2,"sentence":"At work, people pretty much know what they’re supposed to be doing: working, making money, doing the tasks they have to do in order to draw an income.","path":"english2/2015.html"},{"id":"english2-2015-t1-p4-s3","examKey":"english2","examLabel":"英语二","year":"2015","text":1,"paragraph":4,"sentenceNo":3,"sentence":"The bargain is very pure: Employee puts in hours of physical or mental labor and employee draws out life-sustaining moola.","path":"english2/2015.html"},{"id":"english2-2015-t1-p5-s1","examKey":"english2","examLabel":"英语二","year":"2015","text":1,"paragraph":5,"sentenceNo":1,"sentence":"Q25 段落定位 On the home front, however, people have no such clarity.","path":"english2/2015.html"},{"id":"english2-2015-t1-p5-s2","examKey":"english2","examLabel":"英语二","year":"2015","text":1,"paragraph":5,"sentenceNo":2,"sentence":"Rare is the household in which the division of labor is so clinically and methodically laid out.","path":"english2/2015.html"},{"id":"english2-2015-t1-p5-s3","examKey":"english2","examLabel":"英语二","year":"2015","text":1,"paragraph":5,"sentenceNo":3,"sentence":"There are a lot of tasks to be done, there are inadequate rewards for most of them.","path":"english2/2015.html"},{"id":"english2-2015-t1-p5-s4","examKey":"english2","examLabel":"英语二","year":"2015","text":1,"paragraph":5,"sentenceNo":4,"sentence":"Your home colleagues – your family – have no clear rewards for their labor; they need to be talked into it, or if they’re teenagers, threatened with complete removal of all electronic devices.","path":"english2/2015.html"},{"id":"english2-2015-t1-p5-s5","examKey":"english2","examLabel":"英语二","year":"2015","text":1,"paragraph":5,"sentenceNo":5,"sentence":"Plus, they’re your family.","path":"english2/2015.html"},{"id":"english2-2015-t1-p5-s6","examKey":"english2","examLabel":"英语二","year":"2015","text":1,"paragraph":5,"sentenceNo":6,"sentence":"You cannot fire your family.","path":"english2/2015.html"},{"id":"english2-2015-t1-p5-s7","examKey":"english2","examLabel":"英语二","year":"2015","text":1,"paragraph":5,"sentenceNo":7,"sentence":"You never really get to go home from home.","path":"english2/2015.html"},{"id":"english2-2015-t1-p6-s1","examKey":"english2","examLabel":"英语二","year":"2015","text":1,"paragraph":6,"sentenceNo":1,"sentence":"So it’s not surprising that people are more stressed at home.","path":"english2/2015.html"},{"id":"english2-2015-t1-p6-s2","examKey":"english2","examLabel":"英语二","year":"2015","text":1,"paragraph":6,"sentenceNo":2,"sentence":"Not only are the tasks apparently infinite, the co-workers are much harder to motivate.","path":"english2/2015.html"},{"id":"english2-2015-t2-p1-s1","examKey":"english2","examLabel":"英语二","year":"2015","text":2,"paragraph":1,"sentenceNo":1,"sentence":"Q26 段落定位 For years, studies have found that first-generation college students – those who do not have a parent with a college degree – lag other students on a range of education achievement factors.","path":"english2/2015.html"},{"id":"english2-2015-t2-p1-s2","examKey":"english2","examLabel":"英语二","year":"2015","text":2,"paragraph":1,"sentenceNo":2,"sentence":"Their grades are lower and their dropout rates are higher.","path":"english2/2015.html"},{"id":"english2-2015-t2-p1-s3","examKey":"english2","examLabel":"英语二","year":"2015","text":2,"paragraph":1,"sentenceNo":3,"sentence":"But since such students are most likely to advance economically if they succeed in higher education, colleges and universities have pushed for decades to recruit more of them.","path":"english2/2015.html"},{"id":"english2-2015-t2-p1-s4","examKey":"english2","examLabel":"英语二","year":"2015","text":2,"paragraph":1,"sentenceNo":4,"sentence":"This has created “a paradox” in that recruiting first-generation students, but then watching many of them fail, means that higher education has “continued to reproduce and widen, rather than close” an achievement gap based on social class, according to the depressing beginning of a paper forthcoming in the journal Psychological Science.","path":"english2/2015.html"},{"id":"english2-2015-t2-p2-s1","examKey":"english2","examLabel":"英语二","year":"2015","text":2,"paragraph":2,"sentenceNo":1,"sentence":"Q27 段落定位 But the article is actually quite optimistic, as it outlines a potential solution to this problem, suggesting that an approach (which involves a one-hour, next-to-no-cost program) can close 63 percent of the achievement gap (measured by such factors as grades) between first-generation and other students.","path":"english2/2015.html"},{"id":"english2-2015-t2-p3-s1","examKey":"english2","examLabel":"英语二","year":"2015","text":2,"paragraph":3,"sentenceNo":1,"sentence":"Q28 段落定位 The authors of the paper are from different universities, and their findings are based on a study involving 147 students (who completed the project) at an unnamed private university.","path":"english2/2015.html"},{"id":"english2-2015-t2-p3-s2","examKey":"english2","examLabel":"英语二","year":"2015","text":2,"paragraph":3,"sentenceNo":2,"sentence":"First generation was defined as not having a parent with a four-year college degree.","path":"english2/2015.html"},{"id":"english2-2015-t2-p3-s3","examKey":"english2","examLabel":"英语二","year":"2015","text":2,"paragraph":3,"sentenceNo":3,"sentence":"Most of the first-generation students (59.1 percent) were recipients of Pell Grants, a federal grant for undergraduates with financial need, while this was true only for 8.6 percent of the students with at least one parent with a four-year degree.","path":"english2/2015.html"},{"id":"english2-2015-t2-p4-s1","examKey":"english2","examLabel":"英语二","year":"2015","text":2,"paragraph":4,"sentenceNo":1,"sentence":"Q29 段落定位 Their thesis – that a relatively modest intervention could have a big impact – was based on the view that first-generation students may be most lacking not in potential but in practical knowledge about how to deal with the issues that face most college students.","path":"english2/2015.html"},{"id":"english2-2015-t2-p4-s2","examKey":"english2","examLabel":"英语二","year":"2015","text":2,"paragraph":4,"sentenceNo":2,"sentence":"They cite past research by several authors to show that this is the gap that must be narrowed to close the achievement gap.","path":"english2/2015.html"},{"id":"english2-2015-t2-p5-s1","examKey":"english2","examLabel":"英语二","year":"2015","text":2,"paragraph":5,"sentenceNo":1,"sentence":"Q30 段落定位 Many first-generation students “struggle to navigate the middle-class culture of higher education, learn the ‘rules of the game,’ and take advantage of college resources,” they write.","path":"english2/2015.html"},{"id":"english2-2015-t2-p5-s2","examKey":"english2","examLabel":"英语二","year":"2015","text":2,"paragraph":5,"sentenceNo":2,"sentence":"And this becomes more of a problem when colleges don’t talk about the class advantages and disadvantages of different groups of students.","path":"english2/2015.html"},{"id":"english2-2015-t2-p5-s3","examKey":"english2","examLabel":"英语二","year":"2015","text":2,"paragraph":5,"sentenceNo":3,"sentence":"“Because US colleges and universities seldom acknowledge how social class can affect students’ educational experiences, many first-generation students lack insight about why they are struggling and do not understand how students ‘like them’ can improve.”","path":"english2/2015.html"},{"id":"english2-2015-t3-p1-s1","examKey":"english2","examLabel":"英语二","year":"2015","text":3,"paragraph":1,"sentenceNo":1,"sentence":"Q31 人物定位 Even in traditional offices, “the lingua franca of corporate America has gotten much more emotional and much more right-brained than it was 20 years ago,” said Harvard Business School professor Nancy Koehn.","path":"english2/2015.html"},{"id":"english2-2015-t3-p1-s2","examKey":"english2","examLabel":"英语二","year":"2015","text":3,"paragraph":1,"sentenceNo":2,"sentence":"She started spinning off examples.","path":"english2/2015.html"},{"id":"english2-2015-t3-p1-s3","examKey":"english2","examLabel":"英语二","year":"2015","text":3,"paragraph":1,"sentenceNo":3,"sentence":"“If you and I parachuted back to Fortune 500 companies in 1990, we would see much less frequent use of terms like journey, mission, passion.","path":"english2/2015.html"},{"id":"english2-2015-t3-p1-s4","examKey":"english2","examLabel":"英语二","year":"2015","text":3,"paragraph":1,"sentenceNo":4,"sentence":"There were goals, there were strategies, there were objectives, but we didn’t talk about energy; we didn’t talk about passion.”","path":"english2/2015.html"},{"id":"english2-2015-t3-p2-s1","examKey":"english2","examLabel":"英语二","year":"2015","text":3,"paragraph":2,"sentenceNo":1,"sentence":"Q32 段落定位 Koehn pointed out that this new era of corporate vocabulary is very “team”-oriented – and not by coincidence.","path":"english2/2015.html"},{"id":"english2-2015-t3-p2-s2","examKey":"english2","examLabel":"英语二","year":"2015","text":3,"paragraph":2,"sentenceNo":2,"sentence":"“Let’s not forget sports – in male-dominated corporate America, it’s still a big deal.","path":"english2/2015.html"},{"id":"english2-2015-t3-p2-s3","examKey":"english2","examLabel":"英语二","year":"2015","text":3,"paragraph":2,"sentenceNo":3,"sentence":"It’s not explicitly conscious; it’s the idea that I’m a coach, and you’re my team, and we’re in this together.","path":"english2/2015.html"},{"id":"english2-2015-t3-p2-s4","examKey":"english2","examLabel":"英语二","year":"2015","text":3,"paragraph":2,"sentenceNo":4,"sentence":"There are lots and lots of CEOs in very different companies, but most think of themselves as coaches and this is their team and they want to win.”","path":"english2/2015.html"},{"id":"english2-2015-t3-p3-s1","examKey":"english2","examLabel":"英语二","year":"2015","text":3,"paragraph":3,"sentenceNo":1,"sentence":"Q33 人物定位 These terms are also intended to infuse work with meaning – and, as Rakesh Khurana, another professor, points out, increase allegiance to the firm.","path":"english2/2015.html"},{"id":"english2-2015-t3-p3-s2","examKey":"english2","examLabel":"英语二","year":"2015","text":3,"paragraph":3,"sentenceNo":2,"sentence":"“You have the importation of terminology that historically used to be associated with non-profit organizations and religious organizations: terms like vision, values, passion, and purpose,” said Khurana.","path":"english2/2015.html"},{"id":"english2-2015-t3-p4-s1","examKey":"english2","examLabel":"英语二","year":"2015","text":3,"paragraph":4,"sentenceNo":1,"sentence":"Q34 段落定位 This new focus on personal fulfillment can help keep employees motivated amid increasingly loud debates over work-life balance.","path":"english2/2015.html"},{"id":"english2-2015-t3-p4-s2","examKey":"english2","examLabel":"英语二","year":"2015","text":3,"paragraph":4,"sentenceNo":2,"sentence":"The “mommy wars” of the 1990s are still going on today, prompting arguments about why women still can’t have it all and books like Sheryl Sandberg’s Lean In, whose title has become a buzzword in its own right.","path":"english2/2015.html"},{"id":"english2-2015-t3-p4-s3","examKey":"english2","examLabel":"英语二","year":"2015","text":3,"paragraph":4,"sentenceNo":3,"sentence":"Terms like unplug, offline, life-hack, bandwidth, and capacity are all about setting boundaries between the office and the home.","path":"english2/2015.html"},{"id":"english2-2015-t3-p4-s4","examKey":"english2","examLabel":"英语二","year":"2015","text":3,"paragraph":4,"sentenceNo":4,"sentence":"But if your work is your “passion,” you’ll be more likely to devote yourself to it, even if that means going home for dinner and then working long after the kids are in bed.","path":"english2/2015.html"},{"id":"english2-2015-t3-p5-s1","examKey":"english2","examLabel":"英语二","year":"2015","text":3,"paragraph":5,"sentenceNo":1,"sentence":"Q35 段落定位 But this seems to be the irony of office speak: Everyone makes fun of it, but managers love it, companies depend on it, and regular people willingly absorb it.","path":"english2/2015.html"},{"id":"english2-2015-t3-p5-s2","examKey":"english2","examLabel":"英语二","year":"2015","text":3,"paragraph":5,"sentenceNo":2,"sentence":"As a linguist once said, “You can get people to think it’s nonsense at the same time that you buy into it.” In a workplace that’s fundamentally indifferent to your life and its meaning, office speak can help you figure out how you relate to your work – and how your work defines who you are.","path":"english2/2015.html"},{"id":"english2-2015-t4-p1-s1","examKey":"english2","examLabel":"英语二","year":"2015","text":4,"paragraph":1,"sentenceNo":1,"sentence":"Q40 全文主线 Many people talked of the 288,000 new jobs the Labor Department reported for June, along with the drop in the unemployment rate to 6.1 percent, as good news.","path":"english2/2015.html"},{"id":"english2-2015-t4-p1-s2","examKey":"english2","examLabel":"英语二","year":"2015","text":4,"paragraph":1,"sentenceNo":2,"sentence":"And they were right.","path":"english2/2015.html"},{"id":"english2-2015-t4-p1-s3","examKey":"english2","examLabel":"英语二","year":"2015","text":4,"paragraph":1,"sentenceNo":3,"sentence":"For now it appears the economy is creating jobs at a decent pace.","path":"english2/2015.html"},{"id":"english2-2015-t4-p1-s4","examKey":"english2","examLabel":"英语二","year":"2015","text":4,"paragraph":1,"sentenceNo":4,"sentence":"We still have a long way to go to get back to full employment, but at least we are now finally moving forward at a faster pace.","path":"english2/2015.html"},{"id":"english2-2015-t4-p2-s1","examKey":"english2","examLabel":"英语二","year":"2015","text":4,"paragraph":2,"sentenceNo":1,"sentence":"Q36 段落定位 However, there is another important part of the jobs picture that was largely overlooked.","path":"english2/2015.html"},{"id":"english2-2015-t4-p2-s2","examKey":"english2","examLabel":"英语二","year":"2015","text":4,"paragraph":2,"sentenceNo":2,"sentence":"There was a big jump in the number of people who report voluntarily working part-time.","path":"english2/2015.html"},{"id":"english2-2015-t4-p2-s3","examKey":"english2","examLabel":"英语二","year":"2015","text":4,"paragraph":2,"sentenceNo":3,"sentence":"This figure is now 830,000 (4.4 percent) above its year ago level.","path":"english2/2015.html"},{"id":"english2-2015-t4-p3-s1","examKey":"english2","examLabel":"英语二","year":"2015","text":4,"paragraph":3,"sentenceNo":1,"sentence":"Q37 段落定位 Before explaining the connection to the Obamacare, it is worth making an important distinction.","path":"english2/2015.html"},{"id":"english2-2015-t4-p3-s2","examKey":"english2","examLabel":"英语二","year":"2015","text":4,"paragraph":3,"sentenceNo":2,"sentence":"Many people who work part-time jobs actually want full-time jobs.","path":"english2/2015.html"},{"id":"english2-2015-t4-p3-s3","examKey":"english2","examLabel":"英语二","year":"2015","text":4,"paragraph":3,"sentenceNo":3,"sentence":"They take part-time work because this is all they can get.","path":"english2/2015.html"},{"id":"english2-2015-t4-p3-s4","examKey":"english2","examLabel":"英语二","year":"2015","text":4,"paragraph":3,"sentenceNo":4,"sentence":"An increase in involuntary part-time work is evidence of weakness in the labor market and it means that many people will be having a very hard time making ends meet.","path":"english2/2015.html"},{"id":"english2-2015-t4-p4-s1","examKey":"english2","examLabel":"英语二","year":"2015","text":4,"paragraph":4,"sentenceNo":1,"sentence":"Q38 段落定位 There was an increase in involuntary part-time in June, but the general direction has been down.","path":"english2/2015.html"},{"id":"english2-2015-t4-p4-s2","examKey":"english2","examLabel":"英语二","year":"2015","text":4,"paragraph":4,"sentenceNo":2,"sentence":"Involuntary part-time employment is still far higher than before the recession, but it is down by 640,000 (7.9 percent) from its year ago level.","path":"english2/2015.html"},{"id":"english2-2015-t4-p5-s1","examKey":"english2","examLabel":"英语二","year":"2015","text":4,"paragraph":5,"sentenceNo":1,"sentence":"Q40 分类支线 We know the difference between voluntary and involuntary part-time employment because people tell us.","path":"english2/2015.html"},{"id":"english2-2015-t4-p5-s2","examKey":"english2","examLabel":"英语二","year":"2015","text":4,"paragraph":5,"sentenceNo":2,"sentence":"The survey used by the Labor Department asks people if they worked less than 35 hours in the reference week.","path":"english2/2015.html"},{"id":"english2-2015-t4-p5-s3","examKey":"english2","examLabel":"英语二","year":"2015","text":4,"paragraph":5,"sentenceNo":3,"sentence":"If the answer is “yes,” they are classified as working part-time.","path":"english2/2015.html"},{"id":"english2-2015-t4-p5-s4","examKey":"english2","examLabel":"英语二","year":"2015","text":4,"paragraph":5,"sentenceNo":4,"sentence":"The survey then asks whether they worked less than 35 hours in that week because they wanted to work less than full time or because they had no choice.","path":"english2/2015.html"},{"id":"english2-2015-t4-p5-s5","examKey":"english2","examLabel":"英语二","year":"2015","text":4,"paragraph":5,"sentenceNo":5,"sentence":"They are only classified as voluntary part-time workers if they tell the survey taker they chose to work less than 35 hours a week.","path":"english2/2015.html"},{"id":"english2-2015-t4-p6-s1","examKey":"english2","examLabel":"英语二","year":"2015","text":4,"paragraph":6,"sentenceNo":1,"sentence":"Q39 段落定位 The issue of voluntary part-time relates to Obamacare because one of the main purposes was to allow people to get insurance outside of employment.","path":"english2/2015.html"},{"id":"english2-2015-t4-p6-s2","examKey":"english2","examLabel":"英语二","year":"2015","text":4,"paragraph":6,"sentenceNo":2,"sentence":"For many people, especially those with serious health conditions or family members with serious health conditions, before Obamacare the only way to get insurance was through a job that provided health insurance.","path":"english2/2015.html"},{"id":"english2-2015-t4-p7-s1","examKey":"english2","examLabel":"英语二","year":"2015","text":4,"paragraph":7,"sentenceNo":1,"sentence":"However, Obamacare has allowed more than 12 million people to either get insurance through Medicaid or the exchanges.","path":"english2/2015.html"},{"id":"english2-2015-t4-p7-s2","examKey":"english2","examLabel":"英语二","year":"2015","text":4,"paragraph":7,"sentenceNo":2,"sentence":"These are people who may previously have felt the need to get a full-time job that provided insurance in order to cover themselves and their families.","path":"english2/2015.html"},{"id":"english2-2015-t4-p7-s3","examKey":"english2","examLabel":"英语二","year":"2015","text":4,"paragraph":7,"sentenceNo":3,"sentence":"With Obamacare there is no longer a link between employment and insurance.","path":"english2/2015.html"},{"id":"english1-2016-t1-p1-s1","examKey":"english1","examLabel":"英语一","year":"2016","text":1,"paragraph":1,"sentenceNo":1,"sentence":"France, which prides itself as the global innovator of fashion, has decided its fashion industry has lost an absolute right to define physical beauty for women.","path":"english1/2016.html"},{"id":"english1-2016-t1-p1-s2","examKey":"english1","examLabel":"英语一","year":"2016","text":1,"paragraph":1,"sentenceNo":2,"sentence":"Its lawmakers gave preliminary approval last week to a law that would make it a crime to employ ultra-thin models on runways.","path":"english1/2016.html"},{"id":"english1-2016-t1-p1-s3","examKey":"english1","examLabel":"英语一","year":"2016","text":1,"paragraph":1,"sentenceNo":3,"sentence":"The parliament also agreed to ban websites that “incite excessive thinness” by promoting extreme dieting.","path":"english1/2016.html"},{"id":"english1-2016-t1-p2-s1","examKey":"english1","examLabel":"英语一","year":"2016","text":1,"paragraph":2,"sentenceNo":1,"sentence":"Such measures have a couple of uplifting motives.","path":"english1/2016.html"},{"id":"english1-2016-t1-p2-s2","examKey":"english1","examLabel":"英语一","year":"2016","text":1,"paragraph":2,"sentenceNo":2,"sentence":"They suggest beauty should not be defined by looks that end up impinging on health.","path":"english1/2016.html"},{"id":"english1-2016-t1-p2-s3","examKey":"english1","examLabel":"英语一","year":"2016","text":1,"paragraph":2,"sentenceNo":3,"sentence":"That’s a start.","path":"english1/2016.html"},{"id":"english1-2016-t1-p2-s4","examKey":"english1","examLabel":"英语一","year":"2016","text":1,"paragraph":2,"sentenceNo":4,"sentence":"And the ban on ultra-thin models seems to go beyond protecting models from starving themselves to death—as some have done.","path":"english1/2016.html"},{"id":"english1-2016-t1-p2-s5","examKey":"english1","examLabel":"英语一","year":"2016","text":1,"paragraph":2,"sentenceNo":5,"sentence":"It tells the fashion industry that it must take responsibility for the signal it sends women, especially teenage girls, about the social tape-measure they must use to determine their individual worth.","path":"english1/2016.html"},{"id":"english1-2016-t1-p3-s1","examKey":"english1","examLabel":"英语一","year":"2016","text":1,"paragraph":3,"sentenceNo":1,"sentence":"The bans, if fully enforced, would suggest to women (and many men) that they should not let others be arbiters of their beauty.","path":"english1/2016.html"},{"id":"english1-2016-t1-p3-s2","examKey":"english1","examLabel":"英语一","year":"2016","text":1,"paragraph":3,"sentenceNo":2,"sentence":"And perhaps faintly, they hint that people should look to intangible qualities like character and intellect rather than dieting their way to size zero or wasp-waist physiques.","path":"english1/2016.html"},{"id":"english1-2016-t1-p4-s1","examKey":"english1","examLabel":"英语一","year":"2016","text":1,"paragraph":4,"sentenceNo":1,"sentence":"The French measures, however, rely too much on severe punishment to change a culture that still regards beauty as skin-deep—and bone-showing.","path":"english1/2016.html"},{"id":"english1-2016-t1-p4-s2","examKey":"english1","examLabel":"英语一","year":"2016","text":1,"paragraph":4,"sentenceNo":2,"sentence":"Under the law, using a fashion model that does not meet a government-defined index of body mass could result in a $85,000 fine and six months in prison.","path":"english1/2016.html"},{"id":"english1-2016-t1-p5-s1","examKey":"english1","examLabel":"英语一","year":"2016","text":1,"paragraph":5,"sentenceNo":1,"sentence":"The fashion industry knows it has an inherent problem in focusing on material adornment and idealized body types.","path":"english1/2016.html"},{"id":"english1-2016-t1-p5-s2","examKey":"english1","examLabel":"英语一","year":"2016","text":1,"paragraph":5,"sentenceNo":2,"sentence":"In Denmark, the United States, and a few other countries, it is trying to set voluntary standards for models and fashion images that rely more on peer pressure for enforcement.","path":"english1/2016.html"},{"id":"english1-2016-t1-p6-s1","examKey":"english1","examLabel":"英语一","year":"2016","text":1,"paragraph":6,"sentenceNo":1,"sentence":"In contrast to France’s actions, Denmark’s fashion industry agreed last month on rules and sanctions regarding the age, health, and other characteristics of models.","path":"english1/2016.html"},{"id":"english1-2016-t1-p6-s2","examKey":"english1","examLabel":"英语一","year":"2016","text":1,"paragraph":6,"sentenceNo":2,"sentence":"The newly revised Danish Fashion Ethical Charter clearly states: “We are aware of and take responsibility for the impact the fashion industry has on body ideals, especially on young people.” The charter’s main tool of enforcement is to deny access for designers and modeling agencies to Copenhagen Fashion Week (CFW), which is run by the Danish Fashion Institute.","path":"english1/2016.html"},{"id":"english1-2016-t1-p6-s3","examKey":"english1","examLabel":"英语一","year":"2016","text":1,"paragraph":6,"sentenceNo":3,"sentence":"But in general it relies on a name-and-shame method of compliance.","path":"english1/2016.html"},{"id":"english1-2016-t1-p7-s1","examKey":"english1","examLabel":"英语一","year":"2016","text":1,"paragraph":7,"sentenceNo":1,"sentence":"Relying on ethical persuasion rather than law to address the misuse of body ideals may be the best step.","path":"english1/2016.html"},{"id":"english1-2016-t1-p7-s2","examKey":"english1","examLabel":"英语一","year":"2016","text":1,"paragraph":7,"sentenceNo":2,"sentence":"Even better would be to help elevate notions of beauty beyond the material standards of a particular industry.","path":"english1/2016.html"},{"id":"english1-2016-t2-p1-s1","examKey":"english1","examLabel":"英语一","year":"2016","text":2,"paragraph":1,"sentenceNo":1,"sentence":"For the first time in his tory more people live in towns than in the country.","path":"english1/2016.html"},{"id":"english1-2016-t2-p1-s2","examKey":"english1","examLabel":"英语一","year":"2016","text":2,"paragraph":1,"sentenceNo":2,"sentence":"In Britain this has had a curious result.","path":"english1/2016.html"},{"id":"english1-2016-t2-p1-s3","examKey":"english1","examLabel":"英语一","year":"2016","text":2,"paragraph":1,"sentenceNo":3,"sentence":"While polls show Britons rate “the countryside” alongside the royal family, Shakespeare and the National Health Service (NHS) as what makes them proud of their country, this has limited political support.","path":"english1/2016.html"},{"id":"english1-2016-t2-p2-s1","examKey":"english1","examLabel":"英语一","year":"2016","text":2,"paragraph":2,"sentenceNo":1,"sentence":"A century ago Octavia Hill launched the National Trust not to rescue stylish houses but to “save the beauty of natural places for everyone forever.” It was specifically to provide city dwellers with spaces for leisure where they could experience “a refreshing air.” Hill’s pressure later led to the creation of national parks and green belts.","path":"english1/2016.html"},{"id":"english1-2016-t2-p2-s2","examKey":"english1","examLabel":"英语一","year":"2016","text":2,"paragraph":2,"sentenceNo":2,"sentence":"They don’t make countryside any more, and every year concrete consumes more of it.","path":"english1/2016.html"},{"id":"english1-2016-t2-p2-s3","examKey":"english1","examLabel":"英语一","year":"2016","text":2,"paragraph":2,"sentenceNo":3,"sentence":"It needs constant guardianship.","path":"english1/2016.html"},{"id":"english1-2016-t2-p3-s1","examKey":"english1","examLabel":"英语一","year":"2016","text":2,"paragraph":3,"sentenceNo":1,"sentence":"At the next election none of the big parties seem likely to endorse this sentiment.","path":"english1/2016.html"},{"id":"english1-2016-t2-p3-s2","examKey":"english1","examLabel":"英语一","year":"2016","text":2,"paragraph":3,"sentenceNo":2,"sentence":"The Conservatives’ planning reform explicitly gives rural development priority over conservation, even authorising “off-plan” building where local people might object.","path":"english1/2016.html"},{"id":"english1-2016-t2-p3-s3","examKey":"english1","examLabel":"英语一","year":"2016","text":2,"paragraph":3,"sentenceNo":3,"sentence":"The concept of sustainable development has been defined as profitable.","path":"english1/2016.html"},{"id":"english1-2016-t2-p3-s4","examKey":"english1","examLabel":"英语一","year":"2016","text":2,"paragraph":3,"sentenceNo":4,"sentence":"Labour likewise wants to discontinue local planning where councils oppose development.","path":"english1/2016.html"},{"id":"english1-2016-t2-p3-s5","examKey":"english1","examLabel":"英语一","year":"2016","text":2,"paragraph":3,"sentenceNo":5,"sentence":"The Liberal Democrats are silent.","path":"english1/2016.html"},{"id":"english1-2016-t2-p3-s6","examKey":"english1","examLabel":"英语一","year":"2016","text":2,"paragraph":3,"sentenceNo":6,"sentence":"Only Ukip, sensing its chance, has sided with those pleading for a more considered approach to using green land.","path":"english1/2016.html"},{"id":"english1-2016-t2-p3-s7","examKey":"english1","examLabel":"英语一","year":"2016","text":2,"paragraph":3,"sentenceNo":7,"sentence":"Its Campaign to Protect Rural England struck terror into many local Conservative parties.","path":"english1/2016.html"},{"id":"english1-2016-t2-p4-s1","examKey":"english1","examLabel":"英语一","year":"2016","text":2,"paragraph":4,"sentenceNo":1,"sentence":"The sensible place to build new houses, factories and offices is where people are, in cities and towns where infrastructure is in place.","path":"english1/2016.html"},{"id":"english1-2016-t2-p4-s2","examKey":"english1","examLabel":"英语一","year":"2016","text":2,"paragraph":4,"sentenceNo":2,"sentence":"The London agent Stirling Ackroyd recently identified enough sites for half a million houses in the London area alone, with no intrusion on green belt.","path":"english1/2016.html"},{"id":"english1-2016-t2-p4-s3","examKey":"english1","examLabel":"英语一","year":"2016","text":2,"paragraph":4,"sentenceNo":3,"sentence":"What is true of London is even truer of the provinces.","path":"english1/2016.html"},{"id":"english1-2016-t2-p5-s1","examKey":"english1","examLabel":"英语一","year":"2016","text":2,"paragraph":5,"sentenceNo":1,"sentence":"The idea that “housing crisis” equals “concreted meadows” is pure lobby talk.","path":"english1/2016.html"},{"id":"english1-2016-t2-p5-s2","examKey":"english1","examLabel":"英语一","year":"2016","text":2,"paragraph":5,"sentenceNo":2,"sentence":"The issue is not the need for more houses but, as always, where to put them.","path":"english1/2016.html"},{"id":"english1-2016-t2-p5-s3","examKey":"english1","examLabel":"英语一","year":"2016","text":2,"paragraph":5,"sentenceNo":3,"sentence":"Under lobby pressure, George Osborne favours rural new-build against urban renovation and renewal.","path":"english1/2016.html"},{"id":"english1-2016-t2-p5-s4","examKey":"english1","examLabel":"英语一","year":"2016","text":2,"paragraph":5,"sentenceNo":4,"sentence":"He favours out-of-town shopping sites against high streets.","path":"english1/2016.html"},{"id":"english1-2016-t2-p5-s5","examKey":"english1","examLabel":"英语一","year":"2016","text":2,"paragraph":5,"sentenceNo":5,"sentence":"This is not a free market but a biased one.","path":"english1/2016.html"},{"id":"english1-2016-t2-p5-s6","examKey":"english1","examLabel":"英语一","year":"2016","text":2,"paragraph":5,"sentenceNo":6,"sentence":"Rural towns and villages have grown and will always grow.","path":"english1/2016.html"},{"id":"english1-2016-t2-p5-s7","examKey":"english1","examLabel":"英语一","year":"2016","text":2,"paragraph":5,"sentenceNo":7,"sentence":"They do so best where building sticks to their edges and respects their character.","path":"english1/2016.html"},{"id":"english1-2016-t2-p5-s8","examKey":"english1","examLabel":"英语一","year":"2016","text":2,"paragraph":5,"sentenceNo":8,"sentence":"We do not ruin urban conservation areas.","path":"english1/2016.html"},{"id":"english1-2016-t2-p5-s9","examKey":"english1","examLabel":"英语一","year":"2016","text":2,"paragraph":5,"sentenceNo":9,"sentence":"Why ruin rural ones?","path":"english1/2016.html"},{"id":"english1-2016-t2-p6-s1","examKey":"english1","examLabel":"英语一","year":"2016","text":2,"paragraph":6,"sentenceNo":1,"sentence":"Development should be planned, not let rip.","path":"english1/2016.html"},{"id":"english1-2016-t2-p6-s2","examKey":"english1","examLabel":"英语一","year":"2016","text":2,"paragraph":6,"sentenceNo":2,"sentence":"After the Netherlands, Britain is Europe’s most crowded country.","path":"english1/2016.html"},{"id":"english1-2016-t2-p6-s3","examKey":"english1","examLabel":"英语一","year":"2016","text":2,"paragraph":6,"sentenceNo":3,"sentence":"Half a century of town and country planning has enabled it to retain an enviable rural coherence, while still permitting low-density urban living.","path":"english1/2016.html"},{"id":"english1-2016-t2-p6-s4","examKey":"english1","examLabel":"英语一","year":"2016","text":2,"paragraph":6,"sentenceNo":4,"sentence":"There is no doubt of the alternative—the corrupted landscapes of southern Portugal, Spain or Ireland.","path":"english1/2016.html"},{"id":"english1-2016-t2-p6-s5","examKey":"english1","examLabel":"英语一","year":"2016","text":2,"paragraph":6,"sentenceNo":5,"sentence":"Avoiding this rather than promoting it should unite the left and right of the political spectrum.","path":"english1/2016.html"},{"id":"english1-2016-t3-p1-s1","examKey":"english1","examLabel":"英语一","year":"2016","text":3,"paragraph":1,"sentenceNo":1,"sentence":"“There is one and only one social responsibility of business,” wrote Milton Friedman, a Nobel prize-winning economist, “That is, to use its resources and engage in activities designed to increase its profits.” But even if you accept Friedman’s premise and regard corporate social responsibility (CSR) policies as a waste of shareholders’ money, things may not be absolutely clear-cut.","path":"english1/2016.html"},{"id":"english1-2016-t3-p1-s2","examKey":"english1","examLabel":"英语一","year":"2016","text":3,"paragraph":1,"sentenceNo":2,"sentence":"New research suggests that CSR may create monetary value for companies—at least when they are prosecuted for corruption.","path":"english1/2016.html"},{"id":"english1-2016-t3-p2-s1","examKey":"english1","examLabel":"英语一","year":"2016","text":3,"paragraph":2,"sentenceNo":1,"sentence":"The largest firms in America and Britain together spend more than $15 billion a year on CSR, according to an estimate by EPG, a consulting firm.","path":"english1/2016.html"},{"id":"english1-2016-t3-p2-s2","examKey":"english1","examLabel":"英语一","year":"2016","text":3,"paragraph":2,"sentenceNo":2,"sentence":"This could add value to their businesses in three ways.","path":"english1/2016.html"},{"id":"english1-2016-t3-p2-s3","examKey":"english1","examLabel":"英语一","year":"2016","text":3,"paragraph":2,"sentenceNo":3,"sentence":"First, consumers may take CSR spending as a “signal” that a company’s products are of high quality.","path":"english1/2016.html"},{"id":"english1-2016-t3-p2-s4","examKey":"english1","examLabel":"英语一","year":"2016","text":3,"paragraph":2,"sentenceNo":4,"sentence":"Second, customers may be willing to buy a company’s products as an indirect way to donate to the good causes it helps.","path":"english1/2016.html"},{"id":"english1-2016-t3-p2-s5","examKey":"english1","examLabel":"英语一","year":"2016","text":3,"paragraph":2,"sentenceNo":5,"sentence":"And third, through a more diffuse “halo effect,” whereby its good deeds earn it greater consideration from consumers and others.","path":"english1/2016.html"},{"id":"english1-2016-t3-p3-s1","examKey":"english1","examLabel":"英语一","year":"2016","text":3,"paragraph":3,"sentenceNo":1,"sentence":"Previous studies on CSR have had trouble differentiating these effects because consumers can be affected by all three.","path":"english1/2016.html"},{"id":"english1-2016-t3-p3-s2","examKey":"english1","examLabel":"英语一","year":"2016","text":3,"paragraph":3,"sentenceNo":2,"sentence":"A recent study attempts to se para te them by looking at bribery prosecutions under America’s Foreign Corrupt Practices Act (FCPA).","path":"english1/2016.html"},{"id":"english1-2016-t3-p3-s3","examKey":"english1","examLabel":"英语一","year":"2016","text":3,"paragraph":3,"sentenceNo":3,"sentence":"It argues that since prosecutors do not consume a company’s products as part of their investigations, they could be influenced only by the halo effect.","path":"english1/2016.html"},{"id":"english1-2016-t3-p4-s1","examKey":"english1","examLabel":"英语一","year":"2016","text":3,"paragraph":4,"sentenceNo":1,"sentence":"The study found that, among prosecuted firms, those with the most comprehensive CSR programmes tended to get more lenient penalties.","path":"english1/2016.html"},{"id":"english1-2016-t3-p4-s2","examKey":"english1","examLabel":"英语一","year":"2016","text":3,"paragraph":4,"sentenceNo":2,"sentence":"Their analysis ruled out the possibility that it was firms’ political influence, rather than their CSR stand, that accounted for the leniency: Companies that contributed more to political campaigns did not receive lower fines.","path":"english1/2016.html"},{"id":"english1-2016-t3-p5-s1","examKey":"english1","examLabel":"英语一","year":"2016","text":3,"paragraph":5,"sentenceNo":1,"sentence":"In all, the study concludes that whereas prosecutors should only evaluate a case based on its merits, they do seem to be influenced by a company’s record in CSR.","path":"english1/2016.html"},{"id":"english1-2016-t3-p5-s2","examKey":"english1","examLabel":"英语一","year":"2016","text":3,"paragraph":5,"sentenceNo":2,"sentence":"“We estimate that either eliminating a substantial labour-rights concern, such as child labour, or increasing corporate giving by about 20% results in fines that generally are 40% lower than the typical punishment for bribing foreign officials,” says one researcher.","path":"english1/2016.html"},{"id":"english1-2016-t3-p6-s1","examKey":"english1","examLabel":"英语一","year":"2016","text":3,"paragraph":6,"sentenceNo":1,"sentence":"Researchers admit that their study does not answer the question of how much businesses ought to spend on CSR.","path":"english1/2016.html"},{"id":"english1-2016-t3-p6-s2","examKey":"english1","examLabel":"英语一","year":"2016","text":3,"paragraph":6,"sentenceNo":2,"sentence":"Nor does it reveal how much companies are banking on the halo effect, rather than the other possible benefits, when they decide their do-gooding policies.","path":"english1/2016.html"},{"id":"english1-2016-t3-p6-s3","examKey":"english1","examLabel":"英语一","year":"2016","text":3,"paragraph":6,"sentenceNo":3,"sentence":"But at least they have demonstrated that when companies get into trouble with the law, evidence of good character can win them a less costly punishment.","path":"english1/2016.html"},{"id":"english1-2016-t4-p1-s1","examKey":"english1","examLabel":"英语一","year":"2016","text":4,"paragraph":1,"sentenceNo":1,"sentence":"There will eventually come a day when The New York Times ceases to publish stories on newsprint.","path":"english1/2016.html"},{"id":"english1-2016-t4-p1-s2","examKey":"english1","examLabel":"英语一","year":"2016","text":4,"paragraph":1,"sentenceNo":2,"sentence":"Exactly when that day will be is a matter of debate.","path":"english1/2016.html"},{"id":"english1-2016-t4-p1-s3","examKey":"english1","examLabel":"英语一","year":"2016","text":4,"paragraph":1,"sentenceNo":3,"sentence":"“Sometime in the future,” the paper’s publisher said back in 2010.","path":"english1/2016.html"},{"id":"english1-2016-t4-p2-s1","examKey":"english1","examLabel":"英语一","year":"2016","text":4,"paragraph":2,"sentenceNo":1,"sentence":"Nostalgia for ink on paper and the rustle of pages aside, there’s plenty of incentive to ditch print.","path":"english1/2016.html"},{"id":"english1-2016-t4-p2-s2","examKey":"english1","examLabel":"英语一","year":"2016","text":4,"paragraph":2,"sentenceNo":2,"sentence":"The infrastructure required to make a physical newspaper—printing presses, delivery trucks—isn’t just expensive; it’s excessive at a time when online-only competitors don’t have the same set of financial constraints.","path":"english1/2016.html"},{"id":"english1-2016-t4-p2-s3","examKey":"english1","examLabel":"英语一","year":"2016","text":4,"paragraph":2,"sentenceNo":3,"sentence":"Readers are migrating away from print anyway.","path":"english1/2016.html"},{"id":"english1-2016-t4-p2-s4","examKey":"english1","examLabel":"英语一","year":"2016","text":4,"paragraph":2,"sentenceNo":4,"sentence":"And though print ad sales still dwarf their online and mobile counterparts, revenue from print is still declining.","path":"english1/2016.html"},{"id":"english1-2016-t4-p3-s1","examKey":"english1","examLabel":"英语一","year":"2016","text":4,"paragraph":3,"sentenceNo":1,"sentence":"Overhead may be high and circulation lower, but rushing to eliminate its print edition would be a mistake, says BuzzFeed CEO Jonah Peretti.","path":"english1/2016.html"},{"id":"english1-2016-t4-p4-s1","examKey":"english1","examLabel":"英语一","year":"2016","text":4,"paragraph":4,"sentenceNo":1,"sentence":"Peretti says the Times shouldn’t waste time getting out of the print business, but only if they go about doing it the right way.","path":"english1/2016.html"},{"id":"english1-2016-t4-p4-s2","examKey":"english1","examLabel":"英语一","year":"2016","text":4,"paragraph":4,"sentenceNo":2,"sentence":"“Figuring out a way to accelerate that transition would make sense for them,” he said, “but if you discontinue it, you’re going to have your most loyal customers really upset with you.”","path":"english1/2016.html"},{"id":"english1-2016-t4-p5-s1","examKey":"english1","examLabel":"英语一","year":"2016","text":4,"paragraph":5,"sentenceNo":1,"sentence":"Sometimes that’s worth making a change anyway.","path":"english1/2016.html"},{"id":"english1-2016-t4-p5-s2","examKey":"english1","examLabel":"英语一","year":"2016","text":4,"paragraph":5,"sentenceNo":2,"sentence":"Peretti gives the example of Netflix discontinuing its DVD-mailing service to focus on streaming.","path":"english1/2016.html"},{"id":"english1-2016-t4-p5-s3","examKey":"english1","examLabel":"英语一","year":"2016","text":4,"paragraph":5,"sentenceNo":3,"sentence":"“It was seen as a blunder,” he said.","path":"english1/2016.html"},{"id":"english1-2016-t4-p5-s4","examKey":"english1","examLabel":"英语一","year":"2016","text":4,"paragraph":5,"sentenceNo":4,"sentence":"The move turned out to be foresighted.","path":"english1/2016.html"},{"id":"english1-2016-t4-p5-s5","examKey":"english1","examLabel":"英语一","year":"2016","text":4,"paragraph":5,"sentenceNo":5,"sentence":"And if Peretti were in charge at the Times?","path":"english1/2016.html"},{"id":"english1-2016-t4-p5-s6","examKey":"english1","examLabel":"英语一","year":"2016","text":4,"paragraph":5,"sentenceNo":6,"sentence":"“I wouldn’t pick a year to end print,” he said.","path":"english1/2016.html"},{"id":"english1-2016-t4-p5-s7","examKey":"english1","examLabel":"英语一","year":"2016","text":4,"paragraph":5,"sentenceNo":7,"sentence":"“I would raise prices and make it into more of a legacy product.”","path":"english1/2016.html"},{"id":"english1-2016-t4-p6-s1","examKey":"english1","examLabel":"英语一","year":"2016","text":4,"paragraph":6,"sentenceNo":1,"sentence":"The most loyal customers would still get the product they favor, the idea goes, and they’d feel like they were helping sustain the quality of something they believe in.","path":"english1/2016.html"},{"id":"english1-2016-t4-p6-s2","examKey":"english1","examLabel":"英语一","year":"2016","text":4,"paragraph":6,"sentenceNo":2,"sentence":"“So if you’re overpaying for print, you could feel like you were helping,” Peretti said.","path":"english1/2016.html"},{"id":"english1-2016-t4-p6-s3","examKey":"english1","examLabel":"英语一","year":"2016","text":4,"paragraph":6,"sentenceNo":3,"sentence":"“Then increase it at a higher rate each year and essentially try to generate additional revenue.” In other words, if you’re going to make a print product, make it for the people who are already obsessed with it.","path":"english1/2016.html"},{"id":"english1-2016-t4-p6-s4","examKey":"english1","examLabel":"英语一","year":"2016","text":4,"paragraph":6,"sentenceNo":4,"sentence":"Which may be what the Times is doing already.","path":"english1/2016.html"},{"id":"english1-2016-t4-p6-s5","examKey":"english1","examLabel":"英语一","year":"2016","text":4,"paragraph":6,"sentenceNo":5,"sentence":"Getting the print edition seven days a week costs nearly $500 a year—more than twice as much as a digital-only subscription.","path":"english1/2016.html"},{"id":"english1-2016-t4-p7-s1","examKey":"english1","examLabel":"英语一","year":"2016","text":4,"paragraph":7,"sentenceNo":1,"sentence":"“It’s a really hard thing to do and it’s a tremendous luxury that BuzzFeed doesn’t have a legacy business,” Peretti remarked.","path":"english1/2016.html"},{"id":"english1-2016-t4-p7-s2","examKey":"english1","examLabel":"英语一","year":"2016","text":4,"paragraph":7,"sentenceNo":2,"sentence":"“But we’re going to have questions like that where we have things we’re doing that don’t make sense when the market changes and the world changes.","path":"english1/2016.html"},{"id":"english1-2016-t4-p7-s3","examKey":"english1","examLabel":"英语一","year":"2016","text":4,"paragraph":7,"sentenceNo":3,"sentence":"In those situations, it’s better to be more aggressive than less aggressive.”","path":"english1/2016.html"},{"id":"english2-2016-t1-p1-s1","examKey":"english2","examLabel":"英语二","year":"2016","text":1,"paragraph":1,"sentenceNo":1,"sentence":"1 It’s true that high-school coding classes aren’t essential for learning computer science in college.","path":"english2/2016.html"},{"id":"english2-2016-t1-p1-s2","examKey":"english2","examLabel":"英语二","year":"2016","text":1,"paragraph":1,"sentenceNo":2,"sentence":"2 Students without experience can catch up after a few introductory courses, said Tom Cortina, the assistant dean at Carnegie Mellon’s School of Computer Science.","path":"english2/2016.html"},{"id":"english2-2016-t1-p2-s1","examKey":"english2","examLabel":"英语二","year":"2016","text":1,"paragraph":2,"sentenceNo":1,"sentence":"3 However, Cortina said, early exposure is beneficial.","path":"english2/2016.html"},{"id":"english2-2016-t1-p2-s2","examKey":"english2","examLabel":"英语二","year":"2016","text":1,"paragraph":2,"sentenceNo":2,"sentence":"4 When younger kids learn computer science, they learn that it’s not just a confusing, endless string of letters and numbers — but a tool to build apps, or create artwork, or test hypotheses.","path":"english2/2016.html"},{"id":"english2-2016-t1-p2-s3","examKey":"english2","examLabel":"英语二","year":"2016","text":1,"paragraph":2,"sentenceNo":3,"sentence":"5 It’s not as hard for them to transform their thought processes as it is for older students.","path":"english2/2016.html"},{"id":"english2-2016-t1-p2-s4","examKey":"english2","examLabel":"英语二","year":"2016","text":1,"paragraph":2,"sentenceNo":4,"sentence":"6 Breaking down problems into bite-sized chunks and using code to solve them becomes normal.","path":"english2/2016.html"},{"id":"english2-2016-t1-p2-s5","examKey":"english2","examLabel":"英语二","year":"2016","text":1,"paragraph":2,"sentenceNo":5,"sentence":"7 Giving more children this training could increase the number of people interested in the field and help fill the jobs gap, Cortina said.","path":"english2/2016.html"},{"id":"english2-2016-t1-p3-s1","examKey":"english2","examLabel":"英语二","year":"2016","text":1,"paragraph":3,"sentenceNo":1,"sentence":"8 Students also benefit from learning something about coding before they get to college, where introductory computer-science classes are packed to the brim, which can drive the less-experienced or -determined students away.","path":"english2/2016.html"},{"id":"english2-2016-t1-p4-s1","examKey":"english2","examLabel":"英语二","year":"2016","text":1,"paragraph":4,"sentenceNo":1,"sentence":"9 The Flatiron School, where people pay to learn programming, started as one of the many coding bootcamps that’s become popular for adults looking for a career change.","path":"english2/2016.html"},{"id":"english2-2016-t1-p4-s2","examKey":"english2","examLabel":"英语二","year":"2016","text":1,"paragraph":4,"sentenceNo":2,"sentence":"10 The high-schoolers get the same curriculum, but “we try to gear lessons toward things they’re interested in,” said Victoria Friedman, an instructor.","path":"english2/2016.html"},{"id":"english2-2016-t1-p4-s3","examKey":"english2","examLabel":"英语二","year":"2016","text":1,"paragraph":4,"sentenceNo":3,"sentence":"11 For instance, one of the apps the students are developing suggests movies based on your mood.","path":"english2/2016.html"},{"id":"english2-2016-t1-p5-s1","examKey":"english2","examLabel":"英语二","year":"2016","text":1,"paragraph":5,"sentenceNo":1,"sentence":"12 The students in the Flatiron class probably won’t drop out of high school and build the next Facebook.","path":"english2/2016.html"},{"id":"english2-2016-t1-p5-s2","examKey":"english2","examLabel":"英语二","year":"2016","text":1,"paragraph":5,"sentenceNo":2,"sentence":"13 Programming languages have a quick turnover, so the “Ruby on Rails” language they learned may not even be relevant by the time they enter the job market.","path":"english2/2016.html"},{"id":"english2-2016-t1-p5-s3","examKey":"english2","examLabel":"英语二","year":"2016","text":1,"paragraph":5,"sentenceNo":3,"sentence":"14 But the skills they learn — how to think logically through a problem and organize the results — apply to any coding language, said Deborah Seehorn, an education consultant for the state of North Carolina.","path":"english2/2016.html"},{"id":"english2-2016-t1-p6-s1","examKey":"english2","examLabel":"英语二","year":"2016","text":1,"paragraph":6,"sentenceNo":1,"sentence":"Q24 段落定位 Q25 词义定位 15 Indeed, the Flatiron students might not go into IT at all.","path":"english2/2016.html"},{"id":"english2-2016-t1-p6-s2","examKey":"english2","examLabel":"英语二","year":"2016","text":1,"paragraph":6,"sentenceNo":2,"sentence":"16 But creating a future army of coders is not the sole purpose of the classes.","path":"english2/2016.html"},{"id":"english2-2016-t1-p6-s3","examKey":"english2","examLabel":"英语二","year":"2016","text":1,"paragraph":6,"sentenceNo":3,"sentence":"17 These kids are going to be surrounded by computers — in their pockets, in their offices, in their homes — for the rest of their lives.","path":"english2/2016.html"},{"id":"english2-2016-t1-p6-s4","examKey":"english2","examLabel":"英语二","year":"2016","text":1,"paragraph":6,"sentenceNo":4,"sentence":"18 The younger they learn how computers think, how to coax the machine into producing what they want — the earlier they learn that they have the power to do that — the better.","path":"english2/2016.html"},{"id":"english2-2016-t2-p1-s1","examKey":"english2","examLabel":"英语二","year":"2016","text":2,"paragraph":1,"sentenceNo":1,"sentence":"1 Biologists estimate that as many as 2 million lesser prairie chickens — a kind of bird living on stretching grasslands — once lent red to the often grey landscape of the midwestern and southwestern United States.","path":"english2/2016.html"},{"id":"english2-2016-t2-p1-s2","examKey":"english2","examLabel":"英语二","year":"2016","text":2,"paragraph":1,"sentenceNo":2,"sentence":"But just some 22,000 birds remain today, occupying about 16% of the species’ historic range.","path":"english2/2016.html"},{"id":"english2-2016-t2-p2-s1","examKey":"english2","examLabel":"英语二","year":"2016","text":2,"paragraph":2,"sentenceNo":1,"sentence":"2 The crash was a major reason the U.S.","path":"english2/2016.html"},{"id":"english2-2016-t2-p2-s2","examKey":"english2","examLabel":"英语二","year":"2016","text":2,"paragraph":2,"sentenceNo":2,"sentence":"Fish and Wildlife Service (USFWS) decided to formally list the bird as threatened.","path":"english2/2016.html"},{"id":"english2-2016-t2-p2-s3","examKey":"english2","examLabel":"英语二","year":"2016","text":2,"paragraph":2,"sentenceNo":3,"sentence":"3 “The lesser prairie chicken is in a desperate situation,” said USFWS Director Daniel Ashe.","path":"english2/2016.html"},{"id":"english2-2016-t2-p2-s4","examKey":"english2","examLabel":"英语二","year":"2016","text":2,"paragraph":2,"sentenceNo":4,"sentence":"4 Some environmentalists, however, were disappointed.","path":"english2/2016.html"},{"id":"english2-2016-t2-p2-s5","examKey":"english2","examLabel":"英语二","year":"2016","text":2,"paragraph":2,"sentenceNo":5,"sentence":"5 They had pushed the agency to designate the bird as “endangered,” a status that gives federal officials greater regulatory power to crack down on threats.","path":"english2/2016.html"},{"id":"english2-2016-t2-p2-s6","examKey":"english2","examLabel":"英语二","year":"2016","text":2,"paragraph":2,"sentenceNo":6,"sentence":"6 But Ashe and others argued that the “threatened” tag gave the federal government flexibility to try out new, potentially less confrontational conservation approaches.","path":"english2/2016.html"},{"id":"english2-2016-t2-p2-s7","examKey":"english2","examLabel":"英语二","year":"2016","text":2,"paragraph":2,"sentenceNo":7,"sentence":"7 In particular, they called for forging closer collaborations with western state governments, which are often uneasy with federal action, and with the private landowners who control an estimated 95% of the prairie chicken’s habitat.","path":"english2/2016.html"},{"id":"english2-2016-t2-p3-s1","examKey":"english2","examLabel":"英语二","year":"2016","text":2,"paragraph":3,"sentenceNo":1,"sentence":"Q28 段落定位 8 Under the plan, for example, the agency said it would not prosecute landowners or businesses that unintentionally kill, harm, or disturb the bird, as long as they had signed a range-wide management plan to restore prairie chicken habitat.","path":"english2/2016.html"},{"id":"english2-2016-t2-p3-s2","examKey":"english2","examLabel":"英语二","year":"2016","text":2,"paragraph":3,"sentenceNo":2,"sentence":"9 Negotiated by USFWS and the states, the plan requires individuals and businesses that damage habitat as part of their operations to pay into a fund to replace every acre destroyed with 2 new acres of suitable habitat.","path":"english2/2016.html"},{"id":"english2-2016-t2-p3-s3","examKey":"english2","examLabel":"英语二","year":"2016","text":2,"paragraph":3,"sentenceNo":3,"sentence":"10 The fund will also be used to compensate landowners who set aside habitat.","path":"english2/2016.html"},{"id":"english2-2016-t2-p3-s4","examKey":"english2","examLabel":"英语二","year":"2016","text":2,"paragraph":3,"sentenceNo":4,"sentence":"11 USFWS also set an interim goal of restoring prairie chicken populations to an annual average of 67,000 birds over the next 10 years.","path":"english2/2016.html"},{"id":"english2-2016-t2-p3-s5","examKey":"english2","examLabel":"英语二","year":"2016","text":2,"paragraph":3,"sentenceNo":5,"sentence":"12 And it gives the Western Association of Fish and Wildlife Agencies (WAFWA), a coalition of state agencies, the job of monitoring progress.","path":"english2/2016.html"},{"id":"english2-2016-t2-p3-s6","examKey":"english2","examLabel":"英语二","year":"2016","text":2,"paragraph":3,"sentenceNo":6,"sentence":"Overall, the idea is to let “states remain in the driver’s seat” for managing the species, Ashe said.","path":"english2/2016.html"},{"id":"english2-2016-t2-p4-s1","examKey":"english2","examLabel":"英语二","year":"2016","text":2,"paragraph":4,"sentenceNo":1,"sentence":"13 Not everyone buys the win-win rhetoric.","path":"english2/2016.html"},{"id":"english2-2016-t2-p4-s2","examKey":"english2","examLabel":"英语二","year":"2016","text":2,"paragraph":4,"sentenceNo":2,"sentence":"14 Some Congress members are trying to block the plan, and at least a dozen industry groups, four states, and three environmental groups are challenging it in federal court.","path":"english2/2016.html"},{"id":"english2-2016-t2-p4-s3","examKey":"english2","examLabel":"英语二","year":"2016","text":2,"paragraph":4,"sentenceNo":3,"sentence":"15 Not surprisingly, industry groups and states generally argue it goes too far; environmentalists say it doesn’t go far enough.","path":"english2/2016.html"},{"id":"english2-2016-t2-p4-s4","examKey":"english2","examLabel":"英语二","year":"2016","text":2,"paragraph":4,"sentenceNo":4,"sentence":"16 “The federal government is giving responsibility for managing the bird to the same industries that are pushing it to extinction,” says biologist Jay Lininger.","path":"english2/2016.html"},{"id":"english2-2016-t3-p1-s1","examKey":"english2","examLabel":"英语二","year":"2016","text":3,"paragraph":1,"sentenceNo":1,"sentence":"1 That everyone’s too busy these days is a cliché.","path":"english2/2016.html"},{"id":"english2-2016-t3-p1-s2","examKey":"english2","examLabel":"英语二","year":"2016","text":3,"paragraph":1,"sentenceNo":2,"sentence":"But one specific complaint is made especially mournfully: There’s never any time to read.","path":"english2/2016.html"},{"id":"english2-2016-t3-p2-s1","examKey":"english2","examLabel":"英语二","year":"2016","text":3,"paragraph":2,"sentenceNo":1,"sentence":"2 What makes the problem thornier is that the usual time-management techniques don’t seem sufficient.","path":"english2/2016.html"},{"id":"english2-2016-t3-p2-s2","examKey":"english2","examLabel":"英语二","year":"2016","text":3,"paragraph":2,"sentenceNo":2,"sentence":"3 The web’s full of articles offering tips on making time to read: “Give up TV” or “Carry a book with you at all times.” 4 But in my experience, using such methods to free up the odd 30 minutes doesn’t work.","path":"english2/2016.html"},{"id":"english2-2016-t3-p2-s3","examKey":"english2","examLabel":"英语二","year":"2016","text":3,"paragraph":2,"sentenceNo":3,"sentence":"5 Sit down to read and the flywheel of work-related thoughts keeps spinning — or else you’re so exhausted that a challenging book’s the last thing you need.","path":"english2/2016.html"},{"id":"english2-2016-t3-p2-s4","examKey":"english2","examLabel":"英语二","year":"2016","text":3,"paragraph":2,"sentenceNo":4,"sentence":"6 The modern mind, Tim Parks, a novelist and critic, writes, “is overwhelmingly inclined toward communication...","path":"english2/2016.html"},{"id":"english2-2016-t3-p2-s5","examKey":"english2","examLabel":"英语二","year":"2016","text":3,"paragraph":2,"sentenceNo":5,"sentence":"It is not simply that one is interrupted; it is that one is actually inclined to interruption.” 7 Deep reading requires not just time, but a special kind of time which can’t be obtained merely by becoming more efficient.","path":"english2/2016.html"},{"id":"english2-2016-t3-p3-s1","examKey":"english2","examLabel":"英语二","year":"2016","text":3,"paragraph":3,"sentenceNo":1,"sentence":"8 In fact, “becoming more efficient” is part of the problem.","path":"english2/2016.html"},{"id":"english2-2016-t3-p3-s2","examKey":"english2","examLabel":"英语二","year":"2016","text":3,"paragraph":3,"sentenceNo":2,"sentence":"9 Thinking of time as a resource to be maximised means you approach it instrumentally, judging any given moment as well spent only in so far as it advances progress toward some goal.","path":"english2/2016.html"},{"id":"english2-2016-t3-p3-s3","examKey":"english2","examLabel":"英语二","year":"2016","text":3,"paragraph":3,"sentenceNo":3,"sentence":"10 Immersive reading, by contrast, depends on being willing to risk inefficiency, goallessness, even time-wasting.","path":"english2/2016.html"},{"id":"english2-2016-t3-p3-s4","examKey":"english2","examLabel":"英语二","year":"2016","text":3,"paragraph":3,"sentenceNo":4,"sentence":"11 Try to slot it in as a to-do list item and you’ll manage only goal-focused reading — useful, sometimes, but not the most fulfilling kind.","path":"english2/2016.html"},{"id":"english2-2016-t3-p3-s5","examKey":"english2","examLabel":"英语二","year":"2016","text":3,"paragraph":3,"sentenceNo":5,"sentence":"12 “The future comes at us like empty bottles along an unstoppable and nearly infinite conveyor belt,” writes Gary Eberle in his book Sacred Time, and “we feel a pressure to fill these different-sized bottles (days, hours, minutes) as they pass, for if they get by without being filled, we will have wasted them.” 13 No mind-set could be worse for losing yourself in a book.","path":"english2/2016.html"},{"id":"english2-2016-t3-p4-s1","examKey":"english2","examLabel":"英语二","year":"2016","text":3,"paragraph":4,"sentenceNo":1,"sentence":"14 So what does work?","path":"english2/2016.html"},{"id":"english2-2016-t3-p4-s2","examKey":"english2","examLabel":"英语二","year":"2016","text":3,"paragraph":4,"sentenceNo":2,"sentence":"15 Perhaps surprisingly, scheduling regular times for reading.","path":"english2/2016.html"},{"id":"english2-2016-t3-p4-s3","examKey":"english2","examLabel":"英语二","year":"2016","text":3,"paragraph":4,"sentenceNo":3,"sentence":"16 You’d think this might fuel the efficiency mind-set, but in fact, Eberle notes, such ritualistic behaviour helps us “step outside time’s flow” into “soul time.” 17 You could limit distractions by reading only physical books, or on single-purpose e-readers.","path":"english2/2016.html"},{"id":"english2-2016-t3-p4-s4","examKey":"english2","examLabel":"英语二","year":"2016","text":3,"paragraph":4,"sentenceNo":4,"sentence":"18 “Carry a book with you at all times” can actually work, too — providing you dip in often enough, so that reading becomes the default state from which you temporarily surface to take care of business, before dropping back down.","path":"english2/2016.html"},{"id":"english2-2016-t3-p4-s5","examKey":"english2","examLabel":"英语二","year":"2016","text":3,"paragraph":4,"sentenceNo":5,"sentence":"19 On a really good day, it no longer feels as if you’re “making time to read,” but just reading, and making time for everything else.","path":"english2/2016.html"},{"id":"english2-2016-t4-p1-s1","examKey":"english2","examLabel":"英语二","year":"2016","text":4,"paragraph":1,"sentenceNo":1,"sentence":"1 Against a backdrop of drastic changes in economy and population structure, younger Americans are drawing a new 21st-century road map to success, a latest poll has found.","path":"english2/2016.html"},{"id":"english2-2016-t4-p2-s1","examKey":"english2","examLabel":"英语二","year":"2016","text":4,"paragraph":2,"sentenceNo":1,"sentence":"2 Across generational lines, Americans continue to prize many of the same traditional milestones of a successful life, including getting married, having children, owning a home, and retiring in their sixties.","path":"english2/2016.html"},{"id":"english2-2016-t4-p2-s2","examKey":"english2","examLabel":"英语二","year":"2016","text":4,"paragraph":2,"sentenceNo":2,"sentence":"3 But while young and old mostly agree on what constitutes the finish line of a fulfilling life, they offer strikingly different paths for reaching it.","path":"english2/2016.html"},{"id":"english2-2016-t4-p3-s1","examKey":"english2","examLabel":"英语二","year":"2016","text":4,"paragraph":3,"sentenceNo":1,"sentence":"Q37 段落定位 4 Young people who are still getting started in life were more likely than older adults to prioritize personal fulfillment in their work, to believe they will advance their careers most by regularly changing jobs, to favor communities with more public services and a faster pace of life, to agree that couples should be financially secure before getting married or having children, and to maintain that children are best served by two parents working outside the home, the survey found.","path":"english2/2016.html"},{"id":"english2-2016-t4-p4-s1","examKey":"english2","examLabel":"英语二","year":"2016","text":4,"paragraph":4,"sentenceNo":1,"sentence":"5 From career to community and family, these contrasts suggest that in the aftermath of the searing Great Recession, those just starting out in life are defining priorities and expectations that will increasingly spread through virtually all aspects of American life, from consumer preferences to housing patterns to politics.","path":"english2/2016.html"},{"id":"english2-2016-t4-p5-s1","examKey":"english2","examLabel":"英语二","year":"2016","text":4,"paragraph":5,"sentenceNo":1,"sentence":"6 Young and old converge on one key point: Overwhelming majorities of both groups said they believe it is harder for young people today to get started in life than it was for earlier generations.","path":"english2/2016.html"},{"id":"english2-2016-t4-p5-s2","examKey":"english2","examLabel":"英语二","year":"2016","text":4,"paragraph":5,"sentenceNo":2,"sentence":"7 While younger people are somewhat more optimistic than their elders about the prospects for those starting out today, big majorities in both groups believe those “just getting started in life” face a tougher climb than earlier generations in reaching such signpost achievements as securing a good-paying job, starting a family, managing debt, and finding affordable housing.","path":"english2/2016.html"},{"id":"english2-2016-t4-p6-s1","examKey":"english2","examLabel":"英语二","year":"2016","text":4,"paragraph":6,"sentenceNo":1,"sentence":"8 Pete Schneider considers the climb tougher today.","path":"english2/2016.html"},{"id":"english2-2016-t4-p6-s2","examKey":"english2","examLabel":"英语二","year":"2016","text":4,"paragraph":6,"sentenceNo":2,"sentence":"9 Schneider, a 27-year-old auto technician from the Chicago suburbs, says he struggled to find a job after graduating from college.","path":"english2/2016.html"},{"id":"english2-2016-t4-p6-s3","examKey":"english2","examLabel":"英语二","year":"2016","text":4,"paragraph":6,"sentenceNo":3,"sentence":"10 Even now that he is working steadily, he said, “I can’t afford to pay my monthly mortgage payments on my own, so I have to rent rooms out to people to make that happen.” 11 Looking back, he is struck that his parents could provide a comfortable life for their children even though neither had completed college when he was young.","path":"english2/2016.html"},{"id":"english2-2016-t4-p6-s4","examKey":"english2","examLabel":"英语二","year":"2016","text":4,"paragraph":6,"sentenceNo":4,"sentence":"12 “I still grew up in an upper middle-class home with parents who didn’t have college degrees,” Schneider said.","path":"english2/2016.html"},{"id":"english2-2016-t4-p6-s5","examKey":"english2","examLabel":"英语二","year":"2016","text":4,"paragraph":6,"sentenceNo":5,"sentence":"13 “I don’t think people are capable of that anymore.”","path":"english2/2016.html"},{"id":"english1-2017-t1-p1-s1","examKey":"english1","examLabel":"英语一","year":"2017","text":1,"paragraph":1,"sentenceNo":1,"sentence":"First two hours, now three hours — this is how far in advance authorities are recommending people show up to catch a domestic flight, at least at some major U.S. airports with increasingly massive security lines.","path":"english1/2017.html"},{"id":"english1-2017-t1-p2-s1","examKey":"english1","examLabel":"英语一","year":"2017","text":1,"paragraph":2,"sentenceNo":1,"sentence":"Americans are willing to tolerate time-consuming security procedures in return for increased safety.","path":"english1/2017.html"},{"id":"english1-2017-t1-p2-s2","examKey":"english1","examLabel":"英语一","year":"2017","text":1,"paragraph":2,"sentenceNo":2,"sentence":"The crash of EgyptAir Flight 804, which terrorists may have downed over the Mediterranean Sea, provides another tragic reminder of why.","path":"english1/2017.html"},{"id":"english1-2017-t1-p2-s3","examKey":"english1","examLabel":"英语一","year":"2017","text":1,"paragraph":2,"sentenceNo":3,"sentence":"But demanding too much of air travelers or providing too little security in return undermines public support for the process.","path":"english1/2017.html"},{"id":"english1-2017-t1-p2-s4","examKey":"english1","examLabel":"英语一","year":"2017","text":1,"paragraph":2,"sentenceNo":4,"sentence":"And it should: Wasted time is a drag on Americans’ economic and private lives, not to mention infuriating.","path":"english1/2017.html"},{"id":"english1-2017-t1-p3-s1","examKey":"english1","examLabel":"英语一","year":"2017","text":1,"paragraph":3,"sentenceNo":1,"sentence":"Last year, the Transportation Security Administration (TSA) found in a secret check that undercover investigators were able to sneak weapons — both fake and real — past airport security nearly every time they tried.","path":"english1/2017.html"},{"id":"english1-2017-t1-p3-s2","examKey":"english1","examLabel":"英语一","year":"2017","text":1,"paragraph":3,"sentenceNo":2,"sentence":"Enhanced security measures since then, combined with a rise in airline travel due to the improving economy and low oil prices, have resulted in long waits at major airports such as Chicago’s O’Hare International.","path":"english1/2017.html"},{"id":"english1-2017-t1-p3-s3","examKey":"english1","examLabel":"英语一","year":"2017","text":1,"paragraph":3,"sentenceNo":3,"sentence":"It is not yet clear how much more effective air line security has become — but the lines are obvious.","path":"english1/2017.html"},{"id":"english1-2017-t1-p4-s1","examKey":"english1","examLabel":"英语一","year":"2017","text":1,"paragraph":4,"sentenceNo":1,"sentence":"Part of the issue is that the government did not anticipate the steep increase in airline travel, so the TSA is now rushing to get new screeners on the line.","path":"english1/2017.html"},{"id":"english1-2017-t1-p4-s2","examKey":"english1","examLabel":"英语一","year":"2017","text":1,"paragraph":4,"sentenceNo":2,"sentence":"Part of the issue is that airports have only so much room for screening lanes.","path":"english1/2017.html"},{"id":"english1-2017-t1-p4-s3","examKey":"english1","examLabel":"英语一","year":"2017","text":1,"paragraph":4,"sentenceNo":3,"sentence":"Another factor may be that more people are trying to overpack their carry-on bags to avoid checked-baggage fees, though the airlines strongly dispute this.","path":"english1/2017.html"},{"id":"english1-2017-t1-p5-s1","examKey":"english1","examLabel":"英语一","year":"2017","text":1,"paragraph":5,"sentenceNo":1,"sentence":"There is one step the TSA could take that would not require remodeling airports or rushing to hire: Enroll more people in the PreCheck program.","path":"english1/2017.html"},{"id":"english1-2017-t1-p5-s2","examKey":"english1","examLabel":"英语一","year":"2017","text":1,"paragraph":5,"sentenceNo":2,"sentence":"PreCheck is supposed to be a win-win for travelers and the TSA.","path":"english1/2017.html"},{"id":"english1-2017-t1-p5-s3","examKey":"english1","examLabel":"英语一","year":"2017","text":1,"paragraph":5,"sentenceNo":3,"sentence":"Passengers who pass a background check are eligible to use expedited screening lanes.","path":"english1/2017.html"},{"id":"english1-2017-t1-p5-s4","examKey":"english1","examLabel":"英语一","year":"2017","text":1,"paragraph":5,"sentenceNo":4,"sentence":"This allows the TSA to focus on travelers who are higher risk, saving time for everyone involved.","path":"english1/2017.html"},{"id":"english1-2017-t1-p5-s5","examKey":"english1","examLabel":"英语一","year":"2017","text":1,"paragraph":5,"sentenceNo":5,"sentence":"The TSA wants to enroll 25 million people in PreCheck.","path":"english1/2017.html"},{"id":"english1-2017-t1-p6-s1","examKey":"english1","examLabel":"英语一","year":"2017","text":1,"paragraph":6,"sentenceNo":1,"sentence":"It has not gotten anywhere close to that, and one big reason is sticker shock: Passengers must pay $85 every five years to process their background checks.","path":"english1/2017.html"},{"id":"english1-2017-t1-p6-s2","examKey":"english1","examLabel":"英语一","year":"2017","text":1,"paragraph":6,"sentenceNo":2,"sentence":"Since the beginning, this price tag has been PreCheck’s fatal flaw.","path":"english1/2017.html"},{"id":"english1-2017-t1-p6-s3","examKey":"english1","examLabel":"英语一","year":"2017","text":1,"paragraph":6,"sentenceNo":3,"sentence":"Upcoming reforms might bring the price to a more reasonable level.","path":"english1/2017.html"},{"id":"english1-2017-t1-p6-s4","examKey":"english1","examLabel":"英语一","year":"2017","text":1,"paragraph":6,"sentenceNo":4,"sentence":"But Congress should look into doing so directly, by helping to finance PreCheck enrollment or to cut costs in other ways.","path":"english1/2017.html"},{"id":"english1-2017-t1-p7-s1","examKey":"english1","examLabel":"英语一","year":"2017","text":1,"paragraph":7,"sentenceNo":1,"sentence":"The TSA cannot continue diverting resources into underused PreCheck lanes while most of the traveling public suffers in unnecessary lines.","path":"english1/2017.html"},{"id":"english1-2017-t1-p7-s2","examKey":"english1","examLabel":"英语一","year":"2017","text":1,"paragraph":7,"sentenceNo":2,"sentence":"It is long past time to make the program work.","path":"english1/2017.html"},{"id":"english1-2017-t2-p1-s1","examKey":"english1","examLabel":"英语一","year":"2017","text":2,"paragraph":1,"sentenceNo":1,"sentence":"“The ancient Hawaiians were astronomers,” wrote Queen Liliuokalani, Hawaii’s last reigning monarch, in 1897.","path":"english1/2017.html"},{"id":"english1-2017-t2-p1-s2","examKey":"english1","examLabel":"英语一","year":"2017","text":2,"paragraph":1,"sentenceNo":2,"sentence":"Star watchers were among the most esteemed members of Hawaiian society.","path":"english1/2017.html"},{"id":"english1-2017-t2-p1-s3","examKey":"english1","examLabel":"英语一","year":"2017","text":2,"paragraph":1,"sentenceNo":3,"sentence":"Sadly, all is not well with astronomy in Hawaii today.","path":"english1/2017.html"},{"id":"english1-2017-t2-p1-s4","examKey":"english1","examLabel":"英语一","year":"2017","text":2,"paragraph":1,"sentenceNo":4,"sentence":"Protests have erupted over construction of the Thirty Meter Telescope ( TMT ), a giant observatory that promises to revolutionize humanity’s view of the cosmos.","path":"english1/2017.html"},{"id":"english1-2017-t2-p2-s1","examKey":"english1","examLabel":"英语一","year":"2017","text":2,"paragraph":2,"sentenceNo":1,"sentence":"At issue is the TMT ’s planned location on Mauna Kea, a dormant volcano worshiped by some Hawaiians as the piko, that connects the Hawaiian Islands to the heavens.","path":"english1/2017.html"},{"id":"english1-2017-t2-p2-s2","examKey":"english1","examLabel":"英语一","year":"2017","text":2,"paragraph":2,"sentenceNo":2,"sentence":"But Mauna Kea is also home to some of the world’s most powerful telescopes.","path":"english1/2017.html"},{"id":"english1-2017-t2-p2-s3","examKey":"english1","examLabel":"英语一","year":"2017","text":2,"paragraph":2,"sentenceNo":3,"sentence":"Rested in the Pacific Ocean, Mauna Kea’s peak rises above the bulk of our planet’s dense atmosphere, where conditions allow telescopes to obtain images of unsurpassed clarity.","path":"english1/2017.html"},{"id":"english1-2017-t2-p3-s1","examKey":"english1","examLabel":"英语一","year":"2017","text":2,"paragraph":3,"sentenceNo":1,"sentence":"Opposition to telescopes on Mauna Kea is nothing new.","path":"english1/2017.html"},{"id":"english1-2017-t2-p3-s2","examKey":"english1","examLabel":"英语一","year":"2017","text":2,"paragraph":3,"sentenceNo":2,"sentence":"A small but vocal group of Hawaiians and environmentalists have long viewed their presence as disrespect for sacred land and a painful reminder of the occupation of what was once a sovereign nation.","path":"english1/2017.html"},{"id":"english1-2017-t2-p4-s1","examKey":"english1","examLabel":"英语一","year":"2017","text":2,"paragraph":4,"sentenceNo":1,"sentence":"Some blame for the current controversy belongs to astronomers.","path":"english1/2017.html"},{"id":"english1-2017-t2-p4-s2","examKey":"english1","examLabel":"英语一","year":"2017","text":2,"paragraph":4,"sentenceNo":2,"sentence":"In their eagerness to build bigger telescopes, they forgot that science is not the only way of understanding the world.","path":"english1/2017.html"},{"id":"english1-2017-t2-p4-s3","examKey":"english1","examLabel":"英语一","year":"2017","text":2,"paragraph":4,"sentenceNo":3,"sentence":"They did not always prioritize the protection of Mauna Kea’s fragile ecosystems or its holiness to the island’s inhabitants.","path":"english1/2017.html"},{"id":"english1-2017-t2-p4-s4","examKey":"english1","examLabel":"英语一","year":"2017","text":2,"paragraph":4,"sentenceNo":4,"sentence":"Hawaiian culture is not a relic of the past; it is a living culture undergoing a renaissance today.","path":"english1/2017.html"},{"id":"english1-2017-t2-p5-s1","examKey":"english1","examLabel":"英语一","year":"2017","text":2,"paragraph":5,"sentenceNo":1,"sentence":"Yet science has a cultural history, too, with roots going back to the dawn of civilization.","path":"english1/2017.html"},{"id":"english1-2017-t2-p5-s2","examKey":"english1","examLabel":"英语一","year":"2017","text":2,"paragraph":5,"sentenceNo":2,"sentence":"The same curiosity to find what lies beyond the horizon that first brought early Polynesians to Hawaii’s shores inspires astronomers today to explore the heavens.","path":"english1/2017.html"},{"id":"english1-2017-t2-p5-s3","examKey":"english1","examLabel":"英语一","year":"2017","text":2,"paragraph":5,"sentenceNo":3,"sentence":"Calls to disassemble all telescopes on Mauna Kea or to ban future development there ignore the reality that astronomy and Hawaiian culture both seek to answer big questions about who we are, where we come from and where we are going.","path":"english1/2017.html"},{"id":"english1-2017-t2-p5-s4","examKey":"english1","examLabel":"英语一","year":"2017","text":2,"paragraph":5,"sentenceNo":4,"sentence":"Perhaps that is why we explore the starry skies, as if answering a primal calling to know ourselves and our true ancestral homes.","path":"english1/2017.html"},{"id":"english1-2017-t2-p6-s1","examKey":"english1","examLabel":"英语一","year":"2017","text":2,"paragraph":6,"sentenceNo":1,"sentence":"The astronomy community is making compromises to change its use of Mauna Kea.","path":"english1/2017.html"},{"id":"english1-2017-t2-p6-s2","examKey":"english1","examLabel":"英语一","year":"2017","text":2,"paragraph":6,"sentenceNo":2,"sentence":"The TMT site was chosen to minimize the telescope’s visibility around the island and to avoid archaeological and environmental impact.","path":"english1/2017.html"},{"id":"english1-2017-t2-p6-s3","examKey":"english1","examLabel":"英语一","year":"2017","text":2,"paragraph":6,"sentenceNo":3,"sentence":"To limit the number of telescopes on Mauna Kea, old ones will be removed at the end of their lifetimes and their site s returned to a natural state.","path":"english1/2017.html"},{"id":"english1-2017-t2-p6-s4","examKey":"english1","examLabel":"英语一","year":"2017","text":2,"paragraph":6,"sentenceNo":4,"sentence":"There is no reason why everyone cannot be welcomed on Mauna Kea to embrace their cultural heritage and to study the stars.","path":"english1/2017.html"},{"id":"english1-2017-t3-p1-s1","examKey":"english1","examLabel":"英语一","year":"2017","text":3,"paragraph":1,"sentenceNo":1,"sentence":"Robert F.","path":"english1/2017.html"},{"id":"english1-2017-t3-p1-s2","examKey":"english1","examLabel":"英语一","year":"2017","text":3,"paragraph":1,"sentenceNo":2,"sentence":"Kennedy once said that a country’s GDP measures “everything except that which makes life worthwhile.” With Britain voting to leave the European Union, and GDP already predicted to slow as a result, it is now a timely moment to assess what he was referring to.","path":"english1/2017.html"},{"id":"english1-2017-t3-p2-s1","examKey":"english1","examLabel":"英语一","year":"2017","text":3,"paragraph":2,"sentenceNo":1,"sentence":"The question of GDP and its usefulness has annoyed policymakers for over half a century.","path":"english1/2017.html"},{"id":"english1-2017-t3-p2-s2","examKey":"english1","examLabel":"英语一","year":"2017","text":3,"paragraph":2,"sentenceNo":2,"sentence":"Many argue that it is a flawed concept.","path":"english1/2017.html"},{"id":"english1-2017-t3-p2-s3","examKey":"english1","examLabel":"英语一","year":"2017","text":3,"paragraph":2,"sentenceNo":3,"sentence":"It measures things that do not matter and misses things that do.","path":"english1/2017.html"},{"id":"english1-2017-t3-p2-s4","examKey":"english1","examLabel":"英语一","year":"2017","text":3,"paragraph":2,"sentenceNo":4,"sentence":"By most recent measures, the UK’s GDP has been the envy of the Western world, with record low unemployment and high growth figures.","path":"english1/2017.html"},{"id":"english1-2017-t3-p2-s5","examKey":"english1","examLabel":"英语一","year":"2017","text":3,"paragraph":2,"sentenceNo":5,"sentence":"If everything was going so well, then why did over 17 million people vote for Brexit, despite the warnings about what it could do to their country’s economic prospects?","path":"english1/2017.html"},{"id":"english1-2017-t3-p3-s1","examKey":"english1","examLabel":"英语一","year":"2017","text":3,"paragraph":3,"sentenceNo":1,"sentence":"A recent annual study of countries and their ability to convert growth into well-being sheds some light on that question.","path":"english1/2017.html"},{"id":"english1-2017-t3-p3-s2","examKey":"english1","examLabel":"英语一","year":"2017","text":3,"paragraph":3,"sentenceNo":2,"sentence":"Across the 163 countries measured, the UK is one of the poorest performers in ensuring that economic growth is translated into meaningful improvements for its citizens.","path":"english1/2017.html"},{"id":"english1-2017-t3-p3-s3","examKey":"english1","examLabel":"英语一","year":"2017","text":3,"paragraph":3,"sentenceNo":3,"sentence":"Rather than just focusing on GDP, over 40 different sets of criteria from health, education and civil society engagement have been measured to get a more rounded assessment of how countries are performing.","path":"english1/2017.html"},{"id":"english1-2017-t3-p4-s1","examKey":"english1","examLabel":"英语一","year":"2017","text":3,"paragraph":4,"sentenceNo":1,"sentence":"While all of these countries face their own challenges, there are a number of consistent themes.","path":"english1/2017.html"},{"id":"english1-2017-t3-p4-s2","examKey":"english1","examLabel":"英语一","year":"2017","text":3,"paragraph":4,"sentenceNo":2,"sentence":"Yes, there has been a budding economic recovery since the 2008 global crash, but in key indicators in areas such as health and education, major economies have continued to decline.","path":"english1/2017.html"},{"id":"english1-2017-t3-p4-s3","examKey":"english1","examLabel":"英语一","year":"2017","text":3,"paragraph":4,"sentenceNo":3,"sentence":"Yet this isn’t the case with all countries.","path":"english1/2017.html"},{"id":"english1-2017-t3-p4-s4","examKey":"english1","examLabel":"英语一","year":"2017","text":3,"paragraph":4,"sentenceNo":4,"sentence":"Some relatively poor European countries have seen huge improvements across measures including civil society, income equality and the environment.","path":"english1/2017.html"},{"id":"english1-2017-t3-p5-s1","examKey":"english1","examLabel":"英语一","year":"2017","text":3,"paragraph":5,"sentenceNo":1,"sentence":"This is a lesson that rich countries can learn: When GDP is no longer regarded as the sole measure of a country’s success, the world looks very different.","path":"english1/2017.html"},{"id":"english1-2017-t3-p6-s1","examKey":"english1","examLabel":"英语一","year":"2017","text":3,"paragraph":6,"sentenceNo":1,"sentence":"So, what Kennedy was referring to was that while GDP has been the most common method for measuring the economic activity of nations, as a measure, it is no longer enough.","path":"english1/2017.html"},{"id":"english1-2017-t3-p6-s2","examKey":"english1","examLabel":"英语一","year":"2017","text":3,"paragraph":6,"sentenceNo":2,"sentence":"It does not include important factors such as environmental quality or education outcomes — all things that contribute to a person’s sense of well-being.","path":"english1/2017.html"},{"id":"english1-2017-t3-p7-s1","examKey":"english1","examLabel":"英语一","year":"2017","text":3,"paragraph":7,"sentenceNo":1,"sentence":"The sharp hit to growth predicted around the world and in the UK could lead to a decline in the everyday services we depend on for our well-being and for growth.","path":"english1/2017.html"},{"id":"english1-2017-t3-p7-s2","examKey":"english1","examLabel":"英语一","year":"2017","text":3,"paragraph":7,"sentenceNo":2,"sentence":"But policymakers who refocus efforts on improving well-being rather than simply worrying about GDP figures could avoid the forecasted doom and may even see progress.","path":"english1/2017.html"},{"id":"english1-2017-t4-p1-s1","examKey":"english1","examLabel":"英语一","year":"2017","text":4,"paragraph":1,"sentenceNo":1,"sentence":"In a rare unanimous ruling, the US Supreme Court has overturned the corruption conviction of a former Virginia governor, Robert McDonnell.","path":"english1/2017.html"},{"id":"english1-2017-t4-p1-s2","examKey":"english1","examLabel":"英语一","year":"2017","text":4,"paragraph":1,"sentenceNo":2,"sentence":"But it did so while holding its nose at the ethics of his conduct, which included accepting gifts such as a Rolex watch and a Ferrari automobile from a company seeking access to government.","path":"english1/2017.html"},{"id":"english1-2017-t4-p2-s1","examKey":"english1","examLabel":"英语一","year":"2017","text":4,"paragraph":2,"sentenceNo":1,"sentence":"The high court’s decision said the judge in Mr.","path":"english1/2017.html"},{"id":"english1-2017-t4-p2-s2","examKey":"english1","examLabel":"英语一","year":"2017","text":4,"paragraph":2,"sentenceNo":2,"sentence":"McDonnell’s trial failed to tell a jury that it must look only at his “official acts,” or the former governor’s decisions on “specific” and “unsettled” issues related to his duties.","path":"english1/2017.html"},{"id":"english1-2017-t4-p3-s1","examKey":"english1","examLabel":"英语一","year":"2017","text":4,"paragraph":3,"sentenceNo":1,"sentence":"Merely helping a gift-giver gain access to other officials, unless done with clear intent to pressure those officials, is not corruption, the justices found.","path":"english1/2017.html"},{"id":"english1-2017-t4-p4-s1","examKey":"english1","examLabel":"英语一","year":"2017","text":4,"paragraph":4,"sentenceNo":1,"sentence":"The court did suggest that accepting favors in return for opening doors is “distasteful” and “nasty.” But under anti-bribery laws, proof must be made of concrete benefits, such as approval of a contract or regulation.","path":"english1/2017.html"},{"id":"english1-2017-t4-p4-s2","examKey":"english1","examLabel":"英语一","year":"2017","text":4,"paragraph":4,"sentenceNo":2,"sentence":"Simply arranging a meeting, making a phone call, or hosting an event is not an “official act”.","path":"english1/2017.html"},{"id":"english1-2017-t4-p5-s1","examKey":"english1","examLabel":"英语一","year":"2017","text":4,"paragraph":5,"sentenceNo":1,"sentence":"The court’s ruling is legally sound in defining a kind of favoritism that is not criminal.","path":"english1/2017.html"},{"id":"english1-2017-t4-p5-s2","examKey":"english1","examLabel":"英语一","year":"2017","text":4,"paragraph":5,"sentenceNo":2,"sentence":"Elected leaders must be allowed to help supporters deal with bureaucratic problems without fear of prosecution for bribery.","path":"english1/2017.html"},{"id":"english1-2017-t4-p5-s3","examKey":"english1","examLabel":"英语一","year":"2017","text":4,"paragraph":5,"sentenceNo":3,"sentence":"“The basic compact underlying representative government,” wrote Chief Justice John Roberts for the court, “ assumes that public officials will hear from their constituents and act on their concerns.”","path":"english1/2017.html"},{"id":"english1-2017-t4-p6-s1","examKey":"english1","examLabel":"英语一","year":"2017","text":4,"paragraph":6,"sentenceNo":1,"sentence":"But the ruling reinforces the need for citizens and their elected representatives, not the courts, to ensure equality of access to government.","path":"english1/2017.html"},{"id":"english1-2017-t4-p6-s2","examKey":"english1","examLabel":"英语一","year":"2017","text":4,"paragraph":6,"sentenceNo":2,"sentence":"Officials must not be allowed to play favorites in providing information or in arranging meetings simply because an individual or group provides a campaign donation or a personal gift.","path":"english1/2017.html"},{"id":"english1-2017-t4-p6-s3","examKey":"english1","examLabel":"英语一","year":"2017","text":4,"paragraph":6,"sentenceNo":3,"sentence":"This type of integrity requires well-enforced laws in government transparency, such as records of official meetings, rules on lobbying, and information about each elected leader’s source of wealth.","path":"english1/2017.html"},{"id":"english1-2017-t4-p7-s1","examKey":"english1","examLabel":"英语一","year":"2017","text":4,"paragraph":7,"sentenceNo":1,"sentence":"Favoritism in official access can fan public perceptions of corruption.","path":"english1/2017.html"},{"id":"english1-2017-t4-p7-s2","examKey":"english1","examLabel":"英语一","year":"2017","text":4,"paragraph":7,"sentenceNo":2,"sentence":"But it is not always corruption.","path":"english1/2017.html"},{"id":"english1-2017-t4-p7-s3","examKey":"english1","examLabel":"英语一","year":"2017","text":4,"paragraph":7,"sentenceNo":3,"sentence":"Rather officials must avoid double standards, or different types of access for average people and the wealthy.","path":"english1/2017.html"},{"id":"english1-2017-t4-p7-s4","examKey":"english1","examLabel":"英语一","year":"2017","text":4,"paragraph":7,"sentenceNo":4,"sentence":"If connections can be bought, a basic premise of democratic society — that all are equal in treatment by government — is undermined.","path":"english1/2017.html"},{"id":"english1-2017-t4-p7-s5","examKey":"english1","examLabel":"英语一","year":"2017","text":4,"paragraph":7,"sentenceNo":5,"sentence":"Good governance rests on an understanding of the inherent worth of each individual.","path":"english1/2017.html"},{"id":"english1-2017-t4-p8-s1","examKey":"english1","examLabel":"英语一","year":"2017","text":4,"paragraph":8,"sentenceNo":1,"sentence":"The court’s ruling is a step forward in the struggle against both corruption and official favoritism.","path":"english1/2017.html"},{"id":"english2-2017-t1-p1-s1","examKey":"english2","examLabel":"英语二","year":"2017","text":1,"paragraph":1,"sentenceNo":1,"sentence":"Q21 段落定位 Every Saturday morning, at 9 am, more than 50,000 runners set off to run 5km around their local park.","path":"english2/2017.html"},{"id":"english2-2017-t1-p1-s2","examKey":"english2","examLabel":"英语二","year":"2017","text":1,"paragraph":1,"sentenceNo":2,"sentence":"The Parkrun phenomenon began with a dozen friends and has inspired 400 events in the UK and more abroad.","path":"english2/2017.html"},{"id":"english2-2017-t1-p1-s3","examKey":"english2","examLabel":"英语二","year":"2017","text":1,"paragraph":1,"sentenceNo":3,"sentence":"Events are free, staffed by thousands of volunteers.","path":"english2/2017.html"},{"id":"english2-2017-t1-p1-s4","examKey":"english2","examLabel":"英语二","year":"2017","text":1,"paragraph":1,"sentenceNo":4,"sentence":"Runners range from four years old to grandparents; their times range from Andrew Baddeley’s world record 13 minutes 48 seconds up to an hour.","path":"english2/2017.html"},{"id":"english2-2017-t1-p2-s1","examKey":"english2","examLabel":"英语二","year":"2017","text":1,"paragraph":2,"sentenceNo":1,"sentence":"Q22 legacy 定位 Parkrun is succeeding where London’s Olympic “legacy” is failing.","path":"english2/2017.html"},{"id":"english2-2017-t1-p2-s2","examKey":"english2","examLabel":"英语二","year":"2017","text":1,"paragraph":2,"sentenceNo":2,"sentence":"Ten years ago on Monday, it was announced that the Games of the 30th Olympiad would be in London.","path":"english2/2017.html"},{"id":"english2-2017-t1-p2-s3","examKey":"english2","examLabel":"英语二","year":"2017","text":1,"paragraph":2,"sentenceNo":3,"sentence":"Planning documents pledged that the great legacy of the Games would be to lever a nation of sport lovers away from their couches.","path":"english2/2017.html"},{"id":"english2-2017-t1-p2-s4","examKey":"english2","examLabel":"英语二","year":"2017","text":1,"paragraph":2,"sentenceNo":4,"sentence":"The population would be fitter, healthier and produce more winners.","path":"english2/2017.html"},{"id":"english2-2017-t1-p2-s5","examKey":"english2","examLabel":"英语二","year":"2017","text":1,"paragraph":2,"sentenceNo":5,"sentence":"It has not happened.","path":"english2/2017.html"},{"id":"english2-2017-t1-p2-s6","examKey":"english2","examLabel":"英语二","year":"2017","text":1,"paragraph":2,"sentenceNo":6,"sentence":"The number of adults doing weekly sport did rise, by nearly 2 million in the run-up to 2012 — but the general population was growing faster.","path":"english2/2017.html"},{"id":"english2-2017-t1-p2-s7","examKey":"english2","examLabel":"英语二","year":"2017","text":1,"paragraph":2,"sentenceNo":7,"sentence":"Worse, the numbers are now falling at an accelerating rate.","path":"english2/2017.html"},{"id":"english2-2017-t1-p2-s8","examKey":"english2","examLabel":"英语二","year":"2017","text":1,"paragraph":2,"sentenceNo":8,"sentence":"The opposition claims primary school pupils doing at least two hours of sport a week have nearly halved.","path":"english2/2017.html"},{"id":"english2-2017-t1-p2-s9","examKey":"english2","examLabel":"英语二","year":"2017","text":1,"paragraph":2,"sentenceNo":9,"sentence":"Obesity has risen among adults and children.","path":"english2/2017.html"},{"id":"english2-2017-t1-p2-s10","examKey":"english2","examLabel":"英语二","year":"2017","text":1,"paragraph":2,"sentenceNo":10,"sentence":"Official retrospections continue as to why London 2012 failed to “inspire a generation.” The success of Parkrun offers answers.","path":"english2/2017.html"},{"id":"english2-2017-t1-p3-s1","examKey":"english2","examLabel":"英语二","year":"2017","text":1,"paragraph":3,"sentenceNo":1,"sentence":"Q23 差异定位 Parkrun is not a race but a time trial: Your only competitor is the clock.","path":"english2/2017.html"},{"id":"english2-2017-t1-p3-s2","examKey":"english2","examLabel":"英语二","year":"2017","text":1,"paragraph":3,"sentenceNo":2,"sentence":"The ethos welcomes anybody.","path":"english2/2017.html"},{"id":"english2-2017-t1-p3-s3","examKey":"english2","examLabel":"英语二","year":"2017","text":1,"paragraph":3,"sentenceNo":3,"sentence":"There is as much joy over a puffed-out first-timer being clapped over the line as there is about top talent shining.","path":"english2/2017.html"},{"id":"english2-2017-t1-p3-s4","examKey":"english2","examLabel":"英语二","year":"2017","text":1,"paragraph":3,"sentenceNo":4,"sentence":"The Olympic bidders, by contrast, wanted to get more people doing sport and to produce more elite athletes.","path":"english2/2017.html"},{"id":"english2-2017-t1-p3-s5","examKey":"english2","examLabel":"英语二","year":"2017","text":1,"paragraph":3,"sentenceNo":5,"sentence":"The dual aim was mixed up: The stress on success over taking part was intimidating for newcomers.","path":"english2/2017.html"},{"id":"english2-2017-t1-p4-s1","examKey":"english2","examLabel":"英语二","year":"2017","text":1,"paragraph":4,"sentenceNo":1,"sentence":"Q24 政府职责定位 Q25 态度定位 Indeed, there is something a little absurd in the state getting involved in the planning of such a fundamentally “grassroots” concept as community sports associations.","path":"english2/2017.html"},{"id":"english2-2017-t1-p4-s2","examKey":"english2","examLabel":"英语二","year":"2017","text":1,"paragraph":4,"sentenceNo":2,"sentence":"If there is a role for government, it should really be getting involved in providing common goods — making sure there is space for playing fields and the money to pave tennis and netball courts, and encouraging the provision of all these activities in schools.","path":"english2/2017.html"},{"id":"english2-2017-t1-p4-s3","examKey":"english2","examLabel":"英语二","year":"2017","text":1,"paragraph":4,"sentenceNo":3,"sentence":"But successive governments have presided over selling green spaces, squeezing money from local authorities and declining attention on sport in education.","path":"english2/2017.html"},{"id":"english2-2017-t1-p4-s4","examKey":"english2","examLabel":"英语二","year":"2017","text":1,"paragraph":4,"sentenceNo":4,"sentence":"Instead of wordy, worthy strategies, future governments need to do more to provide the conditions for sport to thrive.","path":"english2/2017.html"},{"id":"english2-2017-t1-p4-s5","examKey":"english2","examLabel":"英语二","year":"2017","text":1,"paragraph":4,"sentenceNo":5,"sentence":"Or at least not make them worse.","path":"english2/2017.html"},{"id":"english2-2017-t2-p1-s1","examKey":"english2","examLabel":"英语二","year":"2017","text":2,"paragraph":1,"sentenceNo":1,"sentence":"Q26 Radesky 定位 With so much focus on children’s use of screens, it’s easy for parents to forget about their own screen use.","path":"english2/2017.html"},{"id":"english2-2017-t2-p1-s2","examKey":"english2","examLabel":"英语二","year":"2017","text":2,"paragraph":1,"sentenceNo":2,"sentence":"“Tech is designed to really suck you in,” says Jenny Radesky in her study of digital play, “and digital products are there to promote maximal engagement.","path":"english2/2017.html"},{"id":"english2-2017-t2-p1-s3","examKey":"english2","examLabel":"英语二","year":"2017","text":2,"paragraph":1,"sentenceNo":3,"sentence":"It makes it hard to disengage, and leads to a lot of bleed-over into the family routine.”","path":"english2/2017.html"},{"id":"english2-2017-t2-p2-s1","examKey":"english2","examLabel":"英语二","year":"2017","text":2,"paragraph":2,"sentenceNo":1,"sentence":"Q27 food-testing 定位 Radesky’s food-testing exercise studied the use of mobile phones and tablets at mealtimes by giving mother-child pairs a food-testing exercise.","path":"english2/2017.html"},{"id":"english2-2017-t2-p2-s2","examKey":"english2","examLabel":"英语二","year":"2017","text":2,"paragraph":2,"sentenceNo":2,"sentence":"She found that mothers who used devices during the exercise started 20 per cent fewer verbal and 39 per cent fewer nonverbal interactions with their children.","path":"english2/2017.html"},{"id":"english2-2017-t2-p2-s3","examKey":"english2","examLabel":"英语二","year":"2017","text":2,"paragraph":2,"sentenceNo":3,"sentence":"During a separate observation, she saw that phones became a source of tension in the family.","path":"english2/2017.html"},{"id":"english2-2017-t2-p2-s4","examKey":"english2","examLabel":"英语二","year":"2017","text":2,"paragraph":2,"sentenceNo":4,"sentence":"Parents would be looking at their emails while the children would be making excited bids for their attention.","path":"english2/2017.html"},{"id":"english2-2017-t2-p3-s1","examKey":"english2","examLabel":"英语二","year":"2017","text":2,"paragraph":3,"sentenceNo":1,"sentence":"Q28 still face 定位 Infants are wired to look at parents’ faces to try to understand their world, and if those faces are blank and unresponsive — as they often are when absorbed in a device — it can be extremely disconcerting for the children.","path":"english2/2017.html"},{"id":"english2-2017-t2-p3-s2","examKey":"english2","examLabel":"英语二","year":"2017","text":2,"paragraph":3,"sentenceNo":2,"sentence":"Radesky cites the “still face experiment” devised by developmental psychologist Ed Tronick in the 1970s.","path":"english2/2017.html"},{"id":"english2-2017-t2-p3-s3","examKey":"english2","examLabel":"英语二","year":"2017","text":2,"paragraph":3,"sentenceNo":3,"sentence":"In it, a mother is asked to interact with her child in a normal way before putting on a blank expression and not giving them any visual social feedback: The child becomes increasingly distressed as she tries to capture her mother’s attention.","path":"english2/2017.html"},{"id":"english2-2017-t2-p3-s4","examKey":"english2","examLabel":"英语二","year":"2017","text":2,"paragraph":3,"sentenceNo":4,"sentence":"“Parents don’t have to be exquisitely present at all times, but there needs to be a balance and parents need to be responsive and sensitive to a child’s verbal or nonverbal expressions of an emotional need,” says Radesky.","path":"english2/2017.html"},{"id":"english2-2017-t2-p4-s1","examKey":"english2","examLabel":"英语二","year":"2017","text":2,"paragraph":4,"sentenceNo":1,"sentence":"Q29 Tronick ideology Q30 Tronick 观点 On the other hand, Tronick himself is concerned that the worries about kids’ use of screens are born out of an “oppressive ideology that demands that parents should always be interacting” with their children: “It’s based on a somewhat fantasised, very white, very upper-middle-class ideology that says if you’re failing to expose your child to 30,000 words you are neglecting them.” Tronick believes that just because a child isn’t learning from the screen doesn’t mean there’s no value to it — particularly if it gives parents time to have a shower, do housework or simply have a break from their child.","path":"english2/2017.html"},{"id":"english2-2017-t2-p4-s2","examKey":"english2","examLabel":"英语二","year":"2017","text":2,"paragraph":4,"sentenceNo":2,"sentence":"Parents, he says, can get a lot out of using their devices to speak to a friend or get some work out of the way.","path":"english2/2017.html"},{"id":"english2-2017-t2-p4-s3","examKey":"english2","examLabel":"英语二","year":"2017","text":2,"paragraph":4,"sentenceNo":3,"sentence":"This can make them feel happier, which lets them be more available to their child the rest of the time.","path":"english2/2017.html"},{"id":"english2-2017-t3-p1-s1","examKey":"english2","examLabel":"英语二","year":"2017","text":3,"paragraph":1,"sentenceNo":1,"sentence":"Q31 原因定位 Today, widespread social pressure to immediately go to college in conjunction with increasingly high expectations in a fast-moving world often causes students to completely overlook the possibility of taking a gap year.","path":"english2/2017.html"},{"id":"english2-2017-t3-p1-s2","examKey":"english2","examLabel":"英语二","year":"2017","text":3,"paragraph":1,"sentenceNo":2,"sentence":"After all, if everyone you know is going to college in the fall, it seems silly to stay back a year, doesn’t it?","path":"english2/2017.html"},{"id":"english2-2017-t3-p1-s3","examKey":"english2","examLabel":"英语二","year":"2017","text":3,"paragraph":1,"sentenceNo":3,"sentence":"And after going to school for 12 years, it doesn’t feel natural to spend a year doing something that isn’t academic.","path":"english2/2017.html"},{"id":"english2-2017-t3-p2-s1","examKey":"english2","examLabel":"英语二","year":"2017","text":3,"paragraph":2,"sentenceNo":1,"sentence":"But while this may be true, it’s not a good enough reason to condemn gap years.","path":"english2/2017.html"},{"id":"english2-2017-t3-p2-s2","examKey":"english2","examLabel":"英语二","year":"2017","text":3,"paragraph":2,"sentenceNo":2,"sentence":"There’s always a constant fear of falling behind everyone else on the socially perpetuated “race to the finish line,” whether that be toward graduate school, medical school or a lucrative career.","path":"english2/2017.html"},{"id":"english2-2017-t3-p2-s3","examKey":"english2","examLabel":"英语二","year":"2017","text":3,"paragraph":2,"sentenceNo":3,"sentence":"But despite common misconceptions, a gap year does not hinder the success of academic pursuits — in fact, it probably enhances it.","path":"english2/2017.html"},{"id":"english2-2017-t3-p3-s1","examKey":"english2","examLabel":"英语二","year":"2017","text":3,"paragraph":3,"sentenceNo":1,"sentence":"Q32 研究定位 Q33 词义定位 Studies from the United States and Australia show that students who take a gap year are generally better prepared for and perform better in college than those who do not.","path":"english2/2017.html"},{"id":"english2-2017-t3-p3-s2","examKey":"english2","examLabel":"英语二","year":"2017","text":3,"paragraph":3,"sentenceNo":2,"sentence":"Rather than pulling students back, a gap year pushes them ahead by preparing them for independence, new responsibilities and environmental changes — all things that first-year students often struggle with the most.","path":"english2/2017.html"},{"id":"english2-2017-t3-p3-s3","examKey":"english2","examLabel":"英语二","year":"2017","text":3,"paragraph":3,"sentenceNo":3,"sentence":"Gap year experiences can lessen the blow when it comes to adjusting to college and being thrown into a brand new environment, making it easier to focus on academics and activities rather than acclimation blunders.","path":"english2/2017.html"},{"id":"english2-2017-t3-p4-s1","examKey":"english2","examLabel":"英语二","year":"2017","text":3,"paragraph":4,"sentenceNo":1,"sentence":"Q34 省钱定位 Q35 主旨定位 If you’re not convinced of the inherent value in taking a year off to explore interests, consider its financial impact on future academic choices.","path":"english2/2017.html"},{"id":"english2-2017-t3-p4-s2","examKey":"english2","examLabel":"英语二","year":"2017","text":3,"paragraph":4,"sentenceNo":2,"sentence":"According to the National Center for Education Statistics, nearly 80 percent of college students end up changing their majors at least once.","path":"english2/2017.html"},{"id":"english2-2017-t3-p4-s3","examKey":"english2","examLabel":"英语二","year":"2017","text":3,"paragraph":4,"sentenceNo":3,"sentence":"This isn’t necessarily a bad thing, but depending on the school, it can be very expensive.","path":"english2/2017.html"},{"id":"english2-2017-t3-p4-s4","examKey":"english2","examLabel":"英语二","year":"2017","text":3,"paragraph":4,"sentenceNo":4,"sentence":"Taking a gap year can help students make a more informed decision about what they want to study before they start paying tuition, reducing the risk of costly major changes later on.","path":"english2/2017.html"},{"id":"english2-2017-t4-p1-s1","examKey":"english2","examLabel":"英语二","year":"2017","text":4,"paragraph":1,"sentenceNo":1,"sentence":"Q36 2015 定位 Though often viewed as a problem for western states, the growing frequency of wildfires is a national concern because of its impact on federal tax dollars, says Professor Max Moritz, a specialist in fire ecology and management.","path":"english2/2017.html"},{"id":"english2-2017-t4-p2-s1","examKey":"english2","examLabel":"英语二","year":"2017","text":4,"paragraph":2,"sentenceNo":1,"sentence":"In 2015, the US Forest Service for the first time spent more than half of its $5.5 billion annual budget fighting fires — nearly double the percentage it spent on such efforts 20 years ago.","path":"english2/2017.html"},{"id":"english2-2017-t4-p2-s2","examKey":"english2","examLabel":"英语二","year":"2017","text":4,"paragraph":2,"sentenceNo":2,"sentence":"In effect, fewer federal funds today are going towards the agency’s other work — such as forest conservation, watershed and cultural resources management, and infrastructure upkeep — that affect the lives of all Americans.","path":"english2/2017.html"},{"id":"english2-2017-t4-p3-s1","examKey":"english2","examLabel":"英语二","year":"2017","text":4,"paragraph":3,"sentenceNo":1,"sentence":"Q37 magnifying glass Another nationwide concern is whether public funds from other agencies are going into construction in fire-prone districts.","path":"english2/2017.html"},{"id":"english2-2017-t4-p3-s2","examKey":"english2","examLabel":"英语二","year":"2017","text":4,"paragraph":3,"sentenceNo":2,"sentence":"As Moritz puts it, how often are federal dollars building homes that are likely to be lost to a wildfire?","path":"english2/2017.html"},{"id":"english2-2017-t4-p4-s1","examKey":"english2","examLabel":"英语二","year":"2017","text":4,"paragraph":4,"sentenceNo":1,"sentence":"“It’s already a huge problem from a public expenditure perspective for the whole country,” he says.","path":"english2/2017.html"},{"id":"english2-2017-t4-p4-s2","examKey":"english2","examLabel":"英语二","year":"2017","text":4,"paragraph":4,"sentenceNo":2,"sentence":"“We need to take a magnifying glass to that.","path":"english2/2017.html"},{"id":"english2-2017-t4-p4-s3","examKey":"english2","examLabel":"英语二","year":"2017","text":4,"paragraph":4,"sentenceNo":3,"sentence":"Like, ‘Wait a minute, is this OK?’ Do we want instead to redirect those funds to concentrate on lower-hazard parts of the landscape?”","path":"english2/2017.html"},{"id":"english2-2017-t4-p5-s1","examKey":"english2","examLabel":"英语二","year":"2017","text":4,"paragraph":5,"sentenceNo":1,"sentence":"Such a view would require a corresponding shift in the way US society today views fire, researchers say.","path":"english2/2017.html"},{"id":"english2-2017-t4-p6-s1","examKey":"english2","examLabel":"英语二","year":"2017","text":4,"paragraph":6,"sentenceNo":1,"sentence":"Q38 climate 定位 For one thing, conversations about wildfires need to be more inclusive.","path":"english2/2017.html"},{"id":"english2-2017-t4-p6-s2","examKey":"english2","examLabel":"英语二","year":"2017","text":4,"paragraph":6,"sentenceNo":2,"sentence":"Over the past decade, the focus has been on climate change — how the warming of the Earth from greenhouse gases is leading to conditions that worsen fires.","path":"english2/2017.html"},{"id":"english2-2017-t4-p7-s1","examKey":"english2","examLabel":"英语二","year":"2017","text":4,"paragraph":7,"sentenceNo":1,"sentence":"While climate is a key element, Moritz says, it shouldn’t come at the expense of the rest of the equation.","path":"english2/2017.html"},{"id":"english2-2017-t4-p8-s1","examKey":"english2","examLabel":"英语二","year":"2017","text":4,"paragraph":8,"sentenceNo":1,"sentence":"Q39 simplified view “The human systems ” and the landscapes we live on are linked, and the interactions go both ways,” he says.","path":"english2/2017.html"},{"id":"english2-2017-t4-p8-s2","examKey":"english2","examLabel":"英语二","year":"2017","text":4,"paragraph":8,"sentenceNo":2,"sentence":"Failing to recognize that, he notes, leads to “an overly simplified view” of what the solutions might be.","path":"english2/2017.html"},{"id":"english2-2017-t4-p8-s3","examKey":"english2","examLabel":"英语二","year":"2017","text":4,"paragraph":8,"sentenceNo":3,"sentence":"Our perception of the problem and of what the solution is becomes very limited.”","path":"english2/2017.html"},{"id":"english2-2017-t4-p9-s1","examKey":"english2","examLabel":"英语二","year":"2017","text":4,"paragraph":9,"sentenceNo":1,"sentence":"Q40 Balch 定位 At the same time, people continue to treat fire as an event that needs to wholly controlled and unleashed only out of necessity, says Professor Balch at the University of Colorado.","path":"english2/2017.html"},{"id":"english2-2017-t4-p9-s2","examKey":"english2","examLabel":"英语二","year":"2017","text":4,"paragraph":9,"sentenceNo":2,"sentence":"But acknowledging fire’s inevitable presence in human life is an attitude crucial to developing the laws, policies, and practices that make it as safe as possible, she says.","path":"english2/2017.html"},{"id":"english2-2017-t4-p10-s1","examKey":"english2","examLabel":"英语二","year":"2017","text":4,"paragraph":10,"sentenceNo":1,"sentence":"“We’ve disconnected ourselves from living with fire,” Balch says.","path":"english2/2017.html"},{"id":"english2-2017-t4-p10-s2","examKey":"english2","examLabel":"英语二","year":"2017","text":4,"paragraph":10,"sentenceNo":2,"sentence":"“It is really important to understand and try and tease out what is the human connection with fire today.”","path":"english2/2017.html"},{"id":"english1-2018-t1-p1-s1","examKey":"english1","examLabel":"英语一","year":"2018","text":1,"paragraph":1,"sentenceNo":1,"sentence":"Among the annoying challenges facing the middle class is one that will probably go unmentioned in the next presidential campaign: What happens when the robots come for their jobs?","path":"english1/2018.html"},{"id":"english1-2018-t1-p2-s1","examKey":"english1","examLabel":"英语一","year":"2018","text":1,"paragraph":2,"sentenceNo":1,"sentence":"Don't dismiss that possibility entirely.","path":"english1/2018.html"},{"id":"english1-2018-t1-p2-s2","examKey":"english1","examLabel":"英语一","year":"2018","text":1,"paragraph":2,"sentenceNo":2,"sentence":"About half of U.S. jobs are at high risk of being automated, according to a University of Oxford study, with the middle class disproportionately squeezed.","path":"english1/2018.html"},{"id":"english1-2018-t1-p2-s3","examKey":"english1","examLabel":"英语一","year":"2018","text":1,"paragraph":2,"sentenceNo":3,"sentence":"Lower-income jobs like gardening or day care don't appeal to robots.","path":"english1/2018.html"},{"id":"english1-2018-t1-p2-s4","examKey":"english1","examLabel":"英语一","year":"2018","text":1,"paragraph":2,"sentenceNo":4,"sentence":"But many middle-class occupations —trucking, financial advice, software engineering—have aroused their interest, or soon will.","path":"english1/2018.html"},{"id":"english1-2018-t1-p2-s5","examKey":"english1","examLabel":"英语一","year":"2018","text":1,"paragraph":2,"sentenceNo":5,"sentence":"The rich own the robots, so they will be fine.","path":"english1/2018.html"},{"id":"english1-2018-t1-p3-s1","examKey":"english1","examLabel":"英语一","year":"2018","text":1,"paragraph":3,"sentenceNo":1,"sentence":"This isn't to be alarmist.","path":"english1/2018.html"},{"id":"english1-2018-t1-p3-s2","examKey":"english1","examLabel":"英语一","year":"2018","text":1,"paragraph":3,"sentenceNo":2,"sentence":"Optimists point out that technological upheaval has benefited workers in the past.","path":"english1/2018.html"},{"id":"english1-2018-t1-p3-s3","examKey":"english1","examLabel":"英语一","year":"2018","text":1,"paragraph":3,"sentenceNo":3,"sentence":"The Industrial Revolution didn't go so well for Luddites whose jobs were displaced by mechanized looms, but it eventually raised living standards and created more jobs than it destroyed.","path":"english1/2018.html"},{"id":"english1-2018-t1-p3-s4","examKey":"english1","examLabel":"英语一","year":"2018","text":1,"paragraph":3,"sentenceNo":4,"sentence":"Likewise, automation should eventually boost productivity, stimulate demand by driving down prices, and free workers from hard, boring work.","path":"english1/2018.html"},{"id":"english1-2018-t1-p3-s5","examKey":"english1","examLabel":"英语一","year":"2018","text":1,"paragraph":3,"sentenceNo":5,"sentence":"But in the medium term, middle-class workers may need a lot of help adjusting.","path":"english1/2018.html"},{"id":"english1-2018-t1-p4-s1","examKey":"english1","examLabel":"英语一","year":"2018","text":1,"paragraph":4,"sentenceNo":1,"sentence":"The first step, as Erik Brynjolfsson and Andrew McAfee argue in The Second Machine Age, should be rethinking education and job training.","path":"english1/2018.html"},{"id":"english1-2018-t1-p4-s2","examKey":"english1","examLabel":"英语一","year":"2018","text":1,"paragraph":4,"sentenceNo":2,"sentence":"Curriculums—from grammar school to college—should evolve to focus less on memorizing facts and more on creativity and complex communication.","path":"english1/2018.html"},{"id":"english1-2018-t1-p4-s3","examKey":"english1","examLabel":"英语一","year":"2018","text":1,"paragraph":4,"sentenceNo":3,"sentence":"Vocational schools should do a better job of fostering problem -solving skills and helping students work alongside robots.","path":"english1/2018.html"},{"id":"english1-2018-t1-p4-s4","examKey":"english1","examLabel":"英语一","year":"2018","text":1,"paragraph":4,"sentenceNo":4,"sentence":"Online education can supplement the traditional kind.","path":"english1/2018.html"},{"id":"english1-2018-t1-p4-s5","examKey":"english1","examLabel":"英语一","year":"2018","text":1,"paragraph":4,"sentenceNo":5,"sentence":"It could make extra training and instruction affordable.","path":"english1/2018.html"},{"id":"english1-2018-t1-p4-s6","examKey":"english1","examLabel":"英语一","year":"2018","text":1,"paragraph":4,"sentenceNo":6,"sentence":"Professionals trying to acquire new skills will be able to do so without going into debt.","path":"english1/2018.html"},{"id":"english1-2018-t1-p5-s1","examKey":"english1","examLabel":"英语一","year":"2018","text":1,"paragraph":5,"sentenceNo":1,"sentence":"The challenge of coping with automation underlines the need for the U.S. to revive its fading business dynamism: Starting new companies must be made easier.","path":"english1/2018.html"},{"id":"english1-2018-t1-p5-s2","examKey":"english1","examLabel":"英语一","year":"2018","text":1,"paragraph":5,"sentenceNo":2,"sentence":"In previous eras of drastic technological change, entrepreneurs smoothed the transition by dreaming up ways to combine labor and machines.","path":"english1/2018.html"},{"id":"english1-2018-t1-p5-s3","examKey":"english1","examLabel":"英语一","year":"2018","text":1,"paragraph":5,"sentenceNo":3,"sentence":"The best uses of 3D printers and virtual reality haven't been invented yet.","path":"english1/2018.html"},{"id":"english1-2018-t1-p5-s4","examKey":"english1","examLabel":"英语一","year":"2018","text":1,"paragraph":5,"sentenceNo":4,"sentence":"The U.S. needs the new companies that will invent them.","path":"english1/2018.html"},{"id":"english1-2018-t1-p6-s1","examKey":"english1","examLabel":"英语一","year":"2018","text":1,"paragraph":6,"sentenceNo":1,"sentence":"Finally, because automation threatens to widen the gap between capital income and labor income, taxes and the safety net will have to be rethought.","path":"english1/2018.html"},{"id":"english1-2018-t1-p6-s2","examKey":"english1","examLabel":"英语一","year":"2018","text":1,"paragraph":6,"sentenceNo":2,"sentence":"Taxes on low-wage labor need to be cut, and wage subsidies such as the earned income tax credit should be expanded: This would boost incomes, encourage work, reward companies for job creation, and reduce inequality.","path":"english1/2018.html"},{"id":"english1-2018-t1-p7-s1","examKey":"english1","examLabel":"英语一","year":"2018","text":1,"paragraph":7,"sentenceNo":1,"sentence":"Technology will improve society in ways big and small over the next few years, yet this will be little comfort to those who find their lives and careers upended by automation.","path":"english1/2018.html"},{"id":"english1-2018-t1-p7-s2","examKey":"english1","examLabel":"英语一","year":"2018","text":1,"paragraph":7,"sentenceNo":2,"sentence":"Destroying the machines that are coming for our jobs would be nuts.","path":"english1/2018.html"},{"id":"english1-2018-t1-p7-s3","examKey":"english1","examLabel":"英语一","year":"2018","text":1,"paragraph":7,"sentenceNo":3,"sentence":"But policies to help workers adapt will be indispensable.","path":"english1/2018.html"},{"id":"english1-2018-t2-p1-s1","examKey":"english1","examLabel":"英语一","year":"2018","text":2,"paragraph":1,"sentenceNo":1,"sentence":"A new survey by Harvard University finds more than two-thirds of young Americans disapprove of President Trump's use of Twitter.","path":"english1/2018.html"},{"id":"english1-2018-t2-p1-s2","examKey":"english1","examLabel":"英语一","year":"2018","text":2,"paragraph":1,"sentenceNo":2,"sentence":"The implication is that Millennials prefer news from the White House to be filtered through other sources, not a president's social media platform.","path":"english1/2018.html"},{"id":"english1-2018-t2-p2-s1","examKey":"english1","examLabel":"英语一","year":"2018","text":2,"paragraph":2,"sentenceNo":1,"sentence":"Most Americans rely on social media to check daily head line s.","path":"english1/2018.html"},{"id":"english1-2018-t2-p2-s2","examKey":"english1","examLabel":"英语一","year":"2018","text":2,"paragraph":2,"sentenceNo":2,"sentence":"Yet as distrust has risen toward all media, people may be starting to beef up their media literacy skills.","path":"english1/2018.html"},{"id":"english1-2018-t2-p2-s3","examKey":"english1","examLabel":"英语一","year":"2018","text":2,"paragraph":2,"sentenceNo":3,"sentence":"Such a trend is badly needed.","path":"english1/2018.html"},{"id":"english1-2018-t2-p2-s4","examKey":"english1","examLabel":"英语一","year":"2018","text":2,"paragraph":2,"sentenceNo":4,"sentence":"During the 2016 presidential campaign, nearly a quarter of web content shared by Twitter users in the politically critical state of Michigan was fake news, according to the University of Oxford.","path":"english1/2018.html"},{"id":"english1-2018-t2-p2-s5","examKey":"english1","examLabel":"英语一","year":"2018","text":2,"paragraph":2,"sentenceNo":5,"sentence":"And a survey conducted for BuzzFeed News found 44 percent of Facebook users rarely or never trust news from the media giant.","path":"english1/2018.html"},{"id":"english1-2018-t2-p3-s1","examKey":"english1","examLabel":"英语一","year":"2018","text":2,"paragraph":3,"sentenceNo":1,"sentence":"Young people who are digital natives are indeed becoming more skillful at se para ting fact from fiction in cyberspace.","path":"english1/2018.html"},{"id":"english1-2018-t2-p3-s2","examKey":"english1","examLabel":"英语一","year":"2018","text":2,"paragraph":3,"sentenceNo":2,"sentence":"A Knight Foundation focus-group survey of young people between ages 14 and 24 found they use “distributed trust” to verify stories.","path":"english1/2018.html"},{"id":"english1-2018-t2-p3-s3","examKey":"english1","examLabel":"英语一","year":"2018","text":2,"paragraph":3,"sentenceNo":3,"sentence":"They cross-check sources and prefer news from different perspectives—especially those that are open about any bias.","path":"english1/2018.html"},{"id":"english1-2018-t2-p3-s4","examKey":"english1","examLabel":"英语一","year":"2018","text":2,"paragraph":3,"sentenceNo":4,"sentence":"“ Many young people assume a great deal of personal responsibility for educating themselves and actively seeking out opposing viewpoints,” the survey concluded.","path":"english1/2018.html"},{"id":"english1-2018-t2-p4-s1","examKey":"english1","examLabel":"英语一","year":"2018","text":2,"paragraph":4,"sentenceNo":1,"sentence":"Such active research can have another effect.","path":"english1/2018.html"},{"id":"english1-2018-t2-p4-s2","examKey":"english1","examLabel":"英语一","year":"2018","text":2,"paragraph":4,"sentenceNo":2,"sentence":"A 2014 survey conducted in Australia, Britain, and the United States by the University of Wisconsin-Madison found that young people's reliance on social media led to greater political engagement.","path":"english1/2018.html"},{"id":"english1-2018-t2-p5-s1","examKey":"english1","examLabel":"英语一","year":"2018","text":2,"paragraph":5,"sentenceNo":1,"sentence":"Social media allows users to experience news events more intimately and immediately while also permitting them to re-share news as a projection of their values and interests.","path":"english1/2018.html"},{"id":"english1-2018-t2-p5-s2","examKey":"english1","examLabel":"英语一","year":"2018","text":2,"paragraph":5,"sentenceNo":2,"sentence":"This forces users to be more conscious of their role in passing along information.","path":"english1/2018.html"},{"id":"english1-2018-t2-p5-s3","examKey":"english1","examLabel":"英语一","year":"2018","text":2,"paragraph":5,"sentenceNo":3,"sentence":"A survey by Barna research group found the top reason given by Americans for the fake news phenomenon is “reader error,” more so than made-up stories or factual mistakes in reporting.","path":"english1/2018.html"},{"id":"english1-2018-t2-p5-s4","examKey":"english1","examLabel":"英语一","year":"2018","text":2,"paragraph":5,"sentenceNo":4,"sentence":"About a third say the problem of fake news lies in “misinterpretation or exaggeration of actual news” via social media.","path":"english1/2018.html"},{"id":"english1-2018-t2-p5-s5","examKey":"english1","examLabel":"英语一","year":"2018","text":2,"paragraph":5,"sentenceNo":5,"sentence":"In other words, the choice to share news on social media may be the heart of the issue.","path":"english1/2018.html"},{"id":"english1-2018-t2-p5-s6","examKey":"english1","examLabel":"英语一","year":"2018","text":2,"paragraph":5,"sentenceNo":6,"sentence":"“This indicates there is a real personal responsibility in counteracting this problem,” says Roxanne Stone, editor in chief at Barna Group.","path":"english1/2018.html"},{"id":"english1-2018-t2-p6-s1","examKey":"english1","examLabel":"英语一","year":"2018","text":2,"paragraph":6,"sentenceNo":1,"sentence":"So when young people are critical of an over-tweeting president, they reveal a mental discipline in thinking skills —and in their choices on when to share on social media.","path":"english1/2018.html"},{"id":"english1-2018-t3-p1-s1","examKey":"english1","examLabel":"英语一","year":"2018","text":3,"paragraph":1,"sentenceNo":1,"sentence":"Any fair-minded assessment of the dangers of the deal between Britain's National Health Service (NHS) and DeepMind must start by acknowledging that both sides mean well.","path":"english1/2018.html"},{"id":"english1-2018-t3-p1-s2","examKey":"english1","examLabel":"英语一","year":"2018","text":3,"paragraph":1,"sentenceNo":2,"sentence":"DeepMind is one of the leading artificial intelligence (AI) companies in the world.","path":"english1/2018.html"},{"id":"english1-2018-t3-p1-s3","examKey":"english1","examLabel":"英语一","year":"2018","text":3,"paragraph":1,"sentenceNo":3,"sentence":"The potential of this work applied to healthcare is very great, but it could also lead to further concentration of power in the tech giants.","path":"english1/2018.html"},{"id":"english1-2018-t3-p1-s4","examKey":"english1","examLabel":"英语一","year":"2018","text":3,"paragraph":1,"sentenceNo":4,"sentence":"It is against that background that the information commissioner, Elizabeth Denham, has issued her damning verdict against the Royal Free hospital trust under the NHS, which handed over to DeepMind the records of 1.6 million patients in 2015 on the basis of a vague agreement which took far too little account of the patients' rights and their expectations of privacy.","path":"english1/2018.html"},{"id":"english1-2018-t3-p2-s1","examKey":"english1","examLabel":"英语一","year":"2018","text":3,"paragraph":2,"sentenceNo":1,"sentence":"DeepMind has almost apologized.","path":"english1/2018.html"},{"id":"english1-2018-t3-p2-s2","examKey":"english1","examLabel":"英语一","year":"2018","text":3,"paragraph":2,"sentenceNo":2,"sentence":"The NHS trust has mended its ways.","path":"english1/2018.html"},{"id":"english1-2018-t3-p2-s3","examKey":"english1","examLabel":"英语一","year":"2018","text":3,"paragraph":2,"sentenceNo":3,"sentence":"Further arrangements—and there may be many—between the NHS and DeepMind will be carefully scrutinised to ensure that all necessary permissions have been asked of patients and all unnecessary data has been cleaned.","path":"english1/2018.html"},{"id":"english1-2018-t3-p2-s4","examKey":"english1","examLabel":"英语一","year":"2018","text":3,"paragraph":2,"sentenceNo":4,"sentence":"There are lessons about informed patient consent to learn.","path":"english1/2018.html"},{"id":"english1-2018-t3-p2-s5","examKey":"english1","examLabel":"英语一","year":"2018","text":3,"paragraph":2,"sentenceNo":5,"sentence":"But privacy is not the only angle in this case and not even the most important.","path":"english1/2018.html"},{"id":"english1-2018-t3-p2-s6","examKey":"english1","examLabel":"英语一","year":"2018","text":3,"paragraph":2,"sentenceNo":6,"sentence":"Ms Denham chose to concentrate the blame on the NHS trust, since under existing law it “controlled” the data and DeepMind merely “processed” it.","path":"english1/2018.html"},{"id":"english1-2018-t3-p2-s7","examKey":"english1","examLabel":"英语一","year":"2018","text":3,"paragraph":2,"sentenceNo":7,"sentence":"But this distinction misses the point that it is processing and aggregation, not the mere possession of bits, that gives the data value.","path":"english1/2018.html"},{"id":"english1-2018-t3-p3-s1","examKey":"english1","examLabel":"英语一","year":"2018","text":3,"paragraph":3,"sentenceNo":1,"sentence":"The great question is who should benefit from the analysis of all the data that our lives now generate.","path":"english1/2018.html"},{"id":"english1-2018-t3-p3-s2","examKey":"english1","examLabel":"英语一","year":"2018","text":3,"paragraph":3,"sentenceNo":2,"sentence":"Privacy law builds on the concept of damage to an individual from identifiable knowledge about them.","path":"english1/2018.html"},{"id":"english1-2018-t3-p3-s3","examKey":"english1","examLabel":"英语一","year":"2018","text":3,"paragraph":3,"sentenceNo":3,"sentence":"That misses the way the surveillance economy works.","path":"english1/2018.html"},{"id":"english1-2018-t3-p3-s4","examKey":"english1","examLabel":"英语一","year":"2018","text":3,"paragraph":3,"sentenceNo":4,"sentence":"The data of an individual there gains its value only when it is compared with the data of countless millions more.","path":"english1/2018.html"},{"id":"english1-2018-t3-p4-s1","examKey":"english1","examLabel":"英语一","year":"2018","text":3,"paragraph":4,"sentenceNo":1,"sentence":"The use of privacy law to curb the tech giants in this instance feels slightly maladapted.","path":"english1/2018.html"},{"id":"english1-2018-t3-p4-s2","examKey":"english1","examLabel":"英语一","year":"2018","text":3,"paragraph":4,"sentenceNo":2,"sentence":"This practice does not address the real worry.","path":"english1/2018.html"},{"id":"english1-2018-t3-p4-s3","examKey":"english1","examLabel":"英语一","year":"2018","text":3,"paragraph":4,"sentenceNo":3,"sentence":"It is not enough to say that the algorithms DeepMind develops will benefit patients and save lives.","path":"english1/2018.html"},{"id":"english1-2018-t3-p4-s4","examKey":"english1","examLabel":"英语一","year":"2018","text":3,"paragraph":4,"sentenceNo":4,"sentence":"What matters is that they will belong to a private monopoly which developed them using public resources.","path":"english1/2018.html"},{"id":"english1-2018-t3-p4-s5","examKey":"english1","examLabel":"英语一","year":"2018","text":3,"paragraph":4,"sentenceNo":5,"sentence":"If software promises to save lives on the scale that drugs now can, big data may be expected to behave as a big pharma has done.","path":"english1/2018.html"},{"id":"english1-2018-t3-p5-s1","examKey":"english1","examLabel":"英语一","year":"2018","text":3,"paragraph":5,"sentenceNo":1,"sentence":"We are still at the beginning of this revolution and small choices now may turn out to have gigantic consequences later.","path":"english1/2018.html"},{"id":"english1-2018-t3-p5-s2","examKey":"english1","examLabel":"英语一","year":"2018","text":3,"paragraph":5,"sentenceNo":2,"sentence":"A long struggle will be needed to avoid a future of digital feudalism.","path":"english1/2018.html"},{"id":"english1-2018-t3-p5-s3","examKey":"english1","examLabel":"英语一","year":"2018","text":3,"paragraph":5,"sentenceNo":3,"sentence":"Ms Denham's report is a welcome start.","path":"english1/2018.html"},{"id":"english1-2018-t4-p1-s1","examKey":"english1","examLabel":"英语一","year":"2018","text":4,"paragraph":1,"sentenceNo":1,"sentence":"The U.S.","path":"english1/2018.html"},{"id":"english1-2018-t4-p1-s2","examKey":"english1","examLabel":"英语一","year":"2018","text":4,"paragraph":1,"sentenceNo":2,"sentence":"Postal Service ( USPS ) continues to bleed red ink.","path":"english1/2018.html"},{"id":"english1-2018-t4-p1-s3","examKey":"english1","examLabel":"英语一","year":"2018","text":4,"paragraph":1,"sentenceNo":3,"sentence":"It reported a net loss of $5.6 billion for fiscal 2016, the 10th straight year its expenses have exceeded revenue.","path":"english1/2018.html"},{"id":"english1-2018-t4-p1-s4","examKey":"english1","examLabel":"英语一","year":"2018","text":4,"paragraph":1,"sentenceNo":4,"sentence":"Meanwhile, it has more than $120 billion in unfunded liabilities, mostly for employee health and retirement costs.","path":"english1/2018.html"},{"id":"english1-2018-t4-p1-s5","examKey":"english1","examLabel":"英语一","year":"2018","text":4,"paragraph":1,"sentenceNo":5,"sentence":"There are many reasons this formerly stable federal institution finds itself at the brink of bankruptcy.","path":"english1/2018.html"},{"id":"english1-2018-t4-p1-s6","examKey":"english1","examLabel":"英语一","year":"2018","text":4,"paragraph":1,"sentenceNo":6,"sentence":"Fundamentally, the USPS is in a historic squeeze between technological change that has permanently decreased demand for its bread-and-butter product, first-class mail, and a regulatory structure that denies management the flexibility to adjust its operations to the new reality.","path":"english1/2018.html"},{"id":"english1-2018-t4-p2-s1","examKey":"english1","examLabel":"英语一","year":"2018","text":4,"paragraph":2,"sentenceNo":1,"sentence":"And interest groups ranging from postal unions to greeting-card makers exert self-interested pressure on the USPS's ultimate overseer—Congress—insisting that whatever else happens to the Postal Service, aspects of the status quo they depend on get protected.","path":"english1/2018.html"},{"id":"english1-2018-t4-p2-s2","examKey":"english1","examLabel":"英语一","year":"2018","text":4,"paragraph":2,"sentenceNo":2,"sentence":"This is why repeated attempts at reform legislation have failed in recent years, leaving the Postal Service unable to pay its bills except by deferring vital modernization.","path":"english1/2018.html"},{"id":"english1-2018-t4-p3-s1","examKey":"english1","examLabel":"英语一","year":"2018","text":4,"paragraph":3,"sentenceNo":1,"sentence":"Now comes word that everyone involved—Democrats, Republicans, the Postal Service, the unions and the system's heaviest users—has finally agreed on a plan to fix the system.","path":"english1/2018.html"},{"id":"english1-2018-t4-p3-s2","examKey":"english1","examLabel":"英语一","year":"2018","text":4,"paragraph":3,"sentenceNo":2,"sentence":"Legislation is moving through the House that would save USPS an estimated $28.6 billion over five years, which could help pay for new vehicles, among other survival measures.","path":"english1/2018.html"},{"id":"english1-2018-t4-p3-s3","examKey":"english1","examLabel":"英语一","year":"2018","text":4,"paragraph":3,"sentenceNo":3,"sentence":"Most of the money would come from a penny-per-letter permanent rate increase and from shifting postal retirees into Medicare.","path":"english1/2018.html"},{"id":"english1-2018-t4-p3-s4","examKey":"english1","examLabel":"英语一","year":"2018","text":4,"paragraph":3,"sentenceNo":4,"sentence":"The latter step would largely offset the financial burden of annually pre-funding retiree health care, thus addressing a long-standing complaint by the USPS and its unions.","path":"english1/2018.html"},{"id":"english1-2018-t4-p4-s1","examKey":"english1","examLabel":"英语一","year":"2018","text":4,"paragraph":4,"sentenceNo":1,"sentence":"If it clears the House, this measure would still have to get through the Senate—where someone is bound to point out that it amounts to the bare, bare minimum necessary to keep the Postal Service afloat, not comprehensive reform.","path":"english1/2018.html"},{"id":"english1-2018-t4-p4-s2","examKey":"english1","examLabel":"英语一","year":"2018","text":4,"paragraph":4,"sentenceNo":2,"sentence":"There's no change to collective bargaining at the USPS, a major omission considering that personnel accounts for 80 percent of the agency's costs.","path":"english1/2018.html"},{"id":"english1-2018-t4-p4-s3","examKey":"english1","examLabel":"英语一","year":"2018","text":4,"paragraph":4,"sentenceNo":3,"sentence":"Also missing is any discussion of eliminating Saturday letter delivery.","path":"english1/2018.html"},{"id":"english1-2018-t4-p4-s4","examKey":"english1","examLabel":"英语一","year":"2018","text":4,"paragraph":4,"sentenceNo":4,"sentence":"That common-sense change enjoys wide public support and would save the USPS $2 billion per year.","path":"english1/2018.html"},{"id":"english1-2018-t4-p4-s5","examKey":"english1","examLabel":"英语一","year":"2018","text":4,"paragraph":4,"sentenceNo":5,"sentence":"But postal special-interest groups seem to have killed it, at least in the House.","path":"english1/2018.html"},{"id":"english1-2018-t4-p4-s6","examKey":"english1","examLabel":"英语一","year":"2018","text":4,"paragraph":4,"sentenceNo":6,"sentence":"The emerging consensus around the bill is a sign that legislators are getting frightened about a politically embarrassing short-term collapse at the USPS.","path":"english1/2018.html"},{"id":"english1-2018-t4-p4-s7","examKey":"english1","examLabel":"英语一","year":"2018","text":4,"paragraph":4,"sentenceNo":7,"sentence":"It is not, however, a sign that they're getting serious about transforming the postal system for the 21st century.","path":"english1/2018.html"},{"id":"english2-2018-t1-p1-s1","examKey":"english2","examLabel":"英语二","year":"2018","text":1,"paragraph":1,"sentenceNo":1,"sentence":"1 It is curious that Stephen Koziatek feels almost as though he has to justify his efforts to give his students a better future.","path":"english2/2018.html"},{"id":"english2-2018-t1-p2-s1","examKey":"english2","examLabel":"英语二","year":"2018","text":1,"paragraph":2,"sentenceNo":1,"sentence":"2 Mr.","path":"english2/2018.html"},{"id":"english2-2018-t1-p2-s2","examKey":"english2","examLabel":"英语二","year":"2018","text":1,"paragraph":2,"sentenceNo":2,"sentence":"Koziatek is part of something pioneering.","path":"english2/2018.html"},{"id":"english2-2018-t1-p2-s3","examKey":"english2","examLabel":"英语二","year":"2018","text":1,"paragraph":2,"sentenceNo":3,"sentence":"He is a teacher at a New Hampshire high school where learning is not something of books and tests and mechanical memorization, but practical.","path":"english2/2018.html"},{"id":"english2-2018-t1-p2-s4","examKey":"english2","examLabel":"英语二","year":"2018","text":1,"paragraph":2,"sentenceNo":4,"sentence":"3 When did it become accepted wisdom that students should be able to name the 13th president of the United States but be utterly overwhelmed by a broken bike chain?","path":"english2/2018.html"},{"id":"english2-2018-t1-p3-s1","examKey":"english2","examLabel":"英语二","year":"2018","text":1,"paragraph":3,"sentenceNo":1,"sentence":"4 As Koziatek knows, there is learning in just about everything.","path":"english2/2018.html"},{"id":"english2-2018-t1-p3-s2","examKey":"english2","examLabel":"英语二","year":"2018","text":1,"paragraph":3,"sentenceNo":2,"sentence":"Nothing is necessarily gained by forcing students to learn geometry at a graffitied desk stuck with generations of discarded chewing gum.","path":"english2/2018.html"},{"id":"english2-2018-t1-p3-s3","examKey":"english2","examLabel":"英语二","year":"2018","text":1,"paragraph":3,"sentenceNo":3,"sentence":"5 They can also learn geometry by assembling a bicycle.","path":"english2/2018.html"},{"id":"english2-2018-t1-p4-s1","examKey":"english2","examLabel":"英语二","year":"2018","text":1,"paragraph":4,"sentenceNo":1,"sentence":"6 But he’s also found a kind of insidious prejudice.","path":"english2/2018.html"},{"id":"english2-2018-t1-p4-s2","examKey":"english2","examLabel":"英语二","year":"2018","text":1,"paragraph":4,"sentenceNo":2,"sentence":"7 Working with your hands is seen as almost a mark of inferiority.","path":"english2/2018.html"},{"id":"english2-2018-t1-p4-s3","examKey":"english2","examLabel":"英语二","year":"2018","text":1,"paragraph":4,"sentenceNo":3,"sentence":"8 Schools in the family of vocational education “have that stereotype...that it’s for kids who can’t make it academically,” he says.","path":"english2/2018.html"},{"id":"english2-2018-t1-p5-s1","examKey":"english2","examLabel":"英语二","year":"2018","text":1,"paragraph":5,"sentenceNo":1,"sentence":"Q23 段落定位 9 On one hand, that viewpoint is a logical product of America’s evolution.","path":"english2/2018.html"},{"id":"english2-2018-t1-p5-s2","examKey":"english2","examLabel":"英语二","year":"2018","text":1,"paragraph":5,"sentenceNo":2,"sentence":"Manufacturing is not the economic engine that it once was.","path":"english2/2018.html"},{"id":"english2-2018-t1-p5-s3","examKey":"english2","examLabel":"英语二","year":"2018","text":1,"paragraph":5,"sentenceNo":3,"sentence":"10 The job security that the US economy once offered to high school graduates has largely evaporated.","path":"english2/2018.html"},{"id":"english2-2018-t1-p5-s4","examKey":"english2","examLabel":"英语二","year":"2018","text":1,"paragraph":5,"sentenceNo":4,"sentence":"11 More education is the new principle.","path":"english2/2018.html"},{"id":"english2-2018-t1-p5-s5","examKey":"english2","examLabel":"英语二","year":"2018","text":1,"paragraph":5,"sentenceNo":5,"sentence":"We want more for our kids, and rightfully so.","path":"english2/2018.html"},{"id":"english2-2018-t1-p6-s1","examKey":"english2","examLabel":"英语二","year":"2018","text":1,"paragraph":6,"sentenceNo":1,"sentence":"12 But the headlong push into bachelor’s degrees for all — and the subtle devaluing of anything less — misses an important point: That’s not the only thing the American economy needs.","path":"english2/2018.html"},{"id":"english2-2018-t1-p6-s2","examKey":"english2","examLabel":"英语二","year":"2018","text":1,"paragraph":6,"sentenceNo":2,"sentence":"13 Yes, a bachelor’s degree opens more doors.","path":"english2/2018.html"},{"id":"english2-2018-t1-p6-s3","examKey":"english2","examLabel":"英语二","year":"2018","text":1,"paragraph":6,"sentenceNo":3,"sentence":"But even now, 54 percent of the jobs in the country are middle-skill jobs, such as construction and high-skill manufacturing.","path":"english2/2018.html"},{"id":"english2-2018-t1-p6-s4","examKey":"english2","examLabel":"英语二","year":"2018","text":1,"paragraph":6,"sentenceNo":4,"sentence":"But only 44 percent of workers are adequately trained.","path":"english2/2018.html"},{"id":"english2-2018-t1-p7-s1","examKey":"english2","examLabel":"英语二","year":"2018","text":1,"paragraph":7,"sentenceNo":1,"sentence":"14 In other words, at a time when the working class has turned the country on its political head, frustrated that the opportunity that once defined America is vanishing, one obvious solution is staring us in the face.","path":"english2/2018.html"},{"id":"english2-2018-t1-p7-s2","examKey":"english2","examLabel":"英语二","year":"2018","text":1,"paragraph":7,"sentenceNo":2,"sentence":"15 There is a gap in working-class jobs, but the workers who need those jobs most aren’t equipped to do them.","path":"english2/2018.html"},{"id":"english2-2018-t1-p7-s3","examKey":"english2","examLabel":"英语二","year":"2018","text":1,"paragraph":7,"sentenceNo":3,"sentence":"16 Koziatek’s Manchester School of Technology High School is trying to fill that gap.","path":"english2/2018.html"},{"id":"english2-2018-t1-p8-s1","examKey":"english2","examLabel":"英语二","year":"2018","text":1,"paragraph":8,"sentenceNo":1,"sentence":"17 Koziatek’s school is a wake-up call.","path":"english2/2018.html"},{"id":"english2-2018-t1-p8-s2","examKey":"english2","examLabel":"英语二","year":"2018","text":1,"paragraph":8,"sentenceNo":2,"sentence":"When education becomes one-size-fits-all, it risks overlooking a nation’s diversity of gifts.","path":"english2/2018.html"},{"id":"english2-2018-t2-p1-s1","examKey":"english2","examLabel":"英语二","year":"2018","text":2,"paragraph":1,"sentenceNo":1,"sentence":"1 While fossil fuels — coal, oil, gas — still generate roughly 85 percent of the world’s energy supply, it’s clearer than ever that the future belongs to renewable sources such as wind and solar.","path":"english2/2018.html"},{"id":"english2-2018-t2-p1-s2","examKey":"english2","examLabel":"英语二","year":"2018","text":2,"paragraph":1,"sentenceNo":2,"sentence":"2 The move to renewables is picking up momentum around the world: They now account for more than half of new power sources going on line.","path":"english2/2018.html"},{"id":"english2-2018-t2-p2-s1","examKey":"english2","examLabel":"英语二","year":"2018","text":2,"paragraph":2,"sentenceNo":1,"sentence":"3 Some growth stems from a commitment by governments and farsighted businesses to fund cleaner energy sources.","path":"english2/2018.html"},{"id":"english2-2018-t2-p2-s2","examKey":"english2","examLabel":"英语二","year":"2018","text":2,"paragraph":2,"sentenceNo":2,"sentence":"4 But increasingly the story is about the plummeting prices of renewables, especially wind and solar.","path":"english2/2018.html"},{"id":"english2-2018-t2-p2-s3","examKey":"english2","examLabel":"英语二","year":"2018","text":2,"paragraph":2,"sentenceNo":3,"sentence":"5 The cost of solar panels has dropped by 80 percent and the cost of wind turbines by close to one-third in the past eight years.","path":"english2/2018.html"},{"id":"english2-2018-t2-p3-s1","examKey":"english2","examLabel":"英语二","year":"2018","text":2,"paragraph":3,"sentenceNo":1,"sentence":"6 In many parts of the world renewable energy is already a principal energy source.","path":"english2/2018.html"},{"id":"english2-2018-t2-p3-s2","examKey":"english2","examLabel":"英语二","year":"2018","text":2,"paragraph":3,"sentenceNo":2,"sentence":"7 In Scotland, for example, wind turbines provide enough electricity to power 95 percent of homes.","path":"english2/2018.html"},{"id":"english2-2018-t2-p3-s3","examKey":"english2","examLabel":"英语二","year":"2018","text":2,"paragraph":3,"sentenceNo":3,"sentence":"8 While the rest of the world takes the lead, notably China and Europe, the United States is also seeing a remarkable shift.","path":"english2/2018.html"},{"id":"english2-2018-t2-p3-s4","examKey":"english2","examLabel":"英语二","year":"2018","text":2,"paragraph":3,"sentenceNo":4,"sentence":"9 In March, for the first time, wind and solar power accounted for more than 10 percent of the power generated in the US, reported the US Energy Information Administration.","path":"english2/2018.html"},{"id":"english2-2018-t2-p4-s1","examKey":"english2","examLabel":"英语二","year":"2018","text":2,"paragraph":4,"sentenceNo":1,"sentence":"10 President Trump has underlined fossil fuels — especially coal — as the path to economic growth.","path":"english2/2018.html"},{"id":"english2-2018-t2-p4-s2","examKey":"english2","examLabel":"英语二","year":"2018","text":2,"paragraph":4,"sentenceNo":2,"sentence":"11 In a recent speech in Iowa, he dismissed wind power as an unreliable energy source.","path":"english2/2018.html"},{"id":"english2-2018-t2-p4-s3","examKey":"english2","examLabel":"英语二","year":"2018","text":2,"paragraph":4,"sentenceNo":3,"sentence":"12 But that message did not play well with many in Iowa, where wind turbines dot the fields and provide 36 percent of the state’s electricity generation — and where tech giants like Microsoft are being attracted by the availability of clean energy to power their data centers.","path":"english2/2018.html"},{"id":"english2-2018-t2-p5-s1","examKey":"english2","examLabel":"英语二","year":"2018","text":2,"paragraph":5,"sentenceNo":1,"sentence":"13 The question “what happens when the wind doesn’t blow or the sun doesn’t shine?” has provided a quick put-down for skeptics.","path":"english2/2018.html"},{"id":"english2-2018-t2-p5-s2","examKey":"english2","examLabel":"英语二","year":"2018","text":2,"paragraph":5,"sentenceNo":2,"sentence":"14 But a boost in the storage capacity of batteries is making their ability to keep power flowing around the clock more likely.","path":"english2/2018.html"},{"id":"english2-2018-t2-p6-s1","examKey":"english2","examLabel":"英语二","year":"2018","text":2,"paragraph":6,"sentenceNo":1,"sentence":"15 The advance is driven in part by vehicle manufacturers, who are placing big bets on battery-powered electric vehicles.","path":"english2/2018.html"},{"id":"english2-2018-t2-p6-s2","examKey":"english2","examLabel":"英语二","year":"2018","text":2,"paragraph":6,"sentenceNo":2,"sentence":"16 Although electric cars are still a rarity on roads now, this massive investment could change the picture rapidly in coming years.","path":"english2/2018.html"},{"id":"english2-2018-t2-p7-s1","examKey":"english2","examLabel":"英语二","year":"2018","text":2,"paragraph":7,"sentenceNo":1,"sentence":"Q30 末段定位 17 While there’s a long way to go, the trend lines for renewables are spiking.","path":"english2/2018.html"},{"id":"english2-2018-t2-p7-s2","examKey":"english2","examLabel":"英语二","year":"2018","text":2,"paragraph":7,"sentenceNo":2,"sentence":"18 The pace of change in energy sources appears to be speeding up — perhaps just in time to have a meaningful effect in slowing climate change.","path":"english2/2018.html"},{"id":"english2-2018-t2-p7-s3","examKey":"english2","examLabel":"英语二","year":"2018","text":2,"paragraph":7,"sentenceNo":3,"sentence":"19 What Washington does — or doesn’t do — to promote alternative energy may mean less and less at a time of a global shift in thought.","path":"english2/2018.html"},{"id":"english2-2018-t3-p1-s1","examKey":"english2","examLabel":"英语二","year":"2018","text":3,"paragraph":1,"sentenceNo":1,"sentence":"1 The digital economy creates a profound imbalance between the giant platforms and the people who use them.","path":"english2/2018.html"},{"id":"english2-2018-t3-p1-s2","examKey":"english2","examLabel":"英语二","year":"2018","text":3,"paragraph":1,"sentenceNo":2,"sentence":"2 For companies such as Facebook and Google, the most valuable asset is not merely the service they offer, but the detailed traces of behaviour and relationships that our digital lives yield.","path":"english2/2018.html"},{"id":"english2-2018-t3-p1-s3","examKey":"english2","examLabel":"英语二","year":"2018","text":3,"paragraph":1,"sentenceNo":3,"sentence":"3 Ants keep predatory insects away from where their aphids feed; Gmail keeps the spammers out of our inboxes.","path":"english2/2018.html"},{"id":"english2-2018-t3-p1-s4","examKey":"english2","examLabel":"英语二","year":"2018","text":3,"paragraph":1,"sentenceNo":4,"sentence":"4 It doesn’t feel like a human or democratic relationship, even if both sides benefit.","path":"english2/2018.html"},{"id":"english2-2018-t3-p2-s1","examKey":"english2","examLabel":"英语二","year":"2018","text":3,"paragraph":2,"sentenceNo":1,"sentence":"5 That is why a free service can be worth billions without producing a traditional product at all.","path":"english2/2018.html"},{"id":"english2-2018-t3-p2-s2","examKey":"english2","examLabel":"英语二","year":"2018","text":3,"paragraph":2,"sentenceNo":2,"sentence":"6 What WhatsApp offered Facebook was an intricate and finely detailed web of its users’ friendships and social lives.","path":"english2/2018.html"},{"id":"english2-2018-t3-p3-s1","examKey":"english2","examLabel":"英语二","year":"2018","text":3,"paragraph":3,"sentenceNo":1,"sentence":"7 Facebook promised the European commission then that it would not link phone numbers to Facebook identities, but it broke the promise almost as soon as the deal went through.","path":"english2/2018.html"},{"id":"english2-2018-t3-p3-s2","examKey":"english2","examLabel":"英语二","year":"2018","text":3,"paragraph":3,"sentenceNo":2,"sentence":"8 Even without knowing what was in the messages, the knowledge of who sent them and to whom was enormously revealing and still could be.","path":"english2/2018.html"},{"id":"english2-2018-t3-p3-s3","examKey":"english2","examLabel":"英语二","year":"2018","text":3,"paragraph":3,"sentenceNo":3,"sentence":"9 What political journalist, what party whip, would not want to know the makeup of the WhatsApp groups in which Theresa May’s enemies are currently plotting?","path":"english2/2018.html"},{"id":"english2-2018-t3-p3-s4","examKey":"english2","examLabel":"英语二","year":"2018","text":3,"paragraph":3,"sentenceNo":4,"sentence":"10 It may be that the value of Whole Foods to Amazon is not so much the 460 shops it owns, but the records of which customers have purchased what.","path":"english2/2018.html"},{"id":"english2-2018-t3-p4-s1","examKey":"english2","examLabel":"英语二","year":"2018","text":3,"paragraph":4,"sentenceNo":1,"sentence":"11 Competition law appears to be the only way to address these imbalances of power.","path":"english2/2018.html"},{"id":"english2-2018-t3-p4-s2","examKey":"english2","examLabel":"英语二","year":"2018","text":3,"paragraph":4,"sentenceNo":2,"sentence":"12 But it is clumsy.","path":"english2/2018.html"},{"id":"english2-2018-t3-p4-s3","examKey":"english2","examLabel":"英语二","year":"2018","text":3,"paragraph":4,"sentenceNo":3,"sentence":"13 For one thing, it is very slow compared to the pace of change within the digital economy.","path":"english2/2018.html"},{"id":"english2-2018-t3-p4-s4","examKey":"english2","examLabel":"英语二","year":"2018","text":3,"paragraph":4,"sentenceNo":4,"sentence":"14 By the time a problem has been addressed and remedied, the market may already have changed.","path":"english2/2018.html"},{"id":"english2-2018-t3-p5-s1","examKey":"english2","examLabel":"英语二","year":"2018","text":3,"paragraph":5,"sentenceNo":1,"sentence":"15 The deeper difficulty is that competition law, as presently interpreted, tends to ask whether customers are being overcharged.","path":"english2/2018.html"},{"id":"english2-2018-t3-p5-s2","examKey":"english2","examLabel":"英语二","year":"2018","text":3,"paragraph":5,"sentenceNo":2,"sentence":"16 But users of Facebook are not treated as the paying customers in that framework.","path":"english2/2018.html"},{"id":"english2-2018-t3-p5-s3","examKey":"english2","examLabel":"英语二","year":"2018","text":3,"paragraph":5,"sentenceNo":3,"sentence":"17 Competition law as presently interpreted can hardly protect Facebook users because they are not defined as customers.","path":"english2/2018.html"},{"id":"english2-2018-t4-p1-s1","examKey":"english2","examLabel":"英语二","year":"2018","text":4,"paragraph":1,"sentenceNo":1,"sentence":"1 To combat the trap of putting a premium on being busy, Cal Newport, author of Deep Work: Rules for Focused Success in a Distracted World, recommends building a habit of “deep work” — the ability to focus without distraction.","path":"english2/2018.html"},{"id":"english2-2018-t4-p2-s1","examKey":"english2","examLabel":"英语二","year":"2018","text":4,"paragraph":2,"sentenceNo":1,"sentence":"2 There are a number of approaches to mastering the art of deep work — be it lengthy retreats dedicated to a specific task; developing a daily ritual; or taking “journalistic” approach to seizing moments of deep work when you can throughout the day.","path":"english2/2018.html"},{"id":"english2-2018-t4-p2-s2","examKey":"english2","examLabel":"英语二","year":"2018","text":4,"paragraph":2,"sentenceNo":2,"sentence":"3 Whichever approach, the key is to determine your length of focus time and stick to it.","path":"english2/2018.html"},{"id":"english2-2018-t4-p3-s1","examKey":"english2","examLabel":"英语二","year":"2018","text":4,"paragraph":3,"sentenceNo":1,"sentence":"4 Newport also recommends “deep scheduling” to combat constant interruptions and get more done in less time.","path":"english2/2018.html"},{"id":"english2-2018-t4-p3-s2","examKey":"english2","examLabel":"英语二","year":"2018","text":4,"paragraph":3,"sentenceNo":2,"sentence":"5 “At any given point, I should have deep work scheduled for roughly the next month.","path":"english2/2018.html"},{"id":"english2-2018-t4-p3-s3","examKey":"english2","examLabel":"英语二","year":"2018","text":4,"paragraph":3,"sentenceNo":3,"sentence":"Once on the calendar, I protect this time like I would a doctor’s appointment or important meeting,” he writes.","path":"english2/2018.html"},{"id":"english2-2018-t4-p4-s1","examKey":"english2","examLabel":"英语二","year":"2018","text":4,"paragraph":4,"sentenceNo":1,"sentence":"6 Another approach to getting more done in less time is to rethink how you prioritise your day — in particular how we craft our to-do lists.","path":"english2/2018.html"},{"id":"english2-2018-t4-p4-s2","examKey":"english2","examLabel":"英语二","year":"2018","text":4,"paragraph":4,"sentenceNo":2,"sentence":"Tim Harford, author of Messy: The Power of Disorder to Transform Our Lives, points to a study in the early 1980s that divided undergraduates into two groups: some were advised to set out monthly goals and study activities; others were told to plan activities and goals in much more detail, day by day.","path":"english2/2018.html"},{"id":"english2-2018-t4-p5-s1","examKey":"english2","examLabel":"英语二","year":"2018","text":4,"paragraph":5,"sentenceNo":1,"sentence":"7 While the researchers assumed that the well-structured daily plans would be most effective when it came to the execution of tasks, they were wrong: the detailed daily plans demotivated students.","path":"english2/2018.html"},{"id":"english2-2018-t4-p5-s2","examKey":"english2","examLabel":"英语二","year":"2018","text":4,"paragraph":5,"sentenceNo":2,"sentence":"Harford argues that the inevitable distractions often render the daily to-do list ineffective, while leaving room for improvisation in such a list can reap the best results.","path":"english2/2018.html"},{"id":"english2-2018-t4-p6-s1","examKey":"english2","examLabel":"英语二","year":"2018","text":4,"paragraph":6,"sentenceNo":1,"sentence":"8 In order to make the most of our focus and energy, we also need to embrace downtime, or as Newport suggests, “be lazy”.","path":"english2/2018.html"},{"id":"english2-2018-t4-p6-s2","examKey":"english2","examLabel":"英语二","year":"2018","text":4,"paragraph":6,"sentenceNo":2,"sentence":"9 “Idleness is not just a vacation, an indulgence or a vice; it is as indispensable to the brain as vitamin D is to the body...[idleness] is, paradoxically, necessary to getting any work done,” he argues.","path":"english2/2018.html"},{"id":"english2-2018-t4-p7-s1","examKey":"english2","examLabel":"英语二","year":"2018","text":4,"paragraph":7,"sentenceNo":1,"sentence":"10 Srini Pillay, an assistant professor of psychiatry at Harvard Medical School, believes this counterintuitive link between downtime and productivity may be due to the way our brains operate.","path":"english2/2018.html"},{"id":"english2-2018-t4-p7-s2","examKey":"english2","examLabel":"英语二","year":"2018","text":4,"paragraph":7,"sentenceNo":2,"sentence":"11 When our brains switch between being focused and unfocused on a task, they tend to be more efficient.","path":"english2/2018.html"},{"id":"english2-2018-t4-p8-s1","examKey":"english2","examLabel":"英语二","year":"2018","text":4,"paragraph":8,"sentenceNo":1,"sentence":"12 “What people don’t realise is that in order to complete these tasks they need to use both the focus and unfocus circuits in their brain,” says Pillay.","path":"english2/2018.html"},{"id":"english1-2019-t1-p1-s1","examKey":"english1","examLabel":"英语一","year":"2019","text":1,"paragraph":1,"sentenceNo":1,"sentence":"Financial regulators in Britain have imposed a rather unusual rule on the bosses of big banks.","path":"english1/2019.html"},{"id":"english1-2019-t1-p1-s2","examKey":"english1","examLabel":"英语一","year":"2019","text":1,"paragraph":1,"sentenceNo":2,"sentence":"Starting next year, any guaranteed bonus of top executives could be delayed 10 years if their banks are under investigation for wrongdoing.","path":"english1/2019.html"},{"id":"english1-2019-t1-p1-s3","examKey":"english1","examLabel":"英语一","year":"2019","text":1,"paragraph":1,"sentenceNo":3,"sentence":"The main purpose of this “clawback” rule is to hold bankers accountable for harmful risk-taking and to restore public trust in financial institutions.","path":"english1/2019.html"},{"id":"english1-2019-t1-p1-s4","examKey":"english1","examLabel":"英语一","year":"2019","text":1,"paragraph":1,"sentenceNo":4,"sentence":"Yet officials also hope for a much larger benefit: more long-term decision-making not only by banks but by all corporations, to build a stronger economy for future generations.","path":"english1/2019.html"},{"id":"english1-2019-t1-p2-s1","examKey":"english1","examLabel":"英语一","year":"2019","text":1,"paragraph":2,"sentenceNo":1,"sentence":"“Short-termism,” or the desire for quick profits, has worsened in publicly traded companies, says the Bank of England’s top economist, Andrew Haldane.","path":"english1/2019.html"},{"id":"english1-2019-t1-p2-s2","examKey":"english1","examLabel":"英语一","year":"2019","text":1,"paragraph":2,"sentenceNo":2,"sentence":"He quotes a giant of classical economics, Alfred Marshall, in describing this financial impatience as acting like “children who pick the plums out of their pudding to eat them at once” rather than putting them aside to be eaten last.","path":"english1/2019.html"},{"id":"english1-2019-t1-p3-s1","examKey":"english1","examLabel":"英语一","year":"2019","text":1,"paragraph":3,"sentenceNo":1,"sentence":"The average time for holding a stock in both the United States and Britain, he notes, has dropped from seven years to seven months in recent decades.","path":"english1/2019.html"},{"id":"english1-2019-t1-p3-s2","examKey":"english1","examLabel":"英语一","year":"2019","text":1,"paragraph":3,"sentenceNo":2,"sentence":"Transient investors, who demand high quarterly profits from companies, can hinder a firm’s efforts to invest in long-term research or to build up customer loyalty.","path":"english1/2019.html"},{"id":"english1-2019-t1-p3-s3","examKey":"english1","examLabel":"英语一","year":"2019","text":1,"paragraph":3,"sentenceNo":3,"sentence":"This has been dubbed “quarterly capitalism.”","path":"english1/2019.html"},{"id":"english1-2019-t1-p4-s1","examKey":"english1","examLabel":"英语一","year":"2019","text":1,"paragraph":4,"sentenceNo":1,"sentence":"In addition, new digital technologies have allowed more rapid trading of equities, quicker use of information, and thus shorter attention spans in financial markets.","path":"english1/2019.html"},{"id":"english1-2019-t1-p4-s2","examKey":"english1","examLabel":"英语一","year":"2019","text":1,"paragraph":4,"sentenceNo":2,"sentence":"“There seems to be a predominance of short-term thinking at the expense of long-term investing,” said Commissioner Daniel Gallagher of the US Securities and Exchange Commission in a speech this week.","path":"english1/2019.html"},{"id":"english1-2019-t1-p5-s1","examKey":"english1","examLabel":"英语一","year":"2019","text":1,"paragraph":5,"sentenceNo":1,"sentence":"In the US, the Sarbanes-Oxley Act of 2002 has pushed most public companies to defer performance bonuses for senior executives by about a year, slightly helping reduce “short-termism.” In its latest survey of CEO pay, The Wall Street Journal finds that “a substantial part” of executive pay is now tied to performance.","path":"english1/2019.html"},{"id":"english1-2019-t1-p6-s1","examKey":"english1","examLabel":"英语一","year":"2019","text":1,"paragraph":6,"sentenceNo":1,"sentence":"Much more could be done to encourage “ long-termism,” such as changes in the tax code and quicker disclosure of stock acquisitions.","path":"english1/2019.html"},{"id":"english1-2019-t1-p6-s2","examKey":"english1","examLabel":"英语一","year":"2019","text":1,"paragraph":6,"sentenceNo":2,"sentence":"In France, shareholders who hold onto a company investment for at least two years can sometimes earn more voting rights in a company.","path":"english1/2019.html"},{"id":"english1-2019-t1-p7-s1","examKey":"english1","examLabel":"英语一","year":"2019","text":1,"paragraph":7,"sentenceNo":1,"sentence":"Within companies, the right compensation design can provide incentives for executives to think beyond their own time at the company and on behalf of all stakeholders.","path":"english1/2019.html"},{"id":"english1-2019-t1-p7-s2","examKey":"english1","examLabel":"英语一","year":"2019","text":1,"paragraph":7,"sentenceNo":2,"sentence":"Britain’s new rule is a reminder to bankers that society has an interest in their performance, not just for the short term but for the long term.","path":"english1/2019.html"},{"id":"english1-2019-t2-p1-s1","examKey":"english1","examLabel":"英语一","year":"2019","text":2,"paragraph":1,"sentenceNo":1,"sentence":"Grade inflation —the gradual increase in average GPAs ( grade -point averages) over the past few decades—is often considered a product of a consumer era in higher education, in which students are treated like customers to be pleased.","path":"english1/2019.html"},{"id":"english1-2019-t2-p1-s2","examKey":"english1","examLabel":"英语一","year":"2019","text":2,"paragraph":1,"sentenceNo":2,"sentence":"But another, related force—a policy often buried deep in course catalogs called “grade forgiveness” —is helping raise GPAs.","path":"english1/2019.html"},{"id":"english1-2019-t2-p2-s1","examKey":"english1","examLabel":"英语一","year":"2019","text":2,"paragraph":2,"sentenceNo":1,"sentence":"Grade forgiveness allows students to retake a course in which they received a low grade, and the most recent grade or the highest grade is the only one that counts in calculating a student’s overall GPA.","path":"english1/2019.html"},{"id":"english1-2019-t2-p3-s1","examKey":"english1","examLabel":"英语一","year":"2019","text":2,"paragraph":3,"sentenceNo":1,"sentence":"The use of this little-known practice has accelerated in recent years, as colleges continue to do their utmost to keep students in school (and paying tuition) and improve their graduation rates.","path":"english1/2019.html"},{"id":"english1-2019-t2-p3-s2","examKey":"english1","examLabel":"英语一","year":"2019","text":2,"paragraph":3,"sentenceNo":2,"sentence":"When this practice first started decades ago, it was usually limited to freshmen, to give them a second chance to take a class in their first year if they struggled in their transition to college-level courses.","path":"english1/2019.html"},{"id":"english1-2019-t2-p4-s1","examKey":"english1","examLabel":"英语一","year":"2019","text":2,"paragraph":4,"sentenceNo":1,"sentence":"College officials tend to emphasize that the goal of grade forgiveness is less about the grade itself and more about encouraging students to retake courses critical to their degree program and graduation without incurring a big penalty.","path":"english1/2019.html"},{"id":"english1-2019-t2-p4-s2","examKey":"english1","examLabel":"英语一","year":"2019","text":2,"paragraph":4,"sentenceNo":2,"sentence":"“Ultimately,” said Jack Miner, Ohio State University’s registrar, “we see students achieve more success because they retake a course and do better in subsequent courses or master the content that allows them to graduate on time.”","path":"english1/2019.html"},{"id":"english1-2019-t2-p5-s1","examKey":"english1","examLabel":"英语一","year":"2019","text":2,"paragraph":5,"sentenceNo":1,"sentence":"That said, there is a way in which grade forgiveness satisfies colleges’ own needs as well.","path":"english1/2019.html"},{"id":"english1-2019-t2-p5-s2","examKey":"english1","examLabel":"英语一","year":"2019","text":2,"paragraph":5,"sentenceNo":2,"sentence":"For public institutions, state funds are sometimes tied partly to their success on metrics such as graduation rates and student retention—so better grades can, by boosting figures like those, mean more money.","path":"english1/2019.html"},{"id":"english1-2019-t2-p5-s3","examKey":"english1","examLabel":"英语一","year":"2019","text":2,"paragraph":5,"sentenceNo":3,"sentence":"And anything that raises GPAs will likely make students—who, at the end of the day, are paying the bill—feel they’ve gotten a better value for their tuition dollars, which is another big concern for colleges.","path":"english1/2019.html"},{"id":"english1-2019-t2-p6-s1","examKey":"english1","examLabel":"英语一","year":"2019","text":2,"paragraph":6,"sentenceNo":1,"sentence":"Indeed, grade forgiveness is just another way that universities are responding to consumers’ expectations for higher education.","path":"english1/2019.html"},{"id":"english1-2019-t2-p6-s2","examKey":"english1","examLabel":"英语一","year":"2019","text":2,"paragraph":6,"sentenceNo":2,"sentence":"Since students and parents expect a college degree to lead to a job, it is in the best interest of a school to turn out graduates who are as qualified as possible—or at least appear to be.","path":"english1/2019.html"},{"id":"english1-2019-t2-p6-s3","examKey":"english1","examLabel":"英语一","year":"2019","text":2,"paragraph":6,"sentenceNo":3,"sentence":"On this, students’ and colleges’ incentives seem to be aligned.","path":"english1/2019.html"},{"id":"english1-2019-t3-p1-s1","examKey":"english1","examLabel":"英语一","year":"2019","text":3,"paragraph":1,"sentenceNo":1,"sentence":"This year marks exactly two centuries since the publication of Frankenstein; or, The Modern Prometheus, by Mary Shelley.","path":"english1/2019.html"},{"id":"english1-2019-t3-p1-s2","examKey":"english1","examLabel":"英语一","year":"2019","text":3,"paragraph":1,"sentenceNo":2,"sentence":"Even before the invention of the electric light bulb, the author produced a remarkable work of speculative fiction that would foreshadow many ethical questions to be raised by technologies yet to come.","path":"english1/2019.html"},{"id":"english1-2019-t3-p2-s1","examKey":"english1","examLabel":"英语一","year":"2019","text":3,"paragraph":2,"sentenceNo":1,"sentence":"Today the rapid growth of artificial intelligence (AI) raises fundamental questions: “What is intelligence, identity, or consciousness?","path":"english1/2019.html"},{"id":"english1-2019-t3-p2-s2","examKey":"english1","examLabel":"英语一","year":"2019","text":3,"paragraph":2,"sentenceNo":2,"sentence":"What makes humans humans?”","path":"english1/2019.html"},{"id":"english1-2019-t3-p3-s1","examKey":"english1","examLabel":"英语一","year":"2019","text":3,"paragraph":3,"sentenceNo":1,"sentence":"What is being called artificial general intelligence, machines that would imitate the way humans think, continues to evade scientists.","path":"english1/2019.html"},{"id":"english1-2019-t3-p3-s2","examKey":"english1","examLabel":"英语一","year":"2019","text":3,"paragraph":3,"sentenceNo":2,"sentence":"Yet humans remain fascinated by the idea of robots that would look, move, and respond like humans, similar to those recently depicted on popular sci-fi TV series such as “Westworld” and “Humans.”","path":"english1/2019.html"},{"id":"english1-2019-t3-p4-s1","examKey":"english1","examLabel":"英语一","year":"2019","text":3,"paragraph":4,"sentenceNo":1,"sentence":"Just how people think is still far too complex to be understood, let alone reproduced, says David Eagleman, a Stanford University neuroscientist.","path":"english1/2019.html"},{"id":"english1-2019-t3-p4-s2","examKey":"english1","examLabel":"英语一","year":"2019","text":3,"paragraph":4,"sentenceNo":2,"sentence":"“We are just in a situation where there are no good theories explaining what consciousness actually is and how you could ever build a machine to get there.”","path":"english1/2019.html"},{"id":"english1-2019-t3-p5-s1","examKey":"english1","examLabel":"英语一","year":"2019","text":3,"paragraph":5,"sentenceNo":1,"sentence":"But that doesn’t mean crucial ethical issues involving AI aren’t at hand.","path":"english1/2019.html"},{"id":"english1-2019-t3-p5-s2","examKey":"english1","examLabel":"英语一","year":"2019","text":3,"paragraph":5,"sentenceNo":2,"sentence":"The coming use of autonomous vehicles, for example, poses thorny ethical questions.","path":"english1/2019.html"},{"id":"english1-2019-t3-p5-s3","examKey":"english1","examLabel":"英语一","year":"2019","text":3,"paragraph":5,"sentenceNo":3,"sentence":"Human drivers sometimes must make split-second decisions.","path":"english1/2019.html"},{"id":"english1-2019-t3-p5-s4","examKey":"english1","examLabel":"英语一","year":"2019","text":3,"paragraph":5,"sentenceNo":4,"sentence":"Their reactions may be a complex combination of instant reflexes, input from past driving experiences, and what their eyes and ears tell them in that moment.","path":"english1/2019.html"},{"id":"english1-2019-t3-p5-s5","examKey":"english1","examLabel":"英语一","year":"2019","text":3,"paragraph":5,"sentenceNo":5,"sentence":"AI “vision” today is not nearly as sophisticated as that of humans.","path":"english1/2019.html"},{"id":"english1-2019-t3-p5-s6","examKey":"english1","examLabel":"英语一","year":"2019","text":3,"paragraph":5,"sentenceNo":6,"sentence":"And to anticipate every imaginable driving situation is a difficult programming problem.","path":"english1/2019.html"},{"id":"english1-2019-t3-p6-s1","examKey":"english1","examLabel":"英语一","year":"2019","text":3,"paragraph":6,"sentenceNo":1,"sentence":"Whenever decisions are based on masses of data, “you quickly get into a lot of ethical questions,” notes Tan Kiat How, chief executive of a Singapore-based agency that is helping the government develop a voluntary code for the ethical use of AI.","path":"english1/2019.html"},{"id":"english1-2019-t3-p6-s2","examKey":"english1","examLabel":"英语一","year":"2019","text":3,"paragraph":6,"sentenceNo":2,"sentence":"Along with Singapore, other governments and mega-corporations are beginning to establish their own guidelines.","path":"english1/2019.html"},{"id":"english1-2019-t3-p6-s3","examKey":"english1","examLabel":"英语一","year":"2019","text":3,"paragraph":6,"sentenceNo":3,"sentence":"Britain is setting up a data ethics center.","path":"english1/2019.html"},{"id":"english1-2019-t3-p6-s4","examKey":"english1","examLabel":"英语一","year":"2019","text":3,"paragraph":6,"sentenceNo":4,"sentence":"India released its AI ethics strategy this spring.","path":"english1/2019.html"},{"id":"english1-2019-t3-p7-s1","examKey":"english1","examLabel":"英语一","year":"2019","text":3,"paragraph":7,"sentenceNo":1,"sentence":"On June 7 Google pledged not to “design or deploy AI” that would cause “overall harm,” or to develop AI-directed weapons or use AI for surveillance that would violate international norms.","path":"english1/2019.html"},{"id":"english1-2019-t3-p7-s2","examKey":"english1","examLabel":"英语一","year":"2019","text":3,"paragraph":7,"sentenceNo":2,"sentence":"It also pledged not to deploy AI whose use would violate international laws or human rights.","path":"english1/2019.html"},{"id":"english1-2019-t3-p8-s1","examKey":"english1","examLabel":"英语一","year":"2019","text":3,"paragraph":8,"sentenceNo":1,"sentence":"While the statement is vague, it represents one starting point.","path":"english1/2019.html"},{"id":"english1-2019-t3-p8-s2","examKey":"english1","examLabel":"英语一","year":"2019","text":3,"paragraph":8,"sentenceNo":2,"sentence":"So does the idea that decisions made by AI systems should be explainable, transparent, and fair.","path":"english1/2019.html"},{"id":"english1-2019-t3-p9-s1","examKey":"english1","examLabel":"英语一","year":"2019","text":3,"paragraph":9,"sentenceNo":1,"sentence":"To put it another way: How can we make sure that the thinking of intelligent machines reflects humanity’s highest values?","path":"english1/2019.html"},{"id":"english1-2019-t3-p9-s2","examKey":"english1","examLabel":"英语一","year":"2019","text":3,"paragraph":9,"sentenceNo":2,"sentence":"Only then will they be useful servants and not Frankenstein’s out-of-control monster.","path":"english1/2019.html"},{"id":"english1-2019-t4-p1-s1","examKey":"english1","examLabel":"英语一","year":"2019","text":4,"paragraph":1,"sentenceNo":1,"sentence":"States will be able to force more people to pay sales tax when they make online purchases under a Supreme Court decision Thursday that will leave shoppers with lighter wallets but is a big financial win for states.","path":"english1/2019.html"},{"id":"english1-2019-t4-p2-s1","examKey":"english1","examLabel":"英语一","year":"2019","text":4,"paragraph":2,"sentenceNo":1,"sentence":"The Supreme Court’s opinion Thursday overruled a pair of decades-old decisions that states said cost them billions of dollars in lost revenue annually.","path":"english1/2019.html"},{"id":"english1-2019-t4-p2-s2","examKey":"english1","examLabel":"英语一","year":"2019","text":4,"paragraph":2,"sentenceNo":2,"sentence":"The decisions made it more difficult for states to collect sales tax on certain online purchases.","path":"english1/2019.html"},{"id":"english1-2019-t4-p3-s1","examKey":"english1","examLabel":"英语一","year":"2019","text":4,"paragraph":3,"sentenceNo":1,"sentence":"The cases the court overturned said that if a business was shipping a customer’s purchase to a state where the business didn’t have a physical presence such as a warehouse or office, the business didn’t have to collect sales tax for the state.","path":"english1/2019.html"},{"id":"english1-2019-t4-p3-s2","examKey":"english1","examLabel":"英语一","year":"2019","text":4,"paragraph":3,"sentenceNo":2,"sentence":"Customers were generally responsible for paying the sales tax to the state themselves if they weren’t charged it, but most didn’t realize they owed it and few paid.","path":"english1/2019.html"},{"id":"english1-2019-t4-p4-s1","examKey":"english1","examLabel":"英语一","year":"2019","text":4,"paragraph":4,"sentenceNo":1,"sentence":"Justice Anthony Kennedy wrote that the previous decisions were flawed.","path":"english1/2019.html"},{"id":"english1-2019-t4-p4-s2","examKey":"english1","examLabel":"英语一","year":"2019","text":4,"paragraph":4,"sentenceNo":2,"sentence":"“Each year the physical presence rule becomes further removed from economic reality and results in significant revenue losses to the States,” he wrote in an opinion joined by four other justices.","path":"english1/2019.html"},{"id":"english1-2019-t4-p4-s3","examKey":"english1","examLabel":"英语一","year":"2019","text":4,"paragraph":4,"sentenceNo":3,"sentence":"Kennedy wrote that the rule “limited states’ ability to seek long-term prosperity and has prevented market participants from competing on an even playing field.”","path":"english1/2019.html"},{"id":"english1-2019-t4-p5-s1","examKey":"english1","examLabel":"英语一","year":"2019","text":4,"paragraph":5,"sentenceNo":1,"sentence":"The ruling is a victory for big chains with a presence in many states, since they usually collect sales tax on online purchases already.","path":"english1/2019.html"},{"id":"english1-2019-t4-p5-s2","examKey":"english1","examLabel":"英语一","year":"2019","text":4,"paragraph":5,"sentenceNo":2,"sentence":"Now, rivals will be charging sales tax where they hadn’t before.","path":"english1/2019.html"},{"id":"english1-2019-t4-p5-s3","examKey":"english1","examLabel":"英语一","year":"2019","text":4,"paragraph":5,"sentenceNo":3,"sentence":"Big chains have been collecting sales tax nationwide because they typically have physical stores in whatever state a purchase is being shipped to.","path":"english1/2019.html"},{"id":"english1-2019-t4-p5-s4","examKey":"english1","examLabel":"英语一","year":"2019","text":4,"paragraph":5,"sentenceNo":4,"sentence":"Amazon.com, with its network of warehouses, also collects sales tax in every state that charges it, though third-party sellers who use the site don’t have to.","path":"english1/2019.html"},{"id":"english1-2019-t4-p6-s1","examKey":"english1","examLabel":"英语一","year":"2019","text":4,"paragraph":6,"sentenceNo":1,"sentence":"Until now, many sellers that have a physical presence in only a single state or a few states have been able to avoid charging sales taxes when they ship to addresses outside those states.","path":"english1/2019.html"},{"id":"english1-2019-t4-p6-s2","examKey":"english1","examLabel":"英语一","year":"2019","text":4,"paragraph":6,"sentenceNo":2,"sentence":"Sellers that use eBay and Etsy, which provide platforms for smaller sellers, also haven’t been collecting sales tax nationwide.","path":"english1/2019.html"},{"id":"english1-2019-t4-p6-s3","examKey":"english1","examLabel":"英语一","year":"2019","text":4,"paragraph":6,"sentenceNo":3,"sentence":"Under the ruling Thursday, states can pass laws requiring out-of-state sellers to collect the state’s sales tax from customers and send it to the state.","path":"english1/2019.html"},{"id":"english1-2019-t4-p7-s1","examKey":"english1","examLabel":"英语一","year":"2019","text":4,"paragraph":7,"sentenceNo":1,"sentence":"Retail trade groups praised the ruling, saying it levels the playing field for local and online businesses.","path":"english1/2019.html"},{"id":"english1-2019-t4-p7-s2","examKey":"english1","examLabel":"英语一","year":"2019","text":4,"paragraph":7,"sentenceNo":2,"sentence":"The losers, said retail analyst Neil Saunders, are online-only retailers, especially smaller ones.","path":"english1/2019.html"},{"id":"english1-2019-t4-p7-s3","examKey":"english1","examLabel":"英语一","year":"2019","text":4,"paragraph":7,"sentenceNo":3,"sentence":"Those retailers may face headaches complying with various state sales tax laws.","path":"english1/2019.html"},{"id":"english1-2019-t4-p7-s4","examKey":"english1","examLabel":"英语一","year":"2019","text":4,"paragraph":7,"sentenceNo":4,"sentence":"The Small Business & Entrepreneurship Council advocacy group said in a statement, “Small businesses and internet entrepreneurs are not well served at all by this decision.”","path":"english1/2019.html"},{"id":"english2-2019-t1-p1-s1","examKey":"english2","examLabel":"英语二","year":"2019","text":1,"paragraph":1,"sentenceNo":1,"sentence":"Q21 段落定位 Unlike so-called basic emotions such as sadness, fear, and anger, guilt emerges a little later, in conjunction with a child’s growing grasp of social and moral norms.","path":"english2/2019.html"},{"id":"english2-2019-t1-p1-s2","examKey":"english2","examLabel":"英语二","year":"2019","text":1,"paragraph":1,"sentenceNo":2,"sentence":"Children aren’t born knowing how to say “I’m sorry”; rather, they learn over time that such statements appease parents and friends — and their own consciences.","path":"english2/2019.html"},{"id":"english2-2019-t1-p1-s3","examKey":"english2","examLabel":"英语二","year":"2019","text":1,"paragraph":1,"sentenceNo":3,"sentence":"This is why researchers generally regard so-called moral guilt, in the right amount, to be a good thing.","path":"english2/2019.html"},{"id":"english2-2019-t1-p2-s1","examKey":"english2","examLabel":"英语二","year":"2019","text":1,"paragraph":2,"sentenceNo":1,"sentence":"Q22 段落定位 Q23 Vaish 定位 In the popular imagination, of course, guilt still gets a bad rap.","path":"english2/2019.html"},{"id":"english2-2019-t1-p2-s2","examKey":"english2","examLabel":"英语二","year":"2019","text":1,"paragraph":2,"sentenceNo":2,"sentence":"It is deeply uncomfortable — it’s the emotional equivalent of wearing a jacket weighted with stones.","path":"english2/2019.html"},{"id":"english2-2019-t1-p2-s3","examKey":"english2","examLabel":"英语二","year":"2019","text":1,"paragraph":2,"sentenceNo":3,"sentence":"Yet this understanding is outdated.","path":"english2/2019.html"},{"id":"english2-2019-t1-p2-s4","examKey":"english2","examLabel":"英语二","year":"2019","text":1,"paragraph":2,"sentenceNo":4,"sentence":"“There has been a kind of revival or a rethinking about what guilt is and what role guilt can serve,” says Amrisha Vaish, a psychology researcher at the University of Virginia, adding that this revival is part of a larger recognition that emotions aren’t binary — feelings that may be advantageous in one context may be harmful in another.","path":"english2/2019.html"},{"id":"english2-2019-t1-p2-s5","examKey":"english2","examLabel":"英语二","year":"2019","text":1,"paragraph":2,"sentenceNo":5,"sentence":"Jealousy and anger, for example, may have evolved to alert us to important inequalities.","path":"english2/2019.html"},{"id":"english2-2019-t1-p2-s6","examKey":"english2","examLabel":"英语二","year":"2019","text":1,"paragraph":2,"sentenceNo":6,"sentence":"Too much happiness can be destructive.","path":"english2/2019.html"},{"id":"english2-2019-t1-p3-s1","examKey":"english2","examLabel":"英语二","year":"2019","text":1,"paragraph":3,"sentenceNo":1,"sentence":"And guilt, by prompting us to think more deeply about our goodness, can encourage humans to make up for errors and fix relationships.","path":"english2/2019.html"},{"id":"english2-2019-t1-p3-s2","examKey":"english2","examLabel":"英语二","year":"2019","text":1,"paragraph":3,"sentenceNo":2,"sentence":"Guilt, in other words, can help hold a cooperative species together.","path":"english2/2019.html"},{"id":"english2-2019-t1-p3-s3","examKey":"english2","examLabel":"英语二","year":"2019","text":1,"paragraph":3,"sentenceNo":3,"sentence":"It is a kind of social glue.","path":"english2/2019.html"},{"id":"english2-2019-t1-p4-s1","examKey":"english2","examLabel":"英语二","year":"2019","text":1,"paragraph":4,"sentenceNo":1,"sentence":"Q24 Malti 定位 Viewed in this light, guilt is an opportunity.","path":"english2/2019.html"},{"id":"english2-2019-t1-p4-s2","examKey":"english2","examLabel":"英语二","year":"2019","text":1,"paragraph":4,"sentenceNo":2,"sentence":"Work by Tina Malti, a psychology professor at the University of Toronto, suggests that guilt may compensate for an emotional deficiency.","path":"english2/2019.html"},{"id":"english2-2019-t1-p4-s3","examKey":"english2","examLabel":"英语二","year":"2019","text":1,"paragraph":4,"sentenceNo":3,"sentence":"In a number of studies, Malti and others have shown that guilt and sympathy may represent different pathways to cooperation and sharing.","path":"english2/2019.html"},{"id":"english2-2019-t1-p4-s4","examKey":"english2","examLabel":"英语二","year":"2019","text":1,"paragraph":4,"sentenceNo":4,"sentence":"Some kids who are low in sympathy may make up for that shortfall by experiencing more guilt, which can rein in their nastier impulses.","path":"english2/2019.html"},{"id":"english2-2019-t1-p4-s5","examKey":"english2","examLabel":"英语二","year":"2019","text":1,"paragraph":4,"sentenceNo":5,"sentence":"And vice versa: High sympathy can substitute for low guilt.","path":"english2/2019.html"},{"id":"english2-2019-t1-p5-s1","examKey":"english2","examLabel":"英语二","year":"2019","text":1,"paragraph":5,"sentenceNo":1,"sentence":"Q25 词义定位 In a 2014 study, for example, Malti looked at 244 children.","path":"english2/2019.html"},{"id":"english2-2019-t1-p5-s2","examKey":"english2","examLabel":"英语二","year":"2019","text":1,"paragraph":5,"sentenceNo":2,"sentence":"Using caregiver assessments and the children’s self-observations, she rated each child’s overall sympathy level and his or her tendency to feel negative emotions after moral transgressions.","path":"english2/2019.html"},{"id":"english2-2019-t1-p5-s3","examKey":"english2","examLabel":"英语二","year":"2019","text":1,"paragraph":5,"sentenceNo":3,"sentence":"Then the kids were handed chocolate coins, and given a chance to share them with an anonymous child.","path":"english2/2019.html"},{"id":"english2-2019-t1-p5-s4","examKey":"english2","examLabel":"英语二","year":"2019","text":1,"paragraph":5,"sentenceNo":4,"sentence":"For the low-sympathy kids, how much they shared appeared to turn on how inclined they were to feel guilty.","path":"english2/2019.html"},{"id":"english2-2019-t1-p5-s5","examKey":"english2","examLabel":"英语二","year":"2019","text":1,"paragraph":5,"sentenceNo":5,"sentence":"The guilt-prone ones shared more, even though they hadn’t magically become more sympathetic to the other child’s deprivation.","path":"english2/2019.html"},{"id":"english2-2019-t1-p6-s1","examKey":"english2","examLabel":"英语二","year":"2019","text":1,"paragraph":6,"sentenceNo":1,"sentence":"“That’s good news,” Malti says. “ We can be prosocial because we caused harm and we feel regret.”","path":"english2/2019.html"},{"id":"english2-2019-t2-p1-s1","examKey":"english2","examLabel":"英语二","year":"2019","text":2,"paragraph":1,"sentenceNo":1,"sentence":"Q26 段落定位 Forests give us shade, quiet and one of the harder challenges in the fight against climate change.","path":"english2/2019.html"},{"id":"english2-2019-t2-p1-s2","examKey":"english2","examLabel":"英语二","year":"2019","text":2,"paragraph":1,"sentenceNo":2,"sentence":"Even as we humans count on forests to soak up a good share of the carbon dioxide we produce, we are threatening their ability to do so.","path":"english2/2019.html"},{"id":"english2-2019-t2-p1-s3","examKey":"english2","examLabel":"英语二","year":"2019","text":2,"paragraph":1,"sentenceNo":3,"sentence":"The climate change we are hastening could one day leave us with forests that emit more carbon than they absorb.","path":"english2/2019.html"},{"id":"english2-2019-t2-p2-s1","examKey":"english2","examLabel":"英语二","year":"2019","text":2,"paragraph":2,"sentenceNo":1,"sentence":"Q27 段落定位 Thankfully, there is a way out of this trap — but it involves striking a subtle balance.","path":"english2/2019.html"},{"id":"english2-2019-t2-p2-s2","examKey":"english2","examLabel":"英语二","year":"2019","text":2,"paragraph":2,"sentenceNo":2,"sentence":"Helping forests flourish as valuable “carbon sinks” long into the future may require reducing their capacity to absorb carbon now.","path":"english2/2019.html"},{"id":"english2-2019-t2-p2-s3","examKey":"english2","examLabel":"英语二","year":"2019","text":2,"paragraph":2,"sentenceNo":3,"sentence":"California is leading the way, as it does on so many climate efforts, in figuring out the details.","path":"english2/2019.html"},{"id":"english2-2019-t2-p3-s1","examKey":"english2","examLabel":"英语二","year":"2019","text":2,"paragraph":3,"sentenceNo":1,"sentence":"Q28 计划定位 The state’s proposed Forest Carbon Plan aims to double efforts to thin out young trees and clear brush in parts of the forest.","path":"english2/2019.html"},{"id":"english2-2019-t2-p3-s2","examKey":"english2","examLabel":"英语二","year":"2019","text":2,"paragraph":3,"sentenceNo":2,"sentence":"This temporarily lowers carbon-carrying capacity.","path":"english2/2019.html"},{"id":"english2-2019-t2-p3-s3","examKey":"english2","examLabel":"英语二","year":"2019","text":2,"paragraph":3,"sentenceNo":3,"sentence":"But the remaining trees draw a greater share of the available moisture, so they grow and thrive, restoring the forest’s capacity to pull carbon from the air.","path":"english2/2019.html"},{"id":"english2-2019-t2-p3-s4","examKey":"english2","examLabel":"英语二","year":"2019","text":2,"paragraph":3,"sentenceNo":4,"sentence":"Healthy trees are also better able to fend off insects.","path":"english2/2019.html"},{"id":"english2-2019-t2-p3-s5","examKey":"english2","examLabel":"英语二","year":"2019","text":2,"paragraph":3,"sentenceNo":5,"sentence":"The landscape is rendered less easily burnable.","path":"english2/2019.html"},{"id":"english2-2019-t2-p3-s6","examKey":"english2","examLabel":"英语二","year":"2019","text":2,"paragraph":3,"sentenceNo":6,"sentence":"Even in the event of a fire, fewer trees are consumed.","path":"english2/2019.html"},{"id":"english2-2019-t2-p4-s1","examKey":"english2","examLabel":"英语二","year":"2019","text":2,"paragraph":4,"sentenceNo":1,"sentence":"The need for such planning is increasingly urgent.","path":"english2/2019.html"},{"id":"english2-2019-t2-p4-s2","examKey":"english2","examLabel":"英语二","year":"2019","text":2,"paragraph":4,"sentenceNo":2,"sentence":"Already, since 2010, drought and insects have killed over 100 million trees in California, most of them in 2016 alone, and wildfires have burned hundreds of thousands of acres.","path":"english2/2019.html"},{"id":"english2-2019-t2-p5-s1","examKey":"english2","examLabel":"英语二","year":"2019","text":2,"paragraph":5,"sentenceNo":1,"sentence":"Q29 段落定位 California plans to treat 35,000 acres of forest a year by 2020, and 60,000 by 2030 — financed from the proceeds of the state’s emissions-permit auctions.","path":"english2/2019.html"},{"id":"english2-2019-t2-p5-s2","examKey":"english2","examLabel":"英语二","year":"2019","text":2,"paragraph":5,"sentenceNo":2,"sentence":"That’s only a small share of the total acreage that could benefit, about half a million acres in all, so it will be vital to prioritize areas at greatest risk of fire or drought.","path":"english2/2019.html"},{"id":"english2-2019-t2-p6-s1","examKey":"english2","examLabel":"英语二","year":"2019","text":2,"paragraph":6,"sentenceNo":1,"sentence":"The strategy also aims to ensure that carbon in woody material removed from the forests is locked away in the form of solid lumber or burned as biofuel in vehicles that would otherwise run on fossil fuels.","path":"english2/2019.html"},{"id":"english2-2019-t2-p6-s2","examKey":"english2","examLabel":"英语二","year":"2019","text":2,"paragraph":6,"sentenceNo":2,"sentence":"New research on transportation biofuels is already underway.","path":"english2/2019.html"},{"id":"english2-2019-t2-p7-s1","examKey":"english2","examLabel":"英语二","year":"2019","text":2,"paragraph":7,"sentenceNo":1,"sentence":"Q30 态度定位 State governments are well accustomed to managing forests, but traditionally they’ve focused on wildlife, watersheds and opportunities for recreation.","path":"english2/2019.html"},{"id":"english2-2019-t2-p7-s2","examKey":"english2","examLabel":"英语二","year":"2019","text":2,"paragraph":7,"sentenceNo":2,"sentence":"Only recently have they come to see the vital part forests will have to play in storing carbon.","path":"english2/2019.html"},{"id":"english2-2019-t2-p7-s3","examKey":"english2","examLabel":"英语二","year":"2019","text":2,"paragraph":7,"sentenceNo":3,"sentence":"California’s plan, which is expected to be finalized by the governor next year, should serve as a model.","path":"english2/2019.html"},{"id":"english2-2019-t3-p1-s1","examKey":"english2","examLabel":"英语二","year":"2019","text":3,"paragraph":1,"sentenceNo":1,"sentence":"Q31 段落范围 American farmers have been complaining of labor shortages for several years.","path":"english2/2019.html"},{"id":"english2-2019-t3-p1-s2","examKey":"english2","examLabel":"英语二","year":"2019","text":3,"paragraph":1,"sentenceNo":2,"sentence":"The complaints are unlikely to stop without an overhaul of immigration rules for farm workers.","path":"english2/2019.html"},{"id":"english2-2019-t3-p2-s1","examKey":"english2","examLabel":"英语二","year":"2019","text":3,"paragraph":2,"sentenceNo":1,"sentence":"Congress has obstructed efforts to create a more straightforward visa for agricultural workers that would let foreign workers stay longer in the U.S. and change jobs within the industry.","path":"english2/2019.html"},{"id":"english2-2019-t3-p2-s2","examKey":"english2","examLabel":"英语二","year":"2019","text":3,"paragraph":2,"sentenceNo":2,"sentence":"If this doesn’t change, American businesses, communities, and consumers will be the losers.","path":"english2/2019.html"},{"id":"english2-2019-t3-p3-s1","examKey":"english2","examLabel":"英语二","year":"2019","text":3,"paragraph":3,"sentenceNo":1,"sentence":"Q32 劳动力定位 Perhaps half of U.S. farm laborers are undocumented immigrants.","path":"english2/2019.html"},{"id":"english2-2019-t3-p3-s2","examKey":"english2","examLabel":"英语二","year":"2019","text":3,"paragraph":3,"sentenceNo":2,"sentence":"As fewer such workers enter the country, the characteristics of the agricultural workforce are changing.","path":"english2/2019.html"},{"id":"english2-2019-t3-p3-s3","examKey":"english2","examLabel":"英语二","year":"2019","text":3,"paragraph":3,"sentenceNo":3,"sentence":"Today’s farm laborers, while still predominantly born in Mexico, are more likely to be settled rather than migrating and more likely to be married than single.","path":"english2/2019.html"},{"id":"english2-2019-t3-p3-s4","examKey":"english2","examLabel":"英语二","year":"2019","text":3,"paragraph":3,"sentenceNo":4,"sentence":"They’re also aging.","path":"english2/2019.html"},{"id":"english2-2019-t3-p3-s5","examKey":"english2","examLabel":"英语二","year":"2019","text":3,"paragraph":3,"sentenceNo":5,"sentence":"At the start of this century, about one-third of crop workers were over the age of 35.","path":"english2/2019.html"},{"id":"english2-2019-t3-p3-s6","examKey":"english2","examLabel":"英语二","year":"2019","text":3,"paragraph":3,"sentenceNo":6,"sentence":"Now more than half are.","path":"english2/2019.html"},{"id":"english2-2019-t3-p3-s7","examKey":"english2","examLabel":"英语二","year":"2019","text":3,"paragraph":3,"sentenceNo":7,"sentence":"And picking crops is hard on older bodies.","path":"english2/2019.html"},{"id":"english2-2019-t3-p3-s8","examKey":"english2","examLabel":"英语二","year":"2019","text":3,"paragraph":3,"sentenceNo":8,"sentence":"One oft-debated cure for this labor shortage remains as implausible as it’s been all along: Native U.S. workers won’t be returning to the farm.","path":"english2/2019.html"},{"id":"english2-2019-t3-p4-s1","examKey":"english2","examLabel":"英语二","year":"2019","text":3,"paragraph":4,"sentenceNo":1,"sentence":"Q33 方案定位 Mechanization isn’t the answer, either — not yet, at least.","path":"english2/2019.html"},{"id":"english2-2019-t3-p4-s2","examKey":"english2","examLabel":"英语二","year":"2019","text":3,"paragraph":4,"sentenceNo":2,"sentence":"Production of corn, cotton, rice, soybeans, and wheat has been largely mechanized, but many high-value, labor-intensive crops, such as strawberries, need labor.","path":"english2/2019.html"},{"id":"english2-2019-t3-p4-s3","examKey":"english2","examLabel":"英语二","year":"2019","text":3,"paragraph":4,"sentenceNo":3,"sentence":"Even dairy farms, where robots do a small share of milking, have a long way to go before they’re automated.","path":"english2/2019.html"},{"id":"english2-2019-t3-p5-s1","examKey":"english2","examLabel":"英语二","year":"2019","text":3,"paragraph":5,"sentenceNo":1,"sentence":"Q34 H-2A 定位 As a result, farms have grown increasingly reliant on temporary guest workers using the H-2A visa to fill the gaps in the workforce.","path":"english2/2019.html"},{"id":"english2-2019-t3-p5-s2","examKey":"english2","examLabel":"英语二","year":"2019","text":3,"paragraph":5,"sentenceNo":2,"sentence":"Starting around 2012, requests for the visas rose sharply; from 2011 to 2016 the number of visas issued more than doubled.","path":"english2/2019.html"},{"id":"english2-2019-t3-p6-s1","examKey":"english2","examLabel":"英语二","year":"2019","text":3,"paragraph":6,"sentenceNo":1,"sentence":"The H-2A visa has no numerical cap, unlike the H-2B visa for nonagricultural work, which is limited to 66,000 a year.","path":"english2/2019.html"},{"id":"english2-2019-t3-p6-s2","examKey":"english2","examLabel":"英语二","year":"2019","text":3,"paragraph":6,"sentenceNo":2,"sentence":"Even so, employers complain they aren’t given all the workers they need.","path":"english2/2019.html"},{"id":"english2-2019-t3-p6-s3","examKey":"english2","examLabel":"英语二","year":"2019","text":3,"paragraph":6,"sentenceNo":3,"sentence":"The process is cumbersome, expensive, and unreliable.","path":"english2/2019.html"},{"id":"english2-2019-t3-p6-s4","examKey":"english2","examLabel":"英语二","year":"2019","text":3,"paragraph":6,"sentenceNo":4,"sentence":"One survey found that bureaucratic delays led the average H-2A worker to arrive on the job 22 days late.","path":"english2/2019.html"},{"id":"english2-2019-t3-p6-s5","examKey":"english2","examLabel":"英语二","year":"2019","text":3,"paragraph":6,"sentenceNo":5,"sentence":"The shortage is compounded by federal immigration raids, which remove some workers and drive others underground.","path":"english2/2019.html"},{"id":"english2-2019-t3-p7-s1","examKey":"english2","examLabel":"英语二","year":"2019","text":3,"paragraph":7,"sentenceNo":1,"sentence":"In a 2012 survey, 71 percent of tree-fruit growers and almost 80 percent of raisin and berry growers said they were short of labor.","path":"english2/2019.html"},{"id":"english2-2019-t3-p7-s2","examKey":"english2","examLabel":"英语二","year":"2019","text":3,"paragraph":7,"sentenceNo":2,"sentence":"Some western farmers have responded by moving operations to Mexico.","path":"english2/2019.html"},{"id":"english2-2019-t3-p7-s3","examKey":"english2","examLabel":"英语二","year":"2019","text":3,"paragraph":7,"sentenceNo":3,"sentence":"From 1998 to 2000, 14.5 percent of the fruit Americans consumed was imported.","path":"english2/2019.html"},{"id":"english2-2019-t3-p7-s4","examKey":"english2","examLabel":"英语二","year":"2019","text":3,"paragraph":7,"sentenceNo":4,"sentence":"Little more than a decade later, the share of imports was 25.8 percent.","path":"english2/2019.html"},{"id":"english2-2019-t3-p8-s1","examKey":"english2","examLabel":"英语二","year":"2019","text":3,"paragraph":8,"sentenceNo":1,"sentence":"Q35 标题定位 In effect, the U.S. can import food or it can import the workers who pick it.","path":"english2/2019.html"},{"id":"english2-2019-t4-p1-s1","examKey":"english2","examLabel":"英语二","year":"2019","text":4,"paragraph":1,"sentenceNo":1,"sentence":"Q36 视频定位 Arnold Schwarzenegger, Dia Mirza and Adrian Grenier have a message for you: It’s easy to beat plastic.","path":"english2/2019.html"},{"id":"english2-2019-t4-p1-s2","examKey":"english2","examLabel":"英语二","year":"2019","text":4,"paragraph":1,"sentenceNo":2,"sentence":"They’re part of a bunch of celebrities starring in a new video for World Environment Day — encouraging you, the consumer, to swap out your single-use plastic staples like straws and cutlery to combat the plastics crisis.","path":"english2/2019.html"},{"id":"english2-2019-t4-p2-s1","examKey":"english2","examLabel":"英语二","year":"2019","text":4,"paragraph":2,"sentenceNo":1,"sentence":"The key messages that have been put together for World Environment Day do include a call for governments to enact legislation to curb single-use plastics.","path":"english2/2019.html"},{"id":"english2-2019-t4-p2-s2","examKey":"english2","examLabel":"英语二","year":"2019","text":4,"paragraph":2,"sentenceNo":2,"sentence":"But the overarching message is directed at individuals.","path":"english2/2019.html"},{"id":"english2-2019-t4-p3-s1","examKey":"english2","examLabel":"英语二","year":"2019","text":4,"paragraph":3,"sentenceNo":1,"sentence":"Q37 moral licensing My concern with leaving it up to the individual, however, is our limited sense of what needs to be achieved.","path":"english2/2019.html"},{"id":"english2-2019-t4-p3-s2","examKey":"english2","examLabel":"英语二","year":"2019","text":4,"paragraph":3,"sentenceNo":2,"sentence":"On their own, taking our own bags to the grocery store or quitting plastic straws, for example, will accomplish little and require very little of us.","path":"english2/2019.html"},{"id":"english2-2019-t4-p3-s3","examKey":"english2","examLabel":"英语二","year":"2019","text":4,"paragraph":3,"sentenceNo":3,"sentence":"They could even be detrimental, satisfying a need to have “done our bit” without ever progressing onto bigger, bolder, more effective actions — a kind of “moral licensing” that allays our concerns and stops us doing more and asking more of those in charge.","path":"english2/2019.html"},{"id":"english2-2019-t4-p4-s1","examKey":"english2","examLabel":"英语二","year":"2019","text":4,"paragraph":4,"sentenceNo":1,"sentence":"Q38 citizens 定位 While the conversation around our environment and our responsibility toward it remains centered on shopping bags and straws, we’re ignoring the balance of power that implies that as “consumers” we must shop sustainably, rather than as “ citizens ” hold our governments and industries to account to push for real systemic change.","path":"english2/2019.html"},{"id":"english2-2019-t4-p5-s1","examKey":"english2","examLabel":"英语二","year":"2019","text":4,"paragraph":5,"sentenceNo":1,"sentence":"Q39 DeSombre 定位 It’s important to acknowledge that the environment isn’t everyone’s priority — or even most people’s.","path":"english2/2019.html"},{"id":"english2-2019-t4-p5-s2","examKey":"english2","examLabel":"英语二","year":"2019","text":4,"paragraph":5,"sentenceNo":2,"sentence":"We shouldn’t expect it to be.","path":"english2/2019.html"},{"id":"english2-2019-t4-p5-s3","examKey":"english2","examLabel":"英语二","year":"2019","text":4,"paragraph":5,"sentenceNo":3,"sentence":"In her latest book, Why Good People Do Bad Environmental Things, Wellesley College professor Elizabeth R.","path":"english2/2019.html"},{"id":"english2-2019-t4-p5-s4","examKey":"english2","examLabel":"英语二","year":"2019","text":4,"paragraph":5,"sentenceNo":4,"sentence":"DeSombre argues that the best way to collectively change the behavior of large numbers of people is for the change to be structural.","path":"english2/2019.html"},{"id":"english2-2019-t4-p6-s1","examKey":"english2","examLabel":"英语二","year":"2019","text":4,"paragraph":6,"sentenceNo":1,"sentence":"This might mean implementing policy such as a plastic tax that adds a cost to environmentally problematic action, or banning single-use plastics altogether.","path":"english2/2019.html"},{"id":"english2-2019-t4-p6-s2","examKey":"english2","examLabel":"英语二","year":"2019","text":4,"paragraph":6,"sentenceNo":2,"sentence":"India has just announced it will “eliminate all single-use plastic in the country by 2022.” There are also incentive-based ways of making better environmental choices easier, such as ensuring recycling is at least as easy as trash disposal.","path":"english2/2019.html"},{"id":"english2-2019-t4-p7-s1","examKey":"english2","examLabel":"英语二","year":"2019","text":4,"paragraph":7,"sentenceNo":1,"sentence":"Q40 结论定位 DeSombre isn’t saying people should stop caring about the environment.","path":"english2/2019.html"},{"id":"english2-2019-t4-p7-s2","examKey":"english2","examLabel":"英语二","year":"2019","text":4,"paragraph":7,"sentenceNo":2,"sentence":"It’s just that individual actions are too slow, she says, for that to be the only, or even primary, approach to changing widespread behavior.","path":"english2/2019.html"},{"id":"english2-2019-t4-p8-s1","examKey":"english2","examLabel":"英语二","year":"2019","text":4,"paragraph":8,"sentenceNo":1,"sentence":"None of this is about writing off the individual.","path":"english2/2019.html"},{"id":"english2-2019-t4-p8-s2","examKey":"english2","examLabel":"英语二","year":"2019","text":4,"paragraph":8,"sentenceNo":2,"sentence":"It’s just about putting things into perspective.","path":"english2/2019.html"},{"id":"english2-2019-t4-p8-s3","examKey":"english2","examLabel":"英语二","year":"2019","text":4,"paragraph":8,"sentenceNo":3,"sentence":"We don’t have time to wait.","path":"english2/2019.html"},{"id":"english2-2019-t4-p8-s4","examKey":"english2","examLabel":"英语二","year":"2019","text":4,"paragraph":8,"sentenceNo":4,"sentence":"We need progressive policies that shape collective action (and rein in polluting businesses), alongside engaged citizens pushing for change.","path":"english2/2019.html"},{"id":"english1-2020-t1-p1-s1","examKey":"english1","examLabel":"英语一","year":"2020","text":1,"paragraph":1,"sentenceNo":1,"sentence":"A group of Labour MPs, among them Yvette Cooper, are bringing in the new year with a call to institute a UK “town of culture ” award.","path":"english1/2020.html"},{"id":"english1-2020-t1-p1-s2","examKey":"english1","examLabel":"英语一","year":"2020","text":1,"paragraph":1,"sentenceNo":2,"sentence":"The proposal is that it should sit alongside the existing city of culture title, which was held by Hull in 2017, and has been awarded to Coventry for 2021.","path":"english1/2020.html"},{"id":"english1-2020-t1-p1-s3","examKey":"english1","examLabel":"英语一","year":"2020","text":1,"paragraph":1,"sentenceNo":3,"sentence":"Cooper and her colleagues argue that the success of the crown for Hull, where it brought in £220m of investment and an avalanche of arts, ought not to be confined to cities.","path":"english1/2020.html"},{"id":"english1-2020-t1-p1-s4","examKey":"english1","examLabel":"英语一","year":"2020","text":1,"paragraph":1,"sentenceNo":4,"sentence":"Britain’s towns, it is true, are not prevented from applying, but they generally lack the resources to put together a bid to beat their bigger competitors.","path":"english1/2020.html"},{"id":"english1-2020-t1-p1-s5","examKey":"english1","examLabel":"英语一","year":"2020","text":1,"paragraph":1,"sentenceNo":5,"sentence":"A town of culture award could, it is argued, become an annual event, attracting funding and creating jobs.","path":"english1/2020.html"},{"id":"english1-2020-t1-p2-s1","examKey":"english1","examLabel":"英语一","year":"2020","text":1,"paragraph":2,"sentenceNo":1,"sentence":"Some might see the proposal as a booby prize for the fact that Britain is no longer able to apply for the much more prestigious title of European capital of culture, a sought-after award bagged by Glasgow in 1990 and Liverpool in 2008.","path":"english1/2020.html"},{"id":"english1-2020-t1-p2-s2","examKey":"english1","examLabel":"英语一","year":"2020","text":1,"paragraph":2,"sentenceNo":2,"sentence":"A cynic might speculate that the UK is on the verge of disappearing into an endless fever of self-celebration in its desperation to reinvent itself for the post-Brexit world: after town of culture, who knows what will follow—village of culture?","path":"english1/2020.html"},{"id":"english1-2020-t1-p2-s3","examKey":"english1","examLabel":"英语一","year":"2020","text":1,"paragraph":2,"sentenceNo":3,"sentence":"Suburb of culture?","path":"english1/2020.html"},{"id":"english1-2020-t1-p2-s4","examKey":"english1","examLabel":"英语一","year":"2020","text":1,"paragraph":2,"sentenceNo":4,"sentence":"Hamlet of culture?","path":"english1/2020.html"},{"id":"english1-2020-t1-p3-s1","examKey":"english1","examLabel":"英语一","year":"2020","text":1,"paragraph":3,"sentenceNo":1,"sentence":"It is also wise to recall that such titles are not a cure-all.","path":"english1/2020.html"},{"id":"english1-2020-t1-p3-s2","examKey":"english1","examLabel":"英语一","year":"2020","text":1,"paragraph":3,"sentenceNo":2,"sentence":"A badly run “year of culture” washes in and out of a place like the tide, bringing prominence for a spell but leaving no lasting benefits to the community.","path":"english1/2020.html"},{"id":"english1-2020-t1-p3-s3","examKey":"english1","examLabel":"英语一","year":"2020","text":1,"paragraph":3,"sentenceNo":3,"sentence":"The really successful holders of such titles are those that do a great deal more than fill hotel bedrooms and bring in high-profile arts events and good press for a year.","path":"english1/2020.html"},{"id":"english1-2020-t1-p3-s4","examKey":"english1","examLabel":"英语一","year":"2020","text":1,"paragraph":3,"sentenceNo":4,"sentence":"They transform the aspirations of the people who live there; they nudge the self-image of the city into a bolder and more optimistic light.","path":"english1/2020.html"},{"id":"english1-2020-t1-p3-s5","examKey":"english1","examLabel":"英语一","year":"2020","text":1,"paragraph":3,"sentenceNo":5,"sentence":"It is hard to get right, and requires a remarkable degree of vision, as well as cooperation between city authorities, the private sector, community groups and cultural organisations.","path":"english1/2020.html"},{"id":"english1-2020-t1-p3-s6","examKey":"english1","examLabel":"英语一","year":"2020","text":1,"paragraph":3,"sentenceNo":6,"sentence":"But it can be done: Glasgow’s year as European capital of culture can certainly be seen as one of a complex series of factors that have turned the city into the powerhouse of art, music and theatre that it remains today.","path":"english1/2020.html"},{"id":"english1-2020-t1-p4-s1","examKey":"english1","examLabel":"英语一","year":"2020","text":1,"paragraph":4,"sentenceNo":1,"sentence":"A “town of culture” could be not just about the arts but about honouring a town’s peculiarities—helping sustain its high street, supporting local facilities and above all celebrating its people.","path":"english1/2020.html"},{"id":"english1-2020-t1-p4-s2","examKey":"english1","examLabel":"英语一","year":"2020","text":1,"paragraph":4,"sentenceNo":2,"sentence":"Jeremy Wright, the culture secretary, should welcome this positive, hope-filled proposal, and turn it into action.","path":"english1/2020.html"},{"id":"english1-2020-t2-p1-s1","examKey":"english1","examLabel":"英语一","year":"2020","text":2,"paragraph":1,"sentenceNo":1,"sentence":"Scientific publishing has long been a licence to print money.","path":"english1/2020.html"},{"id":"english1-2020-t2-p1-s2","examKey":"english1","examLabel":"英语一","year":"2020","text":2,"paragraph":1,"sentenceNo":2,"sentence":"Scientists need journals in which to publish their research, so they will supply the articles without monetary reward.","path":"english1/2020.html"},{"id":"english1-2020-t2-p1-s3","examKey":"english1","examLabel":"英语一","year":"2020","text":2,"paragraph":1,"sentenceNo":3,"sentence":"Other scientists perform the specialised work of peer review also for free, because it is a central element in the acquisition of status and the production of scientific knowledge.","path":"english1/2020.html"},{"id":"english1-2020-t2-p2-s1","examKey":"english1","examLabel":"英语一","year":"2020","text":2,"paragraph":2,"sentenceNo":1,"sentence":"With the content of papers secured for free, the publisher needs only to find a market for its journal.","path":"english1/2020.html"},{"id":"english1-2020-t2-p2-s2","examKey":"english1","examLabel":"英语一","year":"2020","text":2,"paragraph":2,"sentenceNo":2,"sentence":"Until this century, university libraries were not very price sensitive.","path":"english1/2020.html"},{"id":"english1-2020-t2-p2-s3","examKey":"english1","examLabel":"英语一","year":"2020","text":2,"paragraph":2,"sentenceNo":3,"sentence":"Scientific publishers routinely report profit margins approaching 40% on their operations, at a time when the rest of the publishing industry is in an existential crisis.","path":"english1/2020.html"},{"id":"english1-2020-t2-p3-s1","examKey":"english1","examLabel":"英语一","year":"2020","text":2,"paragraph":3,"sentenceNo":1,"sentence":"The Dutch giant Elsevier, which claims to publish 25% of the scientific papers produced in the world, made profits of more than £900m last year, while UK universities alone spent more than £210m in 2016 to enable researchers to access their own publicly funded research; both figures seem to rise unstoppably despite increasingly desperate efforts to change them.","path":"english1/2020.html"},{"id":"english1-2020-t2-p4-s1","examKey":"english1","examLabel":"英语一","year":"2020","text":2,"paragraph":4,"sentenceNo":1,"sentence":"The most drastic, and thoroughly illegal, reaction has been the emergence of Sci-Hub, a kind of global photocopier for scientific papers, set up in 2012, which now claims to offer access to every paywalled article published since 2015.","path":"english1/2020.html"},{"id":"english1-2020-t2-p4-s2","examKey":"english1","examLabel":"英语一","year":"2020","text":2,"paragraph":4,"sentenceNo":2,"sentence":"The success of Sci-Hub, which relies on researchers passing on copies they have themselves legally accessed, shows the legal ecosystem has lost legitimacy among its users and must be transformed so that it works for all participants.","path":"english1/2020.html"},{"id":"english1-2020-t2-p5-s1","examKey":"english1","examLabel":"英语一","year":"2020","text":2,"paragraph":5,"sentenceNo":1,"sentence":"In Britain the move towards open access publishing has been driven by funding bodies.","path":"english1/2020.html"},{"id":"english1-2020-t2-p5-s2","examKey":"english1","examLabel":"英语一","year":"2020","text":2,"paragraph":5,"sentenceNo":2,"sentence":"In some ways it has been very success ful.","path":"english1/2020.html"},{"id":"english1-2020-t2-p5-s3","examKey":"english1","examLabel":"英语一","year":"2020","text":2,"paragraph":5,"sentenceNo":3,"sentence":"More than half of all British scientific research is now published under open access terms: either freely available from the moment of publication, or paywalled for a year or so that the publishers can make a profit before being placed on general release.","path":"english1/2020.html"},{"id":"english1-2020-t2-p6-s1","examKey":"english1","examLabel":"英语一","year":"2020","text":2,"paragraph":6,"sentenceNo":1,"sentence":"Yet the new system has not worked out any cheaper for the universities.","path":"english1/2020.html"},{"id":"english1-2020-t2-p6-s2","examKey":"english1","examLabel":"英语一","year":"2020","text":2,"paragraph":6,"sentenceNo":2,"sentence":"Publishers have responded to the demand that they make their product free to readers by charging their writers fees to cover the costs of preparing an article.","path":"english1/2020.html"},{"id":"english1-2020-t2-p6-s3","examKey":"english1","examLabel":"英语一","year":"2020","text":2,"paragraph":6,"sentenceNo":3,"sentence":"These range from around £500 to $5,000.","path":"english1/2020.html"},{"id":"english1-2020-t2-p6-s4","examKey":"english1","examLabel":"英语一","year":"2020","text":2,"paragraph":6,"sentenceNo":4,"sentence":"A report last year pointed out that the costs both of subscriptions and of these “article preparation costs” had been steadily rising at a rate above inflation.","path":"english1/2020.html"},{"id":"english1-2020-t2-p6-s5","examKey":"english1","examLabel":"英语一","year":"2020","text":2,"paragraph":6,"sentenceNo":5,"sentence":"In some ways the scientific publishing model resembles the economy of the social internet: labour is provided free in exchange for the hope of status, while huge profits are made by a few big firms who run the market places.","path":"english1/2020.html"},{"id":"english1-2020-t2-p6-s6","examKey":"english1","examLabel":"英语一","year":"2020","text":2,"paragraph":6,"sentenceNo":6,"sentence":"In both cases, we need a rebalancing of power.","path":"english1/2020.html"},{"id":"english1-2020-t3-p1-s1","examKey":"english1","examLabel":"英语一","year":"2020","text":3,"paragraph":1,"sentenceNo":1,"sentence":"Progressives often support diversity mandates as a path to equality and a way to level the playing field.","path":"english1/2020.html"},{"id":"english1-2020-t3-p1-s2","examKey":"english1","examLabel":"英语一","year":"2020","text":3,"paragraph":1,"sentenceNo":2,"sentence":"But all too often such policies are an insincere form of virtue-signaling that benefits only the most privileged and does little to help average people.","path":"english1/2020.html"},{"id":"english1-2020-t3-p2-s1","examKey":"english1","examLabel":"英语一","year":"2020","text":3,"paragraph":2,"sentenceNo":1,"sentence":"A pair of bills sponsored by Massachusetts state Senator Jason Lewis and House Speaker Pro Tempore Patricia Haddad, to ensure “ gender parity” on boards and commissions, provide a case in point.","path":"english1/2020.html"},{"id":"english1-2020-t3-p3-s1","examKey":"english1","examLabel":"英语一","year":"2020","text":3,"paragraph":3,"sentenceNo":1,"sentence":"Haddad and Lewis are concerned that more than half the state-government boards are less than 40 percent female.","path":"english1/2020.html"},{"id":"english1-2020-t3-p3-s2","examKey":"english1","examLabel":"英语一","year":"2020","text":3,"paragraph":3,"sentenceNo":2,"sentence":"In order to ensure that elite women have more such opportunities, they have proposed imposing government quota s.","path":"english1/2020.html"},{"id":"english1-2020-t3-p3-s3","examKey":"english1","examLabel":"英语一","year":"2020","text":3,"paragraph":3,"sentenceNo":3,"sentence":"If the bills become law, state boards and commissions will be required to set aside 50 percent of board seats for women by 2022.","path":"english1/2020.html"},{"id":"english1-2020-t3-p4-s1","examKey":"english1","examLabel":"英语一","year":"2020","text":3,"paragraph":4,"sentenceNo":1,"sentence":"The bills are similar to a measure recently adopted in California, which last year became the first state to require gender quotas for private companies.","path":"english1/2020.html"},{"id":"english1-2020-t3-p4-s2","examKey":"english1","examLabel":"英语一","year":"2020","text":3,"paragraph":4,"sentenceNo":2,"sentence":"In signing the measure, California Governor Jerry Brown admitted that the law, which expressly classifies people on the basis of sex, is probably unconstitutional.","path":"english1/2020.html"},{"id":"english1-2020-t3-p5-s1","examKey":"english1","examLabel":"英语一","year":"2020","text":3,"paragraph":5,"sentenceNo":1,"sentence":"The US Supreme Court frowns on sex-based classifications unless they are designed to address an “important” policy interest.","path":"english1/2020.html"},{"id":"english1-2020-t3-p5-s2","examKey":"english1","examLabel":"英语一","year":"2020","text":3,"paragraph":5,"sentenceNo":2,"sentence":"Because the California law applies to all boards, even where there is no history of prior discrimination, courts are likely to rule that the law violates the constitutional guarantee of “equal protection.”","path":"english1/2020.html"},{"id":"english1-2020-t3-p6-s1","examKey":"english1","examLabel":"英语一","year":"2020","text":3,"paragraph":6,"sentenceNo":1,"sentence":"But are such government mandates even necessary?","path":"english1/2020.html"},{"id":"english1-2020-t3-p6-s2","examKey":"english1","examLabel":"英语一","year":"2020","text":3,"paragraph":6,"sentenceNo":2,"sentence":"Female participation on corporate boards may not currently mirror the percentage of women in the general population, but so what?","path":"english1/2020.html"},{"id":"english1-2020-t3-p7-s1","examKey":"english1","examLabel":"英语一","year":"2020","text":3,"paragraph":7,"sentenceNo":1,"sentence":"The number of women on corporate boards has been steadily increasing without government interference.","path":"english1/2020.html"},{"id":"english1-2020-t3-p7-s2","examKey":"english1","examLabel":"英语一","year":"2020","text":3,"paragraph":7,"sentenceNo":2,"sentence":"According to a study by Catalyst, between 2010 and 2015 the share of women on the boards of global corporations increased by 54 percent.","path":"english1/2020.html"},{"id":"english1-2020-t3-p8-s1","examKey":"english1","examLabel":"英语一","year":"2020","text":3,"paragraph":8,"sentenceNo":1,"sentence":"Requiring companies to make gender the primary qualification for board membership will inevitably lead to less experienced private sector boards.","path":"english1/2020.html"},{"id":"english1-2020-t3-p8-s2","examKey":"english1","examLabel":"英语一","year":"2020","text":3,"paragraph":8,"sentenceNo":2,"sentence":"That is exactly what happened when Norway adopted a nationwide corporate gender quota.","path":"english1/2020.html"},{"id":"english1-2020-t3-p9-s1","examKey":"english1","examLabel":"英语一","year":"2020","text":3,"paragraph":9,"sentenceNo":1,"sentence":"Writing in The New Republic, Alice Lee notes that increasing the number of opportunities for board membership without increasing the pool of qualified women to serve on such boards has led to a “golden skirt” phenomenon, where the same elite women scoop up multiple seats on a variety of boards.","path":"english1/2020.html"},{"id":"english1-2020-t3-p10-s1","examKey":"english1","examLabel":"英语一","year":"2020","text":3,"paragraph":10,"sentenceNo":1,"sentence":"Next time somebody pushes corporate quotas as a way to promote gender equity, remember that such policies are largely self-serving measures that make their sponsors feel good but do little to help average women.","path":"english1/2020.html"},{"id":"english1-2020-t4-p1-s1","examKey":"english1","examLabel":"英语一","year":"2020","text":4,"paragraph":1,"sentenceNo":1,"sentence":"Last Thursday, the French Senate passed a digital services tax, which would impose an entirely new tax on large multinationals that provide digital services to consumers or users in France.","path":"english1/2020.html"},{"id":"english1-2020-t4-p1-s2","examKey":"english1","examLabel":"英语一","year":"2020","text":4,"paragraph":1,"sentenceNo":2,"sentence":"Digital services include everything from providing a platform for selling goods and services online to targeting advertising based on user data, and the tax applies to gross revenue from such services.","path":"english1/2020.html"},{"id":"english1-2020-t4-p1-s3","examKey":"english1","examLabel":"英语一","year":"2020","text":4,"paragraph":1,"sentenceNo":3,"sentence":"Many French politicians and media outlets have referred to this as a “GAFA tax,” meaning that it is designed to apply primarily to companies such as Google, Apple, Facebook and Amazon—in other words, multinational tech companies based in the United States.","path":"english1/2020.html"},{"id":"english1-2020-t4-p2-s1","examKey":"english1","examLabel":"英语一","year":"2020","text":4,"paragraph":2,"sentenceNo":1,"sentence":"The digital services tax now awaits the signature of President Emmanuel Macron, who has expressed support for the measure, and it could go into effect within the next few weeks.","path":"english1/2020.html"},{"id":"english1-2020-t4-p2-s2","examKey":"english1","examLabel":"英语一","year":"2020","text":4,"paragraph":2,"sentenceNo":2,"sentence":"But it has already sparked significant controversy, with the United States trade representative opening an investigation into whether the tax discriminates against American companies, which in turn could lead to trade sanctions against France.","path":"english1/2020.html"},{"id":"english1-2020-t4-p3-s1","examKey":"english1","examLabel":"英语一","year":"2020","text":4,"paragraph":3,"sentenceNo":1,"sentence":"The French tax is not just a unilateral move by one country in need of revenue.","path":"english1/2020.html"},{"id":"english1-2020-t4-p3-s2","examKey":"english1","examLabel":"英语一","year":"2020","text":4,"paragraph":3,"sentenceNo":2,"sentence":"Instead, the digital services tax is part of a much larger trend, with countries over the past few years proposing or putting in place an alphabet soup of new international tax provisions.","path":"english1/2020.html"},{"id":"english1-2020-t4-p3-s3","examKey":"english1","examLabel":"英语一","year":"2020","text":4,"paragraph":3,"sentenceNo":3,"sentence":"These have included Britain’s DPT (diverted profits tax), Australia’s MAAL (multinational antiavoidance law), and India’s SEP (significant economic presence) test, to name but a few.","path":"english1/2020.html"},{"id":"english1-2020-t4-p3-s4","examKey":"english1","examLabel":"英语一","year":"2020","text":4,"paragraph":3,"sentenceNo":4,"sentence":"At the same time, the European Union, Spain, Britain and several other countries have all seriously contemplated digital services taxes.","path":"english1/2020.html"},{"id":"english1-2020-t4-p4-s1","examKey":"english1","examLabel":"英语一","year":"2020","text":4,"paragraph":4,"sentenceNo":1,"sentence":"These unilateral developments differ in their specifics, but they are all designed to tax multinationals on income and revenue that countries believe they should have a right to tax, even if international tax rules do not grant them that right.","path":"english1/2020.html"},{"id":"english1-2020-t4-p4-s2","examKey":"english1","examLabel":"英语一","year":"2020","text":4,"paragraph":4,"sentenceNo":2,"sentence":"In other words, they all share a view that the international tax system has failed to keep up with the current economy.","path":"english1/2020.html"},{"id":"english1-2020-t4-p5-s1","examKey":"english1","examLabel":"英语一","year":"2020","text":4,"paragraph":5,"sentenceNo":1,"sentence":"In response to these many unilateral measures, the Organization for Economic Cooperation and Development (OECD) is current ly work ing with 131 countries to reach a consensus by the end of 2020 on an international solution.","path":"english1/2020.html"},{"id":"english1-2020-t4-p5-s2","examKey":"english1","examLabel":"英语一","year":"2020","text":4,"paragraph":5,"sentenceNo":2,"sentence":"Both France and the United States are involved in the organization’s work, but France’s digital services tax and the American response raise questions about what the future holds for the international tax system.","path":"english1/2020.html"},{"id":"english1-2020-t4-p6-s1","examKey":"english1","examLabel":"英语一","year":"2020","text":4,"paragraph":6,"sentenceNo":1,"sentence":"France’s planned tax is a clear warning: Unless a broad consensus can be reached on reforming the international tax system, other nations are likely to follow suit, and American companies will face a cascade of different taxes from dozens of nations that will prove burdensome and costly.","path":"english1/2020.html"},{"id":"english2-2020-t1-p1-s1","examKey":"english2","examLabel":"英语二","year":"2020","text":1,"paragraph":1,"sentenceNo":1,"sentence":"Q21 段落定位 1 Rats and other animals need to be highly attuned to social signals from others so they can identify friends to cooperate with and enemies to avoid.","path":"english2/2020.html"},{"id":"english2-2020-t1-p1-s2","examKey":"english2","examLabel":"英语二","year":"2020","text":1,"paragraph":1,"sentenceNo":2,"sentence":"2 To find out if this extends to non-living beings, Laleh Quinn at the University of California, San Diego, and her colleagues tested whether rats can detect social signals from robotic rats.","path":"english2/2020.html"},{"id":"english2-2020-t1-p2-s1","examKey":"english2","examLabel":"英语二","year":"2020","text":1,"paragraph":2,"sentenceNo":1,"sentence":"3 They housed eight adult rats with two types of robotic rat—one social and one asocial —for four days.","path":"english2/2020.html"},{"id":"english2-2020-t1-p2-s2","examKey":"english2","examLabel":"英语二","year":"2020","text":1,"paragraph":2,"sentenceNo":2,"sentence":"4 The robot rats were quite minimalist, resembling a chunkier version of a computer mouse with wheels to move around and colourful markings.","path":"english2/2020.html"},{"id":"english2-2020-t1-p3-s1","examKey":"english2","examLabel":"英语二","year":"2020","text":1,"paragraph":3,"sentenceNo":1,"sentence":"Q22 实验定位 5 During the experiment, the social robot rat followed the living rats around, played with the same toys, and opened cage doors to let trapped rats escape.","path":"english2/2020.html"},{"id":"english2-2020-t1-p3-s2","examKey":"english2","examLabel":"英语二","year":"2020","text":1,"paragraph":3,"sentenceNo":2,"sentence":"6 Meanwhile, the asocial robot simply moved forwards and backwards and side to side.","path":"english2/2020.html"},{"id":"english2-2020-t1-p4-s1","examKey":"english2","examLabel":"英语二","year":"2020","text":1,"paragraph":4,"sentenceNo":1,"sentence":"7 Next, the researchers trapped the robots in cages and gave the rats the opportunity to release them by pressing a lever.","path":"english2/2020.html"},{"id":"english2-2020-t1-p4-s2","examKey":"english2","examLabel":"英语二","year":"2020","text":1,"paragraph":4,"sentenceNo":2,"sentence":"8 Across 18 trials each, the living rats were 52 per cent more likely on average to set the social robot free than the asocial one.","path":"english2/2020.html"},{"id":"english2-2020-t1-p4-s3","examKey":"english2","examLabel":"英语二","year":"2020","text":1,"paragraph":4,"sentenceNo":3,"sentence":"9 This suggests that the rats perceived the social robot as a genuine social being.","path":"english2/2020.html"},{"id":"english2-2020-t1-p4-s4","examKey":"english2","examLabel":"英语二","year":"2020","text":1,"paragraph":4,"sentenceNo":4,"sentence":"10 They may have bonded more with the social robot because it displayed behaviors like communal exploring and playing.","path":"english2/2020.html"},{"id":"english2-2020-t1-p4-s5","examKey":"english2","examLabel":"英语二","year":"2020","text":1,"paragraph":4,"sentenceNo":5,"sentence":"This could lead to the rats better remembering having freed it earlier, and wanting the robot to return the favour when they get trapped, says Quinn.","path":"english2/2020.html"},{"id":"english2-2020-t1-p5-s1","examKey":"english2","examLabel":"英语二","year":"2020","text":1,"paragraph":5,"sentenceNo":1,"sentence":"11 “Rats have been shown to engage in multiple forms of reciprocal help and cooperation, including what is referred to as direct reciprocity —where a rat will help another rat that has previously helped them,” says Quinn.","path":"english2/2020.html"},{"id":"english2-2020-t1-p6-s1","examKey":"english2","examLabel":"英语二","year":"2020","text":1,"paragraph":6,"sentenceNo":1,"sentence":"12 The readiness of the rats to befriend the social robot was surprising given its minimal design.","path":"english2/2020.html"},{"id":"english2-2020-t1-p6-s2","examKey":"english2","examLabel":"英语二","year":"2020","text":1,"paragraph":6,"sentenceNo":2,"sentence":"13 The robot was the same size as a regular rat but resembled a simple plastic box on wheels.","path":"english2/2020.html"},{"id":"english2-2020-t1-p6-s3","examKey":"english2","examLabel":"英语二","year":"2020","text":1,"paragraph":6,"sentenceNo":3,"sentence":"14 “We’d assumed we’d have to give it a moving head and tail, facial features, and put a scent on it to make it smell like a real rat, but that wasn’t necessary,” says Janet Wiles at the University of Queensland in Australia, who helped with the research.","path":"english2/2020.html"},{"id":"english2-2020-t1-p7-s1","examKey":"english2","examLabel":"英语二","year":"2020","text":1,"paragraph":7,"sentenceNo":1,"sentence":"Q25 全文结论 15 The finding shows how sensitive rats are to social cues, even when they come from basic robots.","path":"english2/2020.html"},{"id":"english2-2020-t1-p7-s2","examKey":"english2","examLabel":"英语二","year":"2020","text":1,"paragraph":7,"sentenceNo":2,"sentence":"16 Similarly, children tend to treat robots as if they are fellow beings, even when they display only simple social signals.","path":"english2/2020.html"},{"id":"english2-2020-t1-p7-s3","examKey":"english2","examLabel":"英语二","year":"2020","text":1,"paragraph":7,"sentenceNo":3,"sentence":"17 “We humans seem to be fascinated by robots, and it turns out other animals are too,” says Wiles.","path":"english2/2020.html"},{"id":"english2-2020-t2-p1-s1","examKey":"english2","examLabel":"英语二","year":"2020","text":2,"paragraph":1,"sentenceNo":1,"sentence":"1 It is true that CEO pay has gone up — top ones may make 300 times the pay of typical workers on average, and since the mid-1970s, CEO pay for large publicly traded American corporations has, by varying estimates, gone up by about 500%.","path":"english2/2020.html"},{"id":"english2-2020-t2-p1-s2","examKey":"english2","examLabel":"英语二","year":"2020","text":2,"paragraph":1,"sentenceNo":2,"sentence":"2 The typical CEO of a top American corporation now makes about $18.9 million a year.","path":"english2/2020.html"},{"id":"english2-2020-t2-p2-s1","examKey":"english2","examLabel":"英语二","year":"2020","text":2,"paragraph":2,"sentenceNo":1,"sentence":"3 The best model for understanding the growth of CEO pay is that of limited CEO talent in a world where business opportunities for the top firms are growing rapidly.","path":"english2/2020.html"},{"id":"english2-2020-t2-p2-s2","examKey":"english2","examLabel":"英语二","year":"2020","text":2,"paragraph":2,"sentenceNo":2,"sentence":"4 The efforts of America’s highest-earning 1% have been one of the more dynamic elements of the global economy.","path":"english2/2020.html"},{"id":"english2-2020-t2-p2-s3","examKey":"english2","examLabel":"英语二","year":"2020","text":2,"paragraph":2,"sentenceNo":3,"sentence":"5 It’s not popular to say, but one reason their pay has gone up so much is that CEOs really have upped their game relative to many other workers in the U.S. economy.","path":"english2/2020.html"},{"id":"english2-2020-t2-p3-s1","examKey":"english2","examLabel":"英语二","year":"2020","text":2,"paragraph":3,"sentenceNo":1,"sentence":"6 Q27 前后对比 Today’s CEO, at least for major American firms, must have many more skills than simply being able to “run the company.” 7 CEOs must have a good sense of financial markets and maybe even how the company should trade in them.","path":"english2/2020.html"},{"id":"english2-2020-t2-p3-s2","examKey":"english2","examLabel":"英语二","year":"2020","text":2,"paragraph":3,"sentenceNo":2,"sentence":"8 They also need better public relations skills than their predecessors, as the costs of even a minor slipup can be significant.","path":"english2/2020.html"},{"id":"english2-2020-t2-p3-s3","examKey":"english2","examLabel":"英语二","year":"2020","text":2,"paragraph":3,"sentenceNo":3,"sentence":"9 Then there’s the fact that large American companies are much more globalized than ever before, with supply chains spread across a larger number of countries.","path":"english2/2020.html"},{"id":"english2-2020-t2-p3-s4","examKey":"english2","examLabel":"英语二","year":"2020","text":2,"paragraph":3,"sentenceNo":4,"sentence":"To lead in that system requires knowledge that is fairly mind-boggling.","path":"english2/2020.html"},{"id":"english2-2020-t2-p3-s5","examKey":"english2","examLabel":"英语二","year":"2020","text":2,"paragraph":3,"sentenceNo":5,"sentence":"10 Plus, virtually all major American companies are becoming tech companies, often with their own research and development.","path":"english2/2020.html"},{"id":"english2-2020-t2-p3-s6","examKey":"english2","examLabel":"英语二","year":"2020","text":2,"paragraph":3,"sentenceNo":6,"sentence":"11 And beyond this, major CEOs still have to do all the day-to-day work they have always done.","path":"english2/2020.html"},{"id":"english2-2020-t2-p4-s1","examKey":"english2","examLabel":"英语二","year":"2020","text":2,"paragraph":4,"sentenceNo":1,"sentence":"12 The common idea that high CEO pay is mainly about ripping people off doesn’t explain history very well.","path":"english2/2020.html"},{"id":"english2-2020-t2-p4-s2","examKey":"english2","examLabel":"英语二","year":"2020","text":2,"paragraph":4,"sentenceNo":2,"sentence":"13 By most measures, corporate governance has become a lot tighter and more rigorous since the 1970s.","path":"english2/2020.html"},{"id":"english2-2020-t2-p4-s3","examKey":"english2","examLabel":"英语二","year":"2020","text":2,"paragraph":4,"sentenceNo":3,"sentence":"14 Yet it is principally during this period of stronger governance that CEO pay has been high and rising.","path":"english2/2020.html"},{"id":"english2-2020-t2-p4-s4","examKey":"english2","examLabel":"英语二","year":"2020","text":2,"paragraph":4,"sentenceNo":4,"sentence":"15 That suggests it is in the broader corporate interest to recruit top candidates for increasingly tough jobs.","path":"english2/2020.html"},{"id":"english2-2020-t2-p5-s1","examKey":"english2","examLabel":"英语二","year":"2020","text":2,"paragraph":5,"sentenceNo":1,"sentence":"16 Furthermore, the highest CEO salaries are paid to outside candidates, not to the cozy insider picks, another sign that high CEO pay is not some kind of depredation at the expense of the rest of the company.","path":"english2/2020.html"},{"id":"english2-2020-t2-p5-s2","examKey":"english2","examLabel":"英语二","year":"2020","text":2,"paragraph":5,"sentenceNo":2,"sentence":"17 And the stock market reacts positively when companies tie CEO pay to, say, stock prices, a sign that those practices build up corporate value not just for the CEO.","path":"english2/2020.html"},{"id":"english2-2020-t2-p5-s3","examKey":"english2","examLabel":"英语二","year":"2020","text":2,"paragraph":5,"sentenceNo":3,"sentence":"18 High CEO pay is repeatedly explained as a way to recruit scarce talent for increasingly tough, value-building jobs, not merely as overpayment.","path":"english2/2020.html"},{"id":"english2-2020-t3-p1-s1","examKey":"english2","examLabel":"英语二","year":"2020","text":3,"paragraph":1,"sentenceNo":1,"sentence":"1 Madrid was hailed as a public health guiding light last November when it rolled out ambitious restrictions on the most polluting cars.","path":"english2/2020.html"},{"id":"english2-2020-t3-p1-s2","examKey":"english2","examLabel":"英语二","year":"2020","text":3,"paragraph":1,"sentenceNo":2,"sentence":"2 Seven months and one election day later, a new conservative city council suspended enforcement of the clean air zone, a first step toward its possible termination.","path":"english2/2020.html"},{"id":"english2-2020-t3-p1-s3","examKey":"english2","examLabel":"英语二","year":"2020","text":3,"paragraph":1,"sentenceNo":3,"sentence":"3 Mayor José Luis Martínez-Almeida made opposition to the zone a centerpiece of his election campaign, despite its success in improving air quality.","path":"english2/2020.html"},{"id":"english2-2020-t3-p1-s4","examKey":"english2","examLabel":"英语二","year":"2020","text":3,"paragraph":1,"sentenceNo":4,"sentence":"4 A judge has now overruled the city’s decision to stop levying fines, ordering them restored.","path":"english2/2020.html"},{"id":"english2-2020-t3-p1-s5","examKey":"english2","examLabel":"英语二","year":"2020","text":3,"paragraph":1,"sentenceNo":5,"sentence":"5 But with legal battles ahead, the zone’s future looks uncertain at best.","path":"english2/2020.html"},{"id":"english2-2020-t3-p2-s1","examKey":"english2","examLabel":"英语二","year":"2020","text":3,"paragraph":2,"sentenceNo":1,"sentence":"6 Madrid’s back and forth on clean air is a pointed reminder of the limits to the patchwork, city-by-city approach that characterises efforts on air pollution across Europe, Britain very much included.","path":"english2/2020.html"},{"id":"english2-2020-t3-p3-s1","examKey":"english2","examLabel":"英语二","year":"2020","text":3,"paragraph":3,"sentenceNo":1,"sentence":"7 Among other weaknesses, the measures cities must employ when left to tackle dirty air on their own are politically controversial, and therefore vulnerable.","path":"english2/2020.html"},{"id":"english2-2020-t3-p3-s2","examKey":"english2","examLabel":"英语二","year":"2020","text":3,"paragraph":3,"sentenceNo":2,"sentence":"8 That’s because they inevitably put the costs of cleaning the air on to individual drivers—who must pay fees or buy better vehicles—rather than on to the car manufacturers whose cheating is the real cause of our toxic pollution.","path":"english2/2020.html"},{"id":"english2-2020-t3-p3-s3","examKey":"english2","examLabel":"英语二","year":"2020","text":3,"paragraph":3,"sentenceNo":3,"sentence":"9 It’s not hard to imagine a similar reversal happening in London.","path":"english2/2020.html"},{"id":"english2-2020-t3-p3-s4","examKey":"english2","examLabel":"英语二","year":"2020","text":3,"paragraph":3,"sentenceNo":4,"sentence":"10 The new ultra-low emission zone ( Ulez ) is likely to be a big issue in next year’s mayoral election.","path":"english2/2020.html"},{"id":"english2-2020-t3-p3-s5","examKey":"english2","examLabel":"英语二","year":"2020","text":3,"paragraph":3,"sentenceNo":5,"sentence":"11 And if Sadiq Khan wins and extends it to the North and South Circular roads in 2021 as he intends, it is sure to spark intense opposition from the far larger number of motorists who will then be affected.","path":"english2/2020.html"},{"id":"english2-2020-t3-p4-s1","examKey":"english2","examLabel":"英语二","year":"2020","text":3,"paragraph":4,"sentenceNo":1,"sentence":"12 It’s not that measures such as London’s Ulez are useless.","path":"english2/2020.html"},{"id":"english2-2020-t3-p4-s2","examKey":"english2","examLabel":"英语二","year":"2020","text":3,"paragraph":4,"sentenceNo":2,"sentence":"Far from it.","path":"english2/2020.html"},{"id":"english2-2020-t3-p4-s3","examKey":"english2","examLabel":"英语二","year":"2020","text":3,"paragraph":4,"sentenceNo":3,"sentence":"13 Local officials are using the levers that are available to them to safeguard residents’ health in the face of a serious threat.","path":"english2/2020.html"},{"id":"english2-2020-t3-p4-s4","examKey":"english2","examLabel":"英语二","year":"2020","text":3,"paragraph":4,"sentenceNo":4,"sentence":"14 The zones do deliver some improvements to air quality, and the science tells us that means real health benefits.","path":"english2/2020.html"},{"id":"english2-2020-t3-p5-s1","examKey":"english2","examLabel":"英语二","year":"2020","text":3,"paragraph":5,"sentenceNo":1,"sentence":"15 But mayors and councilors can only do so much about a problem that is far bigger than any one city or town.","path":"english2/2020.html"},{"id":"english2-2020-t3-p5-s2","examKey":"english2","examLabel":"英语二","year":"2020","text":3,"paragraph":5,"sentenceNo":2,"sentence":"16 They are acting because national governments—Britain’s and others across Europe—have failed to do so.","path":"english2/2020.html"},{"id":"english2-2020-t3-p6-s1","examKey":"english2","examLabel":"英语二","year":"2020","text":3,"paragraph":6,"sentenceNo":1,"sentence":"Q35 末段定位 17 Restrictions that keep highly polluting cars out of certain areas—city centres, “school streets”, even individual roads—are a response to the absence of a larger effort to properly enforce existing regulations and require auto companies to bring their vehicles into compliance.","path":"english2/2020.html"},{"id":"english2-2020-t3-p6-s2","examKey":"english2","examLabel":"英语二","year":"2020","text":3,"paragraph":6,"sentenceNo":2,"sentence":"18 Wales has introduced special low speed limits to minimise pollution.","path":"english2/2020.html"},{"id":"english2-2020-t3-p6-s3","examKey":"english2","examLabel":"英语二","year":"2020","text":3,"paragraph":6,"sentenceNo":3,"sentence":"19 We’re doing everything but insist that manufacturers clean up their cars.","path":"english2/2020.html"},{"id":"english2-2020-t4-p1-s1","examKey":"english2","examLabel":"英语二","year":"2020","text":4,"paragraph":1,"sentenceNo":1,"sentence":"1 Now that members of Generation Z are graduating college this spring —the most commonly-accepted definition says this generation was born after 1995, give or take a year—the attention has been rising steadily in recent weeks.","path":"english2/2020.html"},{"id":"english2-2020-t4-p1-s2","examKey":"english2","examLabel":"英语二","year":"2020","text":4,"paragraph":1,"sentenceNo":2,"sentence":"2 Gen Zs are about to hit the streets looking for work in a labor market that’s tighter than it’s been in decades.","path":"english2/2020.html"},{"id":"english2-2020-t4-p1-s3","examKey":"english2","examLabel":"英语二","year":"2020","text":4,"paragraph":1,"sentenceNo":3,"sentence":"3 And employers are planning on hiring about 17 percent more new graduates for jobs in the U.S. this year than last, according to a survey conducted by the National Association of Colleges and Employers.","path":"english2/2020.html"},{"id":"english2-2020-t4-p1-s4","examKey":"english2","examLabel":"英语二","year":"2020","text":4,"paragraph":1,"sentenceNo":4,"sentence":"4 Everybody wants to know how the people who will soon inhabit those empty office cubicles will differ from those who came before them.","path":"english2/2020.html"},{"id":"english2-2020-t4-p2-s1","examKey":"english2","examLabel":"英语二","year":"2020","text":4,"paragraph":2,"sentenceNo":1,"sentence":"5 If “entitled” is the most common adjective, fairly or not, applied to millennials (those born between 1981 and 1995), the catchwords for Generation Z are practical and cautious.","path":"english2/2020.html"},{"id":"english2-2020-t4-p2-s2","examKey":"english2","examLabel":"英语二","year":"2020","text":4,"paragraph":2,"sentenceNo":2,"sentence":"6 According to the career counselors and experts who study them, Generation Zs are clear-eyed, economic pragmatists.","path":"english2/2020.html"},{"id":"english2-2020-t4-p2-s3","examKey":"english2","examLabel":"英语二","year":"2020","text":4,"paragraph":2,"sentenceNo":3,"sentence":"7 Despite graduating into the best economy in the past 50 years, Gen Zs know what an economic train wreck looks like.","path":"english2/2020.html"},{"id":"english2-2020-t4-p2-s4","examKey":"english2","examLabel":"英语二","year":"2020","text":4,"paragraph":2,"sentenceNo":4,"sentence":"8 They were impressionable kids during the crash of 2008, when many of their parents lost their jobs or their life savings or both.","path":"english2/2020.html"},{"id":"english2-2020-t4-p2-s5","examKey":"english2","examLabel":"英语二","year":"2020","text":4,"paragraph":2,"sentenceNo":5,"sentence":"9 They aren’t interested in taking any chances.","path":"english2/2020.html"},{"id":"english2-2020-t4-p2-s6","examKey":"english2","examLabel":"英语二","year":"2020","text":4,"paragraph":2,"sentenceNo":6,"sentence":"10 The booming economy seems to have done little to assuage this underlying generational sense of anxious urgency, especially for those who have college debt.","path":"english2/2020.html"},{"id":"english2-2020-t4-p2-s7","examKey":"english2","examLabel":"英语二","year":"2020","text":4,"paragraph":2,"sentenceNo":7,"sentence":"11 College loan balances in the U.S. now stand at a record $1.5 trillion, according to the Federal Reserve.","path":"english2/2020.html"},{"id":"english2-2020-t4-p3-s1","examKey":"english2","examLabel":"英语二","year":"2020","text":4,"paragraph":3,"sentenceNo":1,"sentence":"Q39 段落定位 12 One survey from Accenture found that 88 percent of graduating seniors this year chose their major with a job in mind.","path":"english2/2020.html"},{"id":"english2-2020-t4-p3-s2","examKey":"english2","examLabel":"英语二","year":"2020","text":4,"paragraph":3,"sentenceNo":2,"sentence":"13 In a 2019 survey of University of Georgia students, meanwhile, the career office found the most desirable trait in a future employer was the ability to offer secure employment (followed by professional development and training, and then inspiring purpose).","path":"english2/2020.html"},{"id":"english2-2020-t4-p3-s3","examKey":"english2","examLabel":"英语二","year":"2020","text":4,"paragraph":3,"sentenceNo":3,"sentence":"14 Job security or stability was the second most important career goal (work-life balance was number one), followed by a sense of being dedicated to a cause or to feel good about serving the greater good.","path":"english2/2020.html"},{"id":"english2-2020-t4-p4-s1","examKey":"english2","examLabel":"英语二","year":"2020","text":4,"paragraph":4,"sentenceNo":1,"sentence":"15 That’s a big change from the previous generation.","path":"english2/2020.html"},{"id":"english2-2020-t4-p4-s2","examKey":"english2","examLabel":"英语二","year":"2020","text":4,"paragraph":4,"sentenceNo":2,"sentence":"16 “ Millennials wanted more flexibility in their lives,” notes Tanya Michelsen, Associate Director of YouthSight, a market research firm.","path":"english2/2020.html"},{"id":"english2-2020-t4-p4-s3","examKey":"english2","examLabel":"英语二","year":"2020","text":4,"paragraph":4,"sentenceNo":3,"sentence":"17 By contrast, Generation Zs are looking for more certainty and stability, which makes them less interested in taking chances and less adventurous than millennials.","path":"english2/2020.html"},{"id":"english1-2021-t1-p1-s1","examKey":"english1","examLabel":"英语一","year":"2021","text":1,"paragraph":1,"sentenceNo":1,"sentence":"How can Britain’s train operators possibly justify yet another increase to rail passenger fares?","path":"english1/2021.html"},{"id":"english1-2021-t1-p1-s2","examKey":"english1","examLabel":"英语一","year":"2021","text":1,"paragraph":1,"sentenceNo":2,"sentence":"It has become a grimly reliable annual ritual: every January the cost of travelling by train rises, imposing a significant extra burden on those who have no option but to use the rail network to get to work or otherwise.","path":"english1/2021.html"},{"id":"english1-2021-t1-p1-s3","examKey":"english1","examLabel":"英语一","year":"2021","text":1,"paragraph":1,"sentenceNo":3,"sentence":"This year’s rise, an average of 2.7 per cent, may be a fraction lower than last year’s, but it is still well above the official Consumer Price Index (CPI) measure of inflation.","path":"english1/2021.html"},{"id":"english1-2021-t1-p2-s1","examKey":"english1","examLabel":"英语一","year":"2021","text":1,"paragraph":2,"sentenceNo":1,"sentence":"Successive governments have permitted such increases on the grounds that the cost of investing in and running the rail network should be borne by those who use it, rather than the general taxpayer.","path":"english1/2021.html"},{"id":"english1-2021-t1-p2-s2","examKey":"english1","examLabel":"英语一","year":"2021","text":1,"paragraph":2,"sentenceNo":2,"sentence":"Why, the argument goes, should a car-driving pensioner from Lincolnshire have to subsidise the daily commute of a stockbroker from Surrey?","path":"english1/2021.html"},{"id":"english1-2021-t1-p2-s3","examKey":"english1","examLabel":"英语一","year":"2021","text":1,"paragraph":2,"sentenceNo":3,"sentence":"Equally, there is a sense that the travails of commuters in the South East, many of whom will face among the biggest rises, have received too much attention compared to those who must endure the relatively poor infrastructure of the Midlands and the North.","path":"english1/2021.html"},{"id":"english1-2021-t1-p3-s1","examKey":"english1","examLabel":"英语一","year":"2021","text":1,"paragraph":3,"sentenceNo":1,"sentence":"However, over the past 12 months, those commuters have also experienced some of the worst rail strikes in years.","path":"english1/2021.html"},{"id":"english1-2021-t1-p3-s2","examKey":"english1","examLabel":"英语一","year":"2021","text":1,"paragraph":3,"sentenceNo":2,"sentence":"It is all very well train operators trumpeting the improvements they are making to the network, but passengers should be able to expect a basic level of service for the substantial sums they are now paying to travel.","path":"english1/2021.html"},{"id":"english1-2021-t1-p3-s3","examKey":"english1","examLabel":"英语一","year":"2021","text":1,"paragraph":3,"sentenceNo":3,"sentence":"The responsibility for the latest wave of strikes rests on the unions.","path":"english1/2021.html"},{"id":"english1-2021-t1-p3-s4","examKey":"english1","examLabel":"英语一","year":"2021","text":1,"paragraph":3,"sentenceNo":4,"sentence":"However, there is a strong case that those who have been worst affected by industrial action should receive compensation for the disruption they have suffered.","path":"english1/2021.html"},{"id":"english1-2021-t1-p4-s1","examKey":"english1","examLabel":"英语一","year":"2021","text":1,"paragraph":4,"sentenceNo":1,"sentence":"The Government has pledged to change the law to introduce a minimum service requirement so that, even when strikes occur, services can continue to operate.","path":"english1/2021.html"},{"id":"english1-2021-t1-p4-s2","examKey":"english1","examLabel":"英语一","year":"2021","text":1,"paragraph":4,"sentenceNo":2,"sentence":"This should form part of a wider package of measures to address the long-running problems on Britain’s railways.","path":"english1/2021.html"},{"id":"english1-2021-t1-p4-s3","examKey":"english1","examLabel":"英语一","year":"2021","text":1,"paragraph":4,"sentenceNo":3,"sentence":"Yes, more investment is needed, but passengers will not be willing to pay more indefinitely if they must also endure cramped, unreliable services, interrupted by regular chaos when timetables are changed, or planned maintenance is managed incompetently.","path":"english1/2021.html"},{"id":"english1-2021-t1-p4-s4","examKey":"english1","examLabel":"英语一","year":"2021","text":1,"paragraph":4,"sentenceNo":4,"sentence":"The threat of nationalisation may have been seen off for now, but it will return with a vengeance if the justified anger of passengers is not addressed in short order.","path":"english1/2021.html"},{"id":"english1-2021-t2-p1-s1","examKey":"english1","examLabel":"英语一","year":"2021","text":2,"paragraph":1,"sentenceNo":1,"sentence":"Last year marked the third year in a row that Indonesia ’s bleak rate of deforestation has slowed in pace.","path":"english1/2021.html"},{"id":"english1-2021-t2-p1-s2","examKey":"english1","examLabel":"英语一","year":"2021","text":2,"paragraph":1,"sentenceNo":2,"sentence":"One reason for the turnaround may be the country’s antipoverty program.","path":"english1/2021.html"},{"id":"english1-2021-t2-p2-s1","examKey":"english1","examLabel":"英语一","year":"2021","text":2,"paragraph":2,"sentenceNo":1,"sentence":"In 2007, Indonesia started phasing in a program that gives money to its poorest residents under certain conditions, such as requiring people to keep kids in school or get regular medical care.","path":"english1/2021.html"},{"id":"english1-2021-t2-p2-s2","examKey":"english1","examLabel":"英语一","year":"2021","text":2,"paragraph":2,"sentenceNo":2,"sentence":"Called conditional cash transfers or CCTs, these social assistance programs are designed to reduce inequality and break the cycle of poverty.","path":"english1/2021.html"},{"id":"english1-2021-t2-p2-s3","examKey":"english1","examLabel":"英语一","year":"2021","text":2,"paragraph":2,"sentenceNo":3,"sentence":"They’re already used in dozens of countries worldwide.","path":"english1/2021.html"},{"id":"english1-2021-t2-p2-s4","examKey":"english1","examLabel":"英语一","year":"2021","text":2,"paragraph":2,"sentenceNo":4,"sentence":"In Indonesia, the program has provided enough food and medicine to substantially reduce severe growth problems among children.","path":"english1/2021.html"},{"id":"english1-2021-t2-p3-s1","examKey":"english1","examLabel":"英语一","year":"2021","text":2,"paragraph":3,"sentenceNo":1,"sentence":"But CCT programs don’t generally consider effects on the environment.","path":"english1/2021.html"},{"id":"english1-2021-t2-p3-s2","examKey":"english1","examLabel":"英语一","year":"2021","text":2,"paragraph":3,"sentenceNo":2,"sentence":"In fact, poverty alleviation and environmental protection are often viewed as conflicting goals, says Paul Ferraro, an economist at Johns Hopkins University.","path":"english1/2021.html"},{"id":"english1-2021-t2-p4-s1","examKey":"english1","examLabel":"英语一","year":"2021","text":2,"paragraph":4,"sentenceNo":1,"sentence":"That’s because economic growth can be correlated with environmental degradation, while protecting the environment is sometimes correlated with greater poverty.","path":"english1/2021.html"},{"id":"english1-2021-t2-p4-s2","examKey":"english1","examLabel":"英语一","year":"2021","text":2,"paragraph":4,"sentenceNo":2,"sentence":"However, those correlations don’t prove cause and effect.","path":"english1/2021.html"},{"id":"english1-2021-t2-p4-s3","examKey":"english1","examLabel":"英语一","year":"2021","text":2,"paragraph":4,"sentenceNo":3,"sentence":"The only previous study analyzing causality, based on an area in Mexico that had instituted CCTs, supported the traditional view.","path":"english1/2021.html"},{"id":"english1-2021-t2-p4-s4","examKey":"english1","examLabel":"英语一","year":"2021","text":2,"paragraph":4,"sentenceNo":4,"sentence":"There, as people got more money, some of them may have cleared more land for cattle to raise for meat, Ferraro says.","path":"english1/2021.html"},{"id":"english1-2021-t2-p5-s1","examKey":"english1","examLabel":"英语一","year":"2021","text":2,"paragraph":5,"sentenceNo":1,"sentence":"Such programs do not have to negatively affect the environment, though.","path":"english1/2021.html"},{"id":"english1-2021-t2-p5-s2","examKey":"english1","examLabel":"英语一","year":"2021","text":2,"paragraph":5,"sentenceNo":2,"sentence":"Ferraro wanted to see if Indonesia’s poverty-alleviation program was affecting deforestation.","path":"english1/2021.html"},{"id":"english1-2021-t2-p5-s3","examKey":"english1","examLabel":"英语一","year":"2021","text":2,"paragraph":5,"sentenceNo":3,"sentence":"Indonesia has the third-largest area of tropical forest in the world and one of the highest deforestation rates.","path":"english1/2021.html"},{"id":"english1-2021-t2-p6-s1","examKey":"english1","examLabel":"英语一","year":"2021","text":2,"paragraph":6,"sentenceNo":1,"sentence":"Ferraro analyzed satellite data show ing annual forest loss from 2008 to 2012—including during Indonesia’s phase-in of the antipoverty program—in 7,468 forested villages across 15 provinces.","path":"english1/2021.html"},{"id":"english1-2021-t2-p6-s2","examKey":"english1","examLabel":"英语一","year":"2021","text":2,"paragraph":6,"sentenceNo":2,"sentence":"“We see that the program is associated with a 30 percent reduction in deforestation,” Ferraro says.","path":"english1/2021.html"},{"id":"english1-2021-t2-p7-s1","examKey":"english1","examLabel":"英语一","year":"2021","text":2,"paragraph":7,"sentenceNo":1,"sentence":"That’s likely because the rural poor are using the money as makeshift insurance policies against inclement weather, Ferraro says.","path":"english1/2021.html"},{"id":"english1-2021-t2-p7-s2","examKey":"english1","examLabel":"英语一","year":"2021","text":2,"paragraph":7,"sentenceNo":2,"sentence":"Typically, if rains are delayed, people may clear land to plant more rice to supplement their harvests.","path":"english1/2021.html"},{"id":"english1-2021-t2-p7-s3","examKey":"english1","examLabel":"英语一","year":"2021","text":2,"paragraph":7,"sentenceNo":3,"sentence":"With the CCTs, individuals instead can use the money to supplement their harvests.","path":"english1/2021.html"},{"id":"english1-2021-t2-p8-s1","examKey":"english1","examLabel":"英语一","year":"2021","text":2,"paragraph":8,"sentenceNo":1,"sentence":"Whether this research translates elsewhere is anybody’s guess.","path":"english1/2021.html"},{"id":"english1-2021-t2-p8-s2","examKey":"english1","examLabel":"英语一","year":"2021","text":2,"paragraph":8,"sentenceNo":2,"sentence":"Ferraro suggests results may transfer to other parts of Asia, due to commonalities such as the importance of growing rice and market access.","path":"english1/2021.html"},{"id":"english1-2021-t2-p8-s3","examKey":"english1","examLabel":"英语一","year":"2021","text":2,"paragraph":8,"sentenceNo":3,"sentence":"And regardless of transferability, the study shows that what’s good for people may also be good for the environment.","path":"english1/2021.html"},{"id":"english1-2021-t2-p8-s4","examKey":"english1","examLabel":"英语一","year":"2021","text":2,"paragraph":8,"sentenceNo":4,"sentence":"Even if this program didn’t reduce poverty, Ferraro says, “the value of the avoided deforestation just for carbon dioxide emissions alone is more than the program costs.”","path":"english1/2021.html"},{"id":"english1-2021-t3-p1-s1","examKey":"english1","examLabel":"英语一","year":"2021","text":3,"paragraph":1,"sentenceNo":1,"sentence":"As a historian who’s always searching for the text or the image that makes us re-evaluate the past, I’ve become preoccupied with looking for photographs that show our Victorian ancestors smiling (what better way to shatter the image of 19th-century prudery?).","path":"english1/2021.html"},{"id":"english1-2021-t3-p1-s2","examKey":"english1","examLabel":"英语一","year":"2021","text":3,"paragraph":1,"sentenceNo":2,"sentence":"I’ve found quite a few, and—since I started posting them on Twitter —they have been causing quite a stir.","path":"english1/2021.html"},{"id":"english1-2021-t3-p1-s3","examKey":"english1","examLabel":"英语一","year":"2021","text":3,"paragraph":1,"sentenceNo":3,"sentence":"People have been surprised to see evidence that Victorians had fun and could, and did, laugh.","path":"english1/2021.html"},{"id":"english1-2021-t3-p1-s4","examKey":"english1","examLabel":"英语一","year":"2021","text":3,"paragraph":1,"sentenceNo":4,"sentence":"They are noting that the Victorians suddenly seem to become more human as the hundred-or-so years that separate us fade away through our common experience of laughter.","path":"english1/2021.html"},{"id":"english1-2021-t3-p2-s1","examKey":"english1","examLabel":"英语一","year":"2021","text":3,"paragraph":2,"sentenceNo":1,"sentence":"Of course, I need to concede that my collection of “Smiling Victorians” makes up only a tiny percentage of the vast catalogue of photographic portraiture created between 1840 and 1900, the majority of which show sitters posing miserably and stiffly in front of painted backdrops, or staring absently into the middle distance.","path":"english1/2021.html"},{"id":"english1-2021-t3-p2-s2","examKey":"english1","examLabel":"英语一","year":"2021","text":3,"paragraph":2,"sentenceNo":2,"sentence":"How do we explain this trend?","path":"english1/2021.html"},{"id":"english1-2021-t3-p3-s1","examKey":"english1","examLabel":"英语一","year":"2021","text":3,"paragraph":3,"sentenceNo":1,"sentence":"During the 1840s and 1850s, in the early days of photography, exposure times were notoriously long: the daguerreotype photographic method (producing an image on a silvered copper plate) could take several minutes to complete, resulting in blurred images as sitters shifted position or adjusted their limbs.","path":"english1/2021.html"},{"id":"english1-2021-t3-p3-s2","examKey":"english1","examLabel":"英语一","year":"2021","text":3,"paragraph":3,"sentenceNo":2,"sentence":"The thought of holding a fixed grin as the camera performed its magical duties was too much to contemplate, and so a non-committal blank stare became the norm.","path":"english1/2021.html"},{"id":"english1-2021-t3-p4-s1","examKey":"english1","examLabel":"英语一","year":"2021","text":3,"paragraph":4,"sentenceNo":1,"sentence":"But exposure times were much quicker by the 1880s, and the introduction of the Box Brownie and other portable cameras meant that, though slow by today’s digital standards, the exposure was almost instantaneous.","path":"english1/2021.html"},{"id":"english1-2021-t3-p4-s2","examKey":"english1","examLabel":"英语一","year":"2021","text":3,"paragraph":4,"sentenceNo":2,"sentence":"Spontaneous smiles were relatively easy to capture by the 1890s, so we must look elsewhere for an explanation of why Victorians still hesitated to smile.","path":"english1/2021.html"},{"id":"english1-2021-t3-p5-s1","examKey":"english1","examLabel":"英语一","year":"2021","text":3,"paragraph":5,"sentenceNo":1,"sentence":"One explanation might be the loss of dignity displayed through a cheesy grin.","path":"english1/2021.html"},{"id":"english1-2021-t3-p5-s2","examKey":"english1","examLabel":"英语一","year":"2021","text":3,"paragraph":5,"sentenceNo":2,"sentence":"“Nature gave us lips to conceal our teeth,” ran one popular Victorian say ing, alluding to the fact that before the birth of proper dentistry, mouths were often in a shocking state of hygiene.","path":"english1/2021.html"},{"id":"english1-2021-t3-p5-s3","examKey":"english1","examLabel":"英语一","year":"2021","text":3,"paragraph":5,"sentenceNo":3,"sentence":"A flashing set of healthy and clean, regular “pearly whites” was a rare sight in Victorian society, the preserve of the super-rich (and even then, dental hygiene was not guaranteed).","path":"english1/2021.html"},{"id":"english1-2021-t3-p6-s1","examKey":"english1","examLabel":"英语一","year":"2021","text":3,"paragraph":6,"sentenceNo":1,"sentence":"A toothy grin (especially when there were gaps or blackened teeth) lacked class: drunks, tramps and music hall performers might gurn and grin with a smile as wide as Lewis Carroll’s gum-exposing Cheshire Cat, but it was not a becoming look for properly bred persons.","path":"english1/2021.html"},{"id":"english1-2021-t3-p6-s2","examKey":"english1","examLabel":"英语一","year":"2021","text":3,"paragraph":6,"sentenceNo":2,"sentence":"Even Mark Twain, a man who enjoyed a hearty laugh, said that when it came to photographic portraits there could be “nothing more damning than a silly, foolish smile fixed forever”.","path":"english1/2021.html"},{"id":"english1-2021-t4-p1-s1","examKey":"english1","examLabel":"英语一","year":"2021","text":4,"paragraph":1,"sentenceNo":1,"sentence":"From the early days of broadband, advocates for consumers and web-based companies worried that the cable and phone companies selling broadband connections had the power and incentive to favor affiliated websites over their rivals’.","path":"english1/2021.html"},{"id":"english1-2021-t4-p1-s2","examKey":"english1","examLabel":"英语一","year":"2021","text":4,"paragraph":1,"sentenceNo":2,"sentence":"That’s why there has been such a strong demand for rules that would prevent broadband providers from picking winners and losers online, preserving the freedom and innovation that have been the lifeblood of the Internet.","path":"english1/2021.html"},{"id":"english1-2021-t4-p2-s1","examKey":"english1","examLabel":"英语一","year":"2021","text":4,"paragraph":2,"sentenceNo":1,"sentence":"Yet that demand has been almost impossible to fill—in part because of pushback from broadband providers, anti-regulatory conservatives and the courts.","path":"english1/2021.html"},{"id":"english1-2021-t4-p2-s2","examKey":"english1","examLabel":"英语一","year":"2021","text":4,"paragraph":2,"sentenceNo":2,"sentence":"A federal appeals court weighed in again Tuesday, but instead of providing a badly needed resolution, it only prolonged the fight.","path":"english1/2021.html"},{"id":"english1-2021-t4-p2-s3","examKey":"english1","examLabel":"英语一","year":"2021","text":4,"paragraph":2,"sentenceNo":3,"sentence":"At issue before the US Court of Appeals for the District of Columbia Circuit was the latest take of the Federal Communications Commission ( FCC ) on net neutrality, adopted on a party-line vote in 2017.","path":"english1/2021.html"},{"id":"english1-2021-t4-p2-s4","examKey":"english1","examLabel":"英语一","year":"2021","text":4,"paragraph":2,"sentenceNo":4,"sentence":"The Republican-penned order not only eliminated the strict net neutrality rules the FCC had adopted when it had a Democratic majority in 2015, but rejected the commission’s authority to require broadband providers to do much of anything.","path":"english1/2021.html"},{"id":"english1-2021-t4-p2-s5","examKey":"english1","examLabel":"英语一","year":"2021","text":4,"paragraph":2,"sentenceNo":5,"sentence":"The order also declared that state and local governments couldn’t regulate broadband providers either.","path":"english1/2021.html"},{"id":"english1-2021-t4-p3-s1","examKey":"english1","examLabel":"英语一","year":"2021","text":4,"paragraph":3,"sentenceNo":1,"sentence":"The commission argue d that other agencies would protect against anti-competitive behavior, such as a broadband-providing conglomerate like AT&T favoring its own video-streaming service at the expense of Netflix and Apple TV.","path":"english1/2021.html"},{"id":"english1-2021-t4-p3-s2","examKey":"english1","examLabel":"英语一","year":"2021","text":4,"paragraph":3,"sentenceNo":2,"sentence":"Yet the FCC also ended the investigations of broadband providers that imposed data caps on their rivals’ streaming services but not their own.","path":"english1/2021.html"},{"id":"english1-2021-t4-p4-s1","examKey":"english1","examLabel":"英语一","year":"2021","text":4,"paragraph":4,"sentenceNo":1,"sentence":"On Tuesday, the appeals court unanimously upheld the 2017 order deregulating broadband providers, citing a Supreme Court ruling from 2005 that upheld a similarly deregulatory move.","path":"english1/2021.html"},{"id":"english1-2021-t4-p4-s2","examKey":"english1","examLabel":"英语一","year":"2021","text":4,"paragraph":4,"sentenceNo":2,"sentence":"But Judge Patricia Millett argued in a concurring opinion that “the result is unhinged from the realities of modern broadband service,” and said Congress or the Supreme Court could intervene to “avoid trapping Internet regulation in technological anachronism.”","path":"english1/2021.html"},{"id":"english1-2021-t4-p5-s1","examKey":"english1","examLabel":"英语一","year":"2021","text":4,"paragraph":5,"sentenceNo":1,"sentence":"In the meantime, the court threw out the FCC’s attempt to block all state rules on net neutrality, while preserving the commission’s power to preempt individual state laws that undermine its order.","path":"english1/2021.html"},{"id":"english1-2021-t4-p5-s2","examKey":"english1","examLabel":"英语一","year":"2021","text":4,"paragraph":5,"sentenceNo":2,"sentence":"That means more battles like the one now going on between the Justice Department and California, which enacted a tough net neutrality law in the wake of the FCC’s abdication.","path":"english1/2021.html"},{"id":"english1-2021-t4-p6-s1","examKey":"english1","examLabel":"英语一","year":"2021","text":4,"paragraph":6,"sentenceNo":1,"sentence":"The endless legal battles and back-and-forth at the FCC cry out for Congress to act.","path":"english1/2021.html"},{"id":"english1-2021-t4-p6-s2","examKey":"english1","examLabel":"英语一","year":"2021","text":4,"paragraph":6,"sentenceNo":2,"sentence":"It needs to give the commission explicit authority once and for all to bar broadband providers from meddling in the traffic on their network and to create clear rules protecting openness and innovation online.","path":"english1/2021.html"},{"id":"english2-2021-t1-p1-s1","examKey":"english2","examLabel":"英语二","year":"2021","text":1,"paragraph":1,"sentenceNo":1,"sentence":"Q21 定位 “Reskilling” is something that sounds like a buzzword but is actually a requirement if we plan to have a future in which a lot of would-be workers do not get left behind.","path":"english2/2021.html"},{"id":"english2-2021-t1-p1-s2","examKey":"english2","examLabel":"英语二","year":"2021","text":1,"paragraph":1,"sentenceNo":2,"sentence":"We know we are moving into a period where the jobs in demand will change rapidly, as will the requirements of the jobs that remain.","path":"english2/2021.html"},{"id":"english2-2021-t1-p1-s3","examKey":"english2","examLabel":"英语二","year":"2021","text":1,"paragraph":1,"sentenceNo":3,"sentence":"Research by the World Economic Forum finds that on average 42 per cent of the “ core skills ” within job roles will change by 2022.","path":"english2/2021.html"},{"id":"english2-2021-t1-p1-s4","examKey":"english2","examLabel":"英语二","year":"2021","text":1,"paragraph":1,"sentenceNo":4,"sentence":"That is a very short timeline.","path":"english2/2021.html"},{"id":"english2-2021-t1-p2-s1","examKey":"english2","examLabel":"英语二","year":"2021","text":1,"paragraph":2,"sentenceNo":1,"sentence":"Q22 AT&T Q23 Canada The question of who should pay for reskilling is a thorny one.","path":"english2/2021.html"},{"id":"english2-2021-t1-p2-s2","examKey":"english2","examLabel":"英语二","year":"2021","text":1,"paragraph":2,"sentenceNo":2,"sentence":"For individual companies, the temptation is always to let go of workers whose skills are no longer in demand and replace them with those whose skills are.","path":"english2/2021.html"},{"id":"english2-2021-t1-p2-s3","examKey":"english2","examLabel":"英语二","year":"2021","text":1,"paragraph":2,"sentenceNo":3,"sentence":"That does not always happen.","path":"english2/2021.html"},{"id":"english2-2021-t1-p2-s4","examKey":"english2","examLabel":"英语二","year":"2021","text":1,"paragraph":2,"sentenceNo":4,"sentence":"AT&T is often given as the gold standard of a company that decided to do a massive reskilling program rather than go with a fire-and-hire strategy.","path":"english2/2021.html"},{"id":"english2-2021-t1-p2-s5","examKey":"english2","examLabel":"英语二","year":"2021","text":1,"paragraph":2,"sentenceNo":5,"sentence":"Other companies had also pledged to create their own plans.","path":"english2/2021.html"},{"id":"english2-2021-t1-p2-s6","examKey":"english2","examLabel":"英语二","year":"2021","text":1,"paragraph":2,"sentenceNo":6,"sentence":"When the skills mismatch is in the broader economy, though, the focus usually turns to government to handle.","path":"english2/2021.html"},{"id":"english2-2021-t1-p2-s7","examKey":"english2","examLabel":"英语二","year":"2021","text":1,"paragraph":2,"sentenceNo":7,"sentence":"Efforts in Canada and elsewhere have been arguably languid at best, and have given us a situation where we frequently hear of employers begging for workers, even at times and in regions where unemployment is high.","path":"english2/2021.html"},{"id":"english2-2021-t1-p3-s1","examKey":"english2","examLabel":"英语二","year":"2021","text":1,"paragraph":3,"sentenceNo":1,"sentence":"Q24 段落定位 With the pandemic, unemployment is very high indeed.","path":"english2/2021.html"},{"id":"english2-2021-t1-p3-s2","examKey":"english2","examLabel":"英语二","year":"2021","text":1,"paragraph":3,"sentenceNo":2,"sentence":"In February, at 3.5 per cent and 5.5 per cent respectively, unemployment rates in Canada and the United States were at generational lows and worker shortages were everywhere.","path":"english2/2021.html"},{"id":"english2-2021-t1-p3-s3","examKey":"english2","examLabel":"英语二","year":"2021","text":1,"paragraph":3,"sentenceNo":3,"sentence":"As of May, those rates had spiked up to 13.3 per cent and 13.7 per cent, and although many worker shortages had disappeared, not all had done so.","path":"english2/2021.html"},{"id":"english2-2021-t1-p3-s4","examKey":"english2","examLabel":"英语二","year":"2021","text":1,"paragraph":3,"sentenceNo":4,"sentence":"In the medical field, to take an obvious example, the pandemic meant that there were still clear shortages of doctors, nurses and other medical personnel.","path":"english2/2021.html"},{"id":"english2-2021-t1-p4-s1","examKey":"english2","examLabel":"英语二","year":"2021","text":1,"paragraph":4,"sentenceNo":1,"sentence":"Q25 Sweden 案例 Of course, it is not like you can take an unemployed waiter and train him to be a doctor in a few weeks.","path":"english2/2021.html"},{"id":"english2-2021-t1-p4-s2","examKey":"english2","examLabel":"英语二","year":"2021","text":1,"paragraph":4,"sentenceNo":2,"sentence":"But even if you cannot close that gap, maybe you can close others, and doing so would be to the benefit of all concerned.","path":"english2/2021.html"},{"id":"english2-2021-t1-p4-s3","examKey":"english2","examLabel":"英语二","year":"2021","text":1,"paragraph":4,"sentenceNo":3,"sentence":"That seems to be the case in Sweden: When forced to furlough 90 per cent of their cabin staff, Scandinavian Airlines decided to start up a short retraining program that reskilled the laid-off workers to support hospital staff.","path":"english2/2021.html"},{"id":"english2-2021-t1-p4-s4","examKey":"english2","examLabel":"英语二","year":"2021","text":1,"paragraph":4,"sentenceNo":4,"sentence":"The effort was a collective one and involved other companies as well as a Swedish university.","path":"english2/2021.html"},{"id":"english2-2021-t2-p1-s1","examKey":"english2","examLabel":"英语二","year":"2021","text":2,"paragraph":1,"sentenceNo":1,"sentence":"With the global population predicted to hit close to 10 billion by 2050, and forecasts that agricultural production in some regions will need to nearly double to keep pace, food security is increasingly making headlines.","path":"english2/2021.html"},{"id":"english2-2021-t2-p1-s2","examKey":"english2","examLabel":"英语二","year":"2021","text":2,"paragraph":1,"sentenceNo":2,"sentence":"In the UK, it has become a big talking point recently too, for a rather particular reason: Brexit.","path":"english2/2021.html"},{"id":"english2-2021-t2-p2-s1","examKey":"english2","examLabel":"英语二","year":"2021","text":2,"paragraph":2,"sentenceNo":1,"sentence":"Q26 观点定位 Brexit is seen by some as an opportunity to reverse a recent trend towards the UK importing food.","path":"english2/2021.html"},{"id":"english2-2021-t2-p2-s2","examKey":"english2","examLabel":"英语二","year":"2021","text":2,"paragraph":2,"sentenceNo":2,"sentence":"The country produces only about 60 per cent of the food it eats, down from almost three-quarters in the late 1980s.","path":"english2/2021.html"},{"id":"english2-2021-t2-p2-s3","examKey":"english2","examLabel":"英语二","year":"2021","text":2,"paragraph":2,"sentenceNo":3,"sentence":"A move back to self-sufficiency, the argument goes, would boost the farming industry, political sovereignty and even the nation’s health.","path":"english2/2021.html"},{"id":"english2-2021-t2-p2-s4","examKey":"english2","examLabel":"英语二","year":"2021","text":2,"paragraph":2,"sentenceNo":4,"sentence":"Sounds great—but how feasible is this vision?","path":"english2/2021.html"},{"id":"english2-2021-t2-p3-s1","examKey":"english2","examLabel":"英语二","year":"2021","text":2,"paragraph":3,"sentenceNo":1,"sentence":"Q27 报告定位 According to a report on UK food production from the University of Leeds, UK, 85 per cent of the country’s total land area is associated with meat and dairy production.","path":"english2/2021.html"},{"id":"english2-2021-t2-p3-s2","examKey":"english2","examLabel":"英语二","year":"2021","text":2,"paragraph":3,"sentenceNo":2,"sentence":"That supplies 80 per cent of what is consumed, so even covering the whole country in livestock farms wouldn’t allow us to cover all our meat and dairy needs.","path":"english2/2021.html"},{"id":"english2-2021-t2-p4-s1","examKey":"english2","examLabel":"英语二","year":"2021","text":2,"paragraph":4,"sentenceNo":1,"sentence":"There are many caveats to those figures, but they are still grave.","path":"english2/2021.html"},{"id":"english2-2021-t2-p4-s2","examKey":"english2","examLabel":"英语二","year":"2021","text":2,"paragraph":4,"sentenceNo":2,"sentence":"To become much more self-sufficient, the UK would need to drastically reduce its consumption of animal foods, and probably also farm more intensively—meaning fewer green fields and more factory-style production.","path":"english2/2021.html"},{"id":"english2-2021-t2-p5-s1","examKey":"english2","examLabel":"英语二","year":"2021","text":2,"paragraph":5,"sentenceNo":1,"sentence":"Q28 作物限制 But switching to a mainly plant-based diet wouldn’t help.","path":"english2/2021.html"},{"id":"english2-2021-t2-p5-s2","examKey":"english2","examLabel":"英语二","year":"2021","text":2,"paragraph":5,"sentenceNo":2,"sentence":"There is a good reason why the UK is dominated by animal husbandry: most of its terrain doesn’t have the right soil or climate to grow crops on a commercial basis.","path":"english2/2021.html"},{"id":"english2-2021-t2-p5-s3","examKey":"english2","examLabel":"英语二","year":"2021","text":2,"paragraph":5,"sentenceNo":3,"sentence":"Just 25 per cent of the country’s land is suitable for crop-growing, most of which is already occupied by arable fields.","path":"english2/2021.html"},{"id":"english2-2021-t2-p5-s4","examKey":"english2","examLabel":"英语二","year":"2021","text":2,"paragraph":5,"sentenceNo":4,"sentence":"Even if we converted all the suitable land to fields of fruit and veg—which would involve taking out all the nature reserves and removing thousands of people from their homes—we would achieve only a 30 per cent boost in crop production.","path":"english2/2021.html"},{"id":"english2-2021-t2-p6-s1","examKey":"english2","examLabel":"英语二","year":"2021","text":2,"paragraph":6,"sentenceNo":1,"sentence":"Q29 最后一段 Q30 态度汇总 Just 23 per cent of the fruit and vegetables consumed in the UK are currently home-grown, so even with the most extreme measures we could meet only 30 per cent of our fresh produce needs.","path":"english2/2021.html"},{"id":"english2-2021-t2-p6-s2","examKey":"english2","examLabel":"英语二","year":"2021","text":2,"paragraph":6,"sentenceNo":2,"sentence":"That is before we look for the space to grow the grains, sugars, seeds and oils that provide us with the vast bulk of our current calorie intake.","path":"english2/2021.html"},{"id":"english2-2021-t3-p1-s1","examKey":"english2","examLabel":"英语二","year":"2021","text":3,"paragraph":1,"sentenceNo":1,"sentence":"Q31 并购后 When Microsoft bought task management app Wunderlist and mobile calendar Sunrise in 2015, it picked two newcomers that were attracting considerable buzz in Silicon Valley.","path":"english2/2021.html"},{"id":"english2-2021-t3-p1-s2","examKey":"english2","examLabel":"英语二","year":"2021","text":3,"paragraph":1,"sentenceNo":2,"sentence":"Microsoft’s own Office dominates the market for “productivity” software, but the start-ups represented a new wave of technology designed from the ground up for the smartphone world.","path":"english2/2021.html"},{"id":"english2-2021-t3-p2-s1","examKey":"english2","examLabel":"英语二","year":"2021","text":3,"paragraph":2,"sentenceNo":1,"sentence":"Both apps, however, were later scrapped after Microsoft said it had used their best features in its own products.","path":"english2/2021.html"},{"id":"english2-2021-t3-p2-s2","examKey":"english2","examLabel":"英语二","year":"2021","text":3,"paragraph":2,"sentenceNo":2,"sentence":"Their teams of engineers stayed on, making them two of the many “acqui-hires” that the biggest companies have used to feed their great hunger for tech talent.","path":"english2/2021.html"},{"id":"english2-2021-t3-p3-s1","examKey":"english2","examLabel":"英语二","year":"2021","text":3,"paragraph":3,"sentenceNo":1,"sentence":"Q32 批评者 To Microsoft’s critics, the fates of Wunderlist and Sunrise are examples of a remorseless drive by Big Tech to chew up any innovative companies that lie in their path. “ They bought the seedlings and closed them down,” complained Paul Arnold, a partner at San Francisco-based Switch Ventures, putting an end to businesses that might one day turn into competitors.","path":"english2/2021.html"},{"id":"english2-2021-t3-p3-s2","examKey":"english2","examLabel":"英语二","year":"2021","text":3,"paragraph":3,"sentenceNo":2,"sentence":"Microsoft declined to comment.","path":"english2/2021.html"},{"id":"english2-2021-t3-p4-s1","examKey":"english2","examLabel":"英语二","year":"2021","text":3,"paragraph":4,"sentenceNo":1,"sentence":"Q33 Arnold 担忧 Like other start-up investors, Mr Arnold’s own business often depends on selling start-ups to larger tech companies, though he admits to mixed feelings about the result: “I think these things are good for me, if I put my selfish hat on.","path":"english2/2021.html"},{"id":"english2-2021-t3-p4-s2","examKey":"english2","examLabel":"英语二","year":"2021","text":3,"paragraph":4,"sentenceNo":2,"sentence":"But are they good for the American economy?","path":"english2/2021.html"},{"id":"english2-2021-t3-p4-s3","examKey":"english2","examLabel":"英语二","year":"2021","text":3,"paragraph":4,"sentenceNo":3,"sentence":"I don’t know. ”","path":"english2/2021.html"},{"id":"english2-2021-t3-p5-s1","examKey":"english2","examLabel":"英语二","year":"2021","text":3,"paragraph":5,"sentenceNo":1,"sentence":"Q34 FTC The U.S.","path":"english2/2021.html"},{"id":"english2-2021-t3-p5-s2","examKey":"english2","examLabel":"英语二","year":"2021","text":3,"paragraph":5,"sentenceNo":2,"sentence":"Federal Trade Commission says it wants to find the answer to that question.","path":"english2/2021.html"},{"id":"english2-2021-t3-p5-s3","examKey":"english2","examLabel":"英语二","year":"2021","text":3,"paragraph":5,"sentenceNo":3,"sentence":"This week, it asked the five most valuable U.S. tech companies for information about their many small acquisitions over the past decade.","path":"english2/2021.html"},{"id":"english2-2021-t3-p5-s4","examKey":"english2","examLabel":"英语二","year":"2021","text":3,"paragraph":5,"sentenceNo":4,"sentence":"Although only a research project at this stage, the request has raised the prospect of regulators wading into early-stage tech markets that until now have been beyond their reach.","path":"english2/2021.html"},{"id":"english2-2021-t3-p6-s1","examKey":"english2","examLabel":"英语二","year":"2021","text":3,"paragraph":6,"sentenceNo":1,"sentence":"Q35 金融压力 Given their combined market value of more than $5.5 trillion, rifling through such small deals—many of them much less prominent than Wunderlist and Sunrise—might seem beside the point.","path":"english2/2021.html"},{"id":"english2-2021-t3-p6-s2","examKey":"english2","examLabel":"英语二","year":"2021","text":3,"paragraph":6,"sentenceNo":2,"sentence":"Between them, the five biggest tech companies have spent an average of only $3.4 billion a year on sub-$1 billion acquisitions over the past five years—a drop in the ocean compared with their massive financial reserves, and the more than $130 billion of venture capital that was invested in the U.S. last year.","path":"english2/2021.html"},{"id":"english2-2021-t3-p7-s1","examKey":"english2","examLabel":"英语二","year":"2021","text":3,"paragraph":7,"sentenceNo":1,"sentence":"However, critics say the big companies use such deals to buy their most threatening potential competitors before their businesses have a chance to gain momentum, in some cases as part of a “buy and kill” tactic to simply close them down.","path":"english2/2021.html"},{"id":"english2-2021-t4-p1-s1","examKey":"english2","examLabel":"英语二","year":"2021","text":4,"paragraph":1,"sentenceNo":1,"sentence":"Q36 Ambady 研究 We’re fairly good at judging people based on first impressions, thin slices of experience ranging from a glimpse of a photo to a five-minute interaction, and deliberation can be not only extraneous but intrusive.","path":"english2/2021.html"},{"id":"english2-2021-t4-p1-s2","examKey":"english2","examLabel":"英语二","year":"2021","text":4,"paragraph":1,"sentenceNo":2,"sentence":"In one study of the ability she called “ thin slicing,” the late psychologist Nalini Ambady asked participants to watch silent 10-second video clips of professors and to rate the instructor’s overall effectiveness.","path":"english2/2021.html"},{"id":"english2-2021-t4-p1-s3","examKey":"english2","examLabel":"英语二","year":"2021","text":4,"paragraph":1,"sentenceNo":3,"sentence":"Their ratings correlated strongly with students’ end-of-semester ratings.","path":"english2/2021.html"},{"id":"english2-2021-t4-p1-s4","examKey":"english2","examLabel":"英语二","year":"2021","text":4,"paragraph":1,"sentenceNo":4,"sentence":"Another set of participants had to count backward from 1,000 by nines as they watched the clips, occupying their conscious working memory.","path":"english2/2021.html"},{"id":"english2-2021-t4-p1-s5","examKey":"english2","examLabel":"英语二","year":"2021","text":4,"paragraph":1,"sentenceNo":5,"sentence":"Their ratings were just as accurate, demonstrating the intuitive nature of the social processing.","path":"english2/2021.html"},{"id":"english2-2021-t4-p2-s1","examKey":"english2","examLabel":"英语二","year":"2021","text":4,"paragraph":2,"sentenceNo":1,"sentence":"Q37 准确率下降 Critically, another group was asked to spend a minute writing down reasons for their judgment, before giving the rating.","path":"english2/2021.html"},{"id":"english2-2021-t4-p2-s2","examKey":"english2","examLabel":"英语二","year":"2021","text":4,"paragraph":2,"sentenceNo":2,"sentence":"Accuracy dropped dramatically.","path":"english2/2021.html"},{"id":"english2-2021-t4-p2-s3","examKey":"english2","examLabel":"英语二","year":"2021","text":4,"paragraph":2,"sentenceNo":3,"sentence":"Ambady suspected that deliberation focused them on vivid but misleading cues, such as certain gestures or utterances, rather than letting the complex interplay of subtle signals form a holistic impression.","path":"english2/2021.html"},{"id":"english2-2021-t4-p2-s4","examKey":"english2","examLabel":"英语二","year":"2021","text":4,"paragraph":2,"sentenceNo":4,"sentence":"She found similar interference when participants watched 15-second clips of pairs of people and judged whether they were strangers, friends, or dating partners.","path":"english2/2021.html"},{"id":"english2-2021-t4-p3-s1","examKey":"english2","examLabel":"英语二","year":"2021","text":4,"paragraph":3,"sentenceNo":1,"sentence":"Q38 Hall 类比 Other research shows we’re better at detecting deception from thin slices when we rely on intuition instead of reflection.","path":"english2/2021.html"},{"id":"english2-2021-t4-p3-s2","examKey":"english2","examLabel":"英语二","year":"2021","text":4,"paragraph":3,"sentenceNo":2,"sentence":"“It’s as if you’re driving a stick shift,” says Judith Hall, a psychologist at Northeastern University, “and if you start thinking about it too much, you can’t remember what you’re doing.","path":"english2/2021.html"},{"id":"english2-2021-t4-p3-s3","examKey":"english2","examLabel":"英语二","year":"2021","text":4,"paragraph":3,"sentenceNo":3,"sentence":"But if you go on automatic pilot, you’re fine.","path":"english2/2021.html"},{"id":"english2-2021-t4-p3-s4","examKey":"english2","examLabel":"英语二","year":"2021","text":4,"paragraph":3,"sentenceNo":4,"sentence":"Much of our social life is like that.”","path":"english2/2021.html"},{"id":"english2-2021-t4-p4-s1","examKey":"english2","examLabel":"英语二","year":"2021","text":4,"paragraph":4,"sentenceNo":1,"sentence":"Q39 复杂决策 Thinking too much can also harm our ability to form preferences.","path":"english2/2021.html"},{"id":"english2-2021-t4-p4-s2","examKey":"english2","examLabel":"英语二","year":"2021","text":4,"paragraph":4,"sentenceNo":2,"sentence":"College students’ ratings of strawberry jams and college courses aligned better with experts’ opinions when the students weren’t asked to analyze their rationale.","path":"english2/2021.html"},{"id":"english2-2021-t4-p4-s3","examKey":"english2","examLabel":"英语二","year":"2021","text":4,"paragraph":4,"sentenceNo":3,"sentence":"And people made car-buying decisions that were both objectively better and more personally satisfying when asked to focus on their feelings rather than on details, but only if the decision was complex —when they had a lot of information to process.","path":"english2/2021.html"},{"id":"english2-2021-t4-p5-s1","examKey":"english2","examLabel":"英语二","year":"2021","text":4,"paragraph":5,"sentenceNo":1,"sentence":"Q40 最后一段 Intuition’s special powers are unleashed only in certain circumstances.","path":"english2/2021.html"},{"id":"english2-2021-t4-p5-s2","examKey":"english2","examLabel":"英语二","year":"2021","text":4,"paragraph":5,"sentenceNo":2,"sentence":"In one study, participants completed a battery of eight tasks, including four that tapped reflective thinking (discerning rules, comprehending vocabulary) and four that tapped intuition and creativity (generating new products or figures of speech).","path":"english2/2021.html"},{"id":"english2-2021-t4-p5-s3","examKey":"english2","examLabel":"英语二","year":"2021","text":4,"paragraph":5,"sentenceNo":3,"sentence":"Then they rated the degree to which they had used intuition (“gut feelings,” “hunches,” “my heart”).","path":"english2/2021.html"},{"id":"english2-2021-t4-p5-s4","examKey":"english2","examLabel":"英语二","year":"2021","text":4,"paragraph":5,"sentenceNo":4,"sentence":"Use of their gut hurt their performance on the first four tasks, as expected, and helped them on the rest.","path":"english2/2021.html"},{"id":"english2-2021-t4-p5-s5","examKey":"english2","examLabel":"英语二","year":"2021","text":4,"paragraph":5,"sentenceNo":5,"sentence":"Sometimes the heart is smarter than the head.","path":"english2/2021.html"},{"id":"english1-2022-t1-p1-s1","examKey":"english1","examLabel":"英语一","year":"2022","text":1,"paragraph":1,"sentenceNo":1,"sentence":"People often complain that plastics are too durable.","path":"english1/2022.html"},{"id":"english1-2022-t1-p1-s2","examKey":"english1","examLabel":"英语一","year":"2022","text":1,"paragraph":1,"sentenceNo":2,"sentence":"Water bottles, shopping bags, and other trash litter the planet, from Mount Everest to the Mariana Trench, because plastics are everywhere and don’t break down easily.","path":"english1/2022.html"},{"id":"english1-2022-t1-p1-s3","examKey":"english1","examLabel":"英语一","year":"2022","text":1,"paragraph":1,"sentenceNo":3,"sentence":"But some plastic materials change over time.","path":"english1/2022.html"},{"id":"english1-2022-t1-p1-s4","examKey":"english1","examLabel":"英语一","year":"2022","text":1,"paragraph":1,"sentenceNo":4,"sentence":"They crack and frizzle.","path":"english1/2022.html"},{"id":"english1-2022-t1-p1-s5","examKey":"english1","examLabel":"英语一","year":"2022","text":1,"paragraph":1,"sentenceNo":5,"sentence":"They “weep” out additives.","path":"english1/2022.html"},{"id":"english1-2022-t1-p1-s6","examKey":"english1","examLabel":"英语一","year":"2022","text":1,"paragraph":1,"sentenceNo":6,"sentence":"They melt into sludge.","path":"english1/2022.html"},{"id":"english1-2022-t1-p1-s7","examKey":"english1","examLabel":"英语一","year":"2022","text":1,"paragraph":1,"sentenceNo":7,"sentence":"All of which creates huge headaches for institutions, such as museums, trying to preserve culturally important objects.","path":"english1/2022.html"},{"id":"english1-2022-t1-p1-s8","examKey":"english1","examLabel":"英语一","year":"2022","text":1,"paragraph":1,"sentenceNo":8,"sentence":"The variety of plastic objects at risk is dizzying: early radios, avant-garde sculptures, celluloid animation stills from Disney films, the first artificial heart.","path":"english1/2022.html"},{"id":"english1-2022-t1-p2-s1","examKey":"english1","examLabel":"英语一","year":"2022","text":1,"paragraph":2,"sentenceNo":1,"sentence":"Certain artifacts are especially vulnerable because some pioneers in plastic art didn’t always know how to mix ingredients properly, says Thea van Oosten, a polymer chemist who, until retiring a few years ago, worked for decades at the Cultural Heritage Agency of the Netherlands.","path":"english1/2022.html"},{"id":"english1-2022-t1-p2-s2","examKey":"english1","examLabel":"英语一","year":"2022","text":1,"paragraph":2,"sentenceNo":2,"sentence":"“It’s like baking a cake: If you don’t have exact amounts, it goes wrong,” she says.","path":"english1/2022.html"},{"id":"english1-2022-t1-p2-s3","examKey":"english1","examLabel":"英语一","year":"2022","text":1,"paragraph":2,"sentenceNo":3,"sentence":"“The object you make is already a time bomb.”","path":"english1/2022.html"},{"id":"english1-2022-t1-p3-s1","examKey":"english1","examLabel":"英语一","year":"2022","text":1,"paragraph":3,"sentenceNo":1,"sentence":"And sometimes, it’s not the artist’s fault.","path":"english1/2022.html"},{"id":"english1-2022-t1-p3-s2","examKey":"english1","examLabel":"英语一","year":"2022","text":1,"paragraph":3,"sentenceNo":2,"sentence":"In the 1960s, the Italian artist Piero Gilardi began to create hundreds of bright, colorful foam pieces.","path":"english1/2022.html"},{"id":"english1-2022-t1-p3-s3","examKey":"english1","examLabel":"英语一","year":"2022","text":1,"paragraph":3,"sentenceNo":3,"sentence":"Those pieces included small beds of roses and other items as well as a few dozen “nature carpets” — large rectangles decorated with foam pumpkins, cabbages, and watermelons.","path":"english1/2022.html"},{"id":"english1-2022-t1-p3-s4","examKey":"english1","examLabel":"英语一","year":"2022","text":1,"paragraph":3,"sentenceNo":4,"sentence":"He wanted viewers to walk around on the carpets—which meant they had to be durable.","path":"english1/2022.html"},{"id":"english1-2022-t1-p4-s1","examKey":"english1","examLabel":"英语一","year":"2022","text":1,"paragraph":4,"sentenceNo":1,"sentence":"Unfortunately, the polyurethane foam he used is inherently unstable.","path":"english1/2022.html"},{"id":"english1-2022-t1-p4-s2","examKey":"english1","examLabel":"英语一","year":"2022","text":1,"paragraph":4,"sentenceNo":2,"sentence":"It’s especially vulnerable to light damage, and by the mid-1990s, Gilardi’s pumpkins, roses, and other figures were splitting and crumbling.","path":"english1/2022.html"},{"id":"english1-2022-t1-p4-s3","examKey":"english1","examLabel":"英语一","year":"2022","text":1,"paragraph":4,"sentenceNo":3,"sentence":"Museums locked some of them away in the dark.","path":"english1/2022.html"},{"id":"english1-2022-t1-p5-s1","examKey":"english1","examLabel":"英语一","year":"2022","text":1,"paragraph":5,"sentenceNo":1,"sentence":"So van Oosten and her colleagues worked to preserve Gilardi’s sculptures.","path":"english1/2022.html"},{"id":"english1-2022-t1-p5-s2","examKey":"english1","examLabel":"英语一","year":"2022","text":1,"paragraph":5,"sentenceNo":2,"sentence":"They infused some with stabilizing and consolidating chemicals.","path":"english1/2022.html"},{"id":"english1-2022-t1-p5-s3","examKey":"english1","examLabel":"英语一","year":"2022","text":1,"paragraph":5,"sentenceNo":3,"sentence":"Van Oosten calls those chemicals “sunscreens” because their goal was to prevent further light damage and rebuild worn polymer fibers.","path":"english1/2022.html"},{"id":"english1-2022-t1-p5-s4","examKey":"english1","examLabel":"英语一","year":"2022","text":1,"paragraph":5,"sentenceNo":4,"sentence":"She is proud that several sculptures have even gone on display again, albeit sometimes beneath protective cases.","path":"english1/2022.html"},{"id":"english1-2022-t1-p6-s1","examKey":"english1","examLabel":"英语一","year":"2022","text":1,"paragraph":6,"sentenceNo":1,"sentence":"Despite success stories like van Oosten’s, preservation of plastics will likely get harder.","path":"english1/2022.html"},{"id":"english1-2022-t1-p6-s2","examKey":"english1","examLabel":"英语一","year":"2022","text":1,"paragraph":6,"sentenceNo":2,"sentence":"Old objects continue to deteriorate.","path":"english1/2022.html"},{"id":"english1-2022-t1-p6-s3","examKey":"english1","examLabel":"英语一","year":"2022","text":1,"paragraph":6,"sentenceNo":3,"sentence":"Worse, biodegradable plastics, designed to disintegrate, are increasingly common.","path":"english1/2022.html"},{"id":"english1-2022-t1-p7-s1","examKey":"english1","examLabel":"英语一","year":"2022","text":1,"paragraph":7,"sentenceNo":1,"sentence":"And more is at stake here than individual objects.","path":"english1/2022.html"},{"id":"english1-2022-t1-p7-s2","examKey":"english1","examLabel":"英语一","year":"2022","text":1,"paragraph":7,"sentenceNo":2,"sentence":"Joana Lia Ferreira, an assistant professor of conservation and restoration at the NOVA School of Science and Technology, notes that archaeologists first defined the great material ages of human history —Stone Age, Iron Age, and so on—after examining artifacts in museums.","path":"english1/2022.html"},{"id":"english1-2022-t1-p7-s3","examKey":"english1","examLabel":"英语一","year":"2022","text":1,"paragraph":7,"sentenceNo":3,"sentence":"We now live in an age of plastic, she says, “and what we decide to collect today, what we decide to preserve...will have a strong impact on how in the future we’ll be seen.”","path":"english1/2022.html"},{"id":"english1-2022-t2-p1-s1","examKey":"english1","examLabel":"英语一","year":"2022","text":2,"paragraph":1,"sentenceNo":1,"sentence":"As the latest crop of students pen their undergraduate application form and weigh up their options, it may be worth considering just how the point, purpose and value of a degree has changed and what Generation Z need to consider as they start the third stage of their educational journey.","path":"english1/2022.html"},{"id":"english1-2022-t2-p2-s1","examKey":"english1","examLabel":"英语一","year":"2022","text":2,"paragraph":2,"sentenceNo":1,"sentence":"Millennials were told that if you did well in school, got a decent degree, you would be set up for life.","path":"english1/2022.html"},{"id":"english1-2022-t2-p2-s2","examKey":"english1","examLabel":"英语一","year":"2022","text":2,"paragraph":2,"sentenceNo":2,"sentence":"But that promise has been found wanting.","path":"english1/2022.html"},{"id":"english1-2022-t2-p2-s3","examKey":"english1","examLabel":"英语一","year":"2022","text":2,"paragraph":2,"sentenceNo":3,"sentence":"As degrees became universal, they became devalued.","path":"english1/2022.html"},{"id":"english1-2022-t2-p2-s4","examKey":"english1","examLabel":"英语一","year":"2022","text":2,"paragraph":2,"sentenceNo":4,"sentence":"Education was no longer a secure route of social mobility.","path":"english1/2022.html"},{"id":"english1-2022-t2-p2-s5","examKey":"english1","examLabel":"英语一","year":"2022","text":2,"paragraph":2,"sentenceNo":5,"sentence":"Today, 28 per cent of graduates in the UK are in non-graduate roles, a percentage which is double the average among the OECD countries.","path":"english1/2022.html"},{"id":"english1-2022-t2-p3-s1","examKey":"english1","examLabel":"英语一","year":"2022","text":2,"paragraph":3,"sentenceNo":1,"sentence":"This is not to say that there is no point in getting a degree, but rather stress that a degree is not for everyone, that the switch from classroom to lecture hall is not an inevitable one and that other options are available.","path":"english1/2022.html"},{"id":"english1-2022-t2-p4-s1","examKey":"english1","examLabel":"英语一","year":"2022","text":2,"paragraph":4,"sentenceNo":1,"sentence":"Thankfully, there are signs that this is already happening, with Generation Z seeking to learn from their millennial predecessors, even if parents and teachers tend to be still set in the degree mindset.","path":"english1/2022.html"},{"id":"english1-2022-t2-p4-s2","examKey":"english1","examLabel":"英语一","year":"2022","text":2,"paragraph":4,"sentenceNo":2,"sentence":"Employers have long seen the advantages of hiring school leavers who often prove themselves to be more committed and loyal employees than graduates.","path":"english1/2022.html"},{"id":"english1-2022-t2-p4-s3","examKey":"english1","examLabel":"英语一","year":"2022","text":2,"paragraph":4,"sentenceNo":3,"sentence":"Many too are seeing the advantages of scrapping a degree requirement for certain roles.","path":"english1/2022.html"},{"id":"english1-2022-t2-p5-s1","examKey":"english1","examLabel":"英语一","year":"2022","text":2,"paragraph":5,"sentenceNo":1,"sentence":"For those for whom a degree is the desired route, consider that this may well be the first of many.","path":"english1/2022.html"},{"id":"english1-2022-t2-p5-s2","examKey":"english1","examLabel":"英语一","year":"2022","text":2,"paragraph":5,"sentenceNo":2,"sentence":"In this age of generalists, it pays to have specific knowledge or skills.","path":"english1/2022.html"},{"id":"english1-2022-t2-p5-s3","examKey":"english1","examLabel":"英语一","year":"2022","text":2,"paragraph":5,"sentenceNo":3,"sentence":"Postgraduates now earn 40 per cent more than graduates.","path":"english1/2022.html"},{"id":"english1-2022-t2-p5-s4","examKey":"english1","examLabel":"英语一","year":"2022","text":2,"paragraph":5,"sentenceNo":4,"sentence":"When more and more of us have a degree, it makes sense to have two.","path":"english1/2022.html"},{"id":"english1-2022-t2-p6-s1","examKey":"english1","examLabel":"英语一","year":"2022","text":2,"paragraph":6,"sentenceNo":1,"sentence":"It is unlikely that Generation Z will be done with education at 18 or 21; they will need to be constantly up-skilling throughout their career to stay employable.","path":"english1/2022.html"},{"id":"english1-2022-t2-p6-s2","examKey":"english1","examLabel":"英语一","year":"2022","text":2,"paragraph":6,"sentenceNo":2,"sentence":"It has been estimated that this generation, due to the pressures of technology, the wish for personal fulfillment and desire for diversity, will work for 17 different employers over the course of their working life and have five different careers.","path":"english1/2022.html"},{"id":"english1-2022-t2-p6-s3","examKey":"english1","examLabel":"英语一","year":"2022","text":2,"paragraph":6,"sentenceNo":3,"sentence":"Education, and not just knowledge gained on campus, will be a core part of Generation Z’s career trajectory.","path":"english1/2022.html"},{"id":"english1-2022-t2-p7-s1","examKey":"english1","examLabel":"英语一","year":"2022","text":2,"paragraph":7,"sentenceNo":1,"sentence":"Older generations often talk about their degree in the present and personal tense: ‘I am a geographer’ or ‘I am a classicist’.","path":"english1/2022.html"},{"id":"english1-2022-t2-p7-s2","examKey":"english1","examLabel":"英语一","year":"2022","text":2,"paragraph":7,"sentenceNo":2,"sentence":"Their sons or daughters would never say such a thing; it’s as if they already know that their degree won’t define them in the same way.","path":"english1/2022.html"},{"id":"english1-2022-t3-p1-s1","examKey":"english1","examLabel":"英语一","year":"2022","text":3,"paragraph":1,"sentenceNo":1,"sentence":"Enlightening, challenging, stimulating, fun.","path":"english1/2022.html"},{"id":"english1-2022-t3-p1-s2","examKey":"english1","examLabel":"英语一","year":"2022","text":3,"paragraph":1,"sentenceNo":2,"sentence":"These were some of the words that Nature readers used to describe their experiences of art-science collaborations in a series of articles on partnerships between artists and researchers.","path":"english1/2022.html"},{"id":"english1-2022-t3-p1-s3","examKey":"english1","examLabel":"英语一","year":"2022","text":3,"paragraph":1,"sentenceNo":3,"sentence":"Nearly 40% of the roughly 350 people who responded to an accompanying poll said they had collaborated with artists; and almost all said they would consider doing so in future.","path":"english1/2022.html"},{"id":"english1-2022-t3-p2-s1","examKey":"english1","examLabel":"英语一","year":"2022","text":3,"paragraph":2,"sentenceNo":1,"sentence":"Such an encouraging result is not surprising.","path":"english1/2022.html"},{"id":"english1-2022-t3-p2-s2","examKey":"english1","examLabel":"英语一","year":"2022","text":3,"paragraph":2,"sentenceNo":2,"sentence":"Scientists are increasingly seeking out visual artists to help them communicate their work to new audiences.","path":"english1/2022.html"},{"id":"english1-2022-t3-p2-s3","examKey":"english1","examLabel":"英语一","year":"2022","text":3,"paragraph":2,"sentenceNo":3,"sentence":"“Artists help scientists reach a broader audience and make emotional connections that enhance learning,” one respondent said.","path":"english1/2022.html"},{"id":"english1-2022-t3-p3-s1","examKey":"english1","examLabel":"英语一","year":"2022","text":3,"paragraph":3,"sentenceNo":1,"sentence":"One example of how artists and scientists have together rocked the senses came last month when the Sydney Symphony Orchestra performed a reworked version of Antonio Vivaldi’s The Four Seasons.","path":"english1/2022.html"},{"id":"english1-2022-t3-p3-s2","examKey":"english1","examLabel":"英语一","year":"2022","text":3,"paragraph":3,"sentenceNo":2,"sentence":"They reimagined the 300-year-old score by injecting the latest climate prediction data for each season—provided by Monash University’s Climate Change Communication Research Hub.","path":"english1/2022.html"},{"id":"english1-2022-t3-p3-s3","examKey":"english1","examLabel":"英语一","year":"2022","text":3,"paragraph":3,"sentenceNo":3,"sentence":"The performance was a creative call to action ahead of November’s United Nations Climate Change Conference in Glasgow, UK.","path":"english1/2022.html"},{"id":"english1-2022-t3-p4-s1","examKey":"english1","examLabel":"英语一","year":"2022","text":3,"paragraph":4,"sentenceNo":1,"sentence":"But a genuine partnership must be a two-way street.","path":"english1/2022.html"},{"id":"english1-2022-t3-p4-s2","examKey":"english1","examLabel":"英语一","year":"2022","text":3,"paragraph":4,"sentenceNo":2,"sentence":"Fewer artists than scientists responded to the Nature poll; however, several respondents noted that artists do not simply assist scientists with their communication requirements.","path":"english1/2022.html"},{"id":"english1-2022-t3-p4-s3","examKey":"english1","examLabel":"英语一","year":"2022","text":3,"paragraph":4,"sentenceNo":3,"sentence":"Nor should their work be considered only as an object of study.","path":"english1/2022.html"},{"id":"english1-2022-t3-p4-s4","examKey":"english1","examLabel":"英语一","year":"2022","text":3,"paragraph":4,"sentenceNo":4,"sentence":"The alliances are most valuable when scientists and artists have a shared stake in a project, are able to jointly design it and can critique each other’s work.","path":"english1/2022.html"},{"id":"english1-2022-t3-p4-s5","examKey":"english1","examLabel":"英语一","year":"2022","text":3,"paragraph":4,"sentenceNo":5,"sentence":"Such an approach can both prompt new research as well as result in powerful art.","path":"english1/2022.html"},{"id":"english1-2022-t3-p5-s1","examKey":"english1","examLabel":"英语一","year":"2022","text":3,"paragraph":5,"sentenceNo":1,"sentence":"More than half a century ago, the Massachusetts Institute of Technology opened its Center for Advanced Visual Studies ( CAVS ) to explore the role of technology in culture.","path":"english1/2022.html"},{"id":"english1-2022-t3-p5-s2","examKey":"english1","examLabel":"英语一","year":"2022","text":3,"paragraph":5,"sentenceNo":2,"sentence":"The founders deliberately focused their projects around light—hence the ‘visual studies’ in the name.","path":"english1/2022.html"},{"id":"english1-2022-t3-p5-s3","examKey":"english1","examLabel":"英语一","year":"2022","text":3,"paragraph":5,"sentenceNo":3,"sentence":"Light was something that both artists and scientists had an interest in, and therefore could form the basis of collaboration.","path":"english1/2022.html"},{"id":"english1-2022-t3-p5-s4","examKey":"english1","examLabel":"英语一","year":"2022","text":3,"paragraph":5,"sentenceNo":4,"sentence":"As science and technology progressed, and divided into more sub-disciplines, the centre was simultaneously looking to a time when leading researchers could also be artists, writers and poets, and vice versa.","path":"english1/2022.html"},{"id":"english1-2022-t3-p6-s1","examKey":"english1","examLabel":"英语一","year":"2022","text":3,"paragraph":6,"sentenceNo":1,"sentence":"Nature’s poll findings suggest that this trend is as strong as ever, but, to make a collaboration work, both sides need to invest time, and embrace surprise and challenge.","path":"english1/2022.html"},{"id":"english1-2022-t3-p6-s2","examKey":"english1","examLabel":"英语一","year":"2022","text":3,"paragraph":6,"sentenceNo":2,"sentence":"The reach of art-science tie-ups needs to go beyond the necessary purpose of research communication, and participants must not fall into the trap of stereotyping each other.","path":"english1/2022.html"},{"id":"english1-2022-t3-p6-s3","examKey":"english1","examLabel":"英语一","year":"2022","text":3,"paragraph":6,"sentenceNo":3,"sentence":"Artists and scientists alike are immersed in discovery and invention, and challenge and critique are core to both, too.","path":"english1/2022.html"},{"id":"english1-2022-t4-p1-s1","examKey":"english1","examLabel":"英语一","year":"2022","text":4,"paragraph":1,"sentenceNo":1,"sentence":"The personal grievance provisions of New Zealand’s Employment Relations Act 2000 ( ERA ) prevent an employer from firing an employee without good cause.","path":"english1/2022.html"},{"id":"english1-2022-t4-p1-s2","examKey":"english1","examLabel":"英语一","year":"2022","text":4,"paragraph":1,"sentenceNo":2,"sentence":"Instead, dismissals must be justified.","path":"english1/2022.html"},{"id":"english1-2022-t4-p1-s3","examKey":"english1","examLabel":"英语一","year":"2022","text":4,"paragraph":1,"sentenceNo":3,"sentence":"Employers must both show cause and act in a procedurally fair way.","path":"english1/2022.html"},{"id":"english1-2022-t4-p2-s1","examKey":"english1","examLabel":"英语一","year":"2022","text":4,"paragraph":2,"sentenceNo":1,"sentence":"Personal grievance procedures were designed to guard the jobs of ordinary workers from “unjustified dismissals”.","path":"english1/2022.html"},{"id":"english1-2022-t4-p2-s2","examKey":"english1","examLabel":"英语一","year":"2022","text":4,"paragraph":2,"sentenceNo":2,"sentence":"The premise was that the common law of contract lacked sufficient safeguards for workers against arbitrary conduct by management.","path":"english1/2022.html"},{"id":"english1-2022-t4-p2-s3","examKey":"english1","examLabel":"英语一","year":"2022","text":4,"paragraph":2,"sentenceNo":3,"sentence":"Long gone are the days when a boss could simply give an employee contractual notice.","path":"english1/2022.html"},{"id":"english1-2022-t4-p3-s1","examKey":"english1","examLabel":"英语一","year":"2022","text":4,"paragraph":3,"sentenceNo":1,"sentence":"But these provisions create difficulties for businesses when applied to highly paid managers and executives.","path":"english1/2022.html"},{"id":"english1-2022-t4-p3-s2","examKey":"english1","examLabel":"英语一","year":"2022","text":4,"paragraph":3,"sentenceNo":2,"sentence":"As countless boards and business owners will attest, constraining firms from firing poorly performing, high-earning managers is a handbrake on boosting productivity and overall performance.","path":"english1/2022.html"},{"id":"english1-2022-t4-p3-s3","examKey":"english1","examLabel":"英语一","year":"2022","text":4,"paragraph":3,"sentenceNo":3,"sentence":"The difference between C-grade and A-grade managers may very well be the difference between business success or failure.","path":"english1/2022.html"},{"id":"english1-2022-t4-p3-s4","examKey":"english1","examLabel":"英语一","year":"2022","text":4,"paragraph":3,"sentenceNo":4,"sentence":"Between preserving the jobs of ordinary workers or losing them.","path":"english1/2022.html"},{"id":"english1-2022-t4-p3-s5","examKey":"english1","examLabel":"英语一","year":"2022","text":4,"paragraph":3,"sentenceNo":5,"sentence":"Yet mediocrity is no longer enough to justify a dismissal.","path":"english1/2022.html"},{"id":"english1-2022-t4-p4-s1","examKey":"english1","examLabel":"英语一","year":"2022","text":4,"paragraph":4,"sentenceNo":1,"sentence":"Consequently—and paradoxically—laws introduced to protect the jobs of ordinary workers may be placing those jobs at risk.","path":"english1/2022.html"},{"id":"english1-2022-t4-p5-s1","examKey":"english1","examLabel":"英语一","year":"2022","text":4,"paragraph":5,"sentenceNo":1,"sentence":"If not placing jobs at risk, to the extent employment protection laws constrain business owners from dismissing underperforming managers, those laws act as a constraint on firm productivity and therefore on workers’ wages.","path":"english1/2022.html"},{"id":"english1-2022-t4-p5-s2","examKey":"english1","examLabel":"英语一","year":"2022","text":4,"paragraph":5,"sentenceNo":2,"sentence":"Indeed, in “An International Perspective on New Zealand’s Productivity Paradox” (2014), the Productivity Commission singled out the low quality of managerial capabilities as a cause of the country’s poor productivity growth record.","path":"english1/2022.html"},{"id":"english1-2022-t4-p6-s1","examKey":"english1","examLabel":"英语一","year":"2022","text":4,"paragraph":6,"sentenceNo":1,"sentence":"Nor are highly paid managers themselves immune from the harm caused by the ERA ’s unjustified dismissal procedures.","path":"english1/2022.html"},{"id":"english1-2022-t4-p6-s2","examKey":"english1","examLabel":"英语一","year":"2022","text":4,"paragraph":6,"sentenceNo":2,"sentence":"Because employment protection laws make it costlier to fire an employee, employers are more cautious about hiring new staff.","path":"english1/2022.html"},{"id":"english1-2022-t4-p6-s3","examKey":"english1","examLabel":"英语一","year":"2022","text":4,"paragraph":6,"sentenceNo":3,"sentence":"This makes it harder for the marginal manager to gain employment.","path":"english1/2022.html"},{"id":"english1-2022-t4-p6-s4","examKey":"english1","examLabel":"英语一","year":"2022","text":4,"paragraph":6,"sentenceNo":4,"sentence":"And firms pay staff less because firms carry the burden of the employment arrangement going wrong.","path":"english1/2022.html"},{"id":"english1-2022-t4-p7-s1","examKey":"english1","examLabel":"英语一","year":"2022","text":4,"paragraph":7,"sentenceNo":1,"sentence":"Society also suffers from excessive employment protections.","path":"english1/2022.html"},{"id":"english1-2022-t4-p7-s2","examKey":"english1","examLabel":"英语一","year":"2022","text":4,"paragraph":7,"sentenceNo":2,"sentence":"Stringent job dismissal regulations adversely affect productivity growth and hamper both prosperity and overall well-being.","path":"english1/2022.html"},{"id":"english1-2022-t4-p8-s1","examKey":"english1","examLabel":"英语一","year":"2022","text":4,"paragraph":8,"sentenceNo":1,"sentence":"Across the Tasman Sea, Australia deals with the unjustified dismissal paradox by excluding employees earning above a specified “ high-income threshold ” from the protection of its unfair dismissal laws.","path":"english1/2022.html"},{"id":"english1-2022-t4-p8-s2","examKey":"english1","examLabel":"英语一","year":"2022","text":4,"paragraph":8,"sentenceNo":2,"sentence":"In New Zealand, a 2016 private members’ Bill tried to permit firms and high-income employees to contract out of the unjustified dismissal regime.","path":"english1/2022.html"},{"id":"english1-2022-t4-p8-s3","examKey":"english1","examLabel":"英语一","year":"2022","text":4,"paragraph":8,"sentenceNo":3,"sentence":"However, the mechanisms proposed were unwieldy and the Bill was voted down following the change in government later that year.","path":"english1/2022.html"},{"id":"english2-2022-t1-p1-s1","examKey":"english2","examLabel":"英语二","year":"2022","text":1,"paragraph":1,"sentenceNo":1,"sentence":"1 On a recent sunny day, 13,000 chickens roam over Larry Brown’s 40 windswept acres in Shiner, Texas.","path":"english2/2022.html"},{"id":"english2-2022-t1-p1-s2","examKey":"english2","examLabel":"英语二","year":"2022","text":1,"paragraph":1,"sentenceNo":2,"sentence":"2 Some rest in the shade of a parked car.","path":"english2/2022.html"},{"id":"english2-2022-t1-p1-s3","examKey":"english2","examLabel":"英语二","year":"2022","text":1,"paragraph":1,"sentenceNo":3,"sentence":"3 Others drink water with the cows.","path":"english2/2022.html"},{"id":"english2-2022-t1-p1-s4","examKey":"english2","examLabel":"英语二","year":"2022","text":1,"paragraph":1,"sentenceNo":4,"sentence":"4 This all seems random, but it’s by design, part of what the $6.1 billion U.S. egg industry bets will be its next big thing: climate-friendly eggs.","path":"english2/2022.html"},{"id":"english2-2022-t1-p2-s1","examKey":"english2","examLabel":"英语二","year":"2022","text":1,"paragraph":2,"sentenceNo":1,"sentence":"1 These eggs, which are making their debut now on shelves for as much as $8 a dozen, are still labeled organic and animal-friendly, but they’re also from birds that live on farms using regenerative agriculture—special techniques to cultivate rich soils that trap green-house gases.","path":"english2/2022.html"},{"id":"english2-2022-t1-p2-s2","examKey":"english2","examLabel":"英语二","year":"2022","text":1,"paragraph":2,"sentenceNo":2,"sentence":"2 Such eggs could be marketed as helping to fight climate change.","path":"english2/2022.html"},{"id":"english2-2022-t1-p3-s1","examKey":"english2","examLabel":"英语二","year":"2022","text":1,"paragraph":3,"sentenceNo":1,"sentence":"1 “ I’m excited about our progress,” says Brown, who is adding more cover crops that draw worms and crickets for the chickens to eat.","path":"english2/2022.html"},{"id":"english2-2022-t1-p3-s2","examKey":"english2","examLabel":"英语二","year":"2022","text":1,"paragraph":3,"sentenceNo":2,"sentence":"2 The birds’ waste then fertilizes fields.","path":"english2/2022.html"},{"id":"english2-2022-t1-p3-s3","examKey":"english2","examLabel":"英语二","year":"2022","text":1,"paragraph":3,"sentenceNo":3,"sentence":"Such improvements “allow our hens to forage for higher-quality natural feed that will be good for the land, the hens, and the eggs that we supply to our customers.”","path":"english2/2022.html"},{"id":"english2-2022-t1-p4-s1","examKey":"english2","examLabel":"英语二","year":"2022","text":1,"paragraph":4,"sentenceNo":1,"sentence":"Q23 段落定位 1 The egg industry’s push is the first major test of whether animal products from regenerative farms can become the next premium offering.","path":"english2/2022.html"},{"id":"english2-2022-t1-p4-s2","examKey":"english2","examLabel":"英语二","year":"2022","text":1,"paragraph":4,"sentenceNo":2,"sentence":"2 In barely more than a decade, organic eggs went from being dismissed as a niche product in natural foods stores to being sold at Walmart.","path":"english2/2022.html"},{"id":"english2-2022-t1-p4-s3","examKey":"english2","examLabel":"英语二","year":"2022","text":1,"paragraph":4,"sentenceNo":3,"sentence":"3 More recently there were similar doubts about probiotics and plant-based meats, but both have exploded into major supermarket categories.","path":"english2/2022.html"},{"id":"english2-2022-t1-p4-s4","examKey":"english2","examLabel":"英语二","year":"2022","text":1,"paragraph":4,"sentenceNo":4,"sentence":"4 If the sustainable-egg rollout is successful, it could open the floodgates for regenerative beef, broccoli, and beyond.","path":"english2/2022.html"},{"id":"english2-2022-t1-p5-s1","examKey":"english2","examLabel":"英语二","year":"2022","text":1,"paragraph":5,"sentenceNo":1,"sentence":"1 Regenerative products could be a hard sell, because the concept is tough to define quickly, says Julie Stanton, associate professor of agricultural economics at Pennsylvania State University Brandywine.","path":"english2/2022.html"},{"id":"english2-2022-t1-p5-s2","examKey":"english2","examLabel":"英语二","year":"2022","text":1,"paragraph":5,"sentenceNo":2,"sentence":"2 Such farming also brings minimal, if any, improvement to the food products (though some producers say their eggs have more protein).","path":"english2/2022.html"},{"id":"english2-2022-t1-p6-s1","examKey":"english2","examLabel":"英语二","year":"2022","text":1,"paragraph":6,"sentenceNo":1,"sentence":"Q24 last paragraph 1 The industry is betting that the same consumers paying more for premium attributes such as free-range, non-GMO, and pasture-raised eggs will embrace sustainability.","path":"english2/2022.html"},{"id":"english2-2022-t1-p6-s2","examKey":"english2","examLabel":"英语二","year":"2022","text":1,"paragraph":6,"sentenceNo":2,"sentence":"2 Surveys show that younger generations are more concerned about climate change, and some of the success of plant-based meat can be chalked up to shoppers wanting to signal their desire to protect the environment.","path":"english2/2022.html"},{"id":"english2-2022-t1-p6-s3","examKey":"english2","examLabel":"英语二","year":"2022","text":1,"paragraph":6,"sentenceNo":3,"sentence":"3 Young adults “really care about the planet,” says John Brunnquell, president of Egg Innovations.","path":"english2/2022.html"},{"id":"english2-2022-t1-p6-s4","examKey":"english2","examLabel":"英语二","year":"2022","text":1,"paragraph":6,"sentenceNo":4,"sentence":"“They are absolutely altering the food chain beyond what I think even they understand what they’re doing.”","path":"english2/2022.html"},{"id":"english2-2022-t2-p1-s1","examKey":"english2","examLabel":"英语二","year":"2022","text":2,"paragraph":1,"sentenceNo":1,"sentence":"1 More Americans are opting to work well into retirement, a growing trend that threatens to upend the old workforce model.","path":"english2/2022.html"},{"id":"english2-2022-t2-p2-s1","examKey":"english2","examLabel":"英语二","year":"2022","text":2,"paragraph":2,"sentenceNo":1,"sentence":"1 One in three Americans who are at least 40 have, or plan to have, a job in retirement to prepare for a longer life, according to a survey conducted by Harris Poll for TD Ameritrade.","path":"english2/2022.html"},{"id":"english2-2022-t2-p2-s2","examKey":"english2","examLabel":"英语二","year":"2022","text":2,"paragraph":2,"sentenceNo":2,"sentence":"2 Even more surprising is that more than half of “unretirees”—those who plan to work in retirement or went back to work after retiring—said they would be employed in their later years even if they had enough money to settle down, the survey showed.","path":"english2/2022.html"},{"id":"english2-2022-t2-p3-s1","examKey":"english2","examLabel":"英语二","year":"2022","text":2,"paragraph":3,"sentenceNo":1,"sentence":"Q27 Paragraph 3 1 Financial needs aren’t the only culprit for the “unretirement” trend.","path":"english2/2022.html"},{"id":"english2-2022-t2-p3-s2","examKey":"english2","examLabel":"英语二","year":"2022","text":2,"paragraph":3,"sentenceNo":2,"sentence":"Other reasons, according to the study, include personal fulfillment such as staying mentally fit, preventing boredom or avoiding depression.","path":"english2/2022.html"},{"id":"english2-2022-t2-p4-s1","examKey":"english2","examLabel":"英语二","year":"2022","text":2,"paragraph":4,"sentenceNo":1,"sentence":"1 “The concept of retirement is evolving,” said Christine Russell, senior manager of retirement at TD Ameritrade.","path":"english2/2022.html"},{"id":"english2-2022-t2-p4-s2","examKey":"english2","examLabel":"英语二","year":"2022","text":2,"paragraph":4,"sentenceNo":2,"sentence":"2 “It’s not just about finances.","path":"english2/2022.html"},{"id":"english2-2022-t2-p4-s3","examKey":"english2","examLabel":"英语二","year":"2022","text":2,"paragraph":4,"sentenceNo":3,"sentence":"The value of work is also driving folks to continue working past retirement.”","path":"english2/2022.html"},{"id":"english2-2022-t2-p5-s1","examKey":"english2","examLabel":"英语二","year":"2022","text":2,"paragraph":5,"sentenceNo":1,"sentence":"1 One reason for the change in retirement patterns: Americans are living longer.","path":"english2/2022.html"},{"id":"english2-2022-t2-p5-s2","examKey":"english2","examLabel":"英语二","year":"2022","text":2,"paragraph":5,"sentenceNo":2,"sentence":"2 Older Americans are also the fastest-growing segment of the U.S. workforce.","path":"english2/2022.html"},{"id":"english2-2022-t2-p5-s3","examKey":"english2","examLabel":"英语二","year":"2022","text":2,"paragraph":5,"sentenceNo":3,"sentence":"3 The percentage of retirement-age people in the labor force has doubled over the past three decades.","path":"english2/2022.html"},{"id":"english2-2022-t2-p5-s4","examKey":"english2","examLabel":"英语二","year":"2022","text":2,"paragraph":5,"sentenceNo":4,"sentence":"4 About 20% of people 65 and older were in the workforce in February 2019, up from an all-time low of 10% in January 1985, according to money manager United Income.","path":"english2/2022.html"},{"id":"english2-2022-t2-p6-s1","examKey":"english2","examLabel":"英语二","year":"2022","text":2,"paragraph":6,"sentenceNo":1,"sentence":"1 Because of longer life spans, Americans are also boosting their savings to preserve their nest eggs, the TD Ameritrade study showed, which surveyed 2,000 adults between 40 to 79.","path":"english2/2022.html"},{"id":"english2-2022-t2-p6-s2","examKey":"english2","examLabel":"英语二","year":"2022","text":2,"paragraph":6,"sentenceNo":2,"sentence":"2 Six in 10 “ unretirees ” are increasing their savings in anticipation of a longer life.","path":"english2/2022.html"},{"id":"english2-2022-t2-p6-s3","examKey":"english2","examLabel":"英语二","year":"2022","text":2,"paragraph":6,"sentenceNo":3,"sentence":"Among the most popular ways they are doing this, the company said, is by reducing their overall expenses, securing life insurance or maximizing their contributions to retirement accounts.","path":"english2/2022.html"},{"id":"english2-2022-t2-p7-s1","examKey":"english2","examLabel":"英语二","year":"2022","text":2,"paragraph":7,"sentenceNo":1,"sentence":"1 Unfortunately, many people who are opting to work in retirement are preparing to do so because they are worried about making ends meet in their later years, said Brent Weiss, a co-founder at Baltimore-based financial-planning firm Facet Wealth.","path":"english2/2022.html"},{"id":"english2-2022-t2-p7-s2","examKey":"english2","examLabel":"英语二","year":"2022","text":2,"paragraph":7,"sentenceNo":2,"sentence":"2 He suggested that pretirees should speak with a financial adviser to set long-term financial goals.","path":"english2/2022.html"},{"id":"english2-2022-t2-p8-s1","examKey":"english2","examLabel":"英语二","year":"2022","text":2,"paragraph":8,"sentenceNo":1,"sentence":"1 “The most challenging moments in life are getting married, starting a family and ultimately retiring,” Weiss said.","path":"english2/2022.html"},{"id":"english2-2022-t2-p8-s2","examKey":"english2","examLabel":"英语二","year":"2022","text":2,"paragraph":8,"sentenceNo":2,"sentence":"2 “It’s not just a financial decision, but an emotional one.","path":"english2/2022.html"},{"id":"english2-2022-t2-p8-s3","examKey":"english2","examLabel":"英语二","year":"2022","text":2,"paragraph":8,"sentenceNo":3,"sentence":"Many people believe they can’t retire. ”","path":"english2/2022.html"},{"id":"english2-2022-t3-p1-s1","examKey":"english2","examLabel":"英语二","year":"2022","text":3,"paragraph":1,"sentenceNo":1,"sentence":"Q31 first two paragraphs 1 We have all encountered them, in both our personal and professional lives.","path":"english2/2022.html"},{"id":"english2-2022-t3-p1-s2","examKey":"english2","examLabel":"英语二","year":"2022","text":3,"paragraph":1,"sentenceNo":2,"sentence":"2 Think about the times you felt tricked or frustrated by a membership or subscription that had a seamless sign-up process but was later difficult to cancel.","path":"english2/2022.html"},{"id":"english2-2022-t3-p1-s3","examKey":"english2","examLabel":"英语二","year":"2022","text":3,"paragraph":1,"sentenceNo":3,"sentence":"3 Something that should be simple and transparent can be complicated, intentionally or unintentionally, in ways that impair consumer choice.","path":"english2/2022.html"},{"id":"english2-2022-t3-p1-s4","examKey":"english2","examLabel":"英语二","year":"2022","text":3,"paragraph":1,"sentenceNo":4,"sentence":"4 These are examples of dark patterns.","path":"english2/2022.html"},{"id":"english2-2022-t3-p2-s1","examKey":"english2","examLabel":"英语二","year":"2022","text":3,"paragraph":2,"sentenceNo":1,"sentence":"1 First coined in 2010 by user experience expert Harry Brignull, “dark patterns” is a catch-all term for practices that manipulate user interfaces to influence the decision-making ability of users.","path":"english2/2022.html"},{"id":"english2-2022-t3-p2-s2","examKey":"english2","examLabel":"英语二","year":"2022","text":3,"paragraph":2,"sentenceNo":2,"sentence":"2 Brignull identifies 12 types of common dark patterns, ranging from misdirection and hidden costs to “roach motel,” where a user experience seems easy and intuitive at the start, but turns difficult when the user tries to get out.","path":"english2/2022.html"},{"id":"english2-2022-t3-p3-s1","examKey":"english2","examLabel":"英语二","year":"2022","text":3,"paragraph":3,"sentenceNo":1,"sentence":"1 In a 2019 study of 53,000 product pages and 11,000 websites, researchers found that about one in 10 employs these design practices.","path":"english2/2022.html"},{"id":"english2-2022-t3-p3-s2","examKey":"english2","examLabel":"英语二","year":"2022","text":3,"paragraph":3,"sentenceNo":2,"sentence":"Though widely prevalent, the concept of dark patterns is still not well understood.","path":"english2/2022.html"},{"id":"english2-2022-t3-p3-s3","examKey":"english2","examLabel":"英语二","year":"2022","text":3,"paragraph":3,"sentenceNo":3,"sentence":"2 Business and nonprofit leaders should be aware of dark patterns and try to avoid the gray areas they engender.","path":"english2/2022.html"},{"id":"english2-2022-t3-p4-s1","examKey":"english2","examLabel":"英语二","year":"2022","text":3,"paragraph":4,"sentenceNo":1,"sentence":"1 Where is the line between ethical, persuasive design and dark patterns?","path":"english2/2022.html"},{"id":"english2-2022-t3-p4-s2","examKey":"english2","examLabel":"英语二","year":"2022","text":3,"paragraph":4,"sentenceNo":2,"sentence":"2 Businesses should engage in conversations with IT, compliance, risk, and legal teams to review their privacy policy, and include in the discussion the customer/user experience designers and coders responsible for the company’s user interface, as well as the marketers and advertisers responsible for sign-ups, checkout baskets, pricing, and promotions.","path":"english2/2022.html"},{"id":"english2-2022-t3-p4-s3","examKey":"english2","examLabel":"英语二","year":"2022","text":3,"paragraph":4,"sentenceNo":3,"sentence":"3 Any or all these teams can play a role in creating or avoiding “digital deception.”","path":"english2/2022.html"},{"id":"english2-2022-t3-p5-s1","examKey":"english2","examLabel":"英语二","year":"2022","text":3,"paragraph":5,"sentenceNo":1,"sentence":"1 Lawmakers and regulators are slowly starting to address the ambiguity around dark patterns, most recently at the state level.","path":"english2/2022.html"},{"id":"english2-2022-t3-p5-s2","examKey":"english2","examLabel":"英语二","year":"2022","text":3,"paragraph":5,"sentenceNo":2,"sentence":"2 In March, the California Attorney General announced the approval of additional regulations under the California Consumer Privacy Act (CCPA) that “ensure that consumers will not be confused or misled when seeking to exercise their data privacy rights.” 3 The regulations aim to ban dark patterns—this means prohibiting companies from using confusing language or unnecessary steps such as forcing them to click through multiple screens or listen to reasons why they shouldn’t opt out.","path":"english2/2022.html"},{"id":"english2-2022-t3-p6-s1","examKey":"english2","examLabel":"英语二","year":"2022","text":3,"paragraph":6,"sentenceNo":1,"sentence":"Q35 last paragraph 1 As more states consider promulgating additional regulations, there is a need for greater accountability from within the business community.","path":"english2/2022.html"},{"id":"english2-2022-t3-p6-s2","examKey":"english2","examLabel":"英语二","year":"2022","text":3,"paragraph":6,"sentenceNo":2,"sentence":"2 Dark patterns also can be addressed on a self-regulatory basis, but only if organizations hold themselves accountable, not just to legal requirements but also to industry best practices and standards.","path":"english2/2022.html"},{"id":"english2-2022-t4-p1-s1","examKey":"english2","examLabel":"英语二","year":"2022","text":4,"paragraph":1,"sentenceNo":1,"sentence":"1 Although ethics classes are common around the world, scientists are unsure if their lessons can actually change behavior; evidence either way is weak, relying on contrived laboratory tests or sometimes unreliable self-reports.","path":"english2/2022.html"},{"id":"english2-2022-t4-p1-s2","examKey":"english2","examLabel":"英语二","year":"2022","text":4,"paragraph":1,"sentenceNo":2,"sentence":"2 But a new study published in Cognition found that, in at least one real-world situation, a single ethics lesson may have had lasting effects.","path":"english2/2022.html"},{"id":"english2-2022-t4-p2-s1","examKey":"english2","examLabel":"英语二","year":"2022","text":4,"paragraph":2,"sentenceNo":1,"sentence":"1 The researchers investigated one class session’s impact on eating meat.","path":"english2/2022.html"},{"id":"english2-2022-t4-p2-s2","examKey":"english2","examLabel":"英语二","year":"2022","text":4,"paragraph":2,"sentenceNo":2,"sentence":"2 They chose this particular behavior for three reasons, according to study co-author Eric Schwitzgebel, a philosopher at the University of California, Riverside: students’ attitudes on the topic are variable and unstable, behavior is easily measurable, and ethics literature largely agrees that eating less meat is good because it reduces environmental harm and animal suffering.","path":"english2/2022.html"},{"id":"english2-2022-t4-p2-s3","examKey":"english2","examLabel":"英语二","year":"2022","text":4,"paragraph":2,"sentenceNo":3,"sentence":"3 Half of the students in four large philosophy classes read an article on the ethics of factory-farmed meat, optionally watched an 11-minute video on the topic and joined a 50-minute discussion.","path":"english2/2022.html"},{"id":"english2-2022-t4-p2-s4","examKey":"english2","examLabel":"英语二","year":"2022","text":4,"paragraph":2,"sentenceNo":4,"sentence":"4 The other half focused on charitable giving instead.","path":"english2/2022.html"},{"id":"english2-2022-t4-p2-s5","examKey":"english2","examLabel":"英语二","year":"2022","text":4,"paragraph":2,"sentenceNo":5,"sentence":"5 Then, unknown to the students, the researchers studied their anonymized meal-card purchases for that semester—nearly 14,000 receipts for almost 500 students.","path":"english2/2022.html"},{"id":"english2-2022-t4-p3-s1","examKey":"english2","examLabel":"英语二","year":"2022","text":4,"paragraph":3,"sentenceNo":1,"sentence":"1 Schwitzgebel predicted the intervention would have no effect; he had previously found that ethics professors do not differ from other professors on a range of behaviors, including voting rates, blood donation and returning library books.","path":"english2/2022.html"},{"id":"english2-2022-t4-p3-s2","examKey":"english2","examLabel":"英语二","year":"2022","text":4,"paragraph":3,"sentenceNo":2,"sentence":"2 But among student subjects who discussed meat ethics, meal purchases containing meat decreased from 52 to 45 percent—and this effect held steady for the study’s duration of several weeks.","path":"english2/2022.html"},{"id":"english2-2022-t4-p3-s3","examKey":"english2","examLabel":"英语二","year":"2022","text":4,"paragraph":3,"sentenceNo":3,"sentence":"3 Purchases from the other group remained at 52 percent.","path":"english2/2022.html"},{"id":"english2-2022-t4-p4-s1","examKey":"english2","examLabel":"英语二","year":"2022","text":4,"paragraph":4,"sentenceNo":1,"sentence":"1 “That’s actually a pretty large effect for a pretty small intervention,” Schwitzgebel says.","path":"english2/2022.html"},{"id":"english2-2022-t4-p4-s2","examKey":"english2","examLabel":"英语二","year":"2022","text":4,"paragraph":4,"sentenceNo":2,"sentence":"2 Psychologist Nina Strohminger at the University of Pennsylvania, who was not involved in the study, says she wants the effect to be real but cannot rule out some unknown confounding variable.","path":"english2/2022.html"},{"id":"english2-2022-t4-p4-s3","examKey":"english2","examLabel":"英语二","year":"2022","text":4,"paragraph":4,"sentenceNo":3,"sentence":"And if real, she notes, it might be reversible by another nudge: “Easy come, easy go.”","path":"english2/2022.html"},{"id":"english2-2022-t4-p5-s1","examKey":"english2","examLabel":"英语二","year":"2022","text":4,"paragraph":5,"sentenceNo":1,"sentence":"1 Schwitzgebel suspects the greatest impact came from social influence—classmates or teaching assistants leading the discussions may have shared their own vegetarianism, showing it as achievable or more common.","path":"english2/2022.html"},{"id":"english2-2022-t4-p5-s2","examKey":"english2","examLabel":"英语二","year":"2022","text":4,"paragraph":5,"sentenceNo":2,"sentence":"Second, the video may have had an emotional impact.","path":"english2/2022.html"},{"id":"english2-2022-t4-p5-s3","examKey":"english2","examLabel":"英语二","year":"2022","text":4,"paragraph":5,"sentenceNo":3,"sentence":"Least rousing, he thinks, was rational argument, although his co-authors say reason might play a bigger role.","path":"english2/2022.html"},{"id":"english2-2022-t4-p5-s4","examKey":"english2","examLabel":"英语二","year":"2022","text":4,"paragraph":5,"sentenceNo":4,"sentence":"2 Now the researchers are probing the specific effects of teaching style, teaching assistants’ eating habits and students’ video exposure.","path":"english2/2022.html"},{"id":"english2-2022-t4-p5-s5","examKey":"english2","examLabel":"英语二","year":"2022","text":4,"paragraph":5,"sentenceNo":5,"sentence":"3 Meanwhile, Schwitzgebel—who had predicted no effect—will be eating his words.","path":"english2/2022.html"},{"id":"english1-2023-t1-p1-s1","examKey":"english1","examLabel":"英语一","year":"2023","text":1,"paragraph":1,"sentenceNo":1,"sentence":"The weather in Texas may have cooled since the recent extreme heat, but the temperature will be high at the State Board of Education meeting in Austin this month as officials debate how climate change is taught in Texas schools.","path":"english1/2023.html"},{"id":"english1-2023-t1-p2-s1","examKey":"english1","examLabel":"英语一","year":"2023","text":1,"paragraph":2,"sentenceNo":1,"sentence":"Pat Hardy, who sympathises with the views of the energy sector, is resisting proposed change s to science standards for pre-teen pupils.","path":"english1/2023.html"},{"id":"english1-2023-t1-p2-s2","examKey":"english1","examLabel":"英语一","year":"2023","text":1,"paragraph":2,"sentenceNo":2,"sentence":"“There are as many scientists working against all the panic of global climate change as there are those who are pushing it,” she claims.","path":"english1/2023.html"},{"id":"english1-2023-t1-p2-s3","examKey":"english1","examLabel":"英语一","year":"2023","text":1,"paragraph":2,"sentenceNo":3,"sentence":"“Texas is an energy state and we need to recognise that.","path":"english1/2023.html"},{"id":"english1-2023-t1-p2-s4","examKey":"english1","examLabel":"英语一","year":"2023","text":1,"paragraph":2,"sentenceNo":4,"sentence":"You need to remember where your bread is buttered.”","path":"english1/2023.html"},{"id":"english1-2023-t1-p3-s1","examKey":"english1","examLabel":"英语一","year":"2023","text":1,"paragraph":3,"sentenceNo":1,"sentence":"Most scientists and experts sharply dispute Hardy’s views.","path":"english1/2023.html"},{"id":"english1-2023-t1-p3-s2","examKey":"english1","examLabel":"英语一","year":"2023","text":1,"paragraph":3,"sentenceNo":2,"sentence":"Board members like her “casually dismiss the career work of scholars and scientists as just another misguided opinion,” says Dan Quinn, senior communications strategist at the Texas Freedom Network, a non-profit group that monitors public education.","path":"english1/2023.html"},{"id":"english1-2023-t1-p4-s1","examKey":"english1","examLabel":"英语一","year":"2023","text":1,"paragraph":4,"sentenceNo":1,"sentence":"Such debates reflect fierce discussions across the US, as researchers, policymakers, teachers and students step up demands for a greater focus on teaching about the facts of climate change in schools.","path":"english1/2023.html"},{"id":"english1-2023-t1-p5-s1","examKey":"english1","examLabel":"英语一","year":"2023","text":1,"paragraph":5,"sentenceNo":1,"sentence":"A study last year by the National Center for Science Education, a non-profit group of scientists and teachers, looking at how state public schools across the country address climate change in science classes, gave barely half of US states a grade B+ or higher.","path":"english1/2023.html"},{"id":"english1-2023-t1-p5-s2","examKey":"english1","examLabel":"英语一","year":"2023","text":1,"paragraph":5,"sentenceNo":2,"sentence":"Among the 10 worst performers were some of the most populous states, including Texas, which was given the lowest grade (F) and has a disproportionate influence because its textbooks are widely sold elsewhere.","path":"english1/2023.html"},{"id":"english1-2023-t1-p6-s1","examKey":"english1","examLabel":"英语一","year":"2023","text":1,"paragraph":6,"sentenceNo":1,"sentence":"Glenn Branch, the centre’s deputy director, cautions that setting state-level science standards is only one limited benchmark in a country that decentralises decisions to local school boards.","path":"english1/2023.html"},{"id":"english1-2023-t1-p6-s2","examKey":"english1","examLabel":"英语一","year":"2023","text":1,"paragraph":6,"sentenceNo":2,"sentence":"Even if a state is considered a high performer in its science standards, “that does not mean it will be taught,” he says.","path":"english1/2023.html"},{"id":"english1-2023-t1-p7-s1","examKey":"english1","examLabel":"英语一","year":"2023","text":1,"paragraph":7,"sentenceNo":1,"sentence":"Another issue is that while climate change is well integrated into some subjects and at some ages—such as earth and space sciences in high schools—it is not as well represented in curricula for younger children and in subjects that are more widely taught, such as biology and chemistry.","path":"english1/2023.html"},{"id":"english1-2023-t1-p7-s2","examKey":"english1","examLabel":"英语一","year":"2023","text":1,"paragraph":7,"sentenceNo":2,"sentence":"It is also less prominent in many social studies courses.","path":"english1/2023.html"},{"id":"english1-2023-t1-p8-s1","examKey":"english1","examLabel":"英语一","year":"2023","text":1,"paragraph":8,"sentenceNo":1,"sentence":"Branch points out that, even if a growing number of official guidelines and textbooks reflect scientific consensus on climate change, unofficial educational materials that convey more slanted perspectives are being distributed to teachers.","path":"english1/2023.html"},{"id":"english1-2023-t1-p8-s2","examKey":"english1","examLabel":"英语一","year":"2023","text":1,"paragraph":8,"sentenceNo":2,"sentence":"They include materials sponsored by energy industry associations.","path":"english1/2023.html"},{"id":"english1-2023-t2-p1-s1","examKey":"english1","examLabel":"英语一","year":"2023","text":2,"paragraph":1,"sentenceNo":1,"sentence":"Communities throughout New England have been attempting to regulate short-term rentals since sites like Airbnb took off in the 2010s.","path":"english1/2023.html"},{"id":"english1-2023-t2-p1-s2","examKey":"english1","examLabel":"英语一","year":"2023","text":2,"paragraph":1,"sentenceNo":2,"sentence":"Now, with record-high home prices and historically low inventory, there’s an increased urgency in such regulation, particularly among those who worry that developers will come in and buy up swaths of housing to flip for a fortune on the short-term rental market.","path":"english1/2023.html"},{"id":"english1-2023-t2-p2-s1","examKey":"english1","examLabel":"英语一","year":"2023","text":2,"paragraph":2,"sentenceNo":1,"sentence":"In New Hampshire, where the rental vacancy rate has dropped below 1 percent, housing advocates fear unchecked short-term rentals will put further pressure on an already strained market.","path":"english1/2023.html"},{"id":"english1-2023-t2-p2-s2","examKey":"english1","examLabel":"英语一","year":"2023","text":2,"paragraph":2,"sentenceNo":2,"sentence":"The state Legislature recently voted against a bill that would’ve made it illegal for towns to create legislation restricting short-term rentals.","path":"english1/2023.html"},{"id":"english1-2023-t2-p3-s1","examKey":"english1","examLabel":"英语一","year":"2023","text":2,"paragraph":3,"sentenceNo":1,"sentence":"“We are at a crisis level on the supply of rental housing,” said Nick Taylor, executive director of the Workforce Housing Coalition of the Greater Seacoast.","path":"english1/2023.html"},{"id":"english1-2023-t2-p3-s2","examKey":"english1","examLabel":"英语一","year":"2023","text":2,"paragraph":3,"sentenceNo":2,"sentence":"Without enough affordable housing in southern New Hampshire towns, “employers are having a hard time attracting employees, and workers are having a hard time finding a place to live,” Taylor said.","path":"english1/2023.html"},{"id":"english1-2023-t2-p4-s1","examKey":"english1","examLabel":"英语一","year":"2023","text":2,"paragraph":4,"sentenceNo":1,"sentence":"However, short-term rentals also provide housing for tourists, pointed out Ryan Castle, CEO of a local association of realtors.","path":"english1/2023.html"},{"id":"english1-2023-t2-p4-s2","examKey":"english1","examLabel":"英语一","year":"2023","text":2,"paragraph":4,"sentenceNo":2,"sentence":"“A lot of workers are servicing the tourist industry, and the tourism industry is serviced by those people coming in short term,” Castle said, “and so it’s a cyclical effect.”","path":"english1/2023.html"},{"id":"english1-2023-t2-p5-s1","examKey":"english1","examLabel":"英语一","year":"2023","text":2,"paragraph":5,"sentenceNo":1,"sentence":"Short-term rentals themselves are not the crux of the issue, said Keren Horn, an expert on affordable housing policy.","path":"english1/2023.html"},{"id":"english1-2023-t2-p5-s2","examKey":"english1","examLabel":"英语一","year":"2023","text":2,"paragraph":5,"sentenceNo":2,"sentence":"“I think individuals being able to rent out their second home is a good thing.","path":"english1/2023.html"},{"id":"english1-2023-t2-p5-s3","examKey":"english1","examLabel":"英语一","year":"2023","text":2,"paragraph":5,"sentenceNo":3,"sentence":"If it’s their vacation home anyway, and it’s just empty, why can’t you make money off it?” Horn said.","path":"english1/2023.html"},{"id":"english1-2023-t2-p5-s4","examKey":"english1","examLabel":"英语一","year":"2023","text":2,"paragraph":5,"sentenceNo":4,"sentence":"Issues arise, however, when developers attempt to create large-scale short-term rental facilities—de facto hotels—to bypass taxes and regulations.","path":"english1/2023.html"},{"id":"english1-2023-t2-p5-s5","examKey":"english1","examLabel":"英语一","year":"2023","text":2,"paragraph":5,"sentenceNo":5,"sentence":"“I think the question is, shouldn’t a developer who’s really building a hotel, but disguising it as not a hotel, be treated and taxed and regulated like a hotel?” Horn said.","path":"english1/2023.html"},{"id":"english1-2023-t2-p6-s1","examKey":"english1","examLabel":"英语一","year":"2023","text":2,"paragraph":6,"sentenceNo":1,"sentence":"At the end of 2018, Governor Charlie Baker of Massachusetts signed a bill to rein in those potential investor-buyers.","path":"english1/2023.html"},{"id":"english1-2023-t2-p6-s2","examKey":"english1","examLabel":"英语一","year":"2023","text":2,"paragraph":6,"sentenceNo":2,"sentence":"The bill requires every rental host to register with the state, mandates they carry insurance, and opens the potential for local taxes on top of a new state levy.","path":"english1/2023.html"},{"id":"english1-2023-t2-p6-s3","examKey":"english1","examLabel":"英语一","year":"2023","text":2,"paragraph":6,"sentenceNo":3,"sentence":"Boston took things even further, requiring renters to register with the city’s Inspectional Services Department.","path":"english1/2023.html"},{"id":"english1-2023-t2-p7-s1","examKey":"english1","examLabel":"英语一","year":"2023","text":2,"paragraph":7,"sentenceNo":1,"sentence":"Horn said similar registration requirements could benefit struggling cities and towns, but “if we want to make a change in the housing market, the main one is we have to build a lot more.”","path":"english1/2023.html"},{"id":"english1-2023-t3-p1-s1","examKey":"english1","examLabel":"英语一","year":"2023","text":3,"paragraph":1,"sentenceNo":1,"sentence":"If you’re heading for your nearest branch of Waterstones, the biggest book retailer in the UK, in search of the Duchess of Sussex’s new children’s book The Bench, you might have to be prepared to hunt around a bit; the same may be true of The President’s Daughter, the new thriller by Bill Clinton and James Patterson.","path":"english1/2023.html"},{"id":"english1-2023-t3-p1-s2","examKey":"english1","examLabel":"英语一","year":"2023","text":3,"paragraph":1,"sentenceNo":2,"sentence":"Both of these books are published by Penguin Random House (PRH), a company currently involved in a stand-off with Waterstones.","path":"english1/2023.html"},{"id":"english1-2023-t3-p2-s1","examKey":"english1","examLabel":"英语一","year":"2023","text":3,"paragraph":2,"sentenceNo":1,"sentence":"The problem began late last year, when PRH confirmed that it had introduced a credit limit with Waterstones “at a very significant level”.","path":"english1/2023.html"},{"id":"english1-2023-t3-p2-s2","examKey":"english1","examLabel":"英语一","year":"2023","text":3,"paragraph":2,"sentenceNo":2,"sentence":"The trade magazine The Bookseller reported that Waterstones branch managers were being told to remove PRH books from prominent areas such as tables, display spaces and windows, and were “quietly retiring them to their relevant sections”.","path":"english1/2023.html"},{"id":"english1-2023-t3-p3-s1","examKey":"english1","examLabel":"英语一","year":"2023","text":3,"paragraph":3,"sentenceNo":1,"sentence":"PRH declined to comment on the issue, but a spokesperson for Waterstones told me: “Waterstones are currently operating with reduced credit terms from PRH, the only publisher in the UK to place any limitations on our ability to trade.","path":"english1/2023.html"},{"id":"english1-2023-t3-p3-s2","examKey":"english1","examLabel":"英语一","year":"2023","text":3,"paragraph":3,"sentenceNo":2,"sentence":"We are not boycotting PRH titles but we are doing our utmost to ensure that availability for customers remains good despite the lower overall levels of stock.","path":"english1/2023.html"},{"id":"english1-2023-t3-p3-s3","examKey":"english1","examLabel":"英语一","year":"2023","text":3,"paragraph":3,"sentenceNo":3,"sentence":"We are hopeful with our shops now open again that normality will return and that we will be allowed to buy appropriately.","path":"english1/2023.html"},{"id":"english1-2023-t3-p3-s4","examKey":"english1","examLabel":"英语一","year":"2023","text":3,"paragraph":3,"sentenceNo":4,"sentence":"Certainly, our shops are exceptionally busy.","path":"english1/2023.html"},{"id":"english1-2023-t3-p3-s5","examKey":"english1","examLabel":"英语一","year":"2023","text":3,"paragraph":3,"sentenceNo":5,"sentence":"The sales for our May Books of the Month surpassed any month since 2018.”","path":"english1/2023.html"},{"id":"english1-2023-t3-p4-s1","examKey":"english1","examLabel":"英语一","year":"2023","text":3,"paragraph":4,"sentenceNo":1,"sentence":"In the meantime, PRH authors have been the losers.","path":"english1/2023.html"},{"id":"english1-2023-t3-p4-s2","examKey":"english1","examLabel":"英语一","year":"2023","text":3,"paragraph":4,"sentenceNo":2,"sentence":"Big-name PRH authors may suffer a bit, but it’s those mid-list authors, who normally rely on Waterstones staff’s passion for promoting books by lesser-known writers, who will be praying for an end to the dispute.","path":"english1/2023.html"},{"id":"english1-2023-t3-p5-s1","examKey":"english1","examLabel":"英语一","year":"2023","text":3,"paragraph":5,"sentenceNo":1,"sentence":"It comes at a time when authors are already worried about the consequences of the proposed merger between PRH and another big publisher, Simon & Schuster —the reduction in the number of unaligned UK publishers is likely to lead to fewer bidding wars, lower advances, and more conformity in terms of what is published.","path":"english1/2023.html"},{"id":"english1-2023-t3-p6-s1","examKey":"english1","examLabel":"英语一","year":"2023","text":3,"paragraph":6,"sentenceNo":1,"sentence":"“This is all part of a wider change towards concentration of power,” says literary agent Andrew Lownie.","path":"english1/2023.html"},{"id":"english1-2023-t3-p6-s2","examKey":"english1","examLabel":"英语一","year":"2023","text":3,"paragraph":6,"sentenceNo":2,"sentence":"“The publishing industry talks about diversity in terms of authors and staff but it also needs a plurality of ways of delivering intellectual contact, choice and different voices.","path":"english1/2023.html"},{"id":"english1-2023-t3-p6-s3","examKey":"english1","examLabel":"英语一","year":"2023","text":3,"paragraph":6,"sentenceNo":3,"sentence":"After all, many of the most interesting books in recent years have come from small publishers.”","path":"english1/2023.html"},{"id":"english1-2023-t3-p7-s1","examKey":"english1","examLabel":"英语一","year":"2023","text":3,"paragraph":7,"sentenceNo":1,"sentence":"We shall see whether that plurality is a casualty of the current need among publishers to be big enough to take on all-comers.","path":"english1/2023.html"},{"id":"english1-2023-t4-p1-s1","examKey":"english1","examLabel":"英语一","year":"2023","text":4,"paragraph":1,"sentenceNo":1,"sentence":"Scientific papers are the recordkeepers of progress in research.","path":"english1/2023.html"},{"id":"english1-2023-t4-p1-s2","examKey":"english1","examLabel":"英语一","year":"2023","text":4,"paragraph":1,"sentenceNo":2,"sentence":"Each year researchers publish millions of papers in more than 30,000 journals.","path":"english1/2023.html"},{"id":"english1-2023-t4-p1-s3","examKey":"english1","examLabel":"英语一","year":"2023","text":4,"paragraph":1,"sentenceNo":3,"sentence":"The scientific community measures the quality of those papers in a number of ways, including the perceived quality of the journal (as reflected by the title’s impact factor) and the number of citations a specific paper accumulates.","path":"english1/2023.html"},{"id":"english1-2023-t4-p1-s4","examKey":"english1","examLabel":"英语一","year":"2023","text":4,"paragraph":1,"sentenceNo":4,"sentence":"The careers of scientists and the reputation of their institutions depend on the number and prestige of the papers they produce, but even more so on the citations attracted by these papers.","path":"english1/2023.html"},{"id":"english1-2023-t4-p2-s1","examKey":"english1","examLabel":"英语一","year":"2023","text":4,"paragraph":2,"sentenceNo":1,"sentence":"Citation cartels, where journals, authors, and institutions conspire to inflate citation numbers, have existed for a long time.","path":"english1/2023.html"},{"id":"english1-2023-t4-p2-s2","examKey":"english1","examLabel":"英语一","year":"2023","text":4,"paragraph":2,"sentenceNo":2,"sentence":"In 2016, researchers developed an algorithm to recognize suspicious citation patterns, including groups of authors that disproportionately cite one another and groups of journals that cite each other frequently to increase the impact factors of their publications.","path":"english1/2023.html"},{"id":"english1-2023-t4-p2-s3","examKey":"english1","examLabel":"英语一","year":"2023","text":4,"paragraph":2,"sentenceNo":3,"sentence":"Recently, another expression of this predatory behavior has emerged: so-called support service consultancies that provide language and other editorial support to individual authors and to journals sometimes advise contributors to add a number of citations to their articles.","path":"english1/2023.html"},{"id":"english1-2023-t4-p3-s1","examKey":"english1","examLabel":"英语一","year":"2023","text":4,"paragraph":3,"sentenceNo":1,"sentence":"The advent of electronic publishing and authors’ need to find outlets for their papers resulted in thousands of new journals.","path":"english1/2023.html"},{"id":"english1-2023-t4-p3-s2","examKey":"english1","examLabel":"英语一","year":"2023","text":4,"paragraph":3,"sentenceNo":2,"sentence":"The birth of predatory journals wasn’t far behind.","path":"english1/2023.html"},{"id":"english1-2023-t4-p3-s3","examKey":"english1","examLabel":"英语一","year":"2023","text":4,"paragraph":3,"sentenceNo":3,"sentence":"These journals can act as milk cows where every single article in an issue may cite a specific paper or a series of papers.","path":"english1/2023.html"},{"id":"english1-2023-t4-p3-s4","examKey":"english1","examLabel":"英语一","year":"2023","text":4,"paragraph":3,"sentenceNo":4,"sentence":"In some instances, there is absolutely no relationship between the content of the article and the citations.","path":"english1/2023.html"},{"id":"english1-2023-t4-p3-s5","examKey":"english1","examLabel":"英语一","year":"2023","text":4,"paragraph":3,"sentenceNo":5,"sentence":"The peculiar part is that the journal that the editor is supposedly working for is not profiting at all—it is just providing citations to other journals.","path":"english1/2023.html"},{"id":"english1-2023-t4-p3-s6","examKey":"english1","examLabel":"英语一","year":"2023","text":4,"paragraph":3,"sentenceNo":6,"sentence":"Such practices can lead an article to accrue more than 150 citations in the same year that it was published.","path":"english1/2023.html"},{"id":"english1-2023-t4-p4-s1","examKey":"english1","examLabel":"英语一","year":"2023","text":4,"paragraph":4,"sentenceNo":1,"sentence":"How insidious is this type of citation manipulation?","path":"english1/2023.html"},{"id":"english1-2023-t4-p4-s2","examKey":"english1","examLabel":"英语一","year":"2023","text":4,"paragraph":4,"sentenceNo":2,"sentence":"In one example, an individual—acting as author, editor, and consultant—was able to use at least 15 journals as citation providers to articles published by five scientists at three universities.","path":"english1/2023.html"},{"id":"english1-2023-t4-p4-s3","examKey":"english1","examLabel":"英语一","year":"2023","text":4,"paragraph":4,"sentenceNo":3,"sentence":"The problem is rampant in Scopus, a citation database, which includes a high number of the new “international” journals.","path":"english1/2023.html"},{"id":"english1-2023-t4-p4-s4","examKey":"english1","examLabel":"英语一","year":"2023","text":4,"paragraph":4,"sentenceNo":4,"sentence":"In fact, a listing in Scopus seems to be a criterion to be targeted in this type of citation manipulation.","path":"english1/2023.html"},{"id":"english1-2023-t4-p5-s1","examKey":"english1","examLabel":"英语一","year":"2023","text":4,"paragraph":5,"sentenceNo":1,"sentence":"Scopus itself has all the data necessary to detect this malpractice.","path":"english1/2023.html"},{"id":"english1-2023-t4-p5-s2","examKey":"english1","examLabel":"英语一","year":"2023","text":4,"paragraph":5,"sentenceNo":2,"sentence":"Red flags include a large number of citations to an article within the first year.","path":"english1/2023.html"},{"id":"english1-2023-t4-p5-s3","examKey":"english1","examLabel":"英语一","year":"2023","text":4,"paragraph":5,"sentenceNo":3,"sentence":"And for authors who wish to steer clear of citation cartel activities: when an editor, a reviewer, or a support service asks you to add inappropriate references, do not oblige and do report the request to the journal.","path":"english1/2023.html"},{"id":"english2-2023-t1-p1-s1","examKey":"english2","examLabel":"英语二","year":"2023","text":1,"paragraph":1,"sentenceNo":1,"sentence":"Q21 定位 Q25 全文起点 In the quest for the perfect lawn, homeowners across the country are taking a shortcut—and it is the environment that is paying the price.","path":"english2/2023.html"},{"id":"english2-2023-t1-p1-s2","examKey":"english2","examLabel":"英语二","year":"2023","text":1,"paragraph":1,"sentenceNo":2,"sentence":"About eight million square metres of plastic grass is sold each year but opposition has now spread to the highest gardening circles.","path":"english2/2023.html"},{"id":"english2-2023-t1-p1-s3","examKey":"english2","examLabel":"英语二","year":"2023","text":1,"paragraph":1,"sentenceNo":3,"sentence":"The Chelsea Flower Show has banned fake grass from this year’s event, declaring it to be not part of its ethos.","path":"english2/2023.html"},{"id":"english2-2023-t1-p1-s4","examKey":"english2","examLabel":"英语二","year":"2023","text":1,"paragraph":1,"sentenceNo":4,"sentence":"The Royal Horticultural Society (RHS), which runs the annual show in west London, says it has introduced the ban because of the damage plastic grass does to the environment and biodiversity.","path":"english2/2023.html"},{"id":"english2-2023-t1-p2-s1","examKey":"english2","examLabel":"英语二","year":"2023","text":1,"paragraph":2,"sentenceNo":1,"sentence":"Ed Horne, of the RHS, said: “We launched our sustainability strategy last year and fake grass is just not in line with our ethos and views on plastic.","path":"english2/2023.html"},{"id":"english2-2023-t1-p2-s2","examKey":"english2","examLabel":"英语二","year":"2023","text":1,"paragraph":2,"sentenceNo":2,"sentence":"We recommend using real grass because of its environmental benefits, which include supporting wildlife, alleviating flooding and cooling the environment.”","path":"english2/2023.html"},{"id":"english2-2023-t1-p3-s1","examKey":"english2","examLabel":"英语二","year":"2023","text":1,"paragraph":3,"sentenceNo":1,"sentence":"Q22 段落定位 The RHS’s decision comes as campaigners try to raise awareness of the problems fake grass causes.","path":"english2/2023.html"},{"id":"english2-2023-t1-p3-s2","examKey":"english2","examLabel":"英语二","year":"2023","text":1,"paragraph":3,"sentenceNo":2,"sentence":"A Twitter account, which claims to “cut through the greenwash” of artificial grass, already has more than 20,000 followers.","path":"english2/2023.html"},{"id":"english2-2023-t1-p3-s3","examKey":"english2","examLabel":"英语二","year":"2023","text":1,"paragraph":3,"sentenceNo":3,"sentence":"It is trying to encourage people to sign two petitions, one calling for a ban on the sale of plastic grass and another calling for an “ecological damage” tax on such lawns.","path":"english2/2023.html"},{"id":"english2-2023-t1-p3-s4","examKey":"english2","examLabel":"英语二","year":"2023","text":1,"paragraph":3,"sentenceNo":4,"sentence":"They have gathered 7,276 and 11,282 signatures.","path":"english2/2023.html"},{"id":"english2-2023-t1-p4-s1","examKey":"english2","examLabel":"英语二","year":"2023","text":1,"paragraph":4,"sentenceNo":1,"sentence":"Q23 段落定位 However, supporters of fake grass point out that there is also an environmental impact with natural lawns, which need mowing and therefore usually consume electricity or petrol.","path":"english2/2023.html"},{"id":"english2-2023-t1-p4-s2","examKey":"english2","examLabel":"英语二","year":"2023","text":1,"paragraph":4,"sentenceNo":2,"sentence":"The industry also points out that real grass requires considerable amounts of water, weed killer or other treatments and that people who lay fake grass tend to use their garden more.","path":"english2/2023.html"},{"id":"english2-2023-t1-p4-s3","examKey":"english2","examLabel":"英语二","year":"2023","text":1,"paragraph":4,"sentenceNo":3,"sentence":"The industry also claims that people who lay fake grass spend an average of £500 on trees or shrubs for their garden, which provides habitat for insects.","path":"english2/2023.html"},{"id":"english2-2023-t1-p5-s1","examKey":"english2","examLabel":"英语二","year":"2023","text":1,"paragraph":5,"sentenceNo":1,"sentence":"Q24 政府回应 In response to another petition last year about banning fake lawns, which gathered 30,000 signatures, the government responded that it has “no plans to ban the use of artificial grass ”.","path":"english2/2023.html"},{"id":"english2-2023-t1-p6-s1","examKey":"english2","examLabel":"英语二","year":"2023","text":1,"paragraph":6,"sentenceNo":1,"sentence":"It added: “ We prefer to help people and organisations make the right choice rather than legislating on such matters.","path":"english2/2023.html"},{"id":"english2-2023-t1-p6-s2","examKey":"english2","examLabel":"英语二","year":"2023","text":1,"paragraph":6,"sentenceNo":2,"sentence":"However, the use of artificial grass must comply with the legal and policy safeguards in place to protect biodiversity and ensure sustainable drainage, while measures such as the strengthened biodiversity duty should serve to encourage public authorities to consider sustainable alternatives.”","path":"english2/2023.html"},{"id":"english2-2023-t2-p1-s1","examKey":"english2","examLabel":"英语二","year":"2023","text":2,"paragraph":1,"sentenceNo":1,"sentence":"It’s easy to dismiss as absurd the federal government’s ideas for plugging the chronic funding gap of our national parks.","path":"english2/2023.html"},{"id":"english2-2023-t2-p1-s2","examKey":"english2","examLabel":"英语二","year":"2023","text":2,"paragraph":1,"sentenceNo":2,"sentence":"Can anyone really think it’s a good idea to allow Amazon deliveries to your tent in Yosemite or food trucks to line up under the redwood trees at Sequoia National Park?","path":"english2/2023.html"},{"id":"english2-2023-t2-p2-s1","examKey":"english2","examLabel":"英语二","year":"2023","text":2,"paragraph":2,"sentenceNo":1,"sentence":"Q26 定位 But the government is right about one thing: U.S. national parks are in crisis.","path":"english2/2023.html"},{"id":"english2-2023-t2-p2-s2","examKey":"english2","examLabel":"英语二","year":"2023","text":2,"paragraph":2,"sentenceNo":2,"sentence":"Collectively, they have a maintenance backlog of more than $12 billion.","path":"english2/2023.html"},{"id":"english2-2023-t2-p2-s3","examKey":"english2","examLabel":"英语二","year":"2023","text":2,"paragraph":2,"sentenceNo":3,"sentence":"Roads, trails, restrooms, visitor centers and other infrastructure are crumbling.","path":"english2/2023.html"},{"id":"english2-2023-t2-p3-s1","examKey":"english2","examLabel":"英语二","year":"2023","text":2,"paragraph":3,"sentenceNo":1,"sentence":"Q27 定位起点 But privatizing and commercializing the campgrounds would not be a cure-all.","path":"english2/2023.html"},{"id":"english2-2023-t2-p3-s2","examKey":"english2","examLabel":"英语二","year":"2023","text":2,"paragraph":3,"sentenceNo":2,"sentence":"Campgrounds are a tiny portion of the overall infrastructure backlog, and businesses in the parks hand over, on average, only about 5% of their revenues to the National Park Service.","path":"english2/2023.html"},{"id":"english2-2023-t2-p4-s1","examKey":"english2","examLabel":"英语二","year":"2023","text":2,"paragraph":4,"sentenceNo":1,"sentence":"Moreover, increased privatization would certainly undercut one of the major reasons why 300 million visitors come to the parks each year: to enjoy nature and get a break from the commercial drumbeat that overwhelms daily life.","path":"english2/2023.html"},{"id":"english2-2023-t2-p5-s1","examKey":"english2","examLabel":"英语二","year":"2023","text":2,"paragraph":5,"sentenceNo":1,"sentence":"Q28 段落定位 The real problem is that the parks have been chronically starved of funding.","path":"english2/2023.html"},{"id":"english2-2023-t2-p5-s2","examKey":"english2","examLabel":"英语二","year":"2023","text":2,"paragraph":5,"sentenceNo":2,"sentence":"An economic survey of 700 U.S. taxpayers found that people would be willing to pay a significant amount of money to make sure the parks and their programs are kept intact.","path":"english2/2023.html"},{"id":"english2-2023-t2-p5-s3","examKey":"english2","examLabel":"英语二","year":"2023","text":2,"paragraph":5,"sentenceNo":3,"sentence":"Some 81% of respondents said they would be willing to pay additional taxes for the next 10 years to avoid any cuts to the national parks.","path":"english2/2023.html"},{"id":"english2-2023-t2-p6-s1","examKey":"english2","examLabel":"英语二","year":"2023","text":2,"paragraph":6,"sentenceNo":1,"sentence":"Q29 定位 The national parks provide great value to U.S. residents both as places to escape and as symbols of nature.","path":"english2/2023.html"},{"id":"english2-2023-t2-p6-s2","examKey":"english2","examLabel":"英语二","year":"2023","text":2,"paragraph":6,"sentenceNo":2,"sentence":"On top of this, they produce value from their extensive educational programs, their positive impact on the climate through carbon sequestration, their contribution to our cultural and artistic life, and of course through tourism.","path":"english2/2023.html"},{"id":"english2-2023-t2-p6-s3","examKey":"english2","examLabel":"英语二","year":"2023","text":2,"paragraph":6,"sentenceNo":3,"sentence":"The parks also help keep America’s past alive, working with thousands of local jurisdictions around the country to protect historical sites and to bring the stories of these places to life.","path":"english2/2023.html"},{"id":"english2-2023-t2-p7-s1","examKey":"english2","examLabel":"英语二","year":"2023","text":2,"paragraph":7,"sentenceNo":1,"sentence":"Q30 结论定位 The parks do all this on a shoestring.","path":"english2/2023.html"},{"id":"english2-2023-t2-p7-s2","examKey":"english2","examLabel":"英语二","year":"2023","text":2,"paragraph":7,"sentenceNo":2,"sentence":"Congress allocates only $3 billion a year to the national park system — an amount that has been flat since 2001 (in inflation-adjusted dollars) with the exception of a onetime boost in 2009.","path":"english2/2023.html"},{"id":"english2-2023-t2-p7-s3","examKey":"english2","examLabel":"英语二","year":"2023","text":2,"paragraph":7,"sentenceNo":3,"sentence":"Meanwhile, the number of annual visitors has increased by more than 50% since 1980, and now stands at 330 million visitors per year.","path":"english2/2023.html"},{"id":"english2-2023-t3-p1-s1","examKey":"english2","examLabel":"英语二","year":"2023","text":3,"paragraph":1,"sentenceNo":1,"sentence":"Q31 定位 The Internet may be changing merely what we remember, not our capacity to do so, suggests Columbia University psychology professor Betsy Sparrow.","path":"english2/2023.html"},{"id":"english2-2023-t3-p1-s2","examKey":"english2","examLabel":"英语二","year":"2023","text":3,"paragraph":1,"sentenceNo":2,"sentence":"In 2011, Sparrow led a study in which participants were asked to record 40 factoids in a computer (“an ostrich’s eye is bigger than its brain,” for example).","path":"english2/2023.html"},{"id":"english2-2023-t3-p1-s3","examKey":"english2","examLabel":"英语二","year":"2023","text":3,"paragraph":1,"sentenceNo":3,"sentence":"Half of the participants were told the information would be erased, while the other half were told it would be saved.","path":"english2/2023.html"},{"id":"english2-2023-t3-p1-s4","examKey":"english2","examLabel":"英语二","year":"2023","text":3,"paragraph":1,"sentenceNo":4,"sentence":"Guess what?","path":"english2/2023.html"},{"id":"english2-2023-t3-p1-s5","examKey":"english2","examLabel":"英语二","year":"2023","text":3,"paragraph":1,"sentenceNo":5,"sentence":"The latter group made no effort to recall the information when quizzed on it later, because they knew they could find it on their computers.","path":"english2/2023.html"},{"id":"english2-2023-t3-p1-s6","examKey":"english2","examLabel":"英语二","year":"2023","text":3,"paragraph":1,"sentenceNo":6,"sentence":"In the same study, a group was asked to remember both the information and the folders it was stored in.","path":"english2/2023.html"},{"id":"english2-2023-t3-p1-s7","examKey":"english2","examLabel":"英语二","year":"2023","text":3,"paragraph":1,"sentenceNo":7,"sentence":"They didn’t remember the information, but they remembered how to find the folders.","path":"english2/2023.html"},{"id":"english2-2023-t3-p1-s8","examKey":"english2","examLabel":"英语二","year":"2023","text":3,"paragraph":1,"sentenceNo":8,"sentence":"In other words, human memory is not deteriorating but “adapting to new communications technology,” Sparrow says.","path":"english2/2023.html"},{"id":"english2-2023-t3-p2-s1","examKey":"english2","examLabel":"英语二","year":"2023","text":3,"paragraph":2,"sentenceNo":1,"sentence":"Q32 定位 Q33 Sparrow 观点 In a very practical way, the Internet is becoming an external hard drive for our memories, a process known as “ cognitive offloading ”.","path":"english2/2023.html"},{"id":"english2-2023-t3-p2-s2","examKey":"english2","examLabel":"英语二","year":"2023","text":3,"paragraph":2,"sentenceNo":2,"sentence":"Traditionally, this role was fulfilled by data banks, libraries, and other humans.","path":"english2/2023.html"},{"id":"english2-2023-t3-p2-s3","examKey":"english2","examLabel":"英语二","year":"2023","text":3,"paragraph":2,"sentenceNo":3,"sentence":"Your father may never remember birthdays because your mother does, for instance.","path":"english2/2023.html"},{"id":"english2-2023-t3-p2-s4","examKey":"english2","examLabel":"英语二","year":"2023","text":3,"paragraph":2,"sentenceNo":4,"sentence":"Some worry that this is having a destructive effect on society, but Sparrow sees an upside.","path":"english2/2023.html"},{"id":"english2-2023-t3-p2-s5","examKey":"english2","examLabel":"英语二","year":"2023","text":3,"paragraph":2,"sentenceNo":5,"sentence":"Perhaps, she suggests, the trend will change our approach to learning from a focus on individual facts and memorization to an emphasis on more conceptual thinking —something that is not available on the Internet.","path":"english2/2023.html"},{"id":"english2-2023-t3-p2-s6","examKey":"english2","examLabel":"英语二","year":"2023","text":3,"paragraph":2,"sentenceNo":6,"sentence":"“I personally have never seen all that much intellectual value in memorizing things,” Sparrow says, adding that we haven’t lost our ability to do it.","path":"english2/2023.html"},{"id":"english2-2023-t3-p3-s1","examKey":"english2","examLabel":"英语二","year":"2023","text":3,"paragraph":3,"sentenceNo":1,"sentence":"Q34 段落定位 Still other experts say it’s too soon to understand how the Internet affects our brains.","path":"english2/2023.html"},{"id":"english2-2023-t3-p3-s2","examKey":"english2","examLabel":"英语二","year":"2023","text":3,"paragraph":3,"sentenceNo":2,"sentence":"There is no experimental evidence showing that it interferes with our ability to focus, for instance, wrote psychologists Christopher Chabris and Daniel J.","path":"english2/2023.html"},{"id":"english2-2023-t3-p3-s3","examKey":"english2","examLabel":"英语二","year":"2023","text":3,"paragraph":3,"sentenceNo":3,"sentence":"Simons.","path":"english2/2023.html"},{"id":"english2-2023-t3-p3-s4","examKey":"english2","examLabel":"英语二","year":"2023","text":3,"paragraph":3,"sentenceNo":4,"sentence":"And surfing the web exercised the brain more than reading did among computer-savvy older adults in a 2008 study involving 24 participants at the Semel Institute for Neuroscience and Human Behavior at the University of California, Los Angeles.","path":"english2/2023.html"},{"id":"english2-2023-t3-p4-s1","examKey":"english2","examLabel":"英语二","year":"2023","text":3,"paragraph":4,"sentenceNo":1,"sentence":"Q35 综合定位 “There may be costs associated with our increased reliance on the Internet, but I’d have to imagine that overall the benefits are going to outweigh those costs,” observes psychology professor Benjamin Storm. “ It seems pretty clear that memory is changing, but is it changing for the better?","path":"english2/2023.html"},{"id":"english2-2023-t3-p4-s2","examKey":"english2","examLabel":"英语二","year":"2023","text":3,"paragraph":4,"sentenceNo":2,"sentence":"At this point, we don’t know. ”","path":"english2/2023.html"},{"id":"english2-2023-t4-p1-s1","examKey":"english2","examLabel":"英语二","year":"2023","text":4,"paragraph":1,"sentenceNo":1,"sentence":"Q36 段落定位 Q40 主旨起点 Teenagers are paradoxical.","path":"english2/2023.html"},{"id":"english2-2023-t4-p1-s2","examKey":"english2","examLabel":"英语二","year":"2023","text":4,"paragraph":1,"sentenceNo":2,"sentence":"That’s a mild and detached way of saying something that parents often express with considerably stronger language.","path":"english2/2023.html"},{"id":"english2-2023-t4-p1-s3","examKey":"english2","examLabel":"英语二","year":"2023","text":4,"paragraph":1,"sentenceNo":3,"sentence":"But the paradox is scientific as well as personal.","path":"english2/2023.html"},{"id":"english2-2023-t4-p1-s4","examKey":"english2","examLabel":"英语二","year":"2023","text":4,"paragraph":1,"sentenceNo":4,"sentence":"In adolescence, helpless and dependent children who have relied on grown-ups for just about everything become independent people who can take care of themselves and help each other.","path":"english2/2023.html"},{"id":"english2-2023-t4-p1-s5","examKey":"english2","examLabel":"英语二","year":"2023","text":4,"paragraph":1,"sentenceNo":5,"sentence":"At the same time, once cheerful and compliant children become rebellious teenage risk-takers.","path":"english2/2023.html"},{"id":"english2-2023-t4-p2-s1","examKey":"english2","examLabel":"英语二","year":"2023","text":4,"paragraph":2,"sentenceNo":1,"sentence":"Q37 段落定位 A new study published in the journal Child Development, by Eveline Crone of the University of Leiden and colleagues, suggests that the positive and negative sides of teenagers go hand in hand.","path":"english2/2023.html"},{"id":"english2-2023-t4-p2-s2","examKey":"english2","examLabel":"英语二","year":"2023","text":4,"paragraph":2,"sentenceNo":2,"sentence":"The study is part of a new wave of thinking about adolescence.","path":"english2/2023.html"},{"id":"english2-2023-t4-p2-s3","examKey":"english2","examLabel":"英语二","year":"2023","text":4,"paragraph":2,"sentenceNo":3,"sentence":"For a long time, scientists and policy makers concentrated on the idea that teenagers were a problem that needed to be solved.","path":"english2/2023.html"},{"id":"english2-2023-t4-p2-s4","examKey":"english2","examLabel":"英语二","year":"2023","text":4,"paragraph":2,"sentenceNo":4,"sentence":"The new work emphasizes that adolescence is a time of opportunity as well as risk.","path":"english2/2023.html"},{"id":"english2-2023-t4-p3-s1","examKey":"english2","examLabel":"英语二","year":"2023","text":4,"paragraph":3,"sentenceNo":1,"sentence":"The researchers studied “prosocial” and rebellious traits in more than 200 children and young adults, ranging from 11 to 28 years old.","path":"english2/2023.html"},{"id":"english2-2023-t4-p3-s2","examKey":"english2","examLabel":"英语二","year":"2023","text":4,"paragraph":3,"sentenceNo":2,"sentence":"The participants filled out questionnaires about how often they did things that were altruistic and positive, like sacrificing their own interests to help a friend, or rebellious and negative, like getting drunk or staying out late.","path":"english2/2023.html"},{"id":"english2-2023-t4-p4-s1","examKey":"english2","examLabel":"英语二","year":"2023","text":4,"paragraph":4,"sentenceNo":1,"sentence":"Q38 定位 Other studies have shown that rebellious behavior increases as you become a teenager and then fades away as you grow older.","path":"english2/2023.html"},{"id":"english2-2023-t4-p4-s2","examKey":"english2","examLabel":"英语二","year":"2023","text":4,"paragraph":4,"sentenceNo":2,"sentence":"But the new study shows that, interestingly, the same pattern holds for prosocial behavior.","path":"english2/2023.html"},{"id":"english2-2023-t4-p4-s3","examKey":"english2","examLabel":"英语二","year":"2023","text":4,"paragraph":4,"sentenceNo":3,"sentence":"Teenagers were more likely than younger children or adults to report that they did things like unselfishly helping a friend.","path":"english2/2023.html"},{"id":"english2-2023-t4-p5-s1","examKey":"english2","examLabel":"英语二","year":"2023","text":4,"paragraph":5,"sentenceNo":1,"sentence":"Q39 last two paragraphs Most significantly, there was a positive correlation between prosociality and rebelliousness.","path":"english2/2023.html"},{"id":"english2-2023-t4-p5-s2","examKey":"english2","examLabel":"英语二","year":"2023","text":4,"paragraph":5,"sentenceNo":2,"sentence":"The teenagers who were more rebellious were also more likely to help others.","path":"english2/2023.html"},{"id":"english2-2023-t4-p5-s3","examKey":"english2","examLabel":"英语二","year":"2023","text":4,"paragraph":5,"sentenceNo":3,"sentence":"The good and bad sides of adolescence seem to develop together.","path":"english2/2023.html"},{"id":"english2-2023-t4-p6-s1","examKey":"english2","examLabel":"英语二","year":"2023","text":4,"paragraph":6,"sentenceNo":1,"sentence":"Is there some common factor that underlies these apparently contradictory developments?","path":"english2/2023.html"},{"id":"english2-2023-t4-p6-s2","examKey":"english2","examLabel":"英语二","year":"2023","text":4,"paragraph":6,"sentenceNo":2,"sentence":"One idea is that teenage behavior is related to what researchers call “ reward sensitivity.” Decision-making always involves balancing rewards and risks, benefits and costs.","path":"english2/2023.html"},{"id":"english2-2023-t4-p6-s3","examKey":"english2","examLabel":"英语二","year":"2023","text":4,"paragraph":6,"sentenceNo":3,"sentence":"“Reward sensitivity” measures how much reward it takes to outweigh risk.","path":"english2/2023.html"},{"id":"english2-2023-t4-p7-s1","examKey":"english2","examLabel":"英语二","year":"2023","text":4,"paragraph":7,"sentenceNo":1,"sentence":"Teenagers are particularly sensitive to social rewards —winning the game, impressing a new friend, getting that boy to notice you.","path":"english2/2023.html"},{"id":"english2-2023-t4-p7-s2","examKey":"english2","examLabel":"英语二","year":"2023","text":4,"paragraph":7,"sentenceNo":2,"sentence":"Reward sensitivity, like prosocial behavior and risk-taking, seems to go up in adolescence and then go down again as we age.","path":"english2/2023.html"},{"id":"english2-2023-t4-p7-s3","examKey":"english2","examLabel":"英语二","year":"2023","text":4,"paragraph":7,"sentenceNo":3,"sentence":"Somehow, when you hit 30, the chance that something exciting and new will happen at that party just doesn’t seem to outweigh the effort of getting up off the couch.","path":"english2/2023.html"},{"id":"english1-2024-t1-p1-s1","examKey":"english1","examLabel":"英语一","year":"2024","text":1,"paragraph":1,"sentenceNo":1,"sentence":"Nearly 2,000 years ago, as the Romans began to pull out of Scotland, they left behind a curious treasure: 10 tons of nails, nearly a million of the things.","path":"english1/2024.html"},{"id":"english1-2024-t1-p1-s2","examKey":"english1","examLabel":"英语一","year":"2024","text":1,"paragraph":1,"sentenceNo":2,"sentence":"The nail hoard was discovered in 1960 in a four-metre-deep pit covered by two metres of gravel.","path":"english1/2024.html"},{"id":"english1-2024-t1-p2-s1","examKey":"english1","examLabel":"英语一","year":"2024","text":1,"paragraph":2,"sentenceNo":1,"sentence":"Why had the Romans buried a million nails?","path":"english1/2024.html"},{"id":"english1-2024-t1-p2-s2","examKey":"english1","examLabel":"英语一","year":"2024","text":1,"paragraph":2,"sentenceNo":2,"sentence":"The likely explanation is that the withdrawal was rushed, and they didn’t want the local Caledonians getting their hands on 10 tons of weapon-grade iron.","path":"english1/2024.html"},{"id":"english1-2024-t1-p2-s3","examKey":"english1","examLabel":"英语一","year":"2024","text":1,"paragraph":2,"sentenceNo":3,"sentence":"The Romans buried the nails so deep that they would not be discovered for almost two millennia.","path":"english1/2024.html"},{"id":"english1-2024-t1-p3-s1","examKey":"english1","examLabel":"英语一","year":"2024","text":1,"paragraph":3,"sentenceNo":1,"sentence":"Later civilisations would value the skilled blacksmith’s labour in a nail even more than the raw material.","path":"english1/2024.html"},{"id":"english1-2024-t1-p3-s2","examKey":"english1","examLabel":"英语一","year":"2024","text":1,"paragraph":3,"sentenceNo":2,"sentence":"As Roma Agrawal explains in her new delightful book Nuts and Bolts, early 17th-century Virginians would sometimes burn down their homes if they were planning to relocate.","path":"english1/2024.html"},{"id":"english1-2024-t1-p3-s3","examKey":"english1","examLabel":"英语一","year":"2024","text":1,"paragraph":3,"sentenceNo":3,"sentence":"This was an attempt to recover the valuable nails, which could be re used after sifting the ashes.","path":"english1/2024.html"},{"id":"english1-2024-t1-p3-s4","examKey":"english1","examLabel":"英语一","year":"2024","text":1,"paragraph":3,"sentenceNo":4,"sentence":"The idea that one might burn down an entire house just to reclaim the nails underlines how scarce, costly and valuable the simple-seeming technology was.","path":"english1/2024.html"},{"id":"english1-2024-t1-p4-s1","examKey":"english1","examLabel":"英语一","year":"2024","text":1,"paragraph":4,"sentenceNo":1,"sentence":"The price of nails fell by 90% between the late 1700s and mid-1900s, as economist Daniel Sichel points out in a research paper.","path":"english1/2024.html"},{"id":"english1-2024-t1-p4-s2","examKey":"english1","examLabel":"英语一","year":"2024","text":1,"paragraph":4,"sentenceNo":2,"sentence":"According to Sichel, although the falling price of nails was driven partly by cheaper iron and cheaper energy, most of the credit goes to nail manufacturers who simply found more efficient ways to turn steel into nails.","path":"english1/2024.html"},{"id":"english1-2024-t1-p5-s1","examKey":"english1","examLabel":"英语一","year":"2024","text":1,"paragraph":5,"sentenceNo":1,"sentence":"Nails themselves have changed over the years, but Sichel studied them because they haven’t changed much.","path":"english1/2024.html"},{"id":"english1-2024-t1-p5-s2","examKey":"english1","examLabel":"英语一","year":"2024","text":1,"paragraph":5,"sentenceNo":2,"sentence":"Roman lamps and Roman chariots are very different from LED strips and sports cars, but Roman nails are still clearly nails.","path":"english1/2024.html"},{"id":"english1-2024-t1-p5-s3","examKey":"english1","examLabel":"英语一","year":"2024","text":1,"paragraph":5,"sentenceNo":3,"sentence":"It would be absurd to try to track the changing price of sports cars since 1695, but to ask the same question of nails makes perfect sense.","path":"english1/2024.html"},{"id":"english1-2024-t1-p6-s1","examKey":"english1","examLabel":"英语一","year":"2024","text":1,"paragraph":6,"sentenceNo":1,"sentence":"I make no apology for being obsessed by a particular feature of everyday objects: their price.","path":"english1/2024.html"},{"id":"english1-2024-t1-p6-s2","examKey":"english1","examLabel":"英语一","year":"2024","text":1,"paragraph":6,"sentenceNo":2,"sentence":"I am an economist, after all.","path":"english1/2024.html"},{"id":"english1-2024-t1-p6-s3","examKey":"english1","examLabel":"英语一","year":"2024","text":1,"paragraph":6,"sentenceNo":3,"sentence":"After writing two books about the history of inventions, one thing I’ve learnt is that while it is the enchantingly sophisticated technologies that get all the hype, it’s the cheap technologies that change the world.","path":"english1/2024.html"},{"id":"english1-2024-t1-p7-s1","examKey":"english1","examLabel":"英语一","year":"2024","text":1,"paragraph":7,"sentenceNo":1,"sentence":"The Gutenberg printing press transformed civilisation not by changing the nature of writing but by changing its cost—and it would have achieved little without a parallel collapse in the price of surfaces to write on, thanks to an often-overlooked technology called paper.","path":"english1/2024.html"},{"id":"english1-2024-t1-p7-s2","examKey":"english1","examLabel":"英语一","year":"2024","text":1,"paragraph":7,"sentenceNo":2,"sentence":"Solar panels had a few niche uses until they became cheap; now they are transforming the global energy system.","path":"english1/2024.html"},{"id":"english1-2024-t2-p1-s1","examKey":"english1","examLabel":"英语一","year":"2024","text":2,"paragraph":1,"sentenceNo":1,"sentence":"Parenting tips obtained from hunter-gatherers in Africa may be the key to bringing up more contented children, researchers have suggested.","path":"english1/2024.html"},{"id":"english1-2024-t2-p1-s2","examKey":"english1","examLabel":"英语一","year":"2024","text":2,"paragraph":1,"sentenceNo":2,"sentence":"The idea is based on studies of communities such as the Kung of Botswana, where each child is cared for by many adults.","path":"english1/2024.html"},{"id":"english1-2024-t2-p1-s3","examKey":"english1","examLabel":"英语一","year":"2024","text":2,"paragraph":1,"sentenceNo":3,"sentence":"Kung children as young as four will help to look after younger ones and “baby-wearing”, in which infants are carried in slings, is considered the norm.","path":"english1/2024.html"},{"id":"english1-2024-t2-p2-s1","examKey":"english1","examLabel":"英语一","year":"2024","text":2,"paragraph":2,"sentenceNo":1,"sentence":"According to Dr Nikhil Chaudhary, an evolutionary anthropologist at Cambridge University, these practices, known as alloparenting, could lead to less anxiety for children and parents.","path":"english1/2024.html"},{"id":"english1-2024-t2-p3-s1","examKey":"english1","examLabel":"英语一","year":"2024","text":2,"paragraph":3,"sentenceNo":1,"sentence":"Dr Annie Swanepoel, a child psychiatrist, believes that there are ways to incorporate them into western life.","path":"english1/2024.html"},{"id":"english1-2024-t2-p3-s2","examKey":"english1","examLabel":"英语一","year":"2024","text":2,"paragraph":3,"sentenceNo":2,"sentence":"In Germany, one scheme has paired an old people’s home with a nursery.","path":"english1/2024.html"},{"id":"english1-2024-t2-p3-s3","examKey":"english1","examLabel":"英语一","year":"2024","text":2,"paragraph":3,"sentenceNo":3,"sentence":"The residents help to look after the children, an arrangement to alloparenting.","path":"english1/2024.html"},{"id":"english1-2024-t2-p3-s4","examKey":"english1","examLabel":"英语一","year":"2024","text":2,"paragraph":3,"sentenceNo":4,"sentence":"Another measure could be encouraging friendships between children in different school years to mirror the unsupervised mixed-age playgroups in hunter-gatherer communities.","path":"english1/2024.html"},{"id":"english1-2024-t2-p4-s1","examKey":"english1","examLabel":"英语一","year":"2024","text":2,"paragraph":4,"sentenceNo":1,"sentence":"In a paper published in the Journal of Child Psychology and Psychiatry, researchers said that the western nuclear family was a recent invention which broke with evolutionary history.","path":"english1/2024.html"},{"id":"english1-2024-t2-p4-s2","examKey":"english1","examLabel":"英语一","year":"2024","text":2,"paragraph":4,"sentenceNo":2,"sentence":"This abrupt shift to an “ intensive mothering narrative ”, which suggests that mothers should manage childcare alone, was likely to have been harmful.","path":"english1/2024.html"},{"id":"english1-2024-t2-p4-s3","examKey":"english1","examLabel":"英语一","year":"2024","text":2,"paragraph":4,"sentenceNo":3,"sentence":"“Such narratives can lead to maternal exhaustion and have dangerous consequences,” they wrote.","path":"english1/2024.html"},{"id":"english1-2024-t2-p5-s1","examKey":"english1","examLabel":"英语一","year":"2024","text":2,"paragraph":5,"sentenceNo":1,"sentence":"By contrast, in hunter-gatherer societies adults other than the parents can provide almost half of a child’s care.","path":"english1/2024.html"},{"id":"english1-2024-t2-p5-s2","examKey":"english1","examLabel":"英语一","year":"2024","text":2,"paragraph":5,"sentenceNo":2,"sentence":"One previous study looked at the Efé people of the Democratic Republic of Congo.","path":"english1/2024.html"},{"id":"english1-2024-t2-p5-s3","examKey":"english1","examLabel":"英语一","year":"2024","text":2,"paragraph":5,"sentenceNo":3,"sentence":"It found that infants had an average of 14 alloparents a day by the time they were 18 weeks old and were passed between caregivers eight times an hour.","path":"english1/2024.html"},{"id":"english1-2024-t2-p6-s1","examKey":"english1","examLabel":"英语一","year":"2024","text":2,"paragraph":6,"sentenceNo":1,"sentence":"Chaudhary said that parents now had less childcare support from family and social networks than during most of humans’ evolutionary history, but introducing additional caregivers could reduce stress and maternal depression, which could have a “knock-on” benefit to a child’s wellbeing.","path":"english1/2024.html"},{"id":"english1-2024-t2-p6-s2","examKey":"english1","examLabel":"英语一","year":"2024","text":2,"paragraph":6,"sentenceNo":2,"sentence":"An infant born to a hunter-gatherer society could have more than ten caregivers—this contrasts starkly to nursery settings in the UK where regulations call for a ratio of one carer to four children aged two to three.","path":"english1/2024.html"},{"id":"english1-2024-t2-p7-s1","examKey":"english1","examLabel":"英语一","year":"2024","text":2,"paragraph":7,"sentenceNo":1,"sentence":"While hunter-gatherer children learnt from observation and imitation in mixed-age playgroups, researchers said that western “instructive teaching”, where pupils are asked to sit still, may contribute to conditions such as attention deficit hyperactivity disorder.","path":"english1/2024.html"},{"id":"english1-2024-t2-p7-s2","examKey":"english1","examLabel":"英语一","year":"2024","text":2,"paragraph":7,"sentenceNo":2,"sentence":"Chaudhary said that Britain should explore the possibility that older siblings helping their parents “might also enhance their own social development”.","path":"english1/2024.html"},{"id":"english1-2024-t3-p1-s1","examKey":"english1","examLabel":"英语一","year":"2024","text":3,"paragraph":1,"sentenceNo":1,"sentence":"A Polish digital artist who uses classical painting styles to create dreamy fantasy landscapes, Greg Rutkowski has made illustrations for games such as Dungeons & Dragons and Magic: The Gathering.","path":"english1/2024.html"},{"id":"english1-2024-t3-p1-s2","examKey":"english1","examLabel":"英语一","year":"2024","text":3,"paragraph":1,"sentenceNo":2,"sentence":"And he’s become a sudden hit in the new world of text-to-image AI generation.","path":"english1/2024.html"},{"id":"english1-2024-t3-p2-s1","examKey":"english1","examLabel":"英语一","year":"2024","text":3,"paragraph":2,"sentenceNo":1,"sentence":"His distinctive style is now one of the most commonly used prompts in the new open-source AI art generator Stable Diffusion.","path":"english1/2024.html"},{"id":"english1-2024-t3-p2-s2","examKey":"english1","examLabel":"英语一","year":"2024","text":3,"paragraph":2,"sentenceNo":2,"sentence":"The tool, along with other popular image-generation AI models, allows anyone to create impressive images based on text prompts.","path":"english1/2024.html"},{"id":"english1-2024-t3-p2-s3","examKey":"english1","examLabel":"英语一","year":"2024","text":3,"paragraph":2,"sentenceNo":3,"sentence":"For example, type in “Wizard with sword and a glowing orb of magic fire fights a fierce dragon Greg Rutkowski,” and the system will produce something that looks not a million miles away from works in Rutkowski’s style.","path":"english1/2024.html"},{"id":"english1-2024-t3-p3-s1","examKey":"english1","examLabel":"英语一","year":"2024","text":3,"paragraph":3,"sentenceNo":1,"sentence":"But these open-source programs are built by scraping images from the Internet, often without permission and proper attribution to artists.","path":"english1/2024.html"},{"id":"english1-2024-t3-p3-s2","examKey":"english1","examLabel":"英语一","year":"2024","text":3,"paragraph":3,"sentenceNo":2,"sentence":"As a result, they are raising tricky questions about ethics and copyright.","path":"english1/2024.html"},{"id":"english1-2024-t3-p3-s3","examKey":"english1","examLabel":"英语一","year":"2024","text":3,"paragraph":3,"sentenceNo":3,"sentence":"And artists like Rutkowski have had enough.","path":"english1/2024.html"},{"id":"english1-2024-t3-p4-s1","examKey":"english1","examLabel":"英语一","year":"2024","text":3,"paragraph":4,"sentenceNo":1,"sentence":"According to the website Lexica, which tracks over 10 million Stable Diffusion images and prompts, Rutkowski’s name has been used as a prompt around 93,000 times.","path":"english1/2024.html"},{"id":"english1-2024-t3-p4-s2","examKey":"english1","examLabel":"英语一","year":"2024","text":3,"paragraph":4,"sentenceNo":2,"sentence":"Rutkowski was initially surprised but thought it might be a good way to reach new audiences.","path":"english1/2024.html"},{"id":"english1-2024-t3-p4-s3","examKey":"english1","examLabel":"英语一","year":"2024","text":3,"paragraph":4,"sentenceNo":3,"sentence":"Then he tried searching for his name to see if a piece he had worked on had been published.","path":"english1/2024.html"},{"id":"english1-2024-t3-p4-s4","examKey":"english1","examLabel":"英语一","year":"2024","text":3,"paragraph":4,"sentenceNo":4,"sentence":"The online search brought back work that had his name attached to it but wasn’t his.","path":"english1/2024.html"},{"id":"english1-2024-t3-p5-s1","examKey":"english1","examLabel":"英语一","year":"2024","text":3,"paragraph":5,"sentenceNo":1,"sentence":"“It’s been just a month.","path":"english1/2024.html"},{"id":"english1-2024-t3-p5-s2","examKey":"english1","examLabel":"英语一","year":"2024","text":3,"paragraph":5,"sentenceNo":2,"sentence":"What about in a year?","path":"english1/2024.html"},{"id":"english1-2024-t3-p5-s3","examKey":"english1","examLabel":"英语一","year":"2024","text":3,"paragraph":5,"sentenceNo":3,"sentence":"I probably won’t be able to find my work out there because the Internet will be flooded with AI art,” Rutkowski said.","path":"english1/2024.html"},{"id":"english1-2024-t3-p5-s4","examKey":"english1","examLabel":"英语一","year":"2024","text":3,"paragraph":5,"sentenceNo":4,"sentence":"“That’s concerning.”","path":"english1/2024.html"},{"id":"english1-2024-t3-p6-s1","examKey":"english1","examLabel":"英语一","year":"2024","text":3,"paragraph":6,"sentenceNo":1,"sentence":"Other artists besides Rutkowski have been surprised by the apparent popularity of their work in text-to-image generators —and some are now fighting back.","path":"english1/2024.html"},{"id":"english1-2024-t3-p7-s1","examKey":"english1","examLabel":"英语一","year":"2024","text":3,"paragraph":7,"sentenceNo":1,"sentence":"Karla Ortiz, an illustrator based in San Francisco who found her work in Stable Diffusion’s data set, has been raising awareness about the issues around AI art and copyright.","path":"english1/2024.html"},{"id":"english1-2024-t3-p7-s2","examKey":"english1","examLabel":"英语一","year":"2024","text":3,"paragraph":7,"sentenceNo":2,"sentence":"Artists say they risk losing income as people start using AI-generated images based on copyrighted material for commercial purposes.","path":"english1/2024.html"},{"id":"english1-2024-t3-p7-s3","examKey":"english1","examLabel":"英语一","year":"2024","text":3,"paragraph":7,"sentenceNo":3,"sentence":"But it’s also a lot more personal, Ortiz says, arguing that because art is so closely linked to a person, it could raise data protection and privacy problems.","path":"english1/2024.html"},{"id":"english1-2024-t3-p8-s1","examKey":"english1","examLabel":"英语一","year":"2024","text":3,"paragraph":8,"sentenceNo":1,"sentence":"“There is a coalition growing within artist industries to figure out how to tackle or mitigate this,” says Ortiz.","path":"english1/2024.html"},{"id":"english1-2024-t3-p8-s2","examKey":"english1","examLabel":"英语一","year":"2024","text":3,"paragraph":8,"sentenceNo":2,"sentence":"The group is in its early days of mobilization, which could involve pushing for new policies or regulation.","path":"english1/2024.html"},{"id":"english1-2024-t3-p8-s3","examKey":"english1","examLabel":"英语一","year":"2024","text":3,"paragraph":8,"sentenceNo":3,"sentence":"One suggestion is that AI models could be trained on images in the public domain, and AI companies could forge partnerships with museums and artists, Ortiz says.","path":"english1/2024.html"},{"id":"english1-2024-t4-p1-s1","examKey":"english1","examLabel":"英语一","year":"2024","text":4,"paragraph":1,"sentenceNo":1,"sentence":"The miracle of the Chesapeake Bay lies not in its depths, but in the complexity of its natural construction, the interaction of fresh and saline waters, and the mix of land and water.","path":"english1/2024.html"},{"id":"english1-2024-t4-p1-s2","examKey":"english1","examLabel":"英语一","year":"2024","text":4,"paragraph":1,"sentenceNo":2,"sentence":"The shallows provide homes for hundreds of species while storing floodwaters, filtering pollutants from water, and protecting nearby communities from potentially destructive storm surges.","path":"english1/2024.html"},{"id":"english1-2024-t4-p2-s1","examKey":"english1","examLabel":"英语一","year":"2024","text":4,"paragraph":2,"sentenceNo":1,"sentence":"All this was put at great risk last month, when the U.S.","path":"english1/2024.html"},{"id":"english1-2024-t4-p2-s2","examKey":"english1","examLabel":"英语一","year":"2024","text":4,"paragraph":2,"sentenceNo":2,"sentence":"Supreme Court issued a ruling in an Idaho case that provides the U.S.","path":"english1/2024.html"},{"id":"english1-2024-t4-p2-s3","examKey":"english1","examLabel":"英语一","year":"2024","text":4,"paragraph":2,"sentenceNo":3,"sentence":"Environmental Protection Agency (EPA) far less authority to regulate wetlands and waterways.","path":"english1/2024.html"},{"id":"english1-2024-t4-p2-s4","examKey":"english1","examLabel":"英语一","year":"2024","text":4,"paragraph":2,"sentenceNo":4,"sentence":"Specifically, a 5-4 majority decided that wetlands protected by the EPA under its Clean Water Act authority must have a “continuous surface connection” to bodies of water.","path":"english1/2024.html"},{"id":"english1-2024-t4-p2-s5","examKey":"english1","examLabel":"英语一","year":"2024","text":4,"paragraph":2,"sentenceNo":5,"sentence":"This narrowing of the regulatory scope was a victory for builders, mining operators and other commercial interests often at odds with environmental rules.","path":"english1/2024.html"},{"id":"english1-2024-t4-p2-s6","examKey":"english1","examLabel":"英语一","year":"2024","text":4,"paragraph":2,"sentenceNo":6,"sentence":"And it carries “significant repercussions for water quality and flood control throughout the United States,” as Justice Brett Kavanaugh observed.","path":"english1/2024.html"},{"id":"english1-2024-t4-p3-s1","examKey":"english1","examLabel":"英语一","year":"2024","text":4,"paragraph":3,"sentenceNo":1,"sentence":"In Maryland, the good news is that there are many state laws in place that provide wetlands protections.","path":"english1/2024.html"},{"id":"english1-2024-t4-p3-s2","examKey":"english1","examLabel":"英语一","year":"2024","text":4,"paragraph":3,"sentenceNo":2,"sentence":"But that’s a very shortsighted view, particularly when it comes to the Chesapeake Bay.","path":"english1/2024.html"},{"id":"english1-2024-t4-p3-s3","examKey":"english1","examLabel":"英语一","year":"2024","text":4,"paragraph":3,"sentenceNo":3,"sentence":"The reality is that water, and the pollutants that so often come with it, don’t respect state boundaries.","path":"english1/2024.html"},{"id":"english1-2024-t4-p3-s4","examKey":"english1","examLabel":"英语一","year":"2024","text":4,"paragraph":3,"sentenceNo":4,"sentence":"The Chesapeake draws from a 64,000-square-mile watershed that extends into Virginia, Pennsylvania, New York, West Virginia, the District of Columbia and Delaware.","path":"english1/2024.html"},{"id":"english1-2024-t4-p3-s5","examKey":"english1","examLabel":"英语一","year":"2024","text":4,"paragraph":3,"sentenceNo":5,"sentence":"Will those jurisdictions extend the same protections now denied under Sackett v.","path":"english1/2024.html"},{"id":"english1-2024-t4-p3-s6","examKey":"english1","examLabel":"英语一","year":"2024","text":4,"paragraph":3,"sentenceNo":6,"sentence":"EPA?","path":"english1/2024.html"},{"id":"english1-2024-t4-p3-s7","examKey":"english1","examLabel":"英语一","year":"2024","text":4,"paragraph":3,"sentenceNo":7,"sentence":"Perhaps some, but all?","path":"english1/2024.html"},{"id":"english1-2024-t4-p3-s8","examKey":"english1","examLabel":"英语一","year":"2024","text":4,"paragraph":3,"sentenceNo":8,"sentence":"That seems unlikely.","path":"english1/2024.html"},{"id":"english1-2024-t4-p4-s1","examKey":"english1","examLabel":"英语一","year":"2024","text":4,"paragraph":4,"sentenceNo":1,"sentence":"It is too easy, and misleading, to see such court rulings as merely standing up for the rights of land owners when the consequences can be so dire for their neighbors.","path":"english1/2024.html"},{"id":"english1-2024-t4-p4-s2","examKey":"english1","examLabel":"英语一","year":"2024","text":4,"paragraph":4,"sentenceNo":2,"sentence":"And it’s a reminder that the EPA’s involvement in the Chesapeake Bay Program has long been crucial as the means to transcend the influence of deep-pocketed special interests in neighboring states.","path":"english1/2024.html"},{"id":"english1-2024-t4-p4-s3","examKey":"english1","examLabel":"英语一","year":"2024","text":4,"paragraph":4,"sentenceNo":3,"sentence":"Pennsylvania farmers, to use one telling example, aren’t thinking about next year’s blue crab harvest in Maryland when they decide whether to spread animal waste on their fields, yet the runoff into nearby creeks can have enormous impact downstream.","path":"english1/2024.html"},{"id":"english1-2024-t4-p5-s1","examKey":"english1","examLabel":"英语一","year":"2024","text":4,"paragraph":5,"sentenceNo":1,"sentence":"And so we would call on state lawmakers from Richmond to Albany to consider reviewing their own wetlands protections and see for themselves the enormous stakes involved.","path":"english1/2024.html"},{"id":"english1-2024-t4-p5-s2","examKey":"english1","examLabel":"英语一","year":"2024","text":4,"paragraph":5,"sentenceNo":2,"sentence":"We can offer them a visit to Blackwater National Wildlife Refuge in Dorchester County where bald eagles fly over tidal marshes so shallow you could not paddle a boat across them but teeming with aquatic life.","path":"english1/2024.html"},{"id":"english1-2024-t4-p5-s3","examKey":"english1","examLabel":"英语一","year":"2024","text":4,"paragraph":5,"sentenceNo":3,"sentence":"It’s worth the scenic drive.","path":"english1/2024.html"},{"id":"english2-2024-t1-p1-s1","examKey":"english2","examLabel":"英语二","year":"2024","text":1,"paragraph":1,"sentenceNo":1,"sentence":"1 In her new book Cogs and Monsters: What Economics Is, and What It Should Be, Diane Coyle, an economist at Cambridge University, argues that the digital economy requires new ways of thinking about progress.","path":"english2/2024.html"},{"id":"english2-2024-t1-p1-s2","examKey":"english2","examLabel":"英语二","year":"2024","text":1,"paragraph":1,"sentenceNo":2,"sentence":"2 “Whatever we mean by the economy growing, by things getting better, the gains will have to be more evenly shared than in the recent past,” she writes.","path":"english2/2024.html"},{"id":"english2-2024-t1-p1-s3","examKey":"english2","examLabel":"英语二","year":"2024","text":1,"paragraph":1,"sentenceNo":3,"sentence":"3 “An economy of tech millionaires or billionaires and gig workers, with middle-income jobs undercut by automation, will not be politically sustainable.”","path":"english2/2024.html"},{"id":"english2-2024-t1-p2-s1","examKey":"english2","examLabel":"英语二","year":"2024","text":1,"paragraph":2,"sentenceNo":1,"sentence":"Q22 段落定位 1 Improving living standards and increasing prosperity for more people will require greater use of digital technologies to boost productivity in various sectors, including health care and construction, says Coyle.","path":"english2/2024.html"},{"id":"english2-2024-t1-p2-s2","examKey":"english2","examLabel":"英语二","year":"2024","text":1,"paragraph":2,"sentenceNo":2,"sentence":"2 But people can’t be expected to embrace the changes if they’re not seeing the benefits—if they’re just seeing good jobs being destroyed.","path":"english2/2024.html"},{"id":"english2-2024-t1-p3-s1","examKey":"english2","examLabel":"英语二","year":"2024","text":1,"paragraph":3,"sentenceNo":1,"sentence":"1 In a recent interview, Coyle said she fears that tech’s inequality problem could be a roadblock to deploying AI.","path":"english2/2024.html"},{"id":"english2-2024-t1-p3-s2","examKey":"english2","examLabel":"英语二","year":"2024","text":1,"paragraph":3,"sentenceNo":2,"sentence":"2 “We’re talking about disruption,” she says.","path":"english2/2024.html"},{"id":"english2-2024-t1-p3-s3","examKey":"english2","examLabel":"英语二","year":"2024","text":1,"paragraph":3,"sentenceNo":3,"sentence":"“These are transformative technologies that change the ways we spend our time every day, that change business models that succeed.” 3 To make such “tremendous changes,” she adds, you need social buy-in.","path":"english2/2024.html"},{"id":"english2-2024-t1-p4-s1","examKey":"english2","examLabel":"英语二","year":"2024","text":1,"paragraph":4,"sentenceNo":1,"sentence":"1 Instead, says Coyle, resentment is simmering among many as the benefits are perceived to go to elites in a handful of prosperous cities.","path":"english2/2024.html"},{"id":"english2-2024-t1-p5-s1","examKey":"english2","examLabel":"英语二","year":"2024","text":1,"paragraph":5,"sentenceNo":1,"sentence":"1 According to the Brookings Institution, a short list of eight American cities that included San Francisco, San Jose, Boston, and Seattle had roughly 38% of all tech jobs by 2019.","path":"english2/2024.html"},{"id":"english2-2024-t1-p5-s2","examKey":"english2","examLabel":"英语二","year":"2024","text":1,"paragraph":5,"sentenceNo":2,"sentence":"2 New AI technologies are particularly concentrated: Brookings’ Mark Muro and Sifan Liu estimate that just 15 cities account for two-thirds of the AI assets and capabilities in the United States.","path":"english2/2024.html"},{"id":"english2-2024-t1-p6-s1","examKey":"english2","examLabel":"英语二","year":"2024","text":1,"paragraph":6,"sentenceNo":1,"sentence":"1 The dominance of a few cities in the invention and commercialization of AI means that geographical disparities in wealth will continue to soar.","path":"english2/2024.html"},{"id":"english2-2024-t1-p6-s2","examKey":"english2","examLabel":"英语二","year":"2024","text":1,"paragraph":6,"sentenceNo":2,"sentence":"2 Not only will this foster political and social unrest, but it could, as Coyle suggests, hold back the sorts of AI technologies needed for regional economies to grow.","path":"english2/2024.html"},{"id":"english2-2024-t1-p7-s1","examKey":"english2","examLabel":"英语二","year":"2024","text":1,"paragraph":7,"sentenceNo":1,"sentence":"1 Part of the solution could lie in somehow loosening the stranglehold that Big Tech has on defining the AI agenda.","path":"english2/2024.html"},{"id":"english2-2024-t1-p7-s2","examKey":"english2","examLabel":"英语二","year":"2024","text":1,"paragraph":7,"sentenceNo":2,"sentence":"2 That will likely take increased federal funding for research independent of the tech giants.","path":"english2/2024.html"},{"id":"english2-2024-t1-p8-s1","examKey":"english2","examLabel":"英语二","year":"2024","text":1,"paragraph":8,"sentenceNo":1,"sentence":"1 A more immediate response is to broaden our digital imaginations to conceive of AI technologies that don’t simply replace jobs but expand opportunities in the sectors that different parts of the country care most about, like health care, education, and manufacturing.","path":"english2/2024.html"},{"id":"english2-2024-t2-p1-s1","examKey":"english2","examLabel":"英语二","year":"2024","text":2,"paragraph":1,"sentenceNo":1,"sentence":"Q26 段落定位 1 The UK is facing a future construction crisis because of a failure to plant trees to produce wood, Confor has warned.","path":"english2/2024.html"},{"id":"english2-2024-t2-p1-s2","examKey":"english2","examLabel":"英语二","year":"2024","text":2,"paragraph":1,"sentenceNo":2,"sentence":"2 The forestry and wood trade body has called for urgent action to reduce the country’s reliance on timber imports and provide a stable supply of wood for future generations.","path":"english2/2024.html"},{"id":"english2-2024-t2-p1-s3","examKey":"english2","examLabel":"英语二","year":"2024","text":2,"paragraph":1,"sentenceNo":3,"sentence":"3 Currently only 20 per cent of the UK’s wood requirement is home-grown while it remains the second-largest net importer of timber in the world.","path":"english2/2024.html"},{"id":"english2-2024-t2-p2-s1","examKey":"english2","examLabel":"英语二","year":"2024","text":2,"paragraph":2,"sentenceNo":1,"sentence":"1 Coming at a time of fresh incentives from the UK government for landowners to grow more trees, the trade body says these don’t go far enough and fail to promote the benefits of planting them to boost timber supplies.","path":"english2/2024.html"},{"id":"english2-2024-t2-p2-s2","examKey":"english2","examLabel":"英语二","year":"2024","text":2,"paragraph":2,"sentenceNo":2,"sentence":"2 “Not only are we facing a carbon crisis now, but we will also be facing a future construction crisis because of a failure to plant trees to produce wood,” said Stuart Goodall, chief executive of Confor.","path":"english2/2024.html"},{"id":"english2-2024-t2-p2-s3","examKey":"english2","examLabel":"英语二","year":"2024","text":2,"paragraph":2,"sentenceNo":3,"sentence":"3 “For decades we have not taken responsibility for investing in our domestic wood supply, leaving us exposed to fluctuating prices and fighting for future supplies of wood as global demand rises and our own supplies fall.”","path":"english2/2024.html"},{"id":"english2-2024-t2-p3-s1","examKey":"english2","examLabel":"英语二","year":"2024","text":2,"paragraph":3,"sentenceNo":1,"sentence":"1 The UK has ideal conditions for growing wood to build low-carbon homes and is a global leader in certifying that its forests are sustainably managed, Confor says.","path":"english2/2024.html"},{"id":"english2-2024-t2-p3-s2","examKey":"english2","examLabel":"英语二","year":"2024","text":2,"paragraph":3,"sentenceNo":2,"sentence":"2 While around three quarters of Scottish homes are built from Scottish timber, the use of home-grown wood in England is only around 25 per cent.","path":"english2/2024.html"},{"id":"english2-2024-t2-p3-s3","examKey":"english2","examLabel":"英语二","year":"2024","text":2,"paragraph":3,"sentenceNo":3,"sentence":"3 The causes of the UK’s current position are complex and range from outdated perceptions of productive forestry to the decimation of trees by grey squirrels.","path":"english2/2024.html"},{"id":"english2-2024-t2-p3-s4","examKey":"english2","examLabel":"英语二","year":"2024","text":2,"paragraph":3,"sentenceNo":4,"sentence":"4 It also encompasses significant hesitation on behalf of farmers and other landowners to invest in longer-term planting projects.","path":"english2/2024.html"},{"id":"english2-2024-t2-p4-s1","examKey":"english2","examLabel":"英语二","year":"2024","text":2,"paragraph":4,"sentenceNo":1,"sentence":"1 While productive tree planting can deliver real financial benefits to rural economies and contribute to the UK’s net-zero strategy, the focus of government support continues to be on food production and the rewilding and planting of native woodland solely for biodiversity.","path":"english2/2024.html"},{"id":"english2-2024-t2-p4-s2","examKey":"english2","examLabel":"英语二","year":"2024","text":2,"paragraph":4,"sentenceNo":2,"sentence":"2 Goodall added: “ While food production and biodiversity health are clearly of critical importance, we need our land to also provide secure supplies of wood for construction, manufacturing and contributing to net zero. ”","path":"english2/2024.html"},{"id":"english2-2024-t2-p5-s1","examKey":"english2","examLabel":"英语二","year":"2024","text":2,"paragraph":5,"sentenceNo":1,"sentence":"1 “While the UK government has stated its ambition for more tree planting, there has been little action on the ground.","path":"english2/2024.html"},{"id":"english2-2024-t2-p5-s2","examKey":"english2","examLabel":"英语二","year":"2024","text":2,"paragraph":5,"sentenceNo":2,"sentence":"2 Confor is now calling for much greater impetus behind those aspirations to ensure we have enough wood to meet increasing demand. ”","path":"english2/2024.html"},{"id":"english2-2024-t3-p1-s1","examKey":"english2","examLabel":"英语二","year":"2024","text":3,"paragraph":1,"sentenceNo":1,"sentence":"Q31 段落定位 1 One of the biggest challenges in keeping unsafe aging drivers off the road is convincing them that it’s time to turn over the keys.","path":"english2/2024.html"},{"id":"english2-2024-t3-p1-s2","examKey":"english2","examLabel":"英语二","year":"2024","text":3,"paragraph":1,"sentenceNo":2,"sentence":"2 “It’s a complete life-changer” when someone stops—or is forced to stop—driving, said former risk manager Anne M.","path":"english2/2024.html"},{"id":"english2-2024-t3-p1-s3","examKey":"english2","examLabel":"英语二","year":"2024","text":3,"paragraph":1,"sentenceNo":3,"sentence":"Menke.","path":"english2/2024.html"},{"id":"english2-2024-t3-p2-s1","examKey":"english2","examLabel":"英语二","year":"2024","text":3,"paragraph":2,"sentenceNo":1,"sentence":"1 “The American Medical Association advises physicians that ‘in situations where clear evidence of substantial driving impairment implies a strong threat to patient and public safety, and where the physician’s advice to discontinue driving privilege is ignored, it is desirable and ethical to notify the Department of Motor Vehicles,’” Menke wrote.","path":"english2/2024.html"},{"id":"english2-2024-t3-p2-s2","examKey":"english2","examLabel":"英语二","year":"2024","text":3,"paragraph":2,"sentenceNo":2,"sentence":"2 Some states require physicians to report, others allow but do not mandate reports, while a few consider a report a breach of confidentiality.","path":"english2/2024.html"},{"id":"english2-2024-t3-p2-s3","examKey":"english2","examLabel":"英语二","year":"2024","text":3,"paragraph":2,"sentenceNo":3,"sentence":"3 There could be liability and penalties if a physician does not act in accordance with state laws on reporting and confidentiality,” she counseled.","path":"english2/2024.html"},{"id":"english2-2024-t3-p3-s1","examKey":"english2","examLabel":"英语二","year":"2024","text":3,"paragraph":3,"sentenceNo":1,"sentence":"1 Part of the problem in keeping older drivers safe is that the difficulties are addressed piecemeal by different professions with different focuses, including gerontologists, highway administration officials, automotive engineers and others, said gerontologist Elizabeth Dugan.","path":"english2/2024.html"},{"id":"english2-2024-t3-p3-s2","examKey":"english2","examLabel":"英语二","year":"2024","text":3,"paragraph":3,"sentenceNo":2,"sentence":"2 “There’s not a National Institute of Older Driver Studies,” she said.","path":"english2/2024.html"},{"id":"english2-2024-t3-p3-s3","examKey":"english2","examLabel":"英语二","year":"2024","text":3,"paragraph":3,"sentenceNo":3,"sentence":"3 “We need better evidence on what makes drivers unsafe” and what can help, said Dugan.","path":"english2/2024.html"},{"id":"english2-2024-t3-p4-s1","examKey":"english2","examLabel":"英语二","year":"2024","text":3,"paragraph":4,"sentenceNo":1,"sentence":"1 One thing that does seem to work is requiring drivers to report in person for license renewal.","path":"english2/2024.html"},{"id":"english2-2024-t3-p4-s2","examKey":"english2","examLabel":"英语二","year":"2024","text":3,"paragraph":4,"sentenceNo":2,"sentence":"2 Mandatory in-person renewal was associated with a 31 per cent reduction in fatal crashes involving drivers 85 or older, according to one study.","path":"english2/2024.html"},{"id":"english2-2024-t3-p4-s3","examKey":"english2","examLabel":"英语二","year":"2024","text":3,"paragraph":4,"sentenceNo":3,"sentence":"3 Passing vision tests also produced a similar decline in fatal crashes for those drivers, although there appeared to be no benefit from combining the two.","path":"english2/2024.html"},{"id":"english2-2024-t3-p5-s1","examKey":"english2","examLabel":"英语二","year":"2024","text":3,"paragraph":5,"sentenceNo":1,"sentence":"1 Many older drivers don’t see eye doctors or can’t afford to.","path":"english2/2024.html"},{"id":"english2-2024-t3-p5-s2","examKey":"english2","examLabel":"英语二","year":"2024","text":3,"paragraph":5,"sentenceNo":2,"sentence":"2 Primary care providers have their hands full and may not be able to follow through with patients who have trouble driving because they can’t turn their heads or remember where they are going —or have gotten shorter and haven’t changed their seat settings sufficiently to reach car pedals easily.","path":"english2/2024.html"},{"id":"english2-2024-t3-p6-s1","examKey":"english2","examLabel":"英语二","year":"2024","text":3,"paragraph":6,"sentenceNo":1,"sentence":"1 As long as there are other cars on the roads, self-driving cars won’t solve the problems of crashes, said Dugan.","path":"english2/2024.html"},{"id":"english2-2024-t3-p6-s2","examKey":"english2","examLabel":"英语二","year":"2024","text":3,"paragraph":6,"sentenceNo":2,"sentence":"2 Avoiding dangers posed by all those human drivers would require too many algorithms, she said.","path":"english2/2024.html"},{"id":"english2-2024-t3-p6-s3","examKey":"english2","examLabel":"英语二","year":"2024","text":3,"paragraph":6,"sentenceNo":3,"sentence":"3 But we need to do more to improve safety, said Dugan.","path":"english2/2024.html"},{"id":"english2-2024-t3-p6-s4","examKey":"english2","examLabel":"英语二","year":"2024","text":3,"paragraph":6,"sentenceNo":4,"sentence":"4 “If we’re going to have 100-year lives, we need cars that a 90-year-old can drive comfortably.”","path":"english2/2024.html"},{"id":"english2-2024-t4-p1-s1","examKey":"english2","examLabel":"英语二","year":"2024","text":4,"paragraph":1,"sentenceNo":1,"sentence":"Q36 段落定位 1 If you look at the apps on your phone, chances are you have at least one related to your health—and probably several.","path":"english2/2024.html"},{"id":"english2-2024-t4-p1-s2","examKey":"english2","examLabel":"英语二","year":"2024","text":4,"paragraph":1,"sentenceNo":2,"sentence":"2 Whether it is a mental health app, a fitness tracker, a connected health device or something else, many of us are taking advantage of this technology to keep better track of our health in some shape or form.","path":"english2/2024.html"},{"id":"english2-2024-t4-p1-s3","examKey":"english2","examLabel":"英语二","year":"2024","text":4,"paragraph":1,"sentenceNo":3,"sentence":"3 Recent research findings from the Organization for the Review of Care and Health Applications found that 350,000 health apps were available on the market, 90,000 of which launched in 2020 alone.","path":"english2/2024.html"},{"id":"english2-2024-t4-p2-s1","examKey":"english2","examLabel":"英语二","year":"2024","text":4,"paragraph":2,"sentenceNo":1,"sentence":"1 While these apps have a great deal to offer, it is not always clear how the personal information we input is collected, safeguarded and shared online.","path":"english2/2024.html"},{"id":"english2-2024-t4-p2-s2","examKey":"english2","examLabel":"英语二","year":"2024","text":4,"paragraph":2,"sentenceNo":2,"sentence":"2 Existing health privacy law, such as the Health Insurance Portability and Accountability Act, is primarily focused on the way hospitals, doctors’ offices, clinics and insurance companies store health records online.","path":"english2/2024.html"},{"id":"english2-2024-t4-p2-s3","examKey":"english2","examLabel":"英语二","year":"2024","text":4,"paragraph":2,"sentenceNo":3,"sentence":"3 The health information these apps and health data tracking wearables are collecting typically does not receive the same legal protections.","path":"english2/2024.html"},{"id":"english2-2024-t4-p3-s1","examKey":"english2","examLabel":"英语二","year":"2024","text":4,"paragraph":3,"sentenceNo":1,"sentence":"1 Without additional protections in place, companies may share (and potentially monetize) personal health information in a way consumers may not have authorized or anticipated.","path":"english2/2024.html"},{"id":"english2-2024-t4-p3-s2","examKey":"english2","examLabel":"英语二","year":"2024","text":4,"paragraph":3,"sentenceNo":2,"sentence":"2 In 2021, Flo Health faced a Federal Trade Commission (FTC) investigation.","path":"english2/2024.html"},{"id":"english2-2024-t4-p3-s3","examKey":"english2","examLabel":"英语二","year":"2024","text":4,"paragraph":3,"sentenceNo":3,"sentence":"3 The FTC alleged in a complaint that “despite express privacy claims, the company took control of users’ sensitive fertility data and shared it with third parties.” 4 Flo Health and the FTC settled the matter with a Consent Order requiring the company to get app users’ express affirmative consent before sharing their health information as well as to instruct the third parties to delete the data they had obtained.","path":"english2/2024.html"},{"id":"english2-2024-t4-p4-s1","examKey":"english2","examLabel":"英语二","year":"2024","text":4,"paragraph":4,"sentenceNo":1,"sentence":"1 Section 5 of the FTC Act empowers the FTC to initiate enforcement action against unfair or deceptive acts, meaning the FTC can only act after the fact if a company’s privacy practices are misleading or cause unjustified consumer harm.","path":"english2/2024.html"},{"id":"english2-2024-t4-p4-s2","examKey":"english2","examLabel":"英语二","year":"2024","text":4,"paragraph":4,"sentenceNo":2,"sentence":"2 While the FTC is doing what it can to ensure apps are keeping their promises to consumers around the handling of their sensitive health information, the rate at which these health apps are hitting the market demonstrates just how immense of a challenge this is.","path":"english2/2024.html"},{"id":"english2-2024-t4-p5-s1","examKey":"english2","examLabel":"英语二","year":"2024","text":4,"paragraph":5,"sentenceNo":1,"sentence":"Q40 末段定位 1 As to the prospects for federal legislation, commentators suggest that comprehensive federal privacy legislation seems unlikely in the short term.","path":"english2/2024.html"},{"id":"english2-2024-t4-p5-s2","examKey":"english2","examLabel":"英语二","year":"2024","text":4,"paragraph":5,"sentenceNo":2,"sentence":"2 States have begun implementing their own solutions to shore up protections for consumer-generated health data.","path":"english2/2024.html"},{"id":"english2-2024-t4-p5-s3","examKey":"english2","examLabel":"英语二","year":"2024","text":4,"paragraph":5,"sentenceNo":3,"sentence":"3 California has been at the forefront of state privacy efforts with the California Consumer Privacy Act of 2018.","path":"english2/2024.html"},{"id":"english2-2024-t4-p5-s4","examKey":"english2","examLabel":"英语二","year":"2024","text":4,"paragraph":5,"sentenceNo":4,"sentence":"4 Virginia, Colorado and Utah have also recently passed state consumer data privacy legislation.","path":"english2/2024.html"},{"id":"english1-2025-t1-p1-s1","examKey":"english1","examLabel":"英语一","year":"2025","text":1,"paragraph":1,"sentenceNo":1,"sentence":"The grammar school boy from Stratford-upon-Avon has landed a scholarly punch after groundbreaking research showed that Shakespeare does benefit children’s literacy and emotional development.","path":"english1/2025.html"},{"id":"english1-2025-t1-p1-s2","examKey":"english1","examLabel":"英语一","year":"2025","text":1,"paragraph":1,"sentenceNo":2,"sentence":"But only if you act him out.","path":"english1/2025.html"},{"id":"english1-2025-t1-p2-s1","examKey":"english1","examLabel":"英语一","year":"2025","text":1,"paragraph":2,"sentenceNo":1,"sentence":"A study found that a “rehearsal room” approach to teaching Shakespeare broadened children’s vocabulary and the complexity of their writing as well as their emotional literacy.","path":"english1/2025.html"},{"id":"english1-2025-t1-p2-s2","examKey":"english1","examLabel":"英语一","year":"2025","text":1,"paragraph":2,"sentenceNo":2,"sentence":"“The research shows that the way actors work makes a big difference to the way children use language and also how they think about themselves,” Jacqui O’Hanlon of the Royal Shakespeare Company (RSC), which commissioned the study, said.","path":"english1/2025.html"},{"id":"english1-2025-t1-p3-s1","examKey":"english1","examLabel":"英语一","year":"2025","text":1,"paragraph":3,"sentenceNo":1,"sentence":"The randomised control trial involved hundreds of year 5 pupils —aged nine and ten—at 45 state primary schools that had not been “previously exposed to RSC pedagogy.” They were split into target and control groups and asked to write, for example, a message in a bottle as Ferdinand following the shipwreck in The Tempest.","path":"english1/2025.html"},{"id":"english1-2025-t1-p3-s2","examKey":"english1","examLabel":"英语一","year":"2025","text":1,"paragraph":3,"sentenceNo":2,"sentence":"The target group were given a 30-minute drama-based activity to accompany the passage.","path":"english1/2025.html"},{"id":"english1-2025-t1-p4-s1","examKey":"english1","examLabel":"英语一","year":"2025","text":1,"paragraph":4,"sentenceNo":1,"sentence":"The peer-reviewed results showed that the target group of pupils drew on a wider vocabulary, used words “classed as more sophisticated or rarer”, and wrote at greater length.","path":"english1/2025.html"},{"id":"english1-2025-t1-p4-s2","examKey":"english1","examLabel":"英语一","year":"2025","text":1,"paragraph":4,"sentenceNo":2,"sentence":"They also “appear to be more comfortable writing in role... while [control] pupils imagine how they themselves would react to being shipwrecked, [target] children put themselves in the shoes of a literary character and express that character’s emotion”.","path":"english1/2025.html"},{"id":"english1-2025-t1-p4-s3","examKey":"english1","examLabel":"英语一","year":"2025","text":1,"paragraph":4,"sentenceNo":3,"sentence":"The Time to Act study, which is published by the RSC this week, also found that while control pupils relied on “desert island clichés” such as palm trees, target pupils were “more expansive [giving] a broader picture of the sky, the sea and the atmospheric conditions”.","path":"english1/2025.html"},{"id":"english1-2025-t1-p5-s1","examKey":"english1","examLabel":"英语一","year":"2025","text":1,"paragraph":5,"sentenceNo":1,"sentence":"O’Hanlon said she had been most surprised by the “emotional literacy” that was evident in the [target] children’s writing and that they were “more resilient in their writing, more hopeful”.","path":"english1/2025.html"},{"id":"english1-2025-t1-p5-s2","examKey":"english1","examLabel":"英语一","year":"2025","text":1,"paragraph":5,"sentenceNo":2,"sentence":"She added “The emotional understanding was very evident and it is probably related to the [rehearsal room process] where you are used to trying to imagine your way through.","path":"english1/2025.html"},{"id":"english1-2025-t1-p5-s3","examKey":"english1","examLabel":"英语一","year":"2025","text":1,"paragraph":5,"sentenceNo":3,"sentence":"They were comfortable in describing different emotional states and part of what you do in drama is put yourself in different shoes.” The study showed the importance of embedding arts in education, she said.","path":"english1/2025.html"},{"id":"english1-2025-t1-p6-s1","examKey":"english1","examLabel":"英语一","year":"2025","text":1,"paragraph":6,"sentenceNo":1,"sentence":"But could the results be replicated with any old dramatist?","path":"english1/2025.html"},{"id":"english1-2025-t1-p6-s2","examKey":"english1","examLabel":"英语一","year":"2025","text":1,"paragraph":6,"sentenceNo":2,"sentence":"O’Hanlon said more research would be needed but suggested that Shakespeare’s use of 20,000 words, compared with the everyday 2,000 words, gave a “massive expansion of language into children’s lives”, which was combined with children “using their whole bodies to bring words to life”.","path":"english1/2025.html"},{"id":"english1-2025-t2-p1-s1","examKey":"english1","examLabel":"英语一","year":"2025","text":2,"paragraph":1,"sentenceNo":1,"sentence":"I was shocked to learn recently that some scientists want to scale back their research in an effort to decrease carbon emissions.","path":"english1/2025.html"},{"id":"english1-2025-t2-p1-s2","examKey":"english1","examLabel":"英语一","year":"2025","text":2,"paragraph":1,"sentenceNo":2,"sentence":"The crisis is here, they said, and we need to cut back on our energy-intensive modelling.","path":"english1/2025.html"},{"id":"english1-2025-t2-p1-s3","examKey":"english1","examLabel":"英语一","year":"2025","text":2,"paragraph":1,"sentenceNo":3,"sentence":"At the very least, we need to make our energy use far more sustainable.","path":"english1/2025.html"},{"id":"english1-2025-t2-p2-s1","examKey":"english1","examLabel":"英语一","year":"2025","text":2,"paragraph":2,"sentenceNo":1,"sentence":"It is unarguable that our laboratories, scientific instruments, rockets and satellites—the tools we scientists need to measure the planet’s pulse—demand significant amounts of energy both in their construction and operation.","path":"english1/2025.html"},{"id":"english1-2025-t2-p2-s2","examKey":"english1","examLabel":"英语一","year":"2025","text":2,"paragraph":2,"sentenceNo":2,"sentence":"And it is equally true that science’s unrelenting appetite for information has ca used a mushrooming of energy-intensive data centres around the world.","path":"english1/2025.html"},{"id":"english1-2025-t2-p2-s3","examKey":"english1","examLabel":"英语一","year":"2025","text":2,"paragraph":2,"sentenceNo":3,"sentence":"According to the International Energy Agency, these buildings now consume about 1 percent of the world’s electricity.","path":"english1/2025.html"},{"id":"english1-2025-t2-p3-s1","examKey":"english1","examLabel":"英语一","year":"2025","text":2,"paragraph":3,"sentenceNo":1,"sentence":"However, this is a price we must pay for understanding the world.","path":"english1/2025.html"},{"id":"english1-2025-t2-p3-s2","examKey":"english1","examLabel":"英语一","year":"2025","text":2,"paragraph":3,"sentenceNo":2,"sentence":"How can we inform decision makers about the best ways to bring down carbon emissions if we can’t track the amount of carbon dioxide in the atmosphere, where it’s coming from and who’s producing it?","path":"english1/2025.html"},{"id":"english1-2025-t2-p3-s3","examKey":"english1","examLabel":"英语一","year":"2025","text":2,"paragraph":3,"sentenceNo":3,"sentence":"The carbon emissions from technological research are well spent: ultimately this research will safeguard the future of our planet.","path":"english1/2025.html"},{"id":"english1-2025-t2-p4-s1","examKey":"english1","examLabel":"英语一","year":"2025","text":2,"paragraph":4,"sentenceNo":1,"sentence":"It can be hard for scientists to make the case because our work is complex, often takes place behind closed doors and does not always lend itself to easy interpretation or explanation.","path":"english1/2025.html"},{"id":"english1-2025-t2-p4-s2","examKey":"english1","examLabel":"英语一","year":"2025","text":2,"paragraph":4,"sentenceNo":2,"sentence":"But demonstrating the efficacy of science will be crucial if we are to solve humanity’s greatest challenges.","path":"english1/2025.html"},{"id":"english1-2025-t2-p4-s3","examKey":"english1","examLabel":"英语一","year":"2025","text":2,"paragraph":4,"sentenceNo":3,"sentence":"It is all too easy to feel paralysed in the face of daunting problems such as climate change and to do nothing.","path":"english1/2025.html"},{"id":"english1-2025-t2-p4-s4","examKey":"english1","examLabel":"英语一","year":"2025","text":2,"paragraph":4,"sentenceNo":4,"sentence":"But then I think of a friend’s daughter who turned her fears into action: she became a wind energy engineer and now thrives on delivering renewable energy, limiting emissions.","path":"english1/2025.html"},{"id":"english1-2025-t2-p5-s1","examKey":"english1","examLabel":"英语一","year":"2025","text":2,"paragraph":5,"sentenceNo":1,"sentence":"Recognising the hope that science and engineering can bring was the impetus behind the creation of the Millennium Technology Prize, which is now entering its 20th year as a celebration of human ingenuity.","path":"english1/2025.html"},{"id":"english1-2025-t2-p5-s2","examKey":"english1","examLabel":"英语一","year":"2025","text":2,"paragraph":5,"sentenceNo":2,"sentence":"One of the past winners, Professor Martin Green from the University of New South Wales, Australia, is the inventor of the Passivated Emitter and Rear Cell technology which is now found in most of the world’s solar panels.","path":"english1/2025.html"},{"id":"english1-2025-t2-p5-s3","examKey":"english1","examLabel":"英语一","year":"2025","text":2,"paragraph":5,"sentenceNo":3,"sentence":"Thanks to his invention, we have a real chance to decrease the world’s carbon emissions.","path":"english1/2025.html"},{"id":"english1-2025-t2-p6-s1","examKey":"english1","examLabel":"英语一","year":"2025","text":2,"paragraph":6,"sentenceNo":1,"sentence":"Every day, scientists, technologists and engineers are discovering new ways to exploit renewable energy sources and develop techniques not just to use power more intelligently but to power our intelligence.","path":"english1/2025.html"},{"id":"english1-2025-t2-p6-s2","examKey":"english1","examLabel":"英语一","year":"2025","text":2,"paragraph":6,"sentenceNo":2,"sentence":"A great example of this is Europe’s largest supercomputer, LUMI in Finland, which is astonishingly carbon-negative.","path":"english1/2025.html"},{"id":"english1-2025-t2-p6-s3","examKey":"english1","examLabel":"英语一","year":"2025","text":2,"paragraph":6,"sentenceNo":3,"sentence":"Established in an old paper mill, it is powered by a nearby river and its remote heat warms the people who live in the surrounding town of Kajaani.","path":"english1/2025.html"},{"id":"english1-2025-t2-p7-s1","examKey":"english1","examLabel":"英语一","year":"2025","text":2,"paragraph":7,"sentenceNo":1,"sentence":"If the world is to meet its net-zero ambitions, we must think hard about how we can deliver sustainable computing and deliver more LUMIs.","path":"english1/2025.html"},{"id":"english1-2025-t3-p1-s1","examKey":"english1","examLabel":"英语一","year":"2025","text":3,"paragraph":1,"sentenceNo":1,"sentence":"Ever since taking on Netflix Inc. at its own game, old Hollywood has struggled to turn a profit in streaming, with the likes of Disney+, Peacock and Paramount+ losing billions of dollars each year, sparking concerns that the services will never be as profitable as cable once was.","path":"english1/2025.html"},{"id":"english1-2025-t3-p1-s2","examKey":"english1","examLabel":"英语一","year":"2025","text":3,"paragraph":1,"sentenceNo":2,"sentence":"But the age of streaming has been a boon for some unintended winners: pirates that use software to rip a film or television show in seconds from legitimate online video platforms and host the titles on their own, illegitimate services, which rake in about $2 billion annually from ads and subscriptions.","path":"english1/2025.html"},{"id":"english1-2025-t3-p2-s1","examKey":"english1","examLabel":"英语一","year":"2025","text":3,"paragraph":2,"sentenceNo":1,"sentence":"With no video production costs, illegal streaming sites have achieved profit margins approaching 90%, according to the Motion Picture Association (MPA), a trade group representing Hollywood studios that’s working to crack down on the thousands of illegal platforms that have cropped up in recent years.","path":"english1/2025.html"},{"id":"english1-2025-t3-p3-s1","examKey":"english1","examLabel":"英语一","year":"2025","text":3,"paragraph":3,"sentenceNo":1,"sentence":"Initially the rise of legitimate online businesses such as Netflix actually helped curb digital piracy, which had largely been based on file uploads.","path":"english1/2025.html"},{"id":"english1-2025-t3-p3-s2","examKey":"english1","examLabel":"英语一","year":"2025","text":3,"paragraph":3,"sentenceNo":2,"sentence":"But now piracy involving illegal streaming services as well as file-sharing costs the US economy about $30 billion in lost revenue a year and some 250,000 jobs, estimates the US Chamber of Commerce’s Global Innovation Policy Center.","path":"english1/2025.html"},{"id":"english1-2025-t3-p3-s3","examKey":"english1","examLabel":"英语一","year":"2025","text":3,"paragraph":3,"sentenceNo":3,"sentence":"The global impact is about $71 billion annually.","path":"english1/2025.html"},{"id":"english1-2025-t3-p4-s1","examKey":"english1","examLabel":"英语一","year":"2025","text":3,"paragraph":4,"sentenceNo":1,"sentence":"“The people who are stealing our movies and our television shows and operating piracy sites are not mom and pop operations,” says Charlie Rivkin, chief executive officer of the MPA.","path":"english1/2025.html"},{"id":"english1-2025-t3-p4-s2","examKey":"english1","examLabel":"英语一","year":"2025","text":3,"paragraph":4,"sentenceNo":2,"sentence":"“This is organized crime.” Rivkin joined the MPA in 2017 after the organization failed five years earlier to build consensus between Hollywood and Silicon Valley to win passage of legislation in Congress aimed at stopping online piracy.","path":"english1/2025.html"},{"id":"english1-2025-t3-p4-s3","examKey":"english1","examLabel":"英语一","year":"2025","text":3,"paragraph":4,"sentenceNo":3,"sentence":"In 2017 the association formed the Alliance for Creativity and Entertainment (ACE), an enforcement task force of about 100 detectives circling the globe to help local authorities arrest streaming pirates.","path":"english1/2025.html"},{"id":"english1-2025-t3-p5-s1","examKey":"english1","examLabel":"英语一","year":"2025","text":3,"paragraph":5,"sentenceNo":1,"sentence":"ACE says it’s helped shrink the number of illegal streaming services in North America to 126, from more than 1,400 in 2018, aided in part by the MPA’s support for a 2020 federal law that made large-scale streaming of copyright material a serious crime.","path":"english1/2025.html"},{"id":"english1-2025-t3-p5-s2","examKey":"english1","examLabel":"英语一","year":"2025","text":3,"paragraph":5,"sentenceNo":2,"sentence":"Consulting firm Parks Associates predicts that legitimate US streaming services’ cumulative loss from piracy since 2022 will reach $113 billion in the next two years.","path":"english1/2025.html"},{"id":"english1-2025-t3-p5-s3","examKey":"english1","examLabel":"英语一","year":"2025","text":3,"paragraph":5,"sentenceNo":3,"sentence":"“While there is some optimism that emerging countermeasures and best practices may see piracy begin to plateau by 2027, there is no consensus among stakeholders as to when it may begin to decline,” says analyst Steve Hawley.","path":"english1/2025.html"},{"id":"english1-2025-t4-p1-s1","examKey":"english1","examLabel":"英语一","year":"2025","text":4,"paragraph":1,"sentenceNo":1,"sentence":"Visit any antiques store and you’ll encounter artifacts from the past: photographs, letters, a brochure detailing the Sinclair dinosaur exhibit from the 1964-1965 World’s Fair, the ephemera of history.","path":"english1/2025.html"},{"id":"english1-2025-t4-p1-s2","examKey":"english1","examLabel":"英语一","year":"2025","text":4,"paragraph":1,"sentenceNo":2,"sentence":"Yet these objects aren’t truly ephemeral, because they’re still here, decades, even centuries later.","path":"english1/2025.html"},{"id":"english1-2025-t4-p1-s3","examKey":"english1","examLabel":"英语一","year":"2025","text":4,"paragraph":1,"sentenceNo":3,"sentence":"Why?","path":"english1/2025.html"},{"id":"english1-2025-t4-p1-s4","examKey":"english1","examLabel":"英语一","year":"2025","text":4,"paragraph":1,"sentenceNo":4,"sentence":"Because they’re tangible.","path":"english1/2025.html"},{"id":"english1-2025-t4-p2-s1","examKey":"english1","examLabel":"英语一","year":"2025","text":4,"paragraph":2,"sentenceNo":1,"sentence":"Have you pondered the life cycle of intangible formats, digital information, given that those who produce these artifacts seldom make provision for their long-term preservation?","path":"english1/2025.html"},{"id":"english1-2025-t4-p2-s2","examKey":"english1","examLabel":"英语一","year":"2025","text":4,"paragraph":2,"sentenceNo":2,"sentence":"For millennia, we’ve known what we’ve known due to artifacts that have survived, often despite their original creators’ neglect.","path":"english1/2025.html"},{"id":"english1-2025-t4-p2-s3","examKey":"english1","examLabel":"英语一","year":"2025","text":4,"paragraph":2,"sentenceNo":3,"sentence":"The thing itself is the medium that delivers the information.","path":"english1/2025.html"},{"id":"english1-2025-t4-p2-s4","examKey":"english1","examLabel":"英语一","year":"2025","text":4,"paragraph":2,"sentenceNo":4,"sentence":"At the time of creation, no attempts were made at intentional preservation, yet analog materials have a chance of surviving and serving as the historical record that biographers, historians, and novelists rely on.","path":"english1/2025.html"},{"id":"english1-2025-t4-p2-s5","examKey":"english1","examLabel":"英语一","year":"2025","text":4,"paragraph":2,"sentenceNo":5,"sentence":"Libraries and archives have traditionally shouldered the responsibility of organization, preservation, and access to information.","path":"english1/2025.html"},{"id":"english1-2025-t4-p2-s6","examKey":"english1","examLabel":"英语一","year":"2025","text":4,"paragraph":2,"sentenceNo":6,"sentence":"Thus, librarians digitize the tangible so that researchers the world over can quickly search and access their holdings.","path":"english1/2025.html"},{"id":"english1-2025-t4-p2-s7","examKey":"english1","examLabel":"英语一","year":"2025","text":4,"paragraph":2,"sentenceNo":7,"sentence":"The result is an embarrassment of historical riches, which brings its own needle-and-haystack problems.","path":"english1/2025.html"},{"id":"english1-2025-t4-p3-s1","examKey":"english1","examLabel":"英语一","year":"2025","text":4,"paragraph":3,"sentenceNo":1,"sentence":"Librarians’ selfless devotion can act against us when users point to universality of access by holding up a cellphone and saying, “it’s all in here” as evidence that libraries are less vital for researchers today.","path":"english1/2025.html"},{"id":"english1-2025-t4-p3-s2","examKey":"english1","examLabel":"英语一","year":"2025","text":4,"paragraph":3,"sentenceNo":2,"sentence":"Yet how was that universality of access made possible and, perhaps more importantly, how is it maintained?","path":"english1/2025.html"},{"id":"english1-2025-t4-p3-s3","examKey":"english1","examLabel":"英语一","year":"2025","text":4,"paragraph":3,"sentenceNo":3,"sentence":"Who curates what is preserved?","path":"english1/2025.html"},{"id":"english1-2025-t4-p3-s4","examKey":"english1","examLabel":"英语一","year":"2025","text":4,"paragraph":3,"sentenceNo":4,"sentence":"When it comes to born-digital information, the terrifying answer can be: if not librarians and archivists, then no one.","path":"english1/2025.html"},{"id":"english1-2025-t4-p3-s5","examKey":"english1","examLabel":"英语一","year":"2025","text":4,"paragraph":3,"sentenceNo":5,"sentence":"Digital information requires a great deal more care than analog.","path":"english1/2025.html"},{"id":"english1-2025-t4-p4-s1","examKey":"english1","examLabel":"英语一","year":"2025","text":4,"paragraph":4,"sentenceNo":1,"sentence":"Even when a digital object is preserved, it may only be the carrier that’s saved, not the information itself.","path":"english1/2025.html"},{"id":"english1-2025-t4-p4-s2","examKey":"english1","examLabel":"英语一","year":"2025","text":4,"paragraph":4,"sentenceNo":2,"sentence":"As technology advances and a format becomes obsolete, the object is useless.","path":"english1/2025.html"},{"id":"english1-2025-t4-p4-s3","examKey":"english1","examLabel":"英语一","year":"2025","text":4,"paragraph":4,"sentenceNo":3,"sentence":"Have you ever stared helplessly at a ZIP disk, thinking: how do I get the files off this?","path":"english1/2025.html"},{"id":"english1-2025-t4-p4-s4","examKey":"english1","examLabel":"英语一","year":"2025","text":4,"paragraph":4,"sentenceNo":4,"sentence":"Without constant migration of digital assets, a nightmare about the foreseeable future is what keeps historians up at night: a historical record that abruptly stops when digital replace analog.","path":"english1/2025.html"},{"id":"english1-2025-t4-p5-s1","examKey":"english1","examLabel":"英语一","year":"2025","text":4,"paragraph":5,"sentenceNo":1,"sentence":"As a librarian whose day job revolves around special collections and digital assets, I share the night terrors of historians, and I’d be lying if I said a comprehensive preservation solution currently exists.","path":"english1/2025.html"},{"id":"english1-2025-t4-p5-s2","examKey":"english1","examLabel":"英语一","year":"2025","text":4,"paragraph":5,"sentenceNo":2,"sentence":"Yet researchers can take some comfort in the fact that there are a multitude of librarians devoted to discovering, organizing, and preserving digital information for researchers current and future.","path":"english1/2025.html"},{"id":"english1-2025-t4-p5-s3","examKey":"english1","examLabel":"英语一","year":"2025","text":4,"paragraph":5,"sentenceNo":3,"sentence":"Librarians are uniquely positioned to understand how end users seek and use information.","path":"english1/2025.html"},{"id":"english1-2025-t4-p5-s4","examKey":"english1","examLabel":"英语一","year":"2025","text":4,"paragraph":5,"sentenceNo":4,"sentence":"Thus we play an integral role in identifying, preserving, and providing accessibility to digital artifacts so that, while future researchers may find the digital realm a challenging place to ply their trade, they won’t find it an impossible one.","path":"english1/2025.html"},{"id":"english2-2025-t1-p1-s1","examKey":"english2","examLabel":"英语二","year":"2025","text":1,"paragraph":1,"sentenceNo":1,"sentence":"Q21 段落定位 U.S. customers historically tipped people they assumed were earning most of their income via tips, such as restaurant servers earning less than the minimum wage.","path":"english2/2025.html"},{"id":"english2-2025-t1-p1-s2","examKey":"english2","examLabel":"英语二","year":"2025","text":1,"paragraph":1,"sentenceNo":2,"sentence":"In the early 2010s, a wide range of businesses started processing purchases with iPads and other digital payment systems.","path":"english2/2025.html"},{"id":"english2-2025-t1-p1-s3","examKey":"english2","examLabel":"英语二","year":"2025","text":1,"paragraph":1,"sentenceNo":3,"sentence":"These systems often prompted customers to tip for services that were not previously tipped.","path":"english2/2025.html"},{"id":"english2-2025-t1-p2-s1","examKey":"english2","examLabel":"英语二","year":"2025","text":1,"paragraph":2,"sentenceNo":1,"sentence":"Q22 段落定位 Today’s tip requests are often not connected to the salary and service norms that used to determine when and how people tip.","path":"english2/2025.html"},{"id":"english2-2025-t1-p2-s2","examKey":"english2","examLabel":"英语二","year":"2025","text":1,"paragraph":2,"sentenceNo":2,"sentence":"Customers in the past nearly always paid tips after receiving a service, such as at the conclusion of a restaurant meal, after getting a haircut or once a pizza was delivered.","path":"english2/2025.html"},{"id":"english2-2025-t1-p2-s3","examKey":"english2","examLabel":"英语二","year":"2025","text":1,"paragraph":2,"sentenceNo":3,"sentence":"That timing could reward high-quality service and give workers an incentive to provide it.","path":"english2/2025.html"},{"id":"english2-2025-t1-p3-s1","examKey":"english2","examLabel":"英语二","year":"2025","text":1,"paragraph":3,"sentenceNo":1,"sentence":"It’s becoming more common for tips to be requested beforehand.","path":"english2/2025.html"},{"id":"english2-2025-t1-p3-s2","examKey":"english2","examLabel":"英语二","year":"2025","text":1,"paragraph":3,"sentenceNo":2,"sentence":"And new tipping technology may even automatically add tips.","path":"english2/2025.html"},{"id":"english2-2025-t1-p4-s1","examKey":"english2","examLabel":"英语二","year":"2025","text":1,"paragraph":4,"sentenceNo":1,"sentence":"Q23 段落定位 The prevalence of digital payment devices has made it easier to ask customers for a tip.","path":"english2/2025.html"},{"id":"english2-2025-t1-p4-s2","examKey":"english2","examLabel":"英语二","year":"2025","text":1,"paragraph":4,"sentenceNo":2,"sentence":"That helps explain why tip requests are creeping into new kinds of services.","path":"english2/2025.html"},{"id":"english2-2025-t1-p4-s3","examKey":"english2","examLabel":"英语二","year":"2025","text":1,"paragraph":4,"sentenceNo":3,"sentence":"Customers now routinely see menus of suggested default options—often well above 20% of what they owe.","path":"english2/2025.html"},{"id":"english2-2025-t1-p4-s4","examKey":"english2","examLabel":"英语二","year":"2025","text":1,"paragraph":4,"sentenceNo":4,"sentence":"The amounts have risen from 10% or less in the 1950s to 15% around the year 2000 to 20% or higher today.","path":"english2/2025.html"},{"id":"english2-2025-t1-p4-s5","examKey":"english2","examLabel":"英语二","year":"2025","text":1,"paragraph":4,"sentenceNo":5,"sentence":"This increase is sometimes called tipflation—the expectation of ever-higher tip amounts.","path":"english2/2025.html"},{"id":"english2-2025-t1-p5-s1","examKey":"english2","examLabel":"英语二","year":"2025","text":1,"paragraph":5,"sentenceNo":1,"sentence":"Tipping has always been a vital source of income for workers in historically tipped services, like restaurants, where the tipped minimum wage can be as low as US$2.13 an hour.","path":"english2/2025.html"},{"id":"english2-2025-t1-p5-s2","examKey":"english2","examLabel":"英语二","year":"2025","text":1,"paragraph":5,"sentenceNo":2,"sentence":"Tip creep and tipflation are now further supplementing the income of many low-wage service workers.","path":"english2/2025.html"},{"id":"english2-2025-t1-p6-s1","examKey":"english2","examLabel":"英语二","year":"2025","text":1,"paragraph":6,"sentenceNo":1,"sentence":"Q24 段落定位 Notably, tipping primarily benefits some of these workers, such as waiters, but not others, such as cooks and dishwashers.","path":"english2/2025.html"},{"id":"english2-2025-t1-p6-s2","examKey":"english2","examLabel":"英语二","year":"2025","text":1,"paragraph":6,"sentenceNo":2,"sentence":"To ensure that all employees were paid fair wages, some restaurants banned tipping and increased prices, but this movement toward no-tipping services has largely fizzled out.","path":"english2/2025.html"},{"id":"english2-2025-t1-p7-s1","examKey":"english2","examLabel":"英语二","year":"2025","text":1,"paragraph":7,"sentenceNo":1,"sentence":"Q25 段落定位 So, to increase employee wages without raising prices, more employers are succumbing to the temptations of tip creep and tipflation.","path":"english2/2025.html"},{"id":"english2-2025-t1-p7-s2","examKey":"english2","examLabel":"英语二","year":"2025","text":1,"paragraph":7,"sentenceNo":2,"sentence":"However, many customers are frustrated because they feel they are being asked for too high of a tip, too often.","path":"english2/2025.html"},{"id":"english2-2025-t1-p7-s3","examKey":"english2","examLabel":"英语二","year":"2025","text":1,"paragraph":7,"sentenceNo":3,"sentence":"And, as our research emphasizes, tipping now seems to be more coercive, less generous and often completely dissociated from service quality.","path":"english2/2025.html"},{"id":"english2-2025-t2-p1-s1","examKey":"english2","examLabel":"英语二","year":"2025","text":2,"paragraph":1,"sentenceNo":1,"sentence":"Q26 段落定位 When it was established, the National Health Service (NHS) was visionary: offering high-quality, timely care to meet the dominant needs of the population it served.","path":"english2/2025.html"},{"id":"english2-2025-t2-p1-s2","examKey":"english2","examLabel":"英语二","year":"2025","text":2,"paragraph":1,"sentenceNo":2,"sentence":"Nearly 75 years on, with the UK facing very different health challenges, it is clear that model is out of date.","path":"english2/2025.html"},{"id":"english2-2025-t2-p2-s1","examKey":"english2","examLabel":"英语二","year":"2025","text":2,"paragraph":2,"sentenceNo":1,"sentence":"Q26 段落定位 From life expectancy to cancer and infant mortality rates, we are lagging behind many of our peers.","path":"english2/2025.html"},{"id":"english2-2025-t2-p2-s2","examKey":"english2","examLabel":"英语二","year":"2025","text":2,"paragraph":2,"sentenceNo":2,"sentence":"With more than 6.8 million on waitlists, healthcare is becoming increasingly inaccessible for those who cannot opt to pay for private treatment; and the cost of providing healthcare is increasingly squeezing out investment in other public services.","path":"english2/2025.html"},{"id":"english2-2025-t2-p2-s3","examKey":"english2","examLabel":"英语二","year":"2025","text":2,"paragraph":2,"sentenceNo":3,"sentence":"As demand for healthcare continues to grow, pressures on the workforce—which is already near breaking point—will only become more acute.","path":"english2/2025.html"},{"id":"english2-2025-t2-p3-s1","examKey":"english2","examLabel":"英语二","year":"2025","text":2,"paragraph":3,"sentenceNo":1,"sentence":"Q27 段落定位 Many of the answers to the crisis in health and care are well rehearsed.","path":"english2/2025.html"},{"id":"english2-2025-t2-p3-s2","examKey":"english2","examLabel":"英语二","year":"2025","text":2,"paragraph":3,"sentenceNo":2,"sentence":"We need to be much better at reducing and diverting demand on health services, rather than simply managing it.","path":"english2/2025.html"},{"id":"english2-2025-t2-p3-s3","examKey":"english2","examLabel":"英语二","year":"2025","text":2,"paragraph":3,"sentenceNo":3,"sentence":"Much more needs to be invested in communities and primary care to reduce our reliance on hospitals.","path":"english2/2025.html"},{"id":"english2-2025-t2-p3-s4","examKey":"english2","examLabel":"英语二","year":"2025","text":2,"paragraph":3,"sentenceNo":4,"sentence":"And capacity in social care needs to be greater, to support the growing number of people living with long-term conditions.","path":"english2/2025.html"},{"id":"english2-2025-t2-p4-s1","examKey":"english2","examLabel":"英语二","year":"2025","text":2,"paragraph":4,"sentenceNo":1,"sentence":"Q28 段落定位 Yet despite two decades of strategies and a number of major health reforms, we have failed to make meaningful progress on any of these aims.","path":"english2/2025.html"},{"id":"english2-2025-t2-p4-s2","examKey":"english2","examLabel":"英语二","year":"2025","text":2,"paragraph":4,"sentenceNo":2,"sentence":"That is why the Reform think tank is launching a new programme of work entitled “Reimagining health”, supported by ten former health ministers.","path":"english2/2025.html"},{"id":"english2-2025-t2-p4-s3","examKey":"english2","examLabel":"英语二","year":"2025","text":2,"paragraph":4,"sentenceNo":3,"sentence":"Together, we are calling for a much more open and honest conversation about the future of health in the UK, and an “urgent rethink” of the hospital-centric model we retain.","path":"english2/2025.html"},{"id":"english2-2025-t2-p5-s1","examKey":"english2","examLabel":"英语二","year":"2025","text":2,"paragraph":5,"sentenceNo":1,"sentence":"Q29 段落定位 This must begin with the question of how we maximise the health of the nation, rather than “fix” the NHS.","path":"english2/2025.html"},{"id":"english2-2025-t2-p5-s2","examKey":"english2","examLabel":"英语二","year":"2025","text":2,"paragraph":5,"sentenceNo":2,"sentence":"It is estimated, for example, that healthcare accounts for only about 20% of health outcomes.","path":"english2/2025.html"},{"id":"english2-2025-t2-p5-s3","examKey":"english2","examLabel":"英语二","year":"2025","text":2,"paragraph":5,"sentenceNo":3,"sentence":"Much more important are the places we live, work and socialise—yet there is no clear cross-government strategy for improving these social determinants of health.","path":"english2/2025.html"},{"id":"english2-2025-t2-p5-s4","examKey":"english2","examLabel":"英语二","year":"2025","text":2,"paragraph":5,"sentenceNo":4,"sentence":"Worse, when policies like the national obesity strategy are scrapped, taxpayers are left with the heavy price tag of treating the illnesses, like diabetes, that result.","path":"english2/2025.html"},{"id":"english2-2025-t2-p6-s1","examKey":"english2","examLabel":"英语二","year":"2025","text":2,"paragraph":6,"sentenceNo":1,"sentence":"Q30 段落定位 Reform wants to ask how power and resources should be distributed in our health system.","path":"english2/2025.html"},{"id":"english2-2025-t2-p6-s2","examKey":"english2","examLabel":"英语二","year":"2025","text":2,"paragraph":6,"sentenceNo":2,"sentence":"What health functions should remain at the centre, and what should be given to local leaders, often responsible for services that create health, and with a much better understanding of the needs of their populations?","path":"english2/2025.html"},{"id":"english2-2025-t3-p1-s1","examKey":"english2","examLabel":"英语二","year":"2025","text":3,"paragraph":1,"sentenceNo":1,"sentence":"Q31 段落定位 Heat action plans, or HAPs, have been proliferating in India in the past few years.","path":"english2/2025.html"},{"id":"english2-2025-t3-p1-s2","examKey":"english2","examLabel":"英语二","year":"2025","text":3,"paragraph":1,"sentenceNo":2,"sentence":"In general, an HAP spells out when and how officials should issue heat warnings and alert hospitals and other institutions.","path":"english2/2025.html"},{"id":"english2-2025-t3-p1-s3","examKey":"english2","examLabel":"英语二","year":"2025","text":3,"paragraph":1,"sentenceNo":3,"sentence":"Nagpur’s plan, for instance, calls for hospitals to set aside “cold wards” in the summer for treating heatstroke patients, and advises builders to give construction laborers a break from work on very hot days.","path":"english2/2025.html"},{"id":"english2-2025-t3-p2-s1","examKey":"english2","examLabel":"英语二","year":"2025","text":3,"paragraph":2,"sentenceNo":1,"sentence":"Q32 段落定位 But implementation of existing HAPs has been uneven, according to a report from the Centre for Policy Research.","path":"english2/2025.html"},{"id":"english2-2025-t3-p2-s2","examKey":"english2","examLabel":"英语二","year":"2025","text":3,"paragraph":2,"sentenceNo":2,"sentence":"Many lack adequate funding, it found.","path":"english2/2025.html"},{"id":"english2-2025-t3-p2-s3","examKey":"english2","examLabel":"英语二","year":"2025","text":3,"paragraph":2,"sentenceNo":3,"sentence":"And their triggering thresholds often are not customized to the local climate.","path":"english2/2025.html"},{"id":"english2-2025-t3-p2-s4","examKey":"english2","examLabel":"英语二","year":"2025","text":3,"paragraph":2,"sentenceNo":4,"sentence":"In some areas, high daytime temperatures alone might serve as an adequate trigger for alerts.","path":"english2/2025.html"},{"id":"english2-2025-t3-p2-s5","examKey":"english2","examLabel":"英语二","year":"2025","text":3,"paragraph":2,"sentenceNo":5,"sentence":"But in other places, nighttime temperatures or humidity might be as important a gauge of risk as daytime highs.","path":"english2/2025.html"},{"id":"english2-2025-t3-p3-s1","examKey":"english2","examLabel":"英语二","year":"2025","text":3,"paragraph":3,"sentenceNo":1,"sentence":"Q33 段落定位 Mumbai’s April heatstroke deaths highlighted the need for more nuanced and localized warnings, researchers say.","path":"english2/2025.html"},{"id":"english2-2025-t3-p3-s2","examKey":"english2","examLabel":"英语二","year":"2025","text":3,"paragraph":3,"sentenceNo":2,"sentence":"That day’s high temperature of roughly 36°C was 1°C shy of the heat wave alert threshold for coastal cities set by national meteorological authorities.","path":"english2/2025.html"},{"id":"english2-2025-t3-p3-s3","examKey":"english2","examLabel":"英语二","year":"2025","text":3,"paragraph":3,"sentenceNo":3,"sentence":"But the effects of the heat were amplified by humidity —an often neglected factor in heat alert systems—and the lack of shade at the late-morning outdoor ceremony.","path":"english2/2025.html"},{"id":"english2-2025-t3-p4-s1","examKey":"english2","examLabel":"英语二","year":"2025","text":3,"paragraph":4,"sentenceNo":1,"sentence":"Q34 段落定位 To help improve HAPs, urban planner Rajashree Kotharkar ’s team is working on a model plan that outlines best practices and could be adapted to local conditions.","path":"english2/2025.html"},{"id":"english2-2025-t3-p4-s2","examKey":"english2","examLabel":"英语二","year":"2025","text":3,"paragraph":4,"sentenceNo":2,"sentence":"Among other things, she says, all cities should create a vulnerability map to help focus responses on the populations most at risk.","path":"english2/2025.html"},{"id":"english2-2025-t3-p5-s1","examKey":"english2","examLabel":"英语二","year":"2025","text":3,"paragraph":5,"sentenceNo":1,"sentence":"Such mapping doesn’t need to be complex, Kotharkar says.","path":"english2/2025.html"},{"id":"english2-2025-t3-p5-s2","examKey":"english2","examLabel":"英语二","year":"2025","text":3,"paragraph":5,"sentenceNo":2,"sentence":"“A useful map can be created by looking at even a few key parameters.” For example, neighborhoods with a large elderly population or informal dwellings that cope poorly with heat could get special warnings or be bolstered with cooling centers.","path":"english2/2025.html"},{"id":"english2-2025-t3-p5-s3","examKey":"english2","examLabel":"英语二","year":"2025","text":3,"paragraph":5,"sentenceNo":3,"sentence":"The Nagpur project has already created a risk and vulnerability map, which enabled Kotharkar to tell officials which neighborhoods to focus on in the event of a heat wave this summer.","path":"english2/2025.html"},{"id":"english2-2025-t3-p6-s1","examKey":"english2","examLabel":"英语二","year":"2025","text":3,"paragraph":6,"sentenceNo":1,"sentence":"Q35 段落定位 HAPs shouldn’t just include short-term emergency responses, researchers say, but also recommend medium- to long-term measures that could make communities cooler.","path":"english2/2025.html"},{"id":"english2-2025-t3-p6-s2","examKey":"english2","examLabel":"英语二","year":"2025","text":3,"paragraph":6,"sentenceNo":2,"sentence":"In Nagpur, for example, Kotharkar’s team has been able to advise city officials about where to plant trees to provide shade.","path":"english2/2025.html"},{"id":"english2-2025-t3-p6-s3","examKey":"english2","examLabel":"英语二","year":"2025","text":3,"paragraph":6,"sentenceNo":3,"sentence":"HAPs could also guide efforts to retrofit homes or modify building regulations.","path":"english2/2025.html"},{"id":"english2-2025-t3-p6-s4","examKey":"english2","examLabel":"英语二","year":"2025","text":3,"paragraph":6,"sentenceNo":4,"sentence":"“Reducing deaths in an emergency is good target to have, but it’s the lowest target,” says climate researcher Chandni Singh.","path":"english2/2025.html"},{"id":"english2-2025-t4-p1-s1","examKey":"english2","examLabel":"英语二","year":"2025","text":4,"paragraph":1,"sentenceNo":1,"sentence":"Q36 段落定位 Navigating beyond the organised pavements and parks of our urban spaces, desire paths are the unofficial footprints of a community, revealing the unspoken preferences, shared shortcuts and collective choices of humans.","path":"english2/2025.html"},{"id":"english2-2025-t4-p1-s2","examKey":"english2","examLabel":"英语二","year":"2025","text":4,"paragraph":1,"sentenceNo":2,"sentence":"Often appearing as trodden dirt tracks through otherwise neat green spaces, these routes of collective disobedience cut corners, bisect lawns and cross hills, representing the natural capability of people (and animals) to go from point A to point B most effectively.","path":"english2/2025.html"},{"id":"english2-2025-t4-p2-s1","examKey":"english2","examLabel":"英语二","year":"2025","text":4,"paragraph":2,"sentenceNo":1,"sentence":"Q37 段落定位 Urban planners interpret desire paths as more than just convenient shortcuts; they offer valuable insights into the dynamics between planning and behaviour.","path":"english2/2025.html"},{"id":"english2-2025-t4-p2-s2","examKey":"english2","examLabel":"英语二","year":"2025","text":4,"paragraph":2,"sentenceNo":2,"sentence":"Ohio State University allowed its students to navigate the Oval, a lawn in the centre of campus, freely, then proceeded to pave the desire paths, creating a web of effective routes students had established.","path":"english2/2025.html"},{"id":"english2-2025-t4-p3-s1","examKey":"english2","examLabel":"英语二","year":"2025","text":4,"paragraph":3,"sentenceNo":1,"sentence":"Q38 段落定位 Yet, reluctance persists among other planners to integrate desire paths into formal plans, citing concerns about safety, environmental impact, or primarily, aesthetics.","path":"english2/2025.html"},{"id":"english2-2025-t4-p3-s2","examKey":"english2","examLabel":"英语二","year":"2025","text":4,"paragraph":3,"sentenceNo":2,"sentence":"A Reddit webpage devoted to the phenomenon, boasting nearly 50,000 members, showcases images of local desire paths adorned with signs instructing pedestrians to adhere to designated walkways, underscoring the rebellious nature inherent in these human-made tracks.","path":"english2/2025.html"},{"id":"english2-2025-t4-p3-s3","examKey":"english2","examLabel":"英语二","year":"2025","text":4,"paragraph":3,"sentenceNo":3,"sentence":"This clash highlights an ongoing struggle between the organic, user-driven evolution of public spaces and the desire for a visually curated and controlled urban environment.","path":"english2/2025.html"},{"id":"english2-2025-t4-p4-s1","examKey":"english2","examLabel":"英语二","year":"2025","text":4,"paragraph":4,"sentenceNo":1,"sentence":"Q39 段落定位 The Wickquasgeck Trail is an example of a historical desire path, created by Native Americans to cross the forests of Manhattan and move between settlements quickly.","path":"english2/2025.html"},{"id":"english2-2025-t4-p4-s2","examKey":"english2","examLabel":"英语二","year":"2025","text":4,"paragraph":4,"sentenceNo":2,"sentence":"This trail, when Dutch colonists arrived, was widened and made into one of the main roads across the island, known at the time as de Heere Straat, or Gentlemen’s Street.","path":"english2/2025.html"},{"id":"english2-2025-t4-p4-s3","examKey":"english2","examLabel":"英语二","year":"2025","text":4,"paragraph":4,"sentenceNo":3,"sentence":"Following the British assumption of control in New York, the street was renamed Broadway.","path":"english2/2025.html"},{"id":"english2-2025-t4-p4-s4","examKey":"english2","examLabel":"英语二","year":"2025","text":4,"paragraph":4,"sentenceNo":4,"sentence":"Notably, Broadway stands out as one of the few areas in NYC that defies the grid-based system applied to the rest of the city, cutting a diagonal across parts of the city.","path":"english2/2025.html"},{"id":"english2-2025-t4-p5-s1","examKey":"english2","examLabel":"英语二","year":"2025","text":4,"paragraph":5,"sentenceNo":1,"sentence":"In online spaces, desire paths have sparked a fascination that can approach obsession, with the Reddit page serving as a hub.","path":"english2/2025.html"},{"id":"english2-2025-t4-p5-s2","examKey":"english2","examLabel":"英语二","year":"2025","text":4,"paragraph":5,"sentenceNo":2,"sentence":"Contributors offer a wide array of stories, from little-known new shortcuts to long-established alternate routes.","path":"english2/2025.html"},{"id":"english2-2025-t4-p6-s1","examKey":"english2","examLabel":"英语二","year":"2025","text":4,"paragraph":6,"sentenceNo":1,"sentence":"Q40 段落定位 Animal desire paths, such as ducks forging trails through frozen ponds or dogs carving direct routes in gardens, highlight the adaptability of these trails in both human and animal experiences.","path":"english2/2025.html"},{"id":"english2-2025-t4-p6-s2","examKey":"english2","examLabel":"英语二","year":"2025","text":4,"paragraph":6,"sentenceNo":2,"sentence":"As desire paths criss-cross through both physical and virtual landscapes, they stand as a proof of the collective insistence on forging unconventional routes and embracing the spirit of communal choice.","path":"english2/2025.html"},{"id":"english1-2026-t1-p1-s1","examKey":"english1","examLabel":"英语一","year":"2026","text":1,"paragraph":1,"sentenceNo":1,"sentence":"For thousands of years, donkeys have been critical for propelling human civilizations forward.","path":"english1/2026.html"},{"id":"english1-2026-t1-p1-s2","examKey":"english1","examLabel":"英语一","year":"2026","text":1,"paragraph":1,"sentenceNo":2,"sentence":"They’ve helped pull wheeled vehicles, carry travelers and move goods across the world.","path":"english1/2026.html"},{"id":"english1-2026-t1-p1-s3","examKey":"english1","examLabel":"英语一","year":"2026","text":1,"paragraph":1,"sentenceNo":3,"sentence":"But where and when these animals first became intertwined with humans has been a mystery.","path":"english1/2026.html"},{"id":"english1-2026-t1-p1-s4","examKey":"english1","examLabel":"英语一","year":"2026","text":1,"paragraph":1,"sentenceNo":4,"sentence":"Now, researchers have used genomes of over 200 donkeys to trace their domestication back to a single event around 7,000 years ago in East Africa — about 3,000 years before humans tamed horses.","path":"english1/2026.html"},{"id":"english1-2026-t1-p1-s5","examKey":"english1","examLabel":"英语一","year":"2026","text":1,"paragraph":1,"sentenceNo":5,"sentence":"The team published their findings in the journal Science this month.","path":"english1/2026.html"},{"id":"english1-2026-t1-p2-s1","examKey":"english1","examLabel":"英语一","year":"2026","text":1,"paragraph":2,"sentenceNo":1,"sentence":"“Through their DNA, the animals are telling their history themselves,” co-author Samantha Brooks, an equine researcher at the University of Florida, says in a statement.","path":"english1/2026.html"},{"id":"english1-2026-t1-p2-s2","examKey":"english1","examLabel":"英语一","year":"2026","text":1,"paragraph":2,"sentenceNo":2,"sentence":"“We usually only get the human’s side of history through written accounts, but of course written history does not always record exactly how something happened.","path":"english1/2026.html"},{"id":"english1-2026-t1-p2-s3","examKey":"english1","examLabel":"英语一","year":"2026","text":1,"paragraph":2,"sentenceNo":3,"sentence":"Looking at these DNA sequences, we get a biological testimony to the environment these animals lived in and the experiences they survived. ”","path":"english1/2026.html"},{"id":"english1-2026-t1-p3-s1","examKey":"english1","examLabel":"英语一","year":"2026","text":1,"paragraph":3,"sentenceNo":1,"sentence":"The researchers examined 207 genomes from modern donkeys living in 31 countries across the globe.","path":"english1/2026.html"},{"id":"english1-2026-t1-p3-s2","examKey":"english1","examLabel":"英语一","year":"2026","text":1,"paragraph":3,"sentenceNo":2,"sentence":"They also looked at genomes from 15 wild equids and 31 earlier donkeys that lived between about 4,000 and 100 years ago.","path":"english1/2026.html"},{"id":"english1-2026-t1-p3-s3","examKey":"english1","examLabel":"英语一","year":"2026","text":1,"paragraph":3,"sentenceNo":3,"sentence":"The team reconstructed the animals’ evolutionary tree and used computer models to pinpoint the domestication event: when herders in Kenya and the Horn of Africa tamed wild asses.","path":"english1/2026.html"},{"id":"english1-2026-t1-p3-s4","examKey":"english1","examLabel":"英语一","year":"2026","text":1,"paragraph":3,"sentenceNo":4,"sentence":"They then traced how the animals spread across the rest of the continent into Europe and Asia about 2,500 years later.","path":"english1/2026.html"},{"id":"english1-2026-t1-p4-s1","examKey":"english1","examLabel":"英语一","year":"2026","text":1,"paragraph":4,"sentenceNo":1,"sentence":"Though it’s still unclear why the original domestication happened, Science News ’ Freda Kreier reports that the event coincided with the Sahara growing larger and drier.","path":"english1/2026.html"},{"id":"english1-2026-t1-p4-s2","examKey":"english1","examLabel":"英语一","year":"2026","text":1,"paragraph":4,"sentenceNo":2,"sentence":"“Donkeys are champions when it comes to carrying stuff and are good at going through deserts,” co-author Ludovic Orlando, an evolutionary biologist at Paul Sabatier University in France, tells the publication.","path":"english1/2026.html"},{"id":"english1-2026-t1-p4-s3","examKey":"english1","examLabel":"英语一","year":"2026","text":1,"paragraph":4,"sentenceNo":3,"sentence":"Prehistoric humans may have tamed donkeys to help navigate the expanding Sahara.","path":"english1/2026.html"},{"id":"english1-2026-t1-p5-s1","examKey":"english1","examLabel":"英语一","year":"2026","text":1,"paragraph":5,"sentenceNo":1,"sentence":"Researchers say these findings could help put donkeys in the spotlight.","path":"english1/2026.html"},{"id":"english1-2026-t1-p5-s2","examKey":"english1","examLabel":"英语一","year":"2026","text":1,"paragraph":5,"sentenceNo":2,"sentence":"The animals could benefit from more research: Currently, there are no published genomes from donkeys located south of the Equator in Africa.","path":"english1/2026.html"},{"id":"english1-2026-t1-p5-s3","examKey":"english1","examLabel":"英语一","year":"2026","text":1,"paragraph":5,"sentenceNo":3,"sentence":"But understanding where the animals were first domesticated could guide archaeologists to a narrow region to search for insights about the original tamed donkeys.","path":"english1/2026.html"},{"id":"english1-2026-t1-p6-s1","examKey":"english1","examLabel":"英语一","year":"2026","text":1,"paragraph":6,"sentenceNo":1,"sentence":"Not only does human-understanding the equines’ genetic makeup help reveal their contribution to human history, but it also might improve their management in the future, as climate change alters the planet’s environment, write the authors.","path":"english1/2026.html"},{"id":"english1-2026-t2-p1-s1","examKey":"english1","examLabel":"英语一","year":"2026","text":2,"paragraph":1,"sentenceNo":1,"sentence":"There’s no business like show business — but in Los Angeles, it feels like there’s no business at all.","path":"english1/2026.html"},{"id":"english1-2026-t2-p2-s1","examKey":"english1","examLabel":"英语一","year":"2026","text":2,"paragraph":2,"sentenceNo":1,"sentence":"If that sounds melodramatic, consider this: The Art Directors Guild, a labor union representing about 3,000 film workers, has suspended a training program and issued a statement explaining that “ we cannot in good conscience encourage you to pursue our profession while so many of our members remain unemployed. ” The guild’s pessimism is a reaction to Hollywood’s decline, which is reaching a critical point for the industry and Southern California ”.","path":"english1/2026.html"},{"id":"english1-2026-t2-p3-s1","examKey":"english1","examLabel":"英语一","year":"2026","text":2,"paragraph":3,"sentenceNo":1,"sentence":"Production has been slipping away from Hollywood since the 1950s, but the effects have never been more apparent than at present.","path":"english1/2026.html"},{"id":"english1-2026-t2-p3-s2","examKey":"english1","examLabel":"英语一","year":"2026","text":2,"paragraph":3,"sentenceNo":2,"sentence":"Other regions in the United States, Canada and Europe have steadily increased incentives to attract TV shows and movies, leaving California in the dust.","path":"english1/2026.html"},{"id":"english1-2026-t2-p3-s3","examKey":"english1","examLabel":"英语一","year":"2026","text":2,"paragraph":3,"sentenceNo":3,"sentence":"Georgia offers up to 30% in transferable tax credits on film and TV production costs, plus an additional 10% increase on the base tax credit if the project includes a Georgia promotional logo.","path":"english1/2026.html"},{"id":"english1-2026-t2-p4-s1","examKey":"english1","examLabel":"英语一","year":"2026","text":2,"paragraph":4,"sentenceNo":1,"sentence":"Even as California lost a huge volume of production to other locations, there was still plenty of film production taking place in Los Angeles before this year.","path":"english1/2026.html"},{"id":"english1-2026-t2-p4-s2","examKey":"english1","examLabel":"英语一","year":"2026","text":2,"paragraph":4,"sentenceNo":2,"sentence":"We were kept afloat by “ peak TV ”, the glut of content that was required by the explosion of streaming services.","path":"english1/2026.html"},{"id":"english1-2026-t2-p5-s1","examKey":"english1","examLabel":"英语一","year":"2026","text":2,"paragraph":5,"sentenceNo":1,"sentence":"But 2022 was the peak of peak TV.","path":"english1/2026.html"},{"id":"english1-2026-t2-p5-s2","examKey":"english1","examLabel":"英语一","year":"2026","text":2,"paragraph":5,"sentenceNo":2,"sentence":"Back then, platforms such as Netflix, Amazon and Apple TV hemorrhaged billions of dollars to generate content to attract new subscribers, resulting in 633 scripted series being released that year.","path":"english1/2026.html"},{"id":"english1-2026-t2-p5-s3","examKey":"english1","examLabel":"英语一","year":"2026","text":2,"paragraph":5,"sentenceNo":3,"sentence":"As the streamers’ emphasis changed from subscriber growth to profitability, prices for the services went up and the number of new shows went down to 481 released in 2023, with the number expected to dip into the 300s within a few years.","path":"english1/2026.html"},{"id":"english1-2026-t2-p6-s1","examKey":"english1","examLabel":"英语一","year":"2026","text":2,"paragraph":6,"sentenceNo":1,"sentence":"As TV and movie productions slowly come back after the writers and actors strikes, they’re nowhere near the volume of 2022 and for the most part, nowhere near Los Angeles.","path":"english1/2026.html"},{"id":"english1-2026-t2-p6-s2","examKey":"english1","examLabel":"英语一","year":"2026","text":2,"paragraph":6,"sentenceNo":2,"sentence":"Disney has 22 live-action movies slated for production in 2024, with only three to be filmed in California.","path":"english1/2026.html"},{"id":"english1-2026-t2-p6-s3","examKey":"english1","examLabel":"英语一","year":"2026","text":2,"paragraph":6,"sentenceNo":3,"sentence":"Other studios such as Sony, Warner Bros. and Universal Pictures are following the same script and taking the majority of their production dollars outside of California.","path":"english1/2026.html"},{"id":"english1-2026-t2-p7-s1","examKey":"english1","examLabel":"英语一","year":"2026","text":2,"paragraph":7,"sentenceNo":1,"sentence":"If productions in Southern California dip below a critical level for too long, the industry’s essential talent will drift away along with enormous sums of revenue.","path":"english1/2026.html"},{"id":"english1-2026-t2-p7-s2","examKey":"english1","examLabel":"英语一","year":"2026","text":2,"paragraph":7,"sentenceNo":2,"sentence":"Persuading studios to film here would become much more challenging if we couldn’t offer a deep bench of local film workers, on-screen talent and local businesses that support the entertainment industry.","path":"english1/2026.html"},{"id":"english1-2026-t2-p8-s1","examKey":"english1","examLabel":"英语一","year":"2026","text":2,"paragraph":8,"sentenceNo":1,"sentence":"That’s why the California Film Commission and its Los Angeles counterpart, Film LA, now should act now, before it’s too late.","path":"english1/2026.html"},{"id":"english1-2026-t2-p8-s2","examKey":"english1","examLabel":"英语一","year":"2026","text":2,"paragraph":8,"sentenceNo":2,"sentence":"These agencies and other government bodies should dramatically improve incentives to keep our current shows and attract new productions to Los Angeles.","path":"english1/2026.html"},{"id":"english1-2026-t2-p8-s3","examKey":"english1","examLabel":"英语一","year":"2026","text":2,"paragraph":8,"sentenceNo":3,"sentence":"Let’s go on with the show … and make sure the show doesn’t go on without us.","path":"english1/2026.html"},{"id":"english1-2026-t3-p1-s1","examKey":"english1","examLabel":"英语一","year":"2026","text":3,"paragraph":1,"sentenceNo":1,"sentence":"The pioneers of wireless saw it as a gift to all the people.","path":"english1/2026.html"},{"id":"english1-2026-t3-p1-s2","examKey":"english1","examLabel":"英语一","year":"2026","text":3,"paragraph":1,"sentenceNo":2,"sentence":"Sir John Reith said that it would end “isolation of the spirit” and rejoiced: “ It does not matter how many thousand may be listening, there is always enough for others… the genius and the fool, the wealthy and the poor listen simultaneously. ”","path":"english1/2026.html"},{"id":"english1-2026-t3-p2-s1","examKey":"english1","examLabel":"英语一","year":"2026","text":3,"paragraph":2,"sentenceNo":1,"sentence":"Between two great wars this technological innovation built a new kind of national consciousness.","path":"english1/2026.html"},{"id":"english1-2026-t3-p2-s2","examKey":"english1","examLabel":"英语一","year":"2026","text":3,"paragraph":2,"sentenceNo":2,"sentence":"Opening this week, a book and exhibition curated by Beatty Rubens at the Bodleian in Oxford records how radio changed everyday life from 1922 to 1939.","path":"english1/2026.html"},{"id":"english1-2026-t3-p2-s3","examKey":"english1","examLabel":"英语一","year":"2026","text":3,"paragraph":2,"sentenceNo":3,"sentence":"She draws on letters, diaries and fiction, and a 1939 field notebook of verbatim audience research by Winifred Gill.","path":"english1/2026.html"},{"id":"english1-2026-t3-p3-s1","examKey":"english1","examLabel":"英语一","year":"2026","text":3,"paragraph":3,"sentenceNo":1,"sentence":"There’s fun in testimonies of people enjoying the sheer newness.","path":"english1/2026.html"},{"id":"english1-2026-t3-p3-s2","examKey":"english1","examLabel":"英语一","year":"2026","text":3,"paragraph":3,"sentenceNo":2,"sentence":"A cartoon mocks a group failing to converse because they’re all in headphones.","path":"english1/2026.html"},{"id":"english1-2026-t3-p3-s3","examKey":"english1","examLabel":"英语一","year":"2026","text":3,"paragraph":3,"sentenceNo":3,"sentence":"People report that broadcast music made workmen whistle new tunes.","path":"english1/2026.html"},{"id":"english1-2026-t3-p3-s4","examKey":"english1","examLabel":"英语一","year":"2026","text":3,"paragraph":3,"sentenceNo":4,"sentence":"A woman says there have been fewer street fights since the arrival of the wireless but also less stopping and “ talking on the brush handle ”.","path":"english1/2026.html"},{"id":"english1-2026-t3-p4-s1","examKey":"english1","examLabel":"英语一","year":"2026","text":3,"paragraph":4,"sentenceNo":1,"sentence":"By and large the wireless was welcome.","path":"english1/2026.html"},{"id":"english1-2026-t3-p4-s2","examKey":"english1","examLabel":"英语一","year":"2026","text":3,"paragraph":4,"sentenceNo":2,"sentence":"I loved the chap from the Thirties research who found that wireless suddenly offered “ a lot of variety … things I thought I’d never be interested in… ice hockey, perhaps ”.","path":"english1/2026.html"},{"id":"english1-2026-t3-p4-s3","examKey":"english1","examLabel":"英语一","year":"2026","text":3,"paragraph":4,"sentenceNo":3,"sentence":"True: for more than 80 pre-digital years, linear speech broadcasting brought the gift of serendipity, random enlivening of a car journey or dull manual task.","path":"english1/2026.html"},{"id":"english1-2026-t3-p4-s4","examKey":"english1","examLabel":"英语一","year":"2026","text":3,"paragraph":4,"sentenceNo":4,"sentence":"In my own book about radio I recorded how, on one drive: “ I caught up with the news, learnt some 17th-century history, and was startlingly educated by an unpretentious programme on the history of the stethoscope. ”","path":"english1/2026.html"},{"id":"english1-2026-t3-p5-s1","examKey":"english1","examLabel":"英语一","year":"2026","text":3,"paragraph":5,"sentenceNo":1,"sentence":"But radio’s enriching serendipity is ebbing.","path":"english1/2026.html"},{"id":"english1-2026-t3-p5-s2","examKey":"english1","examLabel":"英语一","year":"2026","text":3,"paragraph":5,"sentenceNo":2,"sentence":"With multiple networks and countless podcasts, a smartphone user selects what to hear and when.","path":"english1/2026.html"},{"id":"english1-2026-t3-p5-s3","examKey":"english1","examLabel":"英语一","year":"2026","text":3,"paragraph":5,"sentenceNo":3,"sentence":"And while it is wonderful to take a walk with anything in your headphones, infinite choice encourages us to shrink into niche interests and sympathetic beliefs.","path":"english1/2026.html"},{"id":"english1-2026-t3-p6-s1","examKey":"english1","examLabel":"英语一","year":"2026","text":3,"paragraph":6,"sentenceNo":1,"sentence":"A hundred years on from Marconi and Reith, is the art of mere listening endangered?","path":"english1/2026.html"},{"id":"english1-2026-t3-p6-s2","examKey":"english1","examLabel":"英语一","year":"2026","text":3,"paragraph":6,"sentenceNo":2,"sentence":"Some will say the audiobook boom revives it, though I suppose you can then worry about the decline of reading.","path":"english1/2026.html"},{"id":"english1-2026-t3-p6-s3","examKey":"english1","examLabel":"英语一","year":"2026","text":3,"paragraph":6,"sentenceNo":3,"sentence":"But inventions shape all of us and it is worth noticing when techno-social habits do change, and asking whether to control them a bit or shield the youngest.","path":"english1/2026.html"},{"id":"english1-2026-t3-p7-s1","examKey":"english1","examLabel":"英语一","year":"2026","text":3,"paragraph":7,"sentenceNo":1,"sentence":"Whatever we do, innovation will happen.","path":"english1/2026.html"},{"id":"english1-2026-t3-p7-s2","examKey":"english1","examLabel":"英语一","year":"2026","text":3,"paragraph":7,"sentenceNo":2,"sentence":"Today we fret about the isolating culture of smartphone-staring and selfie-vanity, but already in 1939 there was that lady regretting how, when all her street got wirelesses, it lost the neighbourly habit of “ talking on the brush handle ”.","path":"english1/2026.html"},{"id":"english1-2026-t3-p7-s3","examKey":"english1","examLabel":"英语一","year":"2026","text":3,"paragraph":7,"sentenceNo":3,"sentence":"It’s enough to make a person put down the smartphone and go out front with a yard broom.","path":"english1/2026.html"},{"id":"english1-2026-t4-p1-s1","examKey":"english1","examLabel":"英语一","year":"2026","text":4,"paragraph":1,"sentenceNo":1,"sentence":"When Tom Swetnam joined the U.S.","path":"english1/2026.html"},{"id":"english1-2026-t4-p1-s2","examKey":"english1","examLabel":"英语一","year":"2026","text":4,"paragraph":1,"sentenceNo":2,"sentence":"Forest Service in the 1970s, his mandate was to “put everything out,” he recalled.","path":"english1/2026.html"},{"id":"english1-2026-t4-p1-s3","examKey":"english1","examLabel":"英语一","year":"2026","text":4,"paragraph":1,"sentenceNo":3,"sentence":"But when Swetnam enrolled in graduate school at the University of Arizona’s Laboratory of Tree-Ring Research, he was surprised to find a record of repeated blazes dating back hundreds of years before European colonists arrived on the continent.","path":"english1/2026.html"},{"id":"english1-2026-t4-p1-s4","examKey":"english1","examLabel":"英语一","year":"2026","text":4,"paragraph":1,"sentenceNo":4,"sentence":"Some of the trees he analyzed bore more than 20 fire scars among their rings.","path":"english1/2026.html"},{"id":"english1-2026-t4-p2-s1","examKey":"english1","examLabel":"英语一","year":"2026","text":4,"paragraph":2,"sentenceNo":1,"sentence":"The fact that fires happened so often meant they couldn’t have been severe enough to kill most trees.","path":"english1/2026.html"},{"id":"english1-2026-t4-p2-s2","examKey":"english1","examLabel":"英语一","year":"2026","text":4,"paragraph":2,"sentenceNo":2,"sentence":"Instead, a growing body of research showed that frequent, low-severity fires made many ecosystems healthier.","path":"english1/2026.html"},{"id":"english1-2026-t4-p2-s3","examKey":"english1","examLabel":"英语一","year":"2026","text":4,"paragraph":2,"sentenceNo":3,"sentence":"They rid the forest of dead and sick trees, reducing competition and curbing the spread of disease.","path":"english1/2026.html"},{"id":"english1-2026-t4-p2-s4","examKey":"english1","examLabel":"英语一","year":"2026","text":4,"paragraph":2,"sentenceNo":4,"sentence":"Because flammable material couldn’t build up on the landscape, blazes tended to move slowly and peter out when they reached the footprints of previous burns.","path":"english1/2026.html"},{"id":"english1-2026-t4-p3-s1","examKey":"english1","examLabel":"英语一","year":"2026","text":4,"paragraph":3,"sentenceNo":1,"sentence":"In 2022, Swetnam and other scientists teamed up to compile a database of fire-scarred trees from across the continent.","path":"english1/2026.html"},{"id":"english1-2026-t4-p3-s2","examKey":"english1","examLabel":"英语一","year":"2026","text":4,"paragraph":3,"sentenceNo":2,"sentence":"Their North American tree-ring fire-scar network (NAFSN) provided the basis for a study published last month.","path":"english1/2026.html"},{"id":"english1-2026-t4-p3-s3","examKey":"english1","examLabel":"英语一","year":"2026","text":4,"paragraph":3,"sentenceNo":3,"sentence":"In the study, the researchers compared the historical fire cadence with the wildfires recorded over the past few decades, and uncovered a striking shortfall.","path":"english1/2026.html"},{"id":"english1-2026-t4-p3-s4","examKey":"english1","examLabel":"英语一","year":"2026","text":4,"paragraph":3,"sentenceNo":4,"sentence":"The NAFSN sites experienced less than a quarter of the number of fires that would have been expected without fire suppression.","path":"english1/2026.html"},{"id":"english1-2026-t4-p4-s1","examKey":"english1","examLabel":"英语一","year":"2026","text":4,"paragraph":4,"sentenceNo":1,"sentence":"This deficit is a testament to the effectiveness of modern firefighting, said Kelly Martin, a past president of the International Association of Wildland Fire.","path":"english1/2026.html"},{"id":"english1-2026-t4-p4-s2","examKey":"english1","examLabel":"英语一","year":"2026","text":4,"paragraph":4,"sentenceNo":2,"sentence":"“ Yet the combined consequences of suppression and climate change have eroded humanity’s ability to suppress fires, particularly those that ignite under the most dangerous weather conditions. ”","path":"english1/2026.html"},{"id":"english1-2026-t4-p5-s1","examKey":"english1","examLabel":"英语一","year":"2026","text":4,"paragraph":5,"sentenceNo":1,"sentence":"To prevent entire ecosystems from going up in smoke, Martin said, people must bring healthy fire back to places that need it.","path":"english1/2026.html"},{"id":"english1-2026-t4-p5-s2","examKey":"english1","examLabel":"英语一","year":"2026","text":4,"paragraph":5,"sentenceNo":2,"sentence":"At Yosemite National Park, Martin oversaw the use of what is known as prescribed burns to make the landscape more resilient.","path":"english1/2026.html"},{"id":"english1-2026-t4-p5-s3","examKey":"english1","examLabel":"英语一","year":"2026","text":4,"paragraph":5,"sentenceNo":3,"sentence":"These fires were carefully planned and intentionally ignited during periods when weather kept the blazes easy to control, and helped eliminate some of the fuel that had built up around the important park’s facilities.","path":"english1/2026.html"},{"id":"english1-2026-t4-p5-s4","examKey":"english1","examLabel":"英语一","year":"2026","text":4,"paragraph":5,"sentenceNo":4,"sentence":"Research shows that these prescribed burns make subsequent wildfires less severe, even if later fires happen under the most dangerous weather conditions.","path":"english1/2026.html"},{"id":"english1-2026-t4-p6-s1","examKey":"english1","examLabel":"英语一","year":"2026","text":4,"paragraph":6,"sentenceNo":1,"sentence":"Yet even as scientists and public officials increasingly agree on the need for more fires in our forests, climate change is making this tactic more challenging, experts said.","path":"english1/2026.html"},{"id":"english1-2026-t4-p6-s2","examKey":"english1","examLabel":"英语一","year":"2026","text":4,"paragraph":6,"sentenceNo":2,"sentence":"“ It’s a double-edged sword because wildfires are getting more severe and larger under climate change and we need this work even more, but then the work gets more challenging,” said Susan Prichard, a fire ecologist at the University of Washington.","path":"english1/2026.html"},{"id":"english2-2026-t1-p1-s1","examKey":"english2","examLabel":"英语二","year":"2026","text":1,"paragraph":1,"sentenceNo":1,"sentence":"Ask people about public libraries and a certain image springs to mind: dusty, old-fashioned, the sort of place you enjoyed as a child but, rather like a British seaside town, would you go there now?","path":"english2/2026.html"},{"id":"english2-2026-t1-p1-s2","examKey":"english2","examLabel":"英语二","year":"2026","text":1,"paragraph":1,"sentenceNo":2,"sentence":"And anyway-aren’t they all closing?","path":"english2/2026.html"},{"id":"english2-2026-t1-p2-s1","examKey":"english2","examLabel":"英语二","year":"2026","text":1,"paragraph":2,"sentenceNo":1,"sentence":"Q21 段落定位 The reality is startlingly different, as I discovered when the culture department commissioned me to conduct an independent review of English public libraries, published yesterday.","path":"english2/2026.html"},{"id":"english2-2026-t1-p2-s2","examKey":"english2","examLabel":"英语二","year":"2026","text":1,"paragraph":2,"sentenceNo":2,"sentence":"As I visited libraries up and down the country, I was surprised to learn there are more than twice the number of libraries (2,892) as there are branches of McDonald’s.","path":"english2/2026.html"},{"id":"english2-2026-t1-p3-s1","examKey":"english2","examLabel":"英语二","year":"2026","text":1,"paragraph":3,"sentenceNo":1,"sentence":"Q22 段落定位 Enter any one of them and you will find a hive of activity, while books are, and should always be, at the heart of any library, a multitude of other services are offered: employment advice, language classes or digital access and support.","path":"english2/2026.html"},{"id":"english2-2026-t1-p3-s2","examKey":"english2","examLabel":"英语二","year":"2026","text":1,"paragraph":3,"sentenceNo":2,"sentence":"There are libraries with business and intellectual property centres, which can help business owners and entrepreneurs.","path":"english2/2026.html"},{"id":"english2-2026-t1-p3-s3","examKey":"english2","examLabel":"英语二","year":"2026","text":1,"paragraph":3,"sentenceNo":3,"sentence":"Many have nurses on site to carry out basic health checks, with a link to the GP’s surgery, there are libraries where young people can borrow a Fifa-standard football free.","path":"english2/2026.html"},{"id":"english2-2026-t1-p4-s1","examKey":"english2","examLabel":"英语二","year":"2026","text":1,"paragraph":4,"sentenceNo":1,"sentence":"Q22 段落定位 In return for all of this, you’ll be asked for precisely nothing.","path":"english2/2026.html"},{"id":"english2-2026-t1-p4-s2","examKey":"english2","examLabel":"英语二","year":"2026","text":1,"paragraph":4,"sentenceNo":2,"sentence":"There will be no charge and you will never be asked to justify or explain yourself, you will simply be welcomed in, offered help if you need it, and left alone if you do not.","path":"english2/2026.html"},{"id":"english2-2026-t1-p4-s3","examKey":"english2","examLabel":"英语二","year":"2026","text":1,"paragraph":4,"sentenceNo":3,"sentence":"There is no other institution, public or private, that can say the same.","path":"english2/2026.html"},{"id":"english2-2026-t1-p5-s1","examKey":"english2","examLabel":"英语二","year":"2026","text":1,"paragraph":5,"sentenceNo":1,"sentence":"Q23 段落定位 Yet still our libraries are often overlooked and underappreciated.","path":"english2/2026.html"},{"id":"english2-2026-t1-p5-s2","examKey":"english2","examLabel":"英语二","year":"2026","text":1,"paragraph":5,"sentenceNo":2,"sentence":"There is an overall decline in visits and many are struggling as local authorities come under continued financial pressure.","path":"english2/2026.html"},{"id":"english2-2026-t1-p6-s1","examKey":"english2","examLabel":"英语二","year":"2026","text":1,"paragraph":6,"sentenceNo":1,"sentence":"Q24 段落定位 The number of libraries that have closed since 2010 is disputed.","path":"english2/2026.html"},{"id":"english2-2026-t1-p6-s2","examKey":"english2","examLabel":"英语二","year":"2026","text":1,"paragraph":6,"sentenceNo":2,"sentence":"An annual survey by the Chartered Institute of Public Finance and Accountancy puts it at nearly 800 across the UK; official statistics held by the Arts Council record 230 in England.","path":"english2/2026.html"},{"id":"english2-2026-t1-p6-s3","examKey":"english2","examLabel":"英语二","year":"2026","text":1,"paragraph":6,"sentenceNo":3,"sentence":"It is, of course, 230 libraries too many.","path":"english2/2026.html"},{"id":"english2-2026-t1-p6-s4","examKey":"english2","examLabel":"英语二","year":"2026","text":1,"paragraph":6,"sentenceNo":4,"sentence":"So if we are to protect our libraries for future generations, we must raise awareness of them and the work they do.","path":"english2/2026.html"},{"id":"english2-2026-t1-p7-s1","examKey":"english2","examLabel":"英语二","year":"2026","text":1,"paragraph":7,"sentenceNo":1,"sentence":"Q25 段落定位 The review recommends a national branding campaign to give libraries a stronger physical presence, the reintroduction of a scheme to enable members to use their card in any library in the country, and automatic memberships for children.","path":"english2/2026.html"},{"id":"english2-2026-t1-p7-s2","examKey":"english2","examLabel":"英语二","year":"2026","text":1,"paragraph":7,"sentenceNo":2,"sentence":"If we don’t use them, we will end up losing them.","path":"english2/2026.html"},{"id":"english2-2026-t1-p7-s3","examKey":"english2","examLabel":"英语二","year":"2026","text":1,"paragraph":7,"sentenceNo":3,"sentence":"And for those who haven’t been to a library for some time, they may be surprised by what they find.","path":"english2/2026.html"},{"id":"english2-2026-t2-p1-s1","examKey":"english2","examLabel":"英语二","year":"2026","text":2,"paragraph":1,"sentenceNo":1,"sentence":"Q26 段落定位 According to our research, around one in five workers in the UK talk to AI like a friend, looking for guidance on personal and professional problems.","path":"english2/2026.html"},{"id":"english2-2026-t2-p1-s2","examKey":"english2","examLabel":"英语二","year":"2026","text":2,"paragraph":1,"sentenceNo":2,"sentence":"Our data shows that engaging with AI like this can leave us feeling heard and less isolated.","path":"english2/2026.html"},{"id":"english2-2026-t2-p1-s3","examKey":"english2","examLabel":"英语二","year":"2026","text":2,"paragraph":1,"sentenceNo":3,"sentence":"But, with this newfound connection, many of us share sensitive, sometimes highly confidential information, even though over a third of people don’t realise that AI platforms may not be very good at keeping our secrets... secrets.","path":"english2/2026.html"},{"id":"english2-2026-t2-p2-s1","examKey":"english2","examLabel":"英语二","year":"2026","text":2,"paragraph":2,"sentenceNo":1,"sentence":"Q27 段落定位 For business, the implications are worrying.","path":"english2/2026.html"},{"id":"english2-2026-t2-p2-s2","examKey":"english2","examLabel":"英语二","year":"2026","text":2,"paragraph":2,"sentenceNo":2,"sentence":"Consider Microsoft Copilot, for example.","path":"english2/2026.html"},{"id":"english2-2026-t2-p2-s3","examKey":"english2","examLabel":"英语二","year":"2026","text":2,"paragraph":2,"sentenceNo":3,"sentence":"It gains Microsoft broad rights to the data inputted or outputted by any user — rights to use this data in any way it sees fit; it can even share it with third parties.","path":"english2/2026.html"},{"id":"english2-2026-t2-p2-s4","examKey":"english2","examLabel":"英语二","year":"2026","text":2,"paragraph":2,"sentenceNo":4,"sentence":"This means that any sensitive business information could potentially be exposed to the world.","path":"english2/2026.html"},{"id":"english2-2026-t2-p2-s5","examKey":"english2","examLabel":"英语二","year":"2026","text":2,"paragraph":2,"sentenceNo":5,"sentence":"Employers are taking note and taking action.","path":"english2/2026.html"},{"id":"english2-2026-t2-p2-s6","examKey":"english2","examLabel":"英语二","year":"2026","text":2,"paragraph":2,"sentenceNo":6,"sentence":"According to our research, 25% have decided to either outright ban AI or regulate its use within their organisations.","path":"english2/2026.html"},{"id":"english2-2026-t2-p2-s7","examKey":"english2","examLabel":"英语二","year":"2026","text":2,"paragraph":2,"sentenceNo":7,"sentence":"But even with these policies in place, some employees choose to break the rules.","path":"english2/2026.html"},{"id":"english2-2026-t2-p2-s8","examKey":"english2","examLabel":"英语二","year":"2026","text":2,"paragraph":2,"sentenceNo":8,"sentence":"They have their reasons — around 63% of them report that using AI increases their productivity, and some even feel AI offers more help than their human colleagues.","path":"english2/2026.html"},{"id":"english2-2026-t2-p3-s1","examKey":"english2","examLabel":"英语二","year":"2026","text":2,"paragraph":3,"sentenceNo":1,"sentence":"Q29 段落定位 The situation presents a delicate balance between leveraging AI for its productivity gains and risking confidential data exposure.","path":"english2/2026.html"},{"id":"english2-2026-t2-p3-s2","examKey":"english2","examLabel":"英语二","year":"2026","text":2,"paragraph":3,"sentenceNo":2,"sentence":"Employers need to manage AI tools with the same level of care as any other form of data sharing or storage.","path":"english2/2026.html"},{"id":"english2-2026-t2-p3-s3","examKey":"english2","examLabel":"英语二","year":"2026","text":2,"paragraph":3,"sentenceNo":3,"sentence":"There's also a knowledge gap that needs to be addressed — 40% of individuals surveyed are unsure about who retains ownership over the content produced by AI.","path":"english2/2026.html"},{"id":"english2-2026-t2-p3-s4","examKey":"english2","examLabel":"英语二","year":"2026","text":2,"paragraph":3,"sentenceNo":4,"sentence":"By instilling best practices in AI engagement and creating policies that evolve with the technology, business can positively shift the AI landscape.","path":"english2/2026.html"},{"id":"english2-2026-t2-p4-s1","examKey":"english2","examLabel":"英语二","year":"2026","text":2,"paragraph":4,"sentenceNo":1,"sentence":"Q30 段落定位 With AI's potential to simplify our professional lives, do the admin and enhance the work experience.","path":"english2/2026.html"},{"id":"english2-2026-t2-p4-s2","examKey":"english2","examLabel":"英语二","year":"2026","text":2,"paragraph":4,"sentenceNo":2,"sentence":"It's up to us to navigate its usage cautiously so it supports us without compromising our privacy.","path":"english2/2026.html"},{"id":"english2-2026-t2-p4-s3","examKey":"english2","examLabel":"英语二","year":"2026","text":2,"paragraph":4,"sentenceNo":3,"sentence":"There's no need to back away from progress, as long as we're equipped with the knowledge and tools to make sure AI remains a friend.","path":"english2/2026.html"},{"id":"english2-2026-t2-p4-s4","examKey":"english2","examLabel":"英语二","year":"2026","text":2,"paragraph":4,"sentenceNo":4,"sentence":"And this is where the challenge lies.","path":"english2/2026.html"},{"id":"english2-2026-t2-p4-s5","examKey":"english2","examLabel":"英语二","year":"2026","text":2,"paragraph":4,"sentenceNo":5,"sentence":"There are so many products out there, being promoted with huge advertising and marketing budgets, that it's easy to fall victim.","path":"english2/2026.html"},{"id":"english2-2026-t2-p4-s6","examKey":"english2","examLabel":"英语二","year":"2026","text":2,"paragraph":4,"sentenceNo":6,"sentence":"But by building a culture of digital responsibility within our business, we can create a future where AI can help us without spilling the beans.","path":"english2/2026.html"},{"id":"english2-2026-t3-p1-s1","examKey":"english2","examLabel":"英语二","year":"2026","text":3,"paragraph":1,"sentenceNo":1,"sentence":"Q31 段落定位 Since the 2008 launch of the high-speed rail network between Rome and Milan, trains have become the preferred means of travel across Italy for locals and tourists alike.","path":"english2/2026.html"},{"id":"english2-2026-t3-p1-s2","examKey":"english2","examLabel":"英语二","year":"2026","text":3,"paragraph":1,"sentenceNo":2,"sentence":"Fast trains can cover the 500km between the two cities in three hours.","path":"english2/2026.html"},{"id":"english2-2026-t3-p1-s3","examKey":"english2","examLabel":"英语二","year":"2026","text":3,"paragraph":1,"sentenceNo":3,"sentence":"The network also connects Naples, Bologna, Florence and Turin.","path":"english2/2026.html"},{"id":"english2-2026-t3-p1-s4","examKey":"english2","examLabel":"英语二","year":"2026","text":3,"paragraph":1,"sentenceNo":4,"sentence":"In many cases, it is the best option — in terms of travel time and cost — for both leisure and business travellers.","path":"english2/2026.html"},{"id":"english2-2026-t3-p2-s1","examKey":"english2","examLabel":"英语二","year":"2026","text":3,"paragraph":2,"sentenceNo":1,"sentence":"Q31 段落定位 This is why the recent severe delays caused by numerous maintenance works have thrown the rail industry into chaos at a time when most people head on holiday, which matters for business in a country where tourism accounts for 10 percent of GDP.","path":"english2/2026.html"},{"id":"english2-2026-t3-p3-s1","examKey":"english2","examLabel":"英语二","year":"2026","text":3,"paragraph":3,"sentenceNo":1,"sentence":"Q32 段落定位 Disruptions have become increasingly frequent with train delays now a fixture in Italian media coverage.","path":"english2/2026.html"},{"id":"english2-2026-t3-p3-s2","examKey":"english2","examLabel":"英语二","year":"2026","text":3,"paragraph":3,"sentenceNo":2,"sentence":"Ferrovie dello Stato Italiane, the publicly controlled group that owns train operator Trenitalia and the national train network RFI, said 23 percent of all high-speed trains it operated were late in 2023.","path":"english2/2026.html"},{"id":"english2-2026-t3-p4-s1","examKey":"english2","examLabel":"英语二","year":"2026","text":3,"paragraph":4,"sentenceNo":1,"sentence":"The huge improvements in Italy’s obsolete infrastructure partly explained the disruption, said Ferrovie.","path":"english2/2026.html"},{"id":"english2-2026-t3-p4-s2","examKey":"english2","examLabel":"英语二","year":"2026","text":3,"paragraph":4,"sentenceNo":2,"sentence":"RFI, the network operator, is the single largest European recovery fund beneficiary with planned investments of €24bn by 2026.","path":"english2/2026.html"},{"id":"english2-2026-t3-p4-s3","examKey":"english2","examLabel":"英语二","year":"2026","text":3,"paragraph":4,"sentenceNo":3,"sentence":"Ferrovie will invest a total of €124bn in infrastructure over the next 10 years.","path":"english2/2026.html"},{"id":"english2-2026-t3-p5-s1","examKey":"english2","examLabel":"英语二","year":"2026","text":3,"paragraph":5,"sentenceNo":1,"sentence":"Q33 段落定位 Q34 段落定位 But lack of capacity is another problem.","path":"english2/2026.html"},{"id":"english2-2026-t3-p5-s2","examKey":"english2","examLabel":"英语二","year":"2026","text":3,"paragraph":5,"sentenceNo":2,"sentence":"Transport economist Andrea Giuricin said the planned investments would bring improvements but disruptions in the meantime were inevitable.","path":"english2/2026.html"},{"id":"english2-2026-t3-p5-s3","examKey":"english2","examLabel":"英语二","year":"2026","text":3,"paragraph":5,"sentenceNo":3,"sentence":"“We have a mixed system, there is no spare capacity and as soon as there’s a hiccup on the line, the situation becomes highly complex,” he said.","path":"english2/2026.html"},{"id":"english2-2026-t3-p5-s4","examKey":"english2","examLabel":"英语二","year":"2026","text":3,"paragraph":5,"sentenceNo":4,"sentence":"A mixed system means that high-speed trains must travel on the regular tracks on certain routes or when passing through large cities.","path":"english2/2026.html"},{"id":"english2-2026-t3-p5-s5","examKey":"english2","examLabel":"英语二","year":"2026","text":3,"paragraph":5,"sentenceNo":5,"sentence":"If there’s congestion or, for example, a local train breaks down, the entire high-speed network is affected.","path":"english2/2026.html"},{"id":"english2-2026-t3-p6-s1","examKey":"english2","examLabel":"英语二","year":"2026","text":3,"paragraph":6,"sentenceNo":1,"sentence":"Q35 段落定位 One of the most important changes the upgrades will bring is the segregation of the high-speed line from the regular one in certain urban centres through the construction of underground rail links.","path":"english2/2026.html"},{"id":"english2-2026-t3-p6-s2","examKey":"english2","examLabel":"英语二","year":"2026","text":3,"paragraph":6,"sentenceNo":2,"sentence":"Improvements will also come from the high-density technology and satellite signalling that RFI has been investing in for years, say experts.","path":"english2/2026.html"},{"id":"english2-2026-t3-p6-s3","examKey":"english2","examLabel":"英语二","year":"2026","text":3,"paragraph":6,"sentenceNo":3,"sentence":"It will allow for a reduction of the distance between high-speed trains travelling on the same line at any given time, which should mean a significant increase in capacity and traffic fluidity, according to Giuricin.","path":"english2/2026.html"},{"id":"english2-2026-t4-p1-s1","examKey":"english2","examLabel":"英语二","year":"2026","text":4,"paragraph":1,"sentenceNo":1,"sentence":"Q36 段落定位 In 2023, Chicago lost one of its most beloved street festivals.","path":"english2/2026.html"},{"id":"english2-2026-t4-p1-s2","examKey":"english2","examLabel":"英语二","year":"2026","text":4,"paragraph":1,"sentenceNo":2,"sentence":"The Silver Room Block Party, staged by Hyde Park community leader Eric Williams, announced it would not return in 2024.","path":"english2/2026.html"},{"id":"english2-2026-t4-p1-s3","examKey":"english2","examLabel":"英语二","year":"2026","text":4,"paragraph":1,"sentenceNo":3,"sentence":"What began as a small neighborhood gathering blossomed into a massive cultural event welcoming tens of thousands of people each year over nearly two decades before abruptly shutting down.","path":"english2/2026.html"},{"id":"english2-2026-t4-p2-s1","examKey":"english2","examLabel":"英语二","year":"2026","text":4,"paragraph":2,"sentenceNo":1,"sentence":"Q37 段落定位 Williams pointed to rising production costs and declining attendee donations as primary reasons the Silver Room Block Party could not continue, highlighting a reality that all street festival organizers face right now.","path":"english2/2026.html"},{"id":"english2-2026-t4-p2-s2","examKey":"english2","examLabel":"英语二","year":"2026","text":4,"paragraph":2,"sentenceNo":2,"sentence":"The cost of producing a street festival in Chicago has skyrocketed.","path":"english2/2026.html"},{"id":"english2-2026-t4-p2-s3","examKey":"english2","examLabel":"英语二","year":"2026","text":4,"paragraph":2,"sentenceNo":3,"sentence":"Security, entertainment, portable restrooms, insurance and even basics such as fencing and staffing have all become significantly more expensive.","path":"english2/2026.html"},{"id":"english2-2026-t4-p2-s4","examKey":"english2","examLabel":"英语二","year":"2026","text":4,"paragraph":2,"sentenceNo":4,"sentence":"At the same time, donations at festival gates have dropped dramatically.","path":"english2/2026.html"},{"id":"english2-2026-t4-p3-s1","examKey":"english2","examLabel":"英语二","year":"2026","text":4,"paragraph":3,"sentenceNo":1,"sentence":"Q38 段落定位 Chicago’s summer festivals are about more than just entertainment; they are economic engines that directly benefit the neighborhoods they’re in and the city of Chicago as whole.","path":"english2/2026.html"},{"id":"english2-2026-t4-p3-s2","examKey":"english2","examLabel":"英语二","year":"2026","text":4,"paragraph":3,"sentenceNo":2,"sentence":"Street festivals drive foot traffic to local businesses and foster the kind of cultural vibrancy that makes our city special.","path":"english2/2026.html"},{"id":"english2-2026-t4-p4-s1","examKey":"english2","examLabel":"英语二","year":"2026","text":4,"paragraph":4,"sentenceNo":1,"sentence":"Q38 段落定位 We often hear people ask why we solicit donations at our entry points, especially when the city’s largest festivals like the Chicago Jazz Festival do not request donations.","path":"english2/2026.html"},{"id":"english2-2026-t4-p4-s2","examKey":"english2","examLabel":"英语二","year":"2026","text":4,"paragraph":4,"sentenceNo":2,"sentence":"The fact is, unlike those large, city-produced music festivals, your neighborhood street festivals receive no city funding and rely on a combination of sponsorships, vendor fees and gate donations to cover their costs.","path":"english2/2026.html"},{"id":"english2-2026-t4-p5-s1","examKey":"english2","examLabel":"英语二","year":"2026","text":4,"paragraph":5,"sentenceNo":1,"sentence":"Q39 段落定位 Wicker Park Fest has long been one of Chicago’s most anticipated summer festivals, drawing upward of 70,000 attendees for a full weekend of live indie music, local art, small business vendors and, most importantly, community connection.","path":"english2/2026.html"},{"id":"english2-2026-t4-p5-s2","examKey":"english2","examLabel":"英语二","year":"2026","text":4,"paragraph":5,"sentenceNo":2,"sentence":"In 2024, Wicker Park Fest saw record-breaking attendance.","path":"english2/2026.html"},{"id":"english2-2026-t4-p5-s3","examKey":"english2","examLabel":"英语二","year":"2026","text":4,"paragraph":5,"sentenceNo":3,"sentence":"Despite the turnout, gate donations reached their lowest point in our history.","path":"english2/2026.html"},{"id":"english2-2026-t4-p5-s4","examKey":"english2","examLabel":"英语二","year":"2026","text":4,"paragraph":5,"sentenceNo":4,"sentence":"This year, we’ve been forced to scale back the footprint of the fest.","path":"english2/2026.html"},{"id":"english2-2026-t4-p5-s5","examKey":"english2","examLabel":"英语二","year":"2026","text":4,"paragraph":5,"sentenceNo":5,"sentence":"We are eliminating a stage, booking fewer performers and making additional cuts to reduce our costs, all while striving to keep the festival as vibrant as ever, as supportive of local artists and businesses, and as true to Wicker Park’s unique spirit and reputation as festgoers have come to expect.","path":"english2/2026.html"},{"id":"english2-2026-t4-p6-s1","examKey":"english2","examLabel":"英语二","year":"2026","text":4,"paragraph":6,"sentenceNo":1,"sentence":"Q40 段落定位 This summer, as you enjoy your favorite neighborhood street festival, I hope you’ll remember that they exist because of community support.","path":"english2/2026.html"},{"id":"english2-2026-t4-p6-s2","examKey":"english2","examLabel":"英语二","year":"2026","text":4,"paragraph":6,"sentenceNo":2,"sentence":"A thriving summer festival season doesn’t happen by accident; It happens when we all chip in.","path":"english2/2026.html"}];
